        self.i2v_task_mapping: Dict[int, Dict[str, Any]] = {}  # task_index -> {image_path, prompt, output_folder, source_file, local_index, media_id, cookie_index}
        self.i2v_file_output_mapping: Dict[str, Path] = {}  # source_file -> output_dir
        # ✅ Mapping cho Start+End to Video: task_index -> {image_path, end_image_path, prompt, output_folder, source_file, local_index, start_media_id, end_media_id, cookie_index}
        self.start_end_task_mapping: Dict[int, Dict[str, Any]] = {}
        # ✅ Mapping cho Integrate to Video: task_index -> {prompt, integrate_images, output_folder, source_file, local_index, media_ids, cookie_index, is_custom_integrate}
        self.integrate_task_mapping: Dict[int, Dict[str, Any]] = {}
        # ✅ Mapping cho Expand+Reference: task_index -> {prompt, output_folder, source_file, local_index, cookie_index, reference_media_ids}
        self.expand_reference_task_mapping: Dict[int, Dict[str, Any]] = {}
        self.flow_reference_paths: List[str] = []
        self.flow_tasks: List[FlowTaskData] = []  # Task grid data model
