    def init_ui(self):
        """Initialize UI theo layout ảnh"""
        self.setWindowTitle("Google Labs Flow")
        
        # Auto-scale theo màn hình thiết bị
        screen = QApplication.primaryScreen()
        screen_geometry = screen.availableGeometry()
        screen_width = screen_geometry.width()
        screen_height = screen_geometry.height()
        
        # Tính toán kích thước phù hợp (90% màn hình, tối đa 1600x1200) - TĂNG CAO NHIỀU
        window_width = min(int(screen_width * 0.9), 1600)
        window_height = min(int(screen_height * 0.9), 1280)  # Tăng từ 950 → 1200

        # Tối thiểu 1200x900 để đảm bảo UI đầy đủ - TĂNG MIN HEIGHT
        window_width = max(1200, window_width)
        window_height = max(900, window_height)  # Tăng từ 500 → 900
        
        # Center window - Đảm bảo window nằm trong màn hình
        x = max(0, (screen_width - window_width) // 2)
        y = max(0, (screen_height - window_height) // 2)
        
        # Đảm bảo window không bị đẩy ra ngoài màn hình
        if x + window_width > screen_width:
            x = max(0, screen_width - window_width)
        if y + window_height > screen_height:
            y = max(0, screen_height - window_height)
        
        self.setGeometry(x, y, window_width, window_height)
        
        # Cho phép user resize window - TĂNG MIN HEIGHT
        self.setMinimumSize(1200, 900)  # Tăng từ 700 → 900
        # ✅ Không set MaximumSize để cho phép maximize tự do
        # self.setMaximumSize(2560, 1600)  # Đã xóa để enable maximize button
        
        # Log kích thước để debug
        print(f"📐 Screen: {screen_width}x{screen_height}, Window: {window_width}x{window_height}")
        
        central = QWidget()
        self.setCentralWidget(central)
        main_layout = QVBoxLayout(central)
        main_layout.setContentsMargins(0, 0, 0, 0)
        main_layout.setSpacing(0)
        
        self.build_header(main_layout)

        # ===== ACCOUNT BAR =====
        self.build_account_bar(main_layout)

        # ===== WINDOW CONTROLS TOOLBAR =====
        self.build_window_controls(main_layout)

        # ===== MAIN TOOLBAR (4 tabs) =====
        self.build_main_toolbar(main_layout)
        
        # ===== SUB TOOLBAR (Video modes + báo cáo) =====
        self.build_sub_toolbar(main_layout)
        
        # ===== TAB CONTENT (Stacked) =====
        self.tab_stack = QStackedWidget()
        main_layout.addWidget(self.tab_stack)
        
        # Build tab contents
        self.build_video_tab_content()
        self.build_image_tab_content()
        self.build_edit_tab_content()
        self.build_sync_tab_content()
        self.build_rewrite_tab_content()
        self.build_script_writing_tab_content()
        self.build_image_extraction_tab_content()
        self.build_clone_videos_tab_content()
        self.build_flow_tab_content()
        # Khởi tạo Flow concurrent range
        if hasattr(self, "update_flow_concurrent_range"):
            self.update_flow_concurrent_range()
        
        # Set initial tab to Video
        self.tab_stack.setCurrentIndex(0)
        
        # Apply styling
        self.apply_modern_style()

        # Update UI based on user plan
        self.update_ui_based_on_plan()

        # ✅ Load recaptcha settings (headless mode + proxy pool) từ file
        self._load_recaptcha_settings()

        # Setup keyboard shortcuts for testing
        self.setup_keyboard_shortcuts()

