    def toggle_maximize_restore(self):
        """Toggle between maximized and normal window state - Đảm bảo window luôn trong màn hình"""
        if self.is_maximized:
            # Restore normal size
            self.showNormal()
            if self.normal_geometry:
                # Đảm bảo geometry nằm trong màn hình
                screen = QApplication.primaryScreen().availableGeometry()
                x = self.normal_geometry.x()
                y = self.normal_geometry.y()
                width = self.normal_geometry.width()
                height = self.normal_geometry.height()
                
                # Đảm bảo window không bị đẩy ra ngoài màn hình
                if x < screen.x():
                    x = screen.x()
                if y < screen.y():
                    y = screen.y()
                if x + width > screen.x() + screen.width():
                    x = screen.x() + screen.width() - width
                if y + height > screen.y() + screen.height():
                    y = screen.y() + screen.height() - height
                
                # Đảm bảo window không quá nhỏ
                if width < self.minimumWidth():
                    width = self.minimumWidth()
                if height < self.minimumHeight():
                    height = self.minimumHeight()
                
                # Đảm bảo window không quá lớn
                if width > screen.width():
                    width = screen.width()
                if height > screen.height():
                    height = screen.height()
                
                self.setGeometry(x, y, width, height)
            self.btn_maximize.setText("🔲")
            self.btn_maximize.setToolTip("Phóng to")
            self.is_maximized = False
        else:
            # Maximize - Lưu geometry hiện tại trước
            self.normal_geometry = self.geometry()
            # Sử dụng showMaximized() để đảm bảo window nằm đúng trong màn hình
            self.showMaximized()
            self.btn_maximize.setText("🗗")
            self.btn_maximize.setToolTip("Thu nhỏ")
            self.is_maximized = True

    def update_ui_based_on_plan(self):
        """Update UI elements based on user subscription plan"""
        plan_key = getattr(self, "user_plan_key", "free")
        badge_color = self.subscription_limits.get("badge_color", "#4CAF50")
        self.lbl_user_plan.setText(f"Gói: {self.user_plan}")
        self.lbl_user_plan.setStyleSheet(f"color: {badge_color}; font-weight: bold; font-size: 11px;")
        is_free_plan = str(plan_key).lower() == "free"
        
        if plan_key in ("ultra", "enterprise", "premium"):
            self.enable_all_edit_features()
            print(f"✅ {self.user_plan} mode: Bật đầy đủ tính năng")
        else:
            self.limit_edit_features()
            print(f"⚠️ {self.user_plan} mode: Một số tính năng bị giới hạn")

        # ✅ Không ẩn nút Tùy Chỉnh (Trả Phí); chỉ disable nếu gói Free
        if hasattr(self, "rb_integrate_custom") and self.rb_integrate_custom:
            self.rb_integrate_custom.setEnabled(not is_free_plan)
            if is_free_plan:
                self.rb_integrate_custom.setToolTip("Nâng cấp gói để dùng chế độ Tùy Chỉnh")
            else:
                self.rb_integrate_custom.setToolTip("")
        if hasattr(self, "btn_open_custom") and self.btn_open_custom:
            self.btn_open_custom.setEnabled(not is_free_plan)
            if is_free_plan:
                self.btn_open_custom.setToolTip("Nâng cấp gói để dùng cấu hình Tùy Chỉnh")
            else:
                self.btn_open_custom.setToolTip("")

        QTimer.singleShot(100, self.force_update_edit_ui)
        self._apply_extend_group_limit()

