    def get_plan_limit(self, key, default=None):
        limits = getattr(self, "subscription_limits", None)
        if not limits:
            return default
        if key not in limits:
            return default
        return limits[key]

    def _apply_plan_cookie_limit(self):
        """Trim cookies_list to device_info limit from database (if any)."""
        try:
            # ✅ LẤY GIỚI HẠN TỪ DATABASE (device_info) - KHÔNG DÙNG policies
            max_cookies_allowed = None  # None = không giới hạn
            
            try:
                user_id = None
                if hasattr(self, 'current_user_id') and self.current_user_id:
                    user_id = self.current_user_id
                elif hasattr(self, 'user_info') and self.user_info:
                    user_id = self.user_info.get('user_id') or (self.user_info.get('user', {}) or {}).get('id')
                
                if not user_id:
                    try:
                        from iting_api import ItingAPI
                        from supabase_manager import supabase_manager
                        api = ItingAPI()
                        token = api.load_auth_token()
                        if token:
                            user_id = supabase_manager.get_user_id_from_session(token)
                    except:
                        pass
                
                if user_id:
                    from supabase_manager import supabase_manager
                    # Lấy is_key_login từ self nếu có
                    is_key_login = getattr(self, 'is_key_login', None)
                    success, device_info_str = supabase_manager.get_user_device_info(user_id, is_key_login=is_key_login)
                    if success and device_info_str:
                        try:
                            device_info_value = int(str(device_info_str).strip())
                            # Nếu device_info > 0, dùng làm giới hạn
                            if device_info_value > 0:
                                max_cookies_allowed = device_info_value
                            # Nếu device_info <= 0, không giới hạn (None)
                        except:
                            pass
            except Exception as e:
                self.log(f"⚠️ Lỗi khi lấy device_info từ database: {e}")
            
            # Chỉ trim nếu có giới hạn (max_cookies_allowed không phải None)
            if max_cookies_allowed is not None and len(self.cookies_list) > max_cookies_allowed:
                removed = len(self.cookies_list) - max_cookies_allowed
                self.cookies_list = self.cookies_list[:max_cookies_allowed]
                self.log(f"⚠️ Giới hạn device_info chỉ cho phép {max_cookies_allowed} cookie(s) → đã cắt bớt {removed}.")
                self.cookie_value = self.cookies_list[0] if self.cookies_list else ""
        except Exception as e:
            self.log(f"⚠️ Lỗi khi áp giới hạn cookie: {e}")

    def _apply_extend_group_limit(self):
        """Clamp extend group size combo theo gói hiện tại."""
        try:
            if not hasattr(self, "combo_extend_group_size") or self.combo_extend_group_size is None:
                return
            limit = self.get_plan_limit("extend_prompts_per_project")
            # ✅ Ultra và Enterprise: tối đa 100 prompts/project, các gói khác: tối đa 5
            is_ultra = getattr(self, 'is_ultra_user', False) or (self.user_plan_key and ("ultra" in str(self.user_plan_key).lower() or "enterprise" in str(self.user_plan_key).lower()))
            max_value = 100 if is_ultra else 5
            if limit is not None:
                try:
                    limit = int(limit)
                    if limit >= 1:
                        max_value = min(max_value, limit)
                except Exception:
                    pass
            current_value = 1
            try:
                current_value = int(self.combo_extend_group_size.currentText())
            except Exception:
                pass
            self.combo_extend_group_size.blockSignals(True)
            self.combo_extend_group_size.clear()
            self.combo_extend_group_size.addItems([str(i) for i in range(1, max_value + 1)])
            self.combo_extend_group_size.setCurrentText(str(min(current_value, max_value)))
            self.combo_extend_group_size.blockSignals(False)
            # ✅ Cập nhật label hiển thị max prompts
            if hasattr(self, 'lbl_extend_max_prompts'):
                self.lbl_extend_max_prompts.setText(f"đoạn (max {max_value})")
            if limit is not None:
                self.log(f"📏 Gói {self.user_plan}: tối đa {max_value} prompt/project cho Extend.")
            else:
                plan_type = "Ultra/Enterprise" if is_ultra else "Standard"
                self.log(f"✅ Gói hiện tại: tối đa {max_value} prompt/project cho Extend ({plan_type}).")
        except Exception as e:
            self.log(f"⚠️ Lỗi áp giới hạn Extend: {e}")

    def set_user_plan(self, plan, limits=None):
        """Set user subscription plan (accepts any casing or alias)."""
        plan_key = normalize_subscription_type(plan)
        plan_limits = limits or get_subscription_limits(plan_key)
        self.user_plan_key = plan_limits.get("plan_key", plan_key)
        self.subscription_limits = plan_limits
        self.user_plan = plan_limits.get("display_name", self.user_plan_key.title())
        self.update_ui_based_on_plan()
        if plan_limits.get("notes"):
            print(f"📦 User plan updated to: {self.user_plan} ({plan_limits['notes']})")
        else:
            print(f"📦 User plan updated to: {self.user_plan}")
        
        # Ad handling
        if self.user_plan_key in ("ultra", "enterprise", "premium"):
            if hasattr(self, "ad_check_timer") and self.ad_check_timer.isActive():
                self.ad_check_timer.stop()
                self.log("✅ Gói trả phí: đã dừng timer quảng cáo")
            if hasattr(self, "ad_popup") and self.ad_popup and self.ad_popup.isVisible():
                try:
                    self.ad_popup.close()
                    self.ad_popup.deleteLater()
                    self.log("✅ Đã đóng popup quảng cáo do gói trả phí")
                except Exception:
                    pass
        else:
            if hasattr(self, "ad_check_timer") and not self.ad_check_timer.isActive():
                # Khởi động lại timer quảng cáo cho gói Free/Basic
                self.ad_check_timer.start(1200000)
                self.ad_shown_once = False
        # Apply plan-specific limits
        self._apply_plan_cookie_limit()
        try:
            self.update_max_concurrent_from_cookies()
            self._apply_extend_group_limit()
        except Exception:
            pass

    def test_switch_plan(self):
        """Test method to switch between plans (for development)"""
        plans = ["free", "premium", "ultra", "enterprise", "basic"]
        current_key = getattr(self, "user_plan_key", "free")
        try:
            current_index = plans.index(current_key)
        except ValueError:
            current_index = 0
        next_plan = plans[(current_index + 1) % len(plans)]
        self.set_user_plan(next_plan)

    def rebuild_full_edit_interface(self):
        """Rebuild the full edit interface for Ultra users"""
        # Remove current tab and rebuild
        if hasattr(self, 'tab_stack') and self.tab_stack.count() > 2:
            # Remove current edit tab
            self.tab_stack.removeWidget(self.tab_stack.widget(2))
            # Rebuild edit tab with new plan
            self.build_edit_tab_content()
            # Set back to edit tab
            self.tab_stack.setCurrentIndex(2)

    def update_plan_from_api(self, plan_info):
        """Update user plan from API response"""
        if plan_info:
            plan = plan_info.get("plan") or plan_info.get("plan_key")
            limits = plan_info.get("limits")
            self.set_user_plan(plan or "free", limits)
        else:
            self.set_user_plan("premium")

    def fix_edit_tab_layout(self):
        """Fix layout issues in Edit tab for better responsiveness"""
        if hasattr(self, 'tab_stack') and self.tab_stack.count() > 2:  # Edit tab is index 2
            edit_widget = self.tab_stack.widget(2)
            if edit_widget:
                # Ensure the splitter has proper sizes
                splitters = edit_widget.findChildren(QSplitter)
                if splitters:
                    splitter = splitters[0]
                    # Set balanced sizes
                    splitter.setSizes([500, 600])  # Trái: 500, Phải: 600
                    splitter.setChildrenCollapsible(False)

        # Ensure video list has proper height
        if hasattr(self, 'lst_edit_videos'):
            self.lst_edit_videos.setMinimumHeight(350)

        # Group box đã được xóa

    def resizeEvent(self, event):
        """Handle window resize events"""
        super().resizeEvent(event)
        # Fix layout when window is resized
        if hasattr(self, 'tab_stack') and self.tab_stack.currentIndex() == 2:  # Edit tab
            self.fix_edit_tab_layout()

    def build_main_toolbar(self, parent_layout):
        """Main toolbar: 4 main tabs"""
        toolbar = QFrame()
        toolbar.setFixedHeight(45)
        toolbar.setObjectName("mainToolbar")
        # Nổi bật nút được chọn/focus
        toolbar.setStyleSheet("""
            QPushButton#mainTab {
                background: #F3F6FC;
                color: #1f2937;
                border: 1px solid #D6E2FF;
                border-radius: 8px;
                padding: 6px 12px;
                font-weight: 600;
            }
            QPushButton#mainTab:checked {
                background: #1A73E8;
                color: white;
                border: 1px solid #1662c4;
            }
            QPushButton#mainTab:focus {
                outline: none;
                border: 2px solid #1662c4;
            }
        """)
        
        layout = QHBoxLayout(toolbar)
        layout.setContentsMargins(10, 5, 10, 5)
        layout.setSpacing(5)
        
        self.main_tabs = []
        tabs = ["🎬 Tạo Video", "🖼️ Tạo Ảnh Whisk", "✂️ Edit", "⚡ Siêu Đồng Bộ", "✍️ Viết lại nội dung", "📝 Viết Kịch Bản", "🖼️ Trích Xuất Ảnh", "🎥 Clone Videos", "🌊 Tạo Ảnh Banana Pro"]
        
        for i, text in enumerate(tabs):
            btn = QPushButton(text)
            btn.setCheckable(True)
            btn.setFixedHeight(38)
            btn.setObjectName("mainTab")
            btn.clicked.connect(lambda checked, idx=i: self.switch_main_tab(idx))
            layout.addWidget(btn)
            self.main_tabs.append(btn)
        
        self.main_tabs[0].setChecked(True)
        
        # ✅ Ẩn các tab tạm thời không dùng
        hidden_tab_indices = [3, 4, 5, 6, 7]  # Siêu Đồng Bộ, Viết lại nội dung, Viết Kịch Bản, Trích Xuất Ảnh, Clone Videos
        for idx in hidden_tab_indices:
            if idx < len(self.main_tabs):
                self.main_tabs[idx].setVisible(False)
        
        layout.addStretch()
        self.btn_cookie = QPushButton("🔑 Cài Đặt Cookie")
        self.btn_cookie.setCheckable(False)
        self.btn_cookie.setFixedHeight(38)
        self.btn_cookie.setObjectName("reportTab")
        self.btn_cookie.clicked.connect(self.show_cookie_dialog)
        layout.addWidget(self.btn_cookie)
        
        # ✅ Cài Đặt Gemini API Key button (kế bên nút cookie)
        self.btn_gemini_api = QPushButton("🔑 Cài Đặt Gemini API")
        self.btn_gemini_api.setCheckable(False)
        self.btn_gemini_api.setFixedHeight(38)
        self.btn_gemini_api.setObjectName("reportTab")
        self.btn_gemini_api.clicked.connect(self.show_gemini_api_dialog)
        layout.addWidget(self.btn_gemini_api)
        
        parent_layout.addWidget(toolbar)
    
    def build_sub_toolbar(self, parent_layout):
        """Sub toolbar: Video modes + báo cáo"""
