        self.sub_toolbar.setFixedHeight(38)
        self.sub_toolbar.setMinimumWidth(1000)  # Đảm bảo toolbar đủ rộng để hiển thị tất cả nút
        self.sub_toolbar.setObjectName("subToolbar")
