        self.flow_task_grid.setShowGrid(False)
        self.flow_task_grid.setAlternatingRowColors(True)
        self.flow_task_grid.setStyleSheet("""
            QTableWidget {
                background: #ffffff;
                border: 1px solid #e2e8f0;
                border-radius: 10px;
                font-size: 13px;
                outline: none;
            }
            QTableWidget::item {
                padding: 6px 10px;
                border-bottom: 1px solid #f1f5f9;
            }
            QTableWidget::item:alternate {
                background: #fafbfc;
            }
            QTableWidget::item:selected {
                background: #eff6ff;
                color: #1e40af;
            }
            QTableWidget::item:hover {
                background: #f0f9ff;
            }
            QHeaderView::section {
                background: #f1f5f9;
                color: #475569;
                font-weight: 700;
                font-size: 12px;
                border: none;
                border-bottom: 2px solid #cbd5e1;
                padding: 8px 10px;
            }
            QScrollBar:vertical {
                background: #f8fafc;
                width: 8px;
                border-radius: 4px;
            }
            QScrollBar::handle:vertical {
                background: #cbd5e1;
                border-radius: 4px;
                min-height: 30px;
            }
            QScrollBar::handle:vertical:hover {
                background: #94a3b8;
            }
        """)

        # Column widths
        header = self.flow_task_grid.horizontalHeader()
        header.setSectionResizeMode(0, QHeaderView.Fixed)
        self.flow_task_grid.setColumnWidth(0, 45)
        header.setSectionResizeMode(1, QHeaderView.Fixed)
        self.flow_task_grid.setColumnWidth(1, 180)
        header.setSectionResizeMode(2, QHeaderView.Fixed)
        self.flow_task_grid.setColumnWidth(2, 170)
        header.setSectionResizeMode(3, QHeaderView.Stretch)

        layout.addWidget(self.flow_task_grid, 1)

        # ==================== BOTTOM TOOLBAR ====================
        toolbar_frame = QFrame()
