    def build_image_preview_panel(self):
        """RIGHT panel for Image tab: 4 image preview slots"""
        widget = QWidget()
        layout = QVBoxLayout(widget)
        layout.setContentsMargins(5, 5, 5, 5)
        
        preview_group = QGroupBox("🖼️ Xem trước ảnh (4 tấm)")
        preview_layout = QVBoxLayout()
        
        # Create 2x2 grid for 4 preview labels
        grid = QWidget()
        grid_layout = QGridLayout(grid)
        grid_layout.setSpacing(8)
        
        self.preview_labels = []
        self.preview_paths = [None, None, None, None]
        
        for i in range(4):
            row = i // 2
            col = i % 2
            
            # Container for each preview
            slot_frame = QFrame()
            slot_frame.setFrameShape(QFrame.Box)
            slot_layout = QVBoxLayout(slot_frame)
            slot_layout.setContentsMargins(5, 5, 5, 5)
            
            # Label for image display
            img_label = QLabel(f"Preview {i+1}\nChưa có ảnh")
            img_label.setFixedSize(280, 210)
            img_label.setAlignment(Qt.AlignCenter)
            img_label.setStyleSheet("background-color: white; border: 1px solid #D9D9D9;")
            img_label.setScaledContents(False)
            slot_layout.addWidget(img_label)
            
            # Info label
            info_label = QLabel(f"Slot {i+1}")
            info_label.setStyleSheet("font-size: 9px; color: #666666;")
            info_label.setAlignment(Qt.AlignCenter)
            slot_layout.addWidget(info_label)
            
            grid_layout.addWidget(slot_frame, row, col)
            
            # Store references
            self.preview_labels.append((img_label, info_label))
        
        preview_layout.addWidget(grid)
        
        # Preview info
        self.lbl_preview_info = QLabel("Chọn ảnh để xem preview")
        self.lbl_preview_info.setStyleSheet("color: #666666; font-size: 10px; font-style: italic;")
        self.lbl_preview_info.setAlignment(Qt.AlignCenter)
        preview_layout.addWidget(self.lbl_preview_info)
        
        preview_group.setLayout(preview_layout)
        layout.addWidget(preview_group)
        
        return widget
    
    def build_edit_tab_content(self):
        """Build Edit tab content"""
        edit_widget = QWidget()
        layout = QVBoxLayout(edit_widget)
        layout.setContentsMargins(5, 5, 5, 5)
        layout.setSpacing(5)

        # Main splitter: Video List | Audio & Export
        splitter = QSplitter(Qt.Horizontal)

        # LEFT: Video list and controls
        left_panel = self.build_edit_left_panel()
        splitter.addWidget(left_panel)

        # RIGHT: Audio and export settings
        right_panel = self.build_edit_right_panel()
        splitter.addWidget(right_panel)

        splitter.setSizes([600, 600])
        splitter.setChildrenCollapsible(False)

        layout.addWidget(splitter)
        self.tab_stack.addWidget(edit_widget)
    
