    def build_sync_tab_content(self):
        """Build Sync (Siêu Đồng Bộ) tab content.
        
        Hiện tại tab này được thay thế hoàn toàn bằng thông báo hướng dẫn
        sử dụng các chức năng Tham Chiếu / Mở Rộng + Tham Chiếu để thực hiện Siêu Đồng Bộ.
        """
        sync_widget = QWidget()
        layout = QVBoxLayout(sync_widget)
        layout.setContentsMargins(40, 40, 40, 40)
        layout.setSpacing(20)

        info_label = QLabel(
            "Vui lòng sử dụng chức năng Tham chiếu hoặc Mở rộng + Tham chiếu "
            "để thực hiện Siêu Đồng Bộ."
        )
        info_label.setWordWrap(True)
        info_label.setAlignment(Qt.AlignCenter)
        info_label.setStyleSheet(
            "font-size: 16px; font-weight: 600; color: #0f172a; padding: 20px;"
        )

        sub_label = QLabel(
            "Tab Siêu Đồng Bộ cũ đã được đơn giản hóa. "
            "Bạn có thể vào tab Tạo Video và chọn chế độ 'Tham chiếu' hoặc "
            "'Mở rộng + Tham chiếu' để tiếp tục sử dụng tính năng này."
        )
        sub_label.setWordWrap(True)
        sub_label.setAlignment(Qt.AlignCenter)
        sub_label.setStyleSheet("font-size: 13px; color: #64748b;")

        layout.addStretch()
        layout.addWidget(info_label)
        layout.addWidget(sub_label)
        layout.addStretch()

        self.tab_stack.addWidget(sync_widget)
    
    def build_sync_left_panel(self):
        """LEFT panel: Script & Parameters - GIỐNG GUI_APP.PY"""
        widget = QWidget()
        layout = QVBoxLayout(widget)
        layout.setContentsMargins(10, 10, 10, 10)
        layout.setSpacing(10)
        
