    def _update_stage4_generate_state(self):
        has_script = bool(self.stage4_loaded_scenes)
        has_chars = bool(self.stage4_character_profiles)
        ready = has_script and has_chars
        can_generate = ready and not getattr(self, "_stage4_generating", False)
        if hasattr(self, "btn_stage4_generate"):
            self.btn_stage4_generate.setEnabled(can_generate)
        if hasattr(self, "btn_stage4_export"):
            self.btn_stage4_export.setEnabled(bool(self.stage4_prompt_results) and not getattr(self, "_stage4_generating", False))
        status = []
        status.append("✅ Script OK" if has_script else "❌ Chưa có script")
        status.append("✅ Nhân vật OK" if has_chars else "❌ Chưa có nhân vật")
        if hasattr(self, "stage4_status_label") and not getattr(self, "_stage4_generating", False):
            self.stage4_status_label.setText(" | ".join(status))

    def on_stage4_select_script_file(self):
        file_path, _ = QFileDialog.getOpenFileName(
            self, "Chọn file kịch bản JSON", "",
            "JSON Files (*.json *.txt);;All Files (*.*)"
        )
        if not file_path:
            return
        self.stage4_script_input.setText(file_path)
        self.stage4_script_path = file_path
        self.last_exported_script_path = file_path
        self._load_stage4_script_file(file_path)

    def _load_stage4_script_file(self, file_path: str):
        try:
            raw_text = Path(file_path).read_text(encoding="utf-8")
            scenes = []
            if raw_text.strip().startswith("["):
                data = json.loads(raw_text)
                if isinstance(data, list):
                    scenes = data
            else:
                chunks = [chunk.strip() for chunk in raw_text.split("\n---") if chunk.strip()]
                for chunk in chunks:
                    try:
                        scenes.append(json.loads(chunk))
                    except json.JSONDecodeError:
                        continue
            if not scenes:
                scenes = self._parse_stage4_text_script(raw_text)
            if not scenes:
                raise ValueError("Không tìm thấy dữ liệu cảnh hợp lệ trong file này.")
            self.stage4_loaded_scenes = scenes
            self.stage4_script_status_label.setText(f"Đã tải {len(scenes)} cảnh")
            self.stage4_prompt_table.setRowCount(0)
            self.stage4_prompt_results = []
            self._update_stage4_generate_state()
        except Exception as e:
            QMessageBox.critical(self, "Lỗi", f"Không thể đọc file kịch bản: {e}")
            self.stage4_script_status_label.setText("❌ Lỗi đọc file")
            self.stage4_loaded_scenes = []
            self._update_stage4_generate_state()

    def on_stage4_select_character_file(self):
        file_path, _ = QFileDialog.getOpenFileName(
            self, "Chọn file nhân vật", "",
            "JSON Files (*.json);;Text Files (*.txt);;All Files (*.*)"
        )
        if not file_path:
            return
        self.stage4_character_input.setText(file_path)
        self.stage4_character_path = file_path
        self.last_character_file_path = file_path
        self._load_stage4_character_file(file_path)

    def _load_stage4_character_file(self, file_path: str):
        try:
            path = Path(file_path)
            profiles = {}
            if path.suffix.lower() == ".json":
                data = json.loads(path.read_text(encoding="utf-8"))
                if isinstance(data, dict):
                    if "characterProfiles" in data:
                        profiles = data["characterProfiles"]
                    elif "profile" in data and "character_name" in data:
                        profiles = {data["character_name"]: data["profile"]}
                    elif "characters" in data and isinstance(data["characters"], list):
                        profiles = {item.get("name", f"Character_{idx}"): item for idx, item in enumerate(data["characters"], 1)}
                    else:
                        profiles = data
                elif isinstance(data, list):
                    for idx, item in enumerate(data, 1):
                        if isinstance(item, dict):
                            name = item.get("character_name") or item.get("name") or f"Character_{idx}"
                            profiles[name] = item.get("profile", item)
            else:
                text = path.read_text(encoding="utf-8")
                multi = parse_multiple_profiles(text)
                if multi:
                    profiles = multi
                else:
                    single = parse_character_profile_from_text(text, path.stem)
                    if single:
                        profiles = {path.stem: single}
            if not profiles:
                raise ValueError("Không tìm thấy dữ liệu nhân vật trong file.")
            self.stage4_character_profiles = profiles
            self.stage4_character_status_label.setText(f"Đã tải {len(profiles)} nhân vật")
            self._update_stage4_generate_state()
        except Exception as e:
            QMessageBox.critical(self, "Lỗi", f"Không thể đọc file nhân vật: {e}")
            self.stage4_character_status_label.setText("❌ Lỗi đọc file")
            self.stage4_character_profiles = {}
            self._update_stage4_generate_state()

    def _set_stage4_generating(self, is_generating: bool, status_text: Optional[str] = None):
        self._stage4_generating = is_generating
        if status_text and hasattr(self, "stage4_status_label"):
            self.stage4_status_label.setText(status_text)
        self._update_stage4_generate_state()

    def _parse_stage4_text_script(self, text: str):
        scenes = []
        if "🎬 CẢNH" not in text:
            return scenes
        pattern = r"🎬 CẢNH\s+(\d+).*?(?=🎬 CẢNH|\Z)"
        for match in re.finditer(pattern, text, re.S):
            scene_number = int(match.group(1))
            block = match.group(0)
            script_description = self._extract_stage4_section(block, "📝 KỊCH BẢN:", "📹 PROMPT VIDEO:")
            video_prompt = self._extract_stage4_section(block, "📹 PROMPT VIDEO:", "👥 NHÂN VẬT:")
            characters_block = self._extract_stage4_section(block, "👥 NHÂN VẬT:", "⚠️")
            if not characters_block:
                characters_block = self._extract_stage4_section(block, "👥 NHÂN VẬT:", "════════")
            characters = []
            if characters_block:
                for line in characters_block.splitlines():
                    line = line.strip().lstrip("•").strip("• ").strip()
                    if line:
                        characters.append(line)
            if script_description or video_prompt:
                scenes.append({
                    "currentScene": {
                        "sceneNumber": scene_number,
                        "scriptDescription": script_description.strip(),
                        "videoPrompt": video_prompt.strip(),
                        "charactersInScene": characters,
                        "dialogue": []
                    }
                })
        return scenes

    def _extract_stage4_section(self, block: str, start_marker: str, end_marker: str):
        start_pattern = re.escape(start_marker)
        if end_marker:
            end_pattern = re.escape(end_marker)
            regex = start_pattern + r"(.*?)" + end_pattern
        else:
            regex = start_pattern + r"(.*)"
        match = re.search(regex, block, re.S)
        if match:
            return match.group(1).strip()
        return ""

    def _build_stage4_topic_text(self):
        if not self.stage4_loaded_scenes:
            return ""
        sections = ["### SCENE OUTLINE ###"]
        for scene in self.stage4_loaded_scenes:
            info = scene.get("currentScene", scene)
            number = info.get("sceneNumber", len(sections))
            script_desc = info.get("scriptDescription") or ""
            video_prompt = info.get("videoPrompt") or ""
            chars = info.get("charactersInScene") or []
            sections.append(f"Scene {number}: {script_desc}")
            if video_prompt and video_prompt != script_desc:
                sections.append(f"Visual Notes: {video_prompt}")
            if chars:
                sections.append(f"Characters: {', '.join(chars)}")
            sections.append("")
        if self.stage4_character_profiles:
            sections.append("### CHARACTER PROFILES ###")
            for name, profile in self.stage4_character_profiles.items():
                summary = self._summarize_character_profile(name)
                sections.append(f"{name}: {summary}")
        return "\n".join(sections).strip()

    def _stage4_get_profile_field(self, profile_obj, keyword_variants):
        keywords = [k.lower() for k in keyword_variants]
        stack = [profile_obj]
        while stack:
            current = stack.pop()
            if isinstance(current, dict):
                for key, value in current.items():
                    if isinstance(value, (dict, list)):
                        stack.append(value)
                    elif isinstance(value, str) and value.strip():
                        if key.lower() in keywords:
                            return value.strip()
            elif isinstance(current, list):
                stack.extend(current)
        return ""

    def _summarize_character_profile(self, char_name: str) -> str:
        profile = self.stage4_character_profiles.get(char_name)
        if not profile:
            return "No profile"
        appearance = self._stage4_get_profile_field(profile, ["appearance", "ngoại hình"])
        clothing = self._stage4_get_profile_field(profile, ["clothing", "trang phục"])
        personality = self._stage4_get_profile_field(profile, ["personality", "tính cách"])
        behavior = self._stage4_get_profile_field(profile, ["behavior", "hành vi"])
        voice = self._stage4_get_profile_field(profile, ["voice_description", "giọng nói"])
        snippets = []
        if appearance:
            snippets.append(f"Look: {appearance}")
        if clothing:
            snippets.append(f"Outfit: {clothing}")
        if personality:
            snippets.append(f"Traits: {personality}")
        if behavior:
            snippets.append(f"Behavior: {behavior}")
        if voice:
            snippets.append(f"Voice: {voice}")
        return "; ".join(snippets) if snippets else "Profile loaded nhưng thiếu mô tả chi tiết"

    def _format_stage4_dialogue(self, dialogue_list):
        if not dialogue_list:
            return "Dialog: (none)"
        lines = []
        for item in dialogue_list:
            char_name = item.get("character", "Unknown")
            text = item.get("text", "")
            if text:
                lines.append(f"{char_name}: \"{text}\"")
        language = self.cmb_stage4_dialogue.currentText() if hasattr(self, "cmb_stage4_dialogue") else "Vietnamese"
        return f"Dialog ({language}): " + " / ".join(lines)

    def _compose_stage4_prompt(self, scene_data):
        scene_info = scene_data.get("currentScene", scene_data)
        scene_number = scene_info.get("sceneNumber", len(self.stage4_prompt_results) + 1)
        title = scene_info.get("scriptDescription") or f"Cảnh {scene_number}"
        video_prompt = scene_info.get("videoPrompt", "")
        characters = scene_info.get("charactersInScene", [])
        char_section = " | ".join(
            f"{name}: {self._summarize_character_profile(name)}" for name in characters
        ) if characters else "No characters"
        style = self.cmb_stage4_style.currentText()
        camera = self.cmb_stage4_camera.currentText()
        mood = self.cmb_stage4_mood.currentText()
        setting = self.txt_stage4_setting.text().strip() or self.story_manager.project_info.theme
        dialogue = self._format_stage4_dialogue(scene_info.get("dialogue", []))
        subtitles = self.cmb_stage4_subtitles.currentText()
        parts = [
            f"Scene {scene_number:02d} – {title}",
            f"Characters: {char_section}",
            f"Style: {style}",
            f"Camera: {camera}",
            f"Setting: {setting}",
            f"Mood: {mood}",
            f"Video Prompt: {video_prompt}",
            dialogue,
            f"Subtitles: {subtitles}"
        ]
        return " | ".join([part for part in parts if part and part.strip()])

    def _stage4_on_ai_prompts_ready(self, result):
        try:
            scripts = (result or {}).get("script", [])
            if not scripts:
                QMessageBox.warning(self, "AI không trả về prompt", "Vui lòng thử lại hoặc kiểm tra dữ liệu đầu vào.")
                self._set_stage4_generating(False, "AI không trả về prompt. Vui lòng thử lại.")
                return
            self.stage4_prompt_table.setRowCount(0)
            new_results = []
            for idx, script_line in enumerate(scripts, 1):
                title = self._extract_stage4_ai_title(script_line)
                preview = script_line if len(script_line) < 200 else script_line[:197] + "..."
                row = self.stage4_prompt_table.rowCount()
                self.stage4_prompt_table.insertRow(row)
                self.stage4_prompt_table.setItem(row, 0, QTableWidgetItem(f"Cảnh {idx:02d}"))
                self.stage4_prompt_table.setItem(row, 1, QTableWidgetItem(title))
                preview_item = QTableWidgetItem(preview)
                preview_item.setToolTip(script_line)
                self.stage4_prompt_table.setItem(row, 2, preview_item)
                new_results.append({
                    "sceneNumber": idx,
                    "title": title,
                    "prompt": script_line,
                    "characters": self._extract_stage4_ai_characters(script_line),
                    "raw": {"prompt": script_line}
                })
            self.stage4_prompt_results = new_results
            self._set_stage4_generating(False, f"✅ Đã tạo {len(new_results)} prompt từ AI")
            self.btn_stage4_export.setEnabled(True)
        except Exception as e:
            self._set_stage4_generating(False, f"Lỗi xử lý kết quả: {e}")

    def _stage4_on_ai_error(self, error_message):
        self._set_stage4_generating(False, f"❌ Lỗi tạo prompt: {error_message}")
        QMessageBox.critical(self, "Lỗi tạo prompt", error_message)

    def _extract_stage4_ai_title(self, script_line: str) -> str:
        if not script_line:
            return "Prompt"
        first_segment = script_line.split("|", 1)[0].strip()
        return first_segment or "Prompt"

    def _extract_stage4_ai_characters(self, script_line: str) -> List[str]:
        characters = []
        if not script_line:
            return characters
        segments = [seg.strip() for seg in script_line.split("|")]
        for seg in segments[1:5]:
            if not seg:
                continue
            lower = seg.lower()
            if lower.startswith(("style", "character voices", "camera", "setting", "mood", "audio", "dialog", "subtitles")):
                continue
            name = seg.split(":")[0].strip()
            if name and len(name) < 60 and not name.lower().startswith("scene"):
                characters.append(name)
        if not characters and self.stage4_character_profiles:
            characters = list(self.stage4_character_profiles.keys())
        return list(dict.fromkeys(characters))[:4]

    def on_stage4_generate_prompts(self):
        if not self.stage4_loaded_scenes or not self.stage4_character_profiles:
            QMessageBox.warning(self, "Thiếu dữ liệu", "Vui lòng chọn file kịch bản và file nhân vật trước.")
            return
        keys = self.get_gemini_api_keys()
        if not keys:
            QMessageBox.warning(self, "Thiếu Gemini API Key", "Vui lòng nhập Gemini API Key trước khi tạo prompt.")
            return
        topic_text = self._build_stage4_topic_text()
        if not topic_text:
            QMessageBox.warning(self, "Thiếu dữ liệu", "Không thể xây dựng nội dung gửi AI. Vui lòng kiểm tra lại file kịch bản.")
            return
        videoStyle = self.cmb_stage4_style.currentText() if hasattr(self, "cmb_stage4_style") else "Cinematic"
        dialogueLanguage = self.cmb_stage4_dialogue.currentText() if hasattr(self, "cmb_stage4_dialogue") else "Vietnamese"
        subtitles = self.cmb_stage4_subtitles.currentText() if hasattr(self, "cmb_stage4_subtitles") else "Subtitles ON"
        num_prompts = len(self.stage4_loaded_scenes)
        self._set_stage4_generating(True, "🤖 Đang gọi AI tạo prompt ...")

        def worker():
            try:
                result = self._generate_single_veo3_batch(
                    topic_text,
                    num_prompts,
                    videoStyle,
                    dialogueLanguage,
                    subtitles,
                    keys
                )
                QTimer.singleShot(0, lambda: self._stage4_on_ai_prompts_ready(result))
            except Exception as e:
                QTimer.singleShot(0, lambda: self._stage4_on_ai_error(str(e)))

        threading.Thread(target=worker, daemon=True).start()

    def on_stage4_export_prompts(self):
        if not self.stage4_prompt_results:
            QMessageBox.warning(self, "Chưa có dữ liệu", "Vui lòng tạo prompt trước.")
            return
        fmt = self.cmb_stage4_export_format.currentText() if hasattr(self, "cmb_stage4_export_format") else "JSON (multi-line)"
        if fmt.startswith("JSON"):
            file_path, _ = QFileDialog.getSaveFileName(self, "Lưu prompt JSON", "", "JSON Files (*.json)")
            if not file_path:
                return
            if not file_path.endswith(".json"):
                file_path += ".json"
            with open(file_path, "w", encoding="utf-8") as f:
                json.dump(self.stage4_prompt_results, f, ensure_ascii=False, indent=2)
        elif fmt.startswith("NDJSON"):
            file_path, _ = QFileDialog.getSaveFileName(self, "Lưu prompt NDJSON", "", "JSONL Files (*.jsonl);;Text Files (*.txt)")
            if not file_path:
                return
            if not file_path.endswith(".jsonl") and not file_path.endswith(".txt"):
                file_path += ".jsonl"
            with open(file_path, "w", encoding="utf-8") as f:
                for item in self.stage4_prompt_results:
                    record = self._stage4_prompt_to_record(item)
                    f.write(json.dumps(record, ensure_ascii=False) + "\n")
        else:
            file_path, _ = QFileDialog.getSaveFileName(self, "Lưu prompt Text", "", "Text Files (*.txt)")
            if not file_path:
                return
            if not file_path.endswith(".txt"):
                file_path += ".txt"
            with open(file_path, "w", encoding="utf-8") as f:
                for item in self.stage4_prompt_results:
                    f.write(f"{item['sceneNumber']:02d}. {item['title']}\n")
                    f.write(item["prompt"] + "\n\n")
        QMessageBox.information(self, "Thành công", "Đã xuất prompt thành công!")
        self._update_stage4_generate_state()

    def _stage4_prompt_to_record(self, item):
        raw_scene = item.get("raw", {})
        context = raw_scene.get("videoPrompt") or raw_scene.get("scriptDescription") or item.get("prompt", "")
        context = " ".join(context.split())

        action = raw_scene.get("scriptDescription", "").strip() or item.get("prompt", "")
        action = " ".join(action.split())

        subject_chars = item.get("characters") or raw_scene.get("charactersInScene") or []
        subject = ", ".join(subject_chars) if subject_chars else "Primary subjects unspecified"

        style = self.cmb_stage4_style.currentText() if hasattr(self, "cmb_stage4_style") else "Cinematic"
        camera = self.cmb_stage4_camera.currentText() if hasattr(self, "cmb_stage4_camera") else "Wide"
        mood = self.cmb_stage4_mood.currentText() if hasattr(self, "cmb_stage4_mood") else "Neutral"
        setting = self.txt_stage4_setting.text().strip() if hasattr(self, "txt_stage4_setting") else ""
        ambiance = f"{mood} atmosphere"
        if setting:
            ambiance += f", {setting}"

        dialogue_language = self.cmb_stage4_dialogue.currentText() if hasattr(self, "cmb_stage4_dialogue") else "Vietnamese"
        dialogue = raw_scene.get("dialogue") or []
        if dialogue:
            audio = f"{dialogue_language} dialogue exchanges"
        else:
            audio = f"{mood} cinematic score"

        return {
            "Context": context[:800],
            "Subject": subject,
            "Action": action[:800],
            "Style": f"{style}",
            "Camera": camera,
            "Ambiance": ambiance,
            "Audio": audio
        }
    
    # ===== STORY SCRIPT HANDLERS =====
    
    def on_setup_mode_changed(self, index):
        """Xử lý khi thay đổi chế độ khởi tạo"""
        if index == 0:  # Thủ công
            self.manual_setup_frame.setVisible(True)
            self.auto_setup_frame.setVisible(False)
        else:  # Tự động
            self.manual_setup_frame.setVisible(False)
            self.auto_setup_frame.setVisible(True)
    
    def on_speech_changed(self, index):
        """Xử lý khi thay đổi có lời thoại"""
        has_speech = (index == 1)  # "Có" = index 1
        self.lbl_language.setVisible(has_speech)
        self.combo_language.setVisible(has_speech)
    
    def on_start_project_setup(self):
        """Bắt đầu khởi tạo dự án"""
        try:
            mode_index = self.combo_setup_mode.currentIndex()
            
            if mode_index == 0:  # Thủ công
                # Lấy thông tin từ UI
                num_chars = self.spin_num_characters.value()
                platform = self.combo_platform.currentText()
                duration = int(self.combo_scene_duration.currentText())
                theme = self.txt_theme.text().strip()
                has_speech = (self.combo_has_speech.currentIndex() == 1)
                language = self.combo_language.currentText() if has_speech else ""
                
                if not theme:
                    QMessageBox.warning(self, "Cảnh báo", "Vui lòng nhập chủ đề!")
                    return
                
                # Khởi tạo thủ công
                self.story_manager.start_manual_setup()
                self.story_manager.project_info.num_characters = num_chars
                self.story_manager.project_info.platform = platform
                self.story_manager.project_info.scene_duration = duration
                self.story_manager.project_info.theme = theme
                self.story_manager.project_info.has_speech = has_speech
                self.story_manager.project_info.main_language = language
                
                result = self.story_manager.complete_manual_setup()
                
            else:  # Tự động
                story_summary = self.txt_story_summary.toPlainText().strip()
                if not story_summary:
                    QMessageBox.warning(self, "Cảnh báo", "Vui lòng nhập cốt truyện!")
                    return
                
                # Khởi tạo tự động
                result = self.story_manager.start_auto_setup(story_summary)
                
                # Lấy thông tin bổ sung
                platform = self.combo_auto_platform.currentText()
                duration = int(self.combo_auto_duration.currentText())
                has_speech = (self.combo_auto_speech.currentIndex() == 1)
                language = ""  # Có thể thêm combo cho auto mode
                
                result = self.story_manager.complete_auto_setup(platform, duration, has_speech, language)
            
            # Hiển thị tóm tắt
            summary = self.story_manager.get_setup_summary()
            summary_text = "📋 TÓM TẮT CẤU HÌNH:\n\n"
            for key, value in summary.items():
                summary_text += f"• {key}: {value}\n"
            
            self.lbl_setup_summary.setText(summary_text)
            self.lbl_setup_summary.setVisible(True)
            
            # Bật Giai đoạn 2
            stage2_group = self.findChild(QGroupBox, "stage2_group")
            if stage2_group:
                stage2_group.setEnabled(True)
            
            # Cập nhật combo nhân vật
            self.update_character_combo()
            
            QMessageBox.information(self, "Thành công", 
                "Khởi tạo 'Nhật ký cốt truyện' (Story Log) rỗng. Dự án đã sẵn sàng.")
            
        except Exception as e:
            QMessageBox.critical(self, "Lỗi", f"Lỗi khởi tạo dự án: {e}")
            import traceback
            self.log(f"❌ Lỗi setup: {traceback.format_exc()}")
    
    def on_add_character(self):
        """Thêm/Sửa nhân vật - Mở dialog form đầy đủ"""
        from character_profile_dialog import CharacterProfileDialog
        
        # Kiểm tra nếu đang chọn nhân vật thì sửa, không thì tạo mới
        current_char = self.combo_character_select.currentText()
        char_name_for_edit = current_char if current_char and current_char in self.story_manager.character_profiles else None
        
        dialog = CharacterProfileDialog(self, char_name_for_edit, self.story_manager)
        if dialog.exec() == QDialog.Accepted:
            char_name = dialog.get_character_name()
            if char_name:
                # Profile đã được lưu trong dialog
                self.update_character_combo()
                self.combo_character_select.setCurrentText(char_name)
                self.on_character_selected(char_name)
                action = "sửa" if char_name_for_edit else "tạo mới"
                self.log(f"✅ Đã {action} nhân vật: {char_name}")
    
    def on_load_character_from_file(self):
        """Load nhân vật từ file riêng"""
        file_path, _ = QFileDialog.getOpenFileName(
            self, "Chọn file nhân vật", "", 
            "JSON Files (*.json);;Text Files (*.txt);;All Files (*.*)"
        )
        if not file_path:
            return
        
        try:
            char_name, profile = self.story_manager.load_character_from_file(file_path)
            
            # Kiểm tra nếu nhân vật đã tồn tại
            if char_name in self.story_manager.character_profiles:
                reply = QMessageBox.question(
                    self, "Nhân vật đã tồn tại",
                    f"Nhân vật '{char_name}' đã tồn tại. Bạn có muốn ghi đè không?",
                    QMessageBox.Yes | QMessageBox.No
                )
                if reply != QMessageBox.Yes:
                    return
            
            # Thêm hoặc cập nhật
            self.story_manager.character_profiles[char_name] = profile
            self.update_character_combo()
            self.combo_character_select.setCurrentText(char_name)
            self.on_character_selected(char_name)
            
            QMessageBox.information(self, "Thành công", f"Đã load nhân vật '{char_name}' từ file!")
            self.log(f"✅ Đã load nhân vật: {char_name}")
            
        except Exception as e:
            QMessageBox.critical(self, "Lỗi", f"Lỗi load nhân vật: {e}")
            self.log(f"❌ Lỗi load: {e}")
    
    def on_delete_character(self):
        """Xóa nhân vật"""
        char_name = self.combo_character_select.currentText()
        if not char_name:
            QMessageBox.warning(self, "Cảnh báo", "Vui lòng chọn nhân vật để xóa!")
            return
        
        reply = QMessageBox.question(
            self, "Xác nhận xóa",
            f"Bạn có chắc chắn muốn xóa nhân vật '{char_name}'?\n\nLưu ý: Hành động này không thể hoàn tác!",
            QMessageBox.Yes | QMessageBox.No,
            QMessageBox.No
        )
        
        if reply == QMessageBox.Yes:
            if char_name in self.story_manager.character_profiles:
                del self.story_manager.character_profiles[char_name]
                self.update_character_combo()
                self.profile_display.clear()
                QMessageBox.information(self, "Thành công", f"Đã xóa nhân vật '{char_name}'")
                self.log(f"✅ Đã xóa nhân vật: {char_name}")
    
    def on_save_character_to_file(self):
        """Lưu nhân vật vào file riêng"""
        char_name = self.combo_character_select.currentText()
        if not char_name or char_name not in self.story_manager.character_profiles:
            QMessageBox.warning(self, "Cảnh báo", "Vui lòng chọn nhân vật!")
            return
        
        # Chọn định dạng
        format_choice, ok = QInputDialog.getItem(
            self, "Chọn định dạng", "Định dạng file:",
            ["JSON (.json)", "Text (.txt)"], 0, False
        )
        if not ok:
            return
        
        file_format = "json" if "JSON" in format_choice else "text"
        extension = ".json" if file_format == "json" else ".txt"
        
        # Chọn thư mục hoặc file
        chars_dir = self.story_manager.get_characters_directory()
        chars_dir.mkdir(exist_ok=True)
        
        default_path = str(chars_dir / f"{char_name}{extension}")
        file_path, _ = QFileDialog.getSaveFileName(
            self, "Lưu nhân vật", default_path,
            f"{format_choice.upper()} Files (*{extension});;All Files (*.*)"
        )
        
        if not file_path:
            return
        
        try:
            self.story_manager.save_character_to_file(char_name, file_path, file_format)
            QMessageBox.information(self, "Thành công", f"Đã lưu nhân vật '{char_name}' vào file!")
            self.log(f"✅ Đã lưu nhân vật vào file: {file_path}")
        except Exception as e:
            QMessageBox.critical(self, "Lỗi", f"Lỗi lưu file: {e}")
            self.log(f"❌ Lỗi save file: {e}")
    
    def on_export_character(self):
        """Export nhân vật (tương tự save nhưng có thể chọn vị trí khác)"""
        self.on_save_character_to_file()
    
    def update_character_combo(self):
        """Cập nhật combo box nhân vật"""
        self.combo_character_select.clear()
        for char_name in self.story_manager.character_profiles.keys():
            self.combo_character_select.addItem(char_name)
    
