    def on_extraction_mode_changed(self):
        """Switch between single file and batch folder mode"""
        if self.radio_extraction_single.isChecked():
            self.single_file_frame.setVisible(True)
            self.batch_folder_frame.setVisible(False)
            self.extraction_log("📄 Chế độ: Một file video")
        else:
            self.single_file_frame.setVisible(False)
            self.batch_folder_frame.setVisible(True)
            self.extraction_log("📁 Chế độ: Batch từ thư mục")
    
    def browse_extraction_video_file(self):
        """Browse for video file"""
        file_path, _ = QFileDialog.getOpenFileName(
            self, 
            "Chọn file video", 
            str(Path.home()),
            "Video Files (*.mp4 *.avi *.mov *.mkv *.webm *.flv *.wmv);;All Files (*)"
        )
        
        if file_path:
            self.txt_extraction_video_path.setText(file_path)
            self.extraction_log(f"📹 Đã chọn video: {Path(file_path).name}")
            # Get and display video info
            self.get_extraction_video_info(file_path)
    
    def get_extraction_video_info(self, video_path):
        """Get and display video information"""
        try:
            import subprocess
            # Try to get video info using ffprobe
            ffprobe = self.find_extraction_tool("ffprobe")
            if not ffprobe:
                self.lbl_extraction_video_info.setText("⚠️ Cần ffprobe để xem thông tin video")
                return
            
            # Get duration
            duration = self.get_extraction_video_duration_sync(ffprobe, video_path)
            
            # Get video size and other info
            video_info = self.get_extraction_detailed_video_info(ffprobe, video_path)
            
            if duration and video_info:
                # Calculate estimated frames
                interval = self.spin_extraction_interval.value()
                estimated_frames = int(duration / interval) + 1
                
                info_text = f"📊 Duration: {duration:.1f}s | "
                info_text += f"Resolution: {video_info.get('width', '?')}x{video_info.get('height', '?')} | "
                info_text += f"FPS: {video_info.get('fps', '?')} | "
                info_text += f"Dự kiến frames: ~{estimated_frames}"
                
                self.lbl_extraction_video_info.setText(info_text)
                self.lbl_extraction_video_info.setStyleSheet("color: #28a745; font-weight: bold;")
            else:
                self.lbl_extraction_video_info.setText("⚠️ Không thể đọc thông tin video")
                self.lbl_extraction_video_info.setStyleSheet("color: #dc3545;")
                
        except Exception as e:
            self.extraction_log(f"⚠️ Lỗi lấy thông tin video: {e}")
            self.lbl_extraction_video_info.setText("⚠️ Lỗi đọc thông tin video")
    
    def get_extraction_video_duration_sync(self, ffprobe_path, video_path):
        """Get video duration synchronously"""
        try:
            import subprocess
            creationflags = subprocess.CREATE_NO_WINDOW if sys.platform == 'win32' else 0
            result = subprocess.run([
                ffprobe_path,
                "-v", "error",
                "-show_entries", "format=duration",
                "-of", "default=noprint_wrappers=1:nokey=1",
                str(video_path)
            ], stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, timeout=10,
            creationflags=creationflags)
            
            if result.returncode == 0 and result.stdout:
                return float(result.stdout.strip())
        except Exception:
            pass
        return None
    
    def get_extraction_detailed_video_info(self, ffprobe_path, video_path):
        """Get detailed video information"""
        try:
            import subprocess
            creationflags = subprocess.CREATE_NO_WINDOW if sys.platform == 'win32' else 0
            result = subprocess.run([
                ffprobe_path,
                "-v", "error",
                "-select_streams", "v:0",
                "-show_entries", "stream=width,height,r_frame_rate",
                "-of", "csv=s=x:p=0",
                str(video_path)
            ], stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, timeout=10,
            creationflags=creationflags)
            
            if result.returncode == 0 and result.stdout:
                # Parse output: widthxheightxr_frame_rate
                parts = result.stdout.strip().split('x')
                if len(parts) >= 3:
                    info = {
                        'width': parts[0],
                        'height': parts[1],
                        'fps': parts[2] if '/' in parts[2] else f"{float(parts[2]):.1f}"
                    }
                    
                    # Calculate FPS if it's a fraction
                    if '/' in info['fps']:
                        num, den = info['fps'].split('/')
                        try:
                            fps_value = float(num) / float(den)
                            info['fps'] = f"{fps_value:.1f}"
                        except:
                            pass
                    
                    return info
        except Exception:
            pass
        return {}
    
    def find_extraction_tool(self, name):
        """Find ffmpeg/ffprobe tool"""
        import subprocess
        candidates = [
            name,  # In PATH
            f"{name}.exe",  # In PATH (Windows)
            str(Path.cwd() / f"{name}.exe"),  # Local directory
        ]
        
        for candidate in candidates:
            try:
                creationflags = subprocess.CREATE_NO_WINDOW if sys.platform == 'win32' else 0
                result = subprocess.run(
                    [candidate, "-version"], 
                    stdout=subprocess.PIPE, 
                    stderr=subprocess.PIPE,
                    timeout=3,
                    creationflags=creationflags
                )
                if result.returncode == 0:
                    return candidate
            except Exception:
                continue
        return None
    
    def browse_extraction_folder(self):
        """Browse for folder containing video files"""
        folder = QFileDialog.getExistingDirectory(
            self, 
            "Chọn thư mục chứa các file video",
            str(Path.home())
        )
        
        if folder:
            self.txt_extraction_folder_path.setText(folder)
            # Scan for video files (loại bỏ duplicate)
            video_extensions = ['.mp4', '.avi', '.mov', '.mkv', '.webm', '.flv', '.wmv']
            video_files_set = set()  # Dùng set để tránh duplicate
            folder_path = Path(folder)
            
            for ext in video_extensions:
                # Scan cả lowercase và uppercase, nhưng normalize để tránh duplicate
                for file_path in folder_path.glob(f"*{ext}"):
                    video_files_set.add(file_path.resolve())  # resolve() để normalize path
                for file_path in folder_path.glob(f"*{ext.upper()}"):
                    video_files_set.add(file_path.resolve())
            
            video_files = sorted(list(video_files_set), key=lambda x: x.name.lower())
            
            if video_files:
                self.lbl_extraction_folder_info.setText(
                    f"✅ Tìm thấy {len(video_files)} file video:\n" + 
                    "\n".join([f"  • {f.name}" for f in video_files[:5]]) +
                    (f"\n  ... và {len(video_files) - 5} file khác" if len(video_files) > 5 else "")
                )
                self.lbl_extraction_folder_info.setStyleSheet("""
                    color: #28a745; 
                    font-size: 12px; 
                    font-weight: 500;
                    padding: 8px 12px;
                    background: #d4edda;
                    border: 1px solid #c3e6cb;
                    border-radius: 6px;
                """)
                self.extraction_log(f"📁 Đã chọn thư mục: {folder} ({len(video_files)} file video)")
            else:
                self.lbl_extraction_folder_info.setText("⚠️ Không tìm thấy file video nào trong thư mục này")
                self.lbl_extraction_folder_info.setStyleSheet("""
                    color: #dc3545; 
                    font-size: 12px; 
                    font-weight: 500;
                    padding: 8px 12px;
                    background: #f8d7da;
                    border: 1px solid #f5c6cb;
                    border-radius: 6px;
                """)
                self.extraction_log(f"⚠️ Thư mục không chứa file video: {folder}")
    
    def browse_extraction_output_dir(self):
        """Browse for output directory"""
        folder = QFileDialog.getExistingDirectory(
            self, 
            "Chọn thư mục lưu ảnh",
            str(Path.home() / "Pictures")
        )
        
        if folder:
            self.txt_extraction_output_dir.setText(folder)
            self.extraction_log(f"📁 Thư mục lưu: {folder}")
    
    def on_extraction_interval_changed(self):
        """Update video info when interval changes"""
        video_path = self.txt_extraction_video_path.text().strip()
        if video_path and Path(video_path).exists():
            self.get_extraction_video_info(video_path)
    
    def on_start_extraction(self):
        """Start frame extraction - hỗ trợ single file và batch folder"""
        if self.extraction_processing:
            QMessageBox.warning(self, "Cảnh báo", "Đang xử lý, vui lòng chờ!")
            return
        
        # Check mode
        is_batch_mode = self.radio_extraction_batch.isChecked()
        
        # Validate inputs
        if is_batch_mode:
            folder_path = self.txt_extraction_folder_path.text().strip()
            if not folder_path or not Path(folder_path).exists():
                QMessageBox.warning(self, "Cảnh báo", "Vui lòng chọn thư mục chứa video hợp lệ!")
                return
            
            # Scan for video files (loại bỏ duplicate)
            video_extensions = ['.mp4', '.avi', '.mov', '.mkv', '.webm', '.flv', '.wmv']
            video_files_set = set()  # Dùng set để tránh duplicate
            folder_path_obj = Path(folder_path)
            
            for ext in video_extensions:
                # Scan cả lowercase và uppercase, nhưng normalize để tránh duplicate
                for file_path in folder_path_obj.glob(f"*{ext}"):
                    video_files_set.add(file_path.resolve())  # resolve() để normalize path
                for file_path in folder_path_obj.glob(f"*{ext.upper()}"):
                    video_files_set.add(file_path.resolve())
            
            video_files = sorted(list(video_files_set), key=lambda x: x.name.lower())
            
            if not video_files:
                QMessageBox.warning(self, "Cảnh báo", "Không tìm thấy file video nào trong thư mục!")
                return
            
            self.extraction_log(f"📁 Batch mode: Tìm thấy {len(video_files)} file video")
        else:
            video_path = self.txt_extraction_video_path.text().strip()
            if not video_path or not Path(video_path).exists():
                QMessageBox.warning(self, "Cảnh báo", "Vui lòng chọn file video hợp lệ!")
                return
            video_files = [Path(video_path)]
        
        output_dir = self.txt_extraction_output_dir.text().strip()
        if not output_dir:
            QMessageBox.warning(self, "Cảnh báo", "Vui lòng chọn thư mục lưu ảnh!")
            return
        
        interval = self.spin_extraction_interval.value()
        if interval <= 0:
            QMessageBox.warning(self, "Cảnh báo", "Khoảng cách phải lớn hơn 0!")
            return
        
        # Check ffmpeg
        if not self.find_extraction_tool("ffmpeg"):
            QMessageBox.critical(
                self, 
                "Lỗi", 
                "Không tìm thấy ffmpeg!\n\n"
                "Vui lòng:\n"
                "1. Cài đặt ffmpeg vào PATH\n"
                "2. Hoặc đặt ffmpeg.exe cùng thư mục với ứng dụng"
            )
            return
        
        # Get output format
        output_format = self.txt_extraction_format.text().strip().lower()
        if not output_format:
            output_format = "png"
        
        # Validate format
        valid_formats = ["png", "jpg", "jpeg", "bmp", "tiff", "webp"]
        if output_format not in valid_formats:
            QMessageBox.warning(
                self, 
                "Cảnh báo", 
                f"Định dạng '{output_format}' không hỗ trợ!\n\n"
                f"Các định dạng hỗ trợ: {', '.join(valid_formats)}"
            )
            return
        
        # Start processing
        self.extraction_processing = True
        self.btn_extraction_start.setEnabled(False)
        self.btn_extraction_stop.setEnabled(True)
        self.progress_extraction_bar.setValue(0)
        
        if is_batch_mode:
            self.progress_extraction_label.setText(f"Đang trích xuất {len(video_files)} video...")
            self.extraction_log(f"🚀 Bắt đầu batch extraction: {len(video_files)} file, khoảng cách {interval}s/frame")
            # Start batch processing
            self.start_batch_extraction(video_files, output_dir, interval, output_format)
        else:
            self.progress_extraction_label.setText("Đang trích xuất frames...")
            self.progress_extraction_label.setStyleSheet("font-weight: 600; font-size: 14px; color: #007bff; padding: 8px;")
            # Start single file processing
            self.extraction_worker_thread = FrameExtractionWorker(
                video_path=str(video_files[0]),
                output_dir=output_dir,
                interval_seconds=interval,
                output_format=output_format,
                signals=self.signals
            )
            self.extraction_worker_thread.start()
            self.extraction_log(f"🚀 Bắt đầu trích xuất với khoảng cách {interval}s/frame")
    
    def start_batch_extraction(self, video_files, output_dir, interval, output_format):
        """Start batch extraction for multiple video files"""
        # Store batch info
        self.extraction_batch_files = video_files
        self.extraction_batch_output_dir = output_dir
        self.extraction_batch_interval = interval
        self.extraction_batch_format = output_format
        self.extraction_batch_current = 0
        self.extraction_batch_total = len(video_files)
        
        # Start first video
        self.process_next_batch_video()
    
    def process_next_batch_video(self):
        """Process next video in batch"""
        if self.extraction_batch_current >= self.extraction_batch_total:
            # All done
            self.extraction_processing = False
            self.btn_extraction_start.setEnabled(True)
            self.btn_extraction_stop.setEnabled(False)
            self.progress_extraction_bar.setValue(100)
            self.progress_extraction_label.setText(f"✅ Hoàn thành {self.extraction_batch_total} video!")
            self.progress_extraction_label.setStyleSheet("font-weight: 600; font-size: 14px; color: #28a745; padding: 8px;")
            self.extraction_log(f"✅ Batch extraction hoàn thành: {self.extraction_batch_total} video")
            
            QMessageBox.information(
                self, 
                "🎉 Hoàn Thành", 
                f"✅ Trích xuất batch thành công!\n\n"
                f"Đã xử lý {self.extraction_batch_total} video.\n"
                f"📁 Kiểm tra thư mục output để xem kết quả."
            )
            
            if self.chk_extraction_open_folder.isChecked():
                QTimer.singleShot(1000, self.on_open_extraction_output_folder)
            return
        
        # Process current video
        current_video = self.extraction_batch_files[self.extraction_batch_current]
        video_name = current_video.stem
        
        # Create subfolder for this video
        video_output_dir = Path(self.extraction_batch_output_dir) / video_name
        video_output_dir.mkdir(parents=True, exist_ok=True)
        
        self.extraction_log(f"📹 [{self.extraction_batch_current + 1}/{self.extraction_batch_total}] Đang xử lý: {current_video.name}")
        self.progress_extraction_label.setText(
            f"Đang xử lý video {self.extraction_batch_current + 1}/{self.extraction_batch_total}: {current_video.name}"
        )
        self.progress_extraction_label.setStyleSheet("font-weight: 600; font-size: 14px; color: #007bff; padding: 8px;")
        
        # Calculate progress
        batch_progress = int((self.extraction_batch_current / self.extraction_batch_total) * 100)
        self.progress_extraction_bar.setValue(batch_progress)
        
        # Start worker thread
        self.extraction_worker_thread = FrameExtractionWorker(
            video_path=str(current_video),
            output_dir=str(video_output_dir),
            interval_seconds=self.extraction_batch_interval,
            output_format=self.extraction_batch_format,
            signals=self.signals
        )
        self.extraction_worker_thread.start()
    
    def on_stop_extraction(self):
        """Stop frame extraction - hỗ trợ batch mode"""
        if self.extraction_worker_thread and self.extraction_worker_thread.isRunning():
            self.extraction_worker_thread.stop()
            self.extraction_log("🛑 Đang dừng quá trình trích xuất...")
            self.progress_extraction_label.setText("Đang dừng...")
            self.progress_extraction_label.setStyleSheet("font-weight: 600; font-size: 14px; color: #ffc107; padding: 8px;")
            
            # Clear batch mode if active
            if hasattr(self, 'extraction_batch_files'):
                self.extraction_log("⚠️ Batch extraction đã bị dừng")
                self.extraction_processing = False
                self.btn_extraction_start.setEnabled(True)
                self.btn_extraction_stop.setEnabled(False)
    
    def on_open_extraction_output_folder(self):
        """Open output folder"""
        output_dir = self.txt_extraction_output_dir.text().strip()
        if not output_dir:
            QMessageBox.warning(self, "Cảnh báo", "Chưa chọn thư mục lưu!")
            return
        
        folder_path = Path(output_dir)
        if not folder_path.exists():
            folder_path.mkdir(parents=True, exist_ok=True)
        
        try:
            import platform
            import subprocess
            
            system = platform.system()
            if system == "Windows":
                import os
                os.startfile(str(folder_path))
            elif system == "Darwin":  # macOS
                subprocess.run(["open", str(folder_path)])
            else:  # Linux
                subprocess.run(["xdg-open", str(folder_path)])
            
            self.extraction_log(f"📁 Đã mở thư mục: {folder_path}")
            
        except Exception as e:
            self.extraction_log(f"❌ Lỗi mở thư mục: {e}")
    
    @Slot(int)
    def update_extraction_progress(self, progress):
        """Update progress bar - hỗ trợ batch mode"""
        try:
            # Check if in batch mode
            is_batch_mode = hasattr(self, 'extraction_batch_files') and hasattr(self, 'extraction_batch_current')
            
            if is_batch_mode and hasattr(self, 'extraction_batch_total'):
                # Calculate overall progress for batch
                # progress is for current video (0-100)
                # Overall = (current_video_index / total) * 100 + (progress / total)
                current_video_progress = (self.extraction_batch_current / self.extraction_batch_total) * 100
                current_video_contribution = (progress / self.extraction_batch_total)
                overall_progress = int(current_video_progress + current_video_contribution)
                self.progress_extraction_bar.setValue(min(100, overall_progress))
            else:
                # Single file mode
                self.progress_extraction_bar.setValue(progress)
        except Exception:
            pass
    
    @Slot(bool)
    def on_extraction_finished(self, success):
        """Handle extraction completion - hỗ trợ batch mode"""
        try:
            # Check if in batch mode
            is_batch_mode = (hasattr(self, 'extraction_batch_files') and 
                           hasattr(self, 'extraction_batch_current') and
                           hasattr(self, 'extraction_batch_total') and
                           self.extraction_processing)
            
            if is_batch_mode:
                # Batch mode - process next video
                current_idx = self.extraction_batch_current
                if success:
                    self.extraction_log(f"✅ Video {current_idx + 1}/{self.extraction_batch_total} hoàn thành: {self.extraction_batch_files[current_idx].name}")
                else:
                    self.extraction_log(f"⚠️ Video {current_idx + 1}/{self.extraction_batch_total} thất bại, bỏ qua: {self.extraction_batch_files[current_idx].name}")
                
                # Move to next video
                self.extraction_batch_current += 1
                # Process next video
                QTimer.singleShot(500, self.process_next_batch_video)
                return
            
            # Single file mode
            self.extraction_processing = False
            self.btn_extraction_start.setEnabled(True)
            self.btn_extraction_stop.setEnabled(False)
            
            if success:
                self.progress_extraction_label.setText("✅ Trích xuất hoàn thành!")
                self.progress_extraction_label.setStyleSheet("font-weight: 600; font-size: 14px; color: #28a745; padding: 8px;")
                self.progress_extraction_bar.setValue(100)
                
                # Show success message
                QMessageBox.information(
                    self, 
                    "🎉 Hoàn Thành", 
                    "✅ Trích xuất frames thành công!\n\n"
                    "📁 Kiểm tra thư mục output để xem kết quả."
                )
                
                # Auto-open folder if enabled
                if self.chk_extraction_open_folder.isChecked():
                    QTimer.singleShot(1000, self.on_open_extraction_output_folder)
                    
            else:
                self.progress_extraction_label.setText("❌ Trích xuất thất bại")
                self.progress_extraction_label.setStyleSheet("font-weight: 600; font-size: 14px; color: #dc3545; padding: 8px;")
                self.progress_extraction_bar.setValue(0)
                
                # Show error message
                QMessageBox.warning(
                    self,
                    "❌ Thất Bại",
                    "Trích xuất frames thất bại!\n\n"
                    "Vui lòng kiểm tra:\n"
                    "• File video có hợp lệ không?\n"
                    "• Đường dẫn có ký tự đặc biệt không?\n"
                    "• Có quyền ghi vào thư mục output không?\n\n"
                    "Xem log để biết thêm chi tiết."
                )
            
        except Exception as e:
            self.extraction_log(f"❌ Lỗi finalize: {e}")
    
    def clear_extraction_logs(self):
        """Clear log display"""
        self.logs_extraction_display.clear()
        self.extraction_log("🗑️ Đã xóa log")
    
    def export_extraction_logs(self):
        """Export logs to file"""
        try:
            log_content = self.logs_extraction_display.toPlainText()
            
            if not log_content.strip():
                QMessageBox.information(self, "Thông báo", "Log trống, không có gì để xuất")
                return
            
            file_path, _ = QFileDialog.getSaveFileName(
                self, 
                "Xuất Log", 
                f"frame_extractor_log_{datetime.now().strftime('%Y%m%d_%H%M%S')}.txt",
                "Text Files (*.txt);;All Files (*)"
            )
            
            if file_path:
                with open(file_path, 'w', encoding='utf-8') as f:
                    f.write(log_content)
                
                self.extraction_log(f"💾 Đã xuất log: {Path(file_path).name}")
                QMessageBox.information(self, "Thành công", f"Đã xuất log:\n{file_path}")
                
        except Exception as e:
            self.extraction_log(f"❌ Lỗi xuất log: {e}")
    
    def extraction_log(self, message: str):
        """Log with timestamp"""
        timestamp = datetime.now().strftime("[%Y-%m-%d %H:%M:%S]")
        self.signals.new_log.emit(f"{timestamp} {message}")
        # Also append to extraction log display
        try:
            self.logs_extraction_display.append(f"{timestamp} {message}")
            scrollbar = self.logs_extraction_display.verticalScrollBar()
            scrollbar.setValue(scrollbar.maximum())
        except Exception:
            pass
    
