    def browse_extend_txt_folder(self):
        """Chọn thư mục chứa các file .txt (mỗi file là một project, tối đa 5 dòng)"""
        try:
            folder = QFileDialog.getExistingDirectory(self, "Chọn thư mục TXT (mỗi file = 1 project)")
            if not folder:
                return
            self.txt_extend_txt_folder.setText(folder)
            # Khi chọn folder: clear single TXT và tắt gom nhóm (mỗi file là 1 project)
            if hasattr(self, 'txt_extend_txt_file'):
                self.txt_extend_txt_file.clear()
            if hasattr(self, 'combo_extend_group_size'):
                self.combo_extend_group_size.setEnabled(False)
            if hasattr(self, 'lbl_extend_info'):
                    # ✅ Xác định max prompts dựa trên gói user
                    is_ultra = getattr(self, 'is_ultra_user', False) or (hasattr(self, 'user_plan_key') and self.user_plan_key and ("ultra" in str(self.user_plan_key).lower() or "enterprise" in str(self.user_plan_key).lower()))
                    max_segments = 100 if is_ultra else 20
                    self.lbl_extend_info.setText(f"📁 Đang dùng Folder TXT → Mỗi file là 1 project (≤ {max_segments} dòng/file)")
            self.load_extend_projects_from_folder(folder)
        except Exception as e:
            self.log(f"❌ Lỗi chọn thư mục TXT: {e}")
            QMessageBox.critical(self, "Lỗi", f"Không thể chọn thư mục: {e}")
    
    def load_extend_projects_from_folder(self, folder_path: str):
        """Quét folder và tạo danh sách project từ các file .txt (validate ≤ 100 dòng cho Ultra/Enterprise, ≤ 5 cho các gói khác)"""
        try:
            folder = Path(folder_path)
            if not folder.exists() or not folder.is_dir():
                QMessageBox.warning(self, "Cảnh báo", "Thư mục không hợp lệ!")
                return
            
            txt_files = sorted(
                [p for p in folder.iterdir() if p.is_file() and p.suffix.lower() == ".txt"],
                key=lambda p: _alphanum_key(p.stem)
            )
            if not txt_files:
                QMessageBox.information(self, "Thông báo", "Không tìm thấy file .txt nào trong thư mục.")
                return
            
            # ✅ Xác định max prompts dựa trên gói user
            is_ultra = getattr(self, 'is_ultra_user', False) or (hasattr(self, 'user_plan_key') and self.user_plan_key and ("ultra" in str(self.user_plan_key).lower() or "enterprise" in str(self.user_plan_key).lower()))
            max_segments = 100 if is_ultra else 5
            
            # Clear table và nội bộ
            self.extend_projects_table.setRowCount(0)
            if not hasattr(self, 'extend_projects'):
                self.extend_projects = []  # List[dict]: {'name': str, 'path': str, 'segments': [str]}
            self.extend_projects.clear()
            
            total_projects = 0
            skipped = 0
            for txt in txt_files:
                try:
                    lines = [ln.strip() for ln in txt.read_text(encoding="utf-8").splitlines()]
                    # Lọc bỏ dòng rỗng
                    segments = [ln for ln in lines if ln]
                    if len(segments) == 0:
                        continue
                    if len(segments) > max_segments:  # ✅ Giới hạn tối đa dựa trên gói user
                        skipped += 1
                        self.log(f"⚠️ Bỏ qua {txt.name}: {len(segments)} dòng > {max_segments}")
                        continue
                    
                    project_name = txt.stem
                    self.extend_projects.append({
                        'name': project_name,
                        'path': str(txt),
                        'segments': segments
                    })
                    
                    row = self.extend_projects_table.rowCount()
                    self.extend_projects_table.insertRow(row)
                    
                    # Col0: Project
                    self.extend_projects_table.setItem(row, 0, QTableWidgetItem(project_name))
                    # Col1: Segments count
                    self.extend_projects_table.setItem(row, 1, QTableWidgetItem(str(len(segments))))
                    # Col2: Trạng thái
                    self.extend_projects_table.setItem(row, 2, QTableWidgetItem("Chờ"))
                    # Col3: Tiến độ (progress bar)
                    pb = self.create_progress_bar(0)
                    self.extend_projects_table.setCellWidget(row, 3, pb)
                    # Col4: Thao tác (Xem)
                    btn = QPushButton("Xem")
                    btn.setFixedSize(70, 24)
                    btn.clicked.connect(lambda checked=False, path=str(txt): self._open_file_location(path))
                    self.extend_projects_table.setCellWidget(row, 4, btn)
                    
                    total_projects += 1
                except Exception as ie:
                    self.log(f"⚠️ Lỗi đọc {txt.name}: {ie}")
                    continue
            
            self.extend_projects_table.setVisible(total_projects > 0)
            if hasattr(self, 'lbl_extend_info'):
                self.lbl_extend_info.setText(f"📁 Projects: {total_projects} | Bỏ qua: {skipped}")
            if total_projects == 0:
                QMessageBox.information(self, "Thông báo", f"Không có project hợp lệ (≤ {max_segments} dòng) được tạo.")
        except Exception as e:
            self.log(f"❌ Lỗi load projects từ folder: {e}")
            QMessageBox.critical(self, "Lỗi", f"Không thể load folder: {e}")
    
    def _open_file_location(self, file_path: str):
        """Mở thư mục chứa file và chọn file đó (Windows)"""
        try:
            import subprocess
            subprocess.Popen(f'explorer /select,"{file_path}"')
        except Exception as e:
            self.log(f"⚠️ Không thể mở Explorer: {e}")
    
