    def get_device_info(self):
        """Lấy device_info từ database"""
        try:
            user_id = None
            
            # Cách 1: Từ user_info nếu có
            if hasattr(self, 'user_info') and self.user_info:
                user_id = self.user_info.get('id') or self.user_info.get('user_id')
            
            # Cách 2: Từ session token
            if not user_id:
                try:
                    from iting_api import ItingAPI
                    api = ItingAPI()
                    token = api.load_auth_token()
                    if token:
                        from supabase_manager import supabase_manager
                        user_id = supabase_manager.get_user_id_from_session(token)
                except Exception:
                    pass
            
            # Lấy device_info từ database
            if user_id:
                try:
                    from supabase_manager import supabase_manager
                    # Lấy is_key_login từ self nếu có
                    is_key_login = getattr(self, 'is_key_login', None)
                    success, device_info_str = supabase_manager.get_user_device_info(user_id, is_key_login=is_key_login)
                    if success and device_info_str:
                        try:
                            device_info = int(str(device_info_str).strip())
                            return device_info
                        except (ValueError, TypeError):
                            return 0
                except Exception:
                    return 0
            
            # Nếu không lấy được, mặc định là 0 (sẽ hiện quảng cáo)
            return 0
            
        except Exception as e:
            # Silent fail - trả về 0 (sẽ hiện quảng cáo)
            return 0
    
    def check_and_show_ad_first_time(self):
        """✅ Hiện quảng cáo LẦN ĐẦU sau 15s"""
        try:
            plan_key = getattr(self, "user_plan_key", "free")
            # ✅ Gói trả phí (Premium/Ultra/Enterprise) không hiện quảng cáo
            if plan_key in ("premium", "ultra", "enterprise"):
                self.log(f"✅ Gói {self.user_plan} không hiện quảng cáo")
                return
            
            # Show ad lần đầu
            self.show_ad_popup()
            self.ad_shown_once = True
            
            # ✅ Start recurring timer: 20 phút/lần (1200000ms = 20 minutes)
            self.ad_check_timer.start(1200000)
            self.log("📢 Đã hiện quảng cáo lần đầu, timer 20 phút đã bắt đầu")
            
        except Exception as e:
            # Silent fail
            pass
    
    def check_and_show_ad_recurring(self):
        """✅ Hiện quảng cáo ĐỊNH KỲ mỗi 20 phút"""
        try:
            plan_key = getattr(self, "user_plan_key", "free")
            if plan_key in ("premium", "ultra", "enterprise"):
                # Stop timer nếu user đã upgrade lên Ultra
                self.ad_check_timer.stop()
                self.log("✅ Gói trả phí, dừng quảng cáo định kỳ")
                return
            
            # Nếu đã có popup đang mở, không hiện thêm
            if self.ad_popup and self.ad_popup.isVisible():
                return
            
            # Show ad
            self.show_ad_popup()
            self.log("📢 Hiện quảng cáo định kỳ (20 phút)")
            
        except Exception as e:
            # Silent fail
            pass
    
    def show_ad_popup(self):
        """Hiện popup quảng cáo - Non-blocking, không ảnh hưởng thread"""
        try:
            # Đóng popup cũ nếu có
            if self.ad_popup:
                try:
                    self.ad_popup.close()
                    self.ad_popup.deleteLater()
                except:
                    pass
            
            # Tạo popup mới với parent là cửa sổ chính
            self.ad_popup = AdPopupDialog(self)
            
            # Đặt vị trí ở giữa cửa sổ chính (parent window)
            if self.isVisible():
                # Lấy vị trí và kích thước cửa sổ chính
                main_window_x = self.x()
                main_window_y = self.y()
                main_window_width = self.width()
                main_window_height = self.height()
                
                # Tính toán vị trí giữa
                popup_x = main_window_x + (main_window_width - self.ad_popup.width()) // 2
                popup_y = main_window_y + (main_window_height - self.ad_popup.height()) // 2
                
                self.ad_popup.move(popup_x, popup_y)
            else:
                # Fallback: center trên màn hình
                screen = QApplication.primaryScreen().availableGeometry()
                popup_x = (screen.width() - self.ad_popup.width()) // 2
                popup_y = (screen.height() - self.ad_popup.height()) // 2
                self.ad_popup.move(popup_x, popup_y)
            
            # Hiện popup (non-modal - không block)
            self.ad_popup.show()
            
            # Đảm bảo popup luôn ở trên cùng
            self.ad_popup.raise_()
            self.ad_popup.activateWindow()
            
        except Exception as e:
            # Silent fail - không ảnh hưởng app
            pass
    
    def _cleanup_and_logout(self):
        """Hàm cleanup chung để logout session - được gọi khi app đóng hoặc bị kill"""
        try:
            # Dừng subscription monitoring và cookie refresh  
            if hasattr(self, 'stop_subscription_monitoring'):
                self.stop_subscription_monitoring()
            if hasattr(self, 'stop_cookie_refresh'):
                self.stop_cookie_refresh()
            
            # Dừng toàn bộ tác vụ nền (Flow/Whisk/Video/Extend)
            if hasattr(self, 'stop_event'):
                self.stop_event.set()
            if hasattr(self, 'extend_stop_event'):
                self.extend_stop_event.set()
            
            # Dừng timer quảng cáo
            if hasattr(self, 'ad_check_timer'):
                try:
                    self.ad_check_timer.stop()
                except:
                    pass
            
            # Đóng popup quảng cáo nếu đang mở
            if hasattr(self, 'ad_popup') and self.ad_popup:
                try:
                    self.ad_popup.close()
                    self.ad_popup.deleteLater()
                except:
                    pass
            
            # Dừng các workers khác
            if hasattr(self, 'stop_event'):
                self.stop_event.set()
            if hasattr(self, 'executor') and self.executor:
                try:
                    self.executor.shutdown(wait=False, cancel_futures=True)
                except:
                    pass
            
            # ✅ Đóng tất cả Chrome driver (Selenium)
            try:
                from complete_flow import LabsFlowClient
                if hasattr(LabsFlowClient, 'cleanup_selenium_driver'):
                    LabsFlowClient.cleanup_selenium_driver()
                    print("✅ Đã đóng tất cả Chrome driver")
            except Exception as selenium_error:
                print(f"⚠️ Lỗi khi đóng Chrome driver: {selenium_error}")
            
            # ✅ Logout với app_close type để deactivate session
            try:
                api = ItingAPI()
                token = api.load_auth_token()
                if token:
                    logout_iting_user(session_token=token, logout_type="app_close")
                    print("✅ Cleanup logout successful")
            except Exception as logout_error:
                print(f"⚠️ Error during cleanup logout: {logout_error}")
                
        except Exception as e:
            print(f"⚠️ Error during cleanup: {e}")
    
    def _register_signal_handlers(self):
        """Đăng ký signal handlers để bắt khi app bị tắt đột ngột"""
        try:
            # Lưu reference đến instance để dùng trong signal handlers
            app_instance = self
            
            def signal_handler(signum, frame):
                """Handler cho signal (SIGTERM, SIGINT)"""
                print(f"⚠️ Received signal {signum}, cleaning up...")
                app_instance._cleanup_and_logout()
                os._exit(0)
            
            # Đăng ký signal handlers (chỉ trên Unix/Linux, Windows có giới hạn)
            if hasattr(signal, 'SIGTERM'):
                signal.signal(signal.SIGTERM, signal_handler)
            if hasattr(signal, 'SIGINT'):
                signal.signal(signal.SIGINT, signal_handler)
            
            # ✅ Đăng ký atexit để cleanup khi process exit (hoạt động trên cả Windows và Unix)
            atexit.register(self._cleanup_and_logout)
            
            # ✅ Windows-specific: SetConsoleCtrlHandler để bắt Ctrl+C, Ctrl+Break, và logoff/shutdown
            if sys.platform == 'win32':
                try:
                    import ctypes
                    from ctypes import wintypes
                    
                    # Define handler function type
                    PHANDLER_ROUTINE = ctypes.WINFUNCTYPE(wintypes.BOOL, wintypes.DWORD)
                    
                    def console_handler(ctrl_type):
                        """Handler cho Windows console events"""
                        print(f"⚠️ Windows console event {ctrl_type}, cleaning up...")
                        try:
                            app_instance._cleanup_and_logout()
                        except:
                            pass
                        # Return False để Windows tiếp tục xử lý event (shutdown/logoff)
                        # Cleanup đã chạy xong, có thể để Windows shutdown
                        return False
                    
                    # Đăng ký handler
                    handler = PHANDLER_ROUTINE(console_handler)
                    kernel32 = ctypes.windll.kernel32
                    kernel32.SetConsoleCtrlHandler(handler, True)
                    print("✅ Windows console handler registered")
                except Exception as e:
                    print(f"⚠️ Could not register Windows console handler: {e}")
            
            print("✅ Signal handlers registered")
            
        except Exception as e:
            print(f"⚠️ Error registering signal handlers: {e}")
    
    def closeEvent(self, event):
        """Override close event để cleanup subscription monitoring"""
        try:
            # Đánh dấu đang đóng app để chặn tạo client/token mới
            self.app_closing = True
            if hasattr(self, 'stop_event'):
                self.stop_event.set()
            if hasattr(self, 'extend_stop_event'):
                self.extend_stop_event.set()
            self._save_video_delay_setting()
            self._save_whisk_delay_setting()
            self._save_flow_delay_setting()
            # Gọi cleanup chung
            self._cleanup_and_logout()
            
            # Accept close event
            event.accept()

            # 🔥 Kill toàn bộ process Python ngay lập tức để tránh thread ngầm còn chạy
            # Lưu ý: os._exit() bỏ qua atexit / finally, nhưng ở đây ta đã cleanup phía trên.
            try:
                os._exit(0)
            except Exception:
                # Fallback, trong trường hợp hiếm hoi _exit lỗi
                import sys as _sys
                _sys.exit(0)
            
        except Exception as e:
            print(f"❌ Error during close: {e}")
            event.accept()
    
