    # ===== EVENT HANDLERS =====
    
    def switch_main_tab(self, index):
        for i, btn in enumerate(self.main_tabs):
            btn.setChecked(i == index)
        
        # Ẩn/hiện sub toolbar (chứa các nút video mode)
        # CHỈ hiển thị khi ở tab "Tạo Video" (index=0)
        if hasattr(self, 'sub_toolbar'):
            self.sub_toolbar.setVisible(index == 0)
        
        # Switch tab content
        if index == 0:  # Tạo Video
            self.tab_stack.setCurrentIndex(0)
        elif index == 1:  # Tạo Ảnh Whisk
            self.tab_stack.setCurrentIndex(1)
        elif index == 2:  # Edit
            self.tab_stack.setCurrentIndex(2)
            # Fix layout for Edit tab
            QTimer.singleShot(100, self.fix_edit_tab_layout)
        elif index == 3:  # Siêu Đồng Bộ
            self.tab_stack.setCurrentIndex(3)
        elif index == 4:  # Viết lại nội dung
            self.tab_stack.setCurrentIndex(4)
        elif index == 5:  # Viết Kịch Bản
            self.tab_stack.setCurrentIndex(5)
        elif index == 6:  # Trích Xuất Ảnh
            self.tab_stack.setCurrentIndex(6)
        elif index == 7:  # Clone Videos
            self.tab_stack.setCurrentIndex(7)
        elif index == 8:  # Tạo Ảnh Flow
            self.tab_stack.setCurrentIndex(8)

        self.log(f"Tab: {self.main_tabs[index].text()}")
    
    def switch_video_mode(self, mode):
        # ✅ FIX: So sánh đúng - mode là logic mode, cần convert button text sang logic mode để so sánh
        for btn in self.video_modes:
            btn_display_text = btn.text()
            btn_logic_mode = self.video_mode_display_to_logic.get(btn_display_text, btn_display_text)
            btn.setChecked(btn_logic_mode == mode)
        
        self.current_video_mode = mode
        
        # Show/hide input panels based on mode
        is_exp_ref = (mode == "Expand + Reference")
        is_t2v = (mode == "Text to Video")
        is_i2v = (mode == "Image to Video")
        is_se = (mode == "Start+End to Video")
        is_int = (mode == "Integrate to Video")
        is_ext = (mode == "Extend Video")
        
        # ẨN toàn bộ "Ảnh đầu vào" section khi ở Text to Video
        # (vì T2V chỉ dùng Batch Job, không cần ảnh đầu vào)
        # Expand + Reference sẽ hiển thị integrate frame (giống Integrate to Video)
        if hasattr(self, 'input_group'):
            self.input_group.setVisible(not is_t2v)
        
        # txt_t2v_frame luôn ẩn (đã bỏ prompt 1 dòng - chỉ dùng batch job)
        if hasattr(self, 'txt_t2v_frame'):
            self.txt_t2v_frame.setVisible(False)
        
        # Các frame khác hiện theo mode
        if hasattr(self, 'txt_i2v_frame'):
            self.txt_i2v_frame.setVisible(is_i2v)
        if hasattr(self, 'txt_start_end_frame'):
            self.txt_start_end_frame.setVisible(is_se)
        if hasattr(self, 'txt_integrate_frame'):
            # ✅ Hiển thị integrate frame cho cả Integrate to Video và Expand + Reference
            self.txt_integrate_frame.setVisible(is_int or is_exp_ref)
            # ✅ DEBUG: Log để kiểm tra
            self.log(f"🔍 Integrate frame visibility: {is_int or is_exp_ref}, mode: {mode}")
            
            # ✅ Khi chuyển sang Integrate mode hoặc Expand + Reference, đảm bảo hiển thị đúng frame (default hoặc custom)
            if (is_int or is_exp_ref) and hasattr(self, 'rb_integrate_default'):
                try:
                    if self.rb_integrate_custom.isChecked():
                        self.integrate_default_frame.setVisible(False)
                        self.integrate_custom_frame.setVisible(True)
                    else:
                        self.integrate_default_frame.setVisible(True)
                        self.integrate_custom_frame.setVisible(False)
                except Exception as e:
                    # Fallback: hiển thị default frame
                    if hasattr(self, 'integrate_default_frame'):
                        self.integrate_default_frame.setVisible(True)
                    if hasattr(self, 'integrate_custom_frame'):
                        self.integrate_custom_frame.setVisible(False)
        if hasattr(self, 'txt_extend_frame'):
            self.txt_extend_frame.setVisible(is_ext)
        
        # Show/hide Batch Job widgets
        if hasattr(self, 'batch_job_group'):
            # Batch Job group ẩn khi ở Extend Video (vì Extend có folder output riêng)
            self.batch_job_group.setVisible(not is_ext)
            
            # Nhưng ẩn File TXT và Thư mục batch với I2V/Start+End/Expand+Reference
            if hasattr(self, 'batch_file_widgets'):
                for widget in self.batch_file_widgets:
                    if widget:
                        widget.setVisible(is_t2v or is_exp_ref)
            
            if hasattr(self, 'batch_folder_widgets'):
                for widget in self.batch_folder_widgets:
                    if widget:
                        widget.setVisible(is_t2v or is_exp_ref)
            
            # Ẩn/hiện batch table (chỉ cho T2V và Expand+Reference)
            if hasattr(self, 'batch_table'):
                self.batch_table.setVisible(is_t2v or is_exp_ref)
            
            # Ẩn/hiện label "Danh sách file batch"
            if hasattr(self, 'batch_table_label'):
                self.batch_table_label.setVisible(is_t2v or is_exp_ref)
        
        # Show/hide Extend Video controls và table
        if hasattr(self, 'extend_control_frame'):
            self.extend_control_frame.setVisible(is_ext)
            
        if hasattr(self, 'extend_projects_table'):
            # Chỉ show table nếu có data, ngược lại ẩn
            if is_ext and hasattr(self, 'extend_projects_data') and self.extend_projects_data:
                self.extend_projects_table.setVisible(True)
                self.log(f"📊 Hiển thị {len(self.extend_projects_data)} projects")
            else:
                # Ẩn table khi chưa có data hoặc không phải Extend mode
                if not is_ext:
                    self.extend_projects_table.setVisible(False)
        
        # Di chuyển hộp Thiết lập xuống dưới khi ở Extend mode để tăng không gian phần trên
        try:
            if hasattr(self, 'settings_box') and self.settings_box and hasattr(self, 'extend_control_frame'):
                parent_layout = self.settings_box.parent().layout()
                if parent_layout and is_ext:
                    parent_layout.removeWidget(self.settings_box)
                    parent_layout.addWidget(self.settings_box)
        except Exception:
            pass
        
        # Hide normal control buttons when in Extend mode
        if hasattr(self, 'normal_control_frame'):
            self.normal_control_frame.setVisible(not is_ext)
        
        # KHÔNG clear bảng - giữ nguyên data khi chuyển tab
        # User có thể chuyển qua lại giữa các mode
        
        self.log(f"Mode: {mode}")
    
    def browse_txt_file(self):
        """Browse file TXT và load NGAY vào Prompts table - Chỉ chấp nhận file .txt"""
        file_path, _ = QFileDialog.getOpenFileName(
            self, "Chọn file prompt (chỉ chấp nhận file .txt)", "", "Text Files (*.txt);;All Files (*)"
        )
        if file_path:
            # Kiểm tra extension
            if not file_path.lower().endswith('.txt'):
                QMessageBox.warning(self, "Cảnh báo", "Chỉ chấp nhận file .txt!")
                return
            # ✅ XÓA ĐƯỜNG DẪN THƯ MỤC khi chọn File TXT (như bên Whisk)
            self.batch_folder.clear()
            # Tự động điền path vào input (read-only)
            self.txt_file.setText(file_path)
            self.log(f"📄 File TXT: {file_path} (đã xóa thư mục batch)")
            
            try:
                # Read file
                with open(file_path, 'r', encoding='utf-8') as f:
                    lines = [line.strip() for line in f if line.strip()]
                
                self.log(f"📊 Đọc được {len(lines)} prompts")
                
                # Clear batch table
                self.batch_table.setRowCount(0)
                
                # Add to batch table
                self.batch_table.insertRow(0)
                self.batch_table.setItem(0, 0, QTableWidgetItem("1"))
                self.batch_table.setItem(0, 1, QTableWidgetItem(Path(file_path).name))
                self.batch_table.setItem(0, 2, QTableWidgetItem(f"0/{len(lines)}"))
                
                # LOAD NGAY VÀO PROMPTS TABLE (preview)
                self.load_prompts_to_table(lines)
                
                self.log(f"✅ Đã load {len(lines)} prompts vào bảng")
                
                # ✅ ENABLE nút Bắt đầu khi có file mới VÀ RESET STYLE
                self.btn_start.setEnabled(True)
                self.btn_start.setStyleSheet("")  # Clear any custom style (restore default)
                
                # ✅ FORCE UPDATE style để đảm bảo button sáng lên
                self.btn_start.style().unpolish(self.btn_start)  # Clear cached style
                self.btn_start.style().polish(self.btn_start)    # Reapply default style
                
                # ✅ CLEAR CURRENT_TASKS và PROGRESS để ensure fresh start
                self.current_tasks = []
                self.btn_fix_all.setEnabled(False)  # Disable fix button khi load file mới
                
                # ✅ Clear progress để tránh cross-contamination với file cũ
                if hasattr(self, 'global_task_progress'):
                    old_count = len(self.global_task_progress)
                    self.global_task_progress.clear()
                    self.log(f"🧹 Đã clear {old_count} progress entries cũ")
                
                # ✅ Clear mappings nếu có
                if hasattr(self, 'video_prompt_file_mapping'):
                    self.video_prompt_file_mapping.clear()
                if hasattr(self, 'video_prompt_local_mapping'):
                    self.video_prompt_local_mapping.clear()
                if hasattr(self, 'video_batch_file_status'):
                    self.video_batch_file_status.clear()
                
            except Exception as e:
                self.log(f"❌ Lỗi đọc file: {e}")
    
    def load_prompts_to_table(self, prompts):
        """Load prompts vào Prompts table với PAGINATION (200 rows/page)
        
        Args:
            prompts: List of prompt strings
        """
        try:
            # ✅ Store all prompts data
            self.all_prompts_data = prompts
            
            # Calculate pagination
            total_prompts = len(prompts)
            self.total_prompts_pages = max(1, (total_prompts + self.prompts_per_page - 1) // self.prompts_per_page)
            self.current_prompts_page = 1  # Reset to page 1
            
            self.log(f"📋 Total prompts: {total_prompts}, Pages: {self.total_prompts_pages} (200/page)")
            
            # Load first page
            self.refresh_prompts_table_page()
            
        except Exception as e:
            self.log(f"❌ Lỗi load prompts to table: {e}")
    
    def refresh_prompts_table_page(self):
        """✅ Refresh prompts table để hiển thị trang hiện tại
        
        Hỗ trợ filter theo file batch (giống tab ảnh)
        ✅ BUG FIX: Preserve progress bars khi filter
        """
        try:
            # ✅ Khởi tạo mappings nếu chưa có
            if not hasattr(self, 'video_prompt_file_mapping'):
                self.video_prompt_file_mapping = {}
            if not hasattr(self, 'video_prompt_local_mapping'):
                self.video_prompt_local_mapping = {}
            
            # ✅ SAVE current progress values trước khi clear table
            # Update global progress storage - ĐÚNG THEO GLOBAL INDEX
            for row in range(self.prompts_table.rowCount()):
                # Get global index from prompt item
                prompt_item = self.prompts_table.item(row, 1)
                if prompt_item:
                    global_idx = prompt_item.data(Qt.UserRole)  # Đây là global index đúng
                    if global_idx:
                        # Get progress bar value và lưu vào global storage
                        progress_bar = self.prompts_table.cellWidget(row, 2)
                        if isinstance(progress_bar, QProgressBar):
                            # ✅ Lưu theo GLOBAL INDEX, không phải local index
                            self.global_task_progress[global_idx] = progress_bar.value()
            
            # Clear table
            self.prompts_table.setRowCount(0)
            
            if not self.all_prompts_data:
                self.lbl_prompts_page_info.setText("Trang 1/1 (0 prompts)")
                self.lbl_prompts_current_page.setText("1/1")
                self.btn_prompts_prev_page.setEnabled(False)
                self.btn_prompts_next_page.setEnabled(False)
                return
            
            # ✅ Filter by batch file if needed (giống tab ảnh)
            if hasattr(self, 'current_video_batch_filter') and self.current_video_batch_filter:
                # Get indices of prompts from selected file
                filtered_indices = [
                    idx for idx in range(1, len(self.all_prompts_data) + 1)
                    if self.video_prompt_file_mapping.get(idx) == self.current_video_batch_filter
                ]
                
                # Get filtered prompts
                filtered_prompts = [self.all_prompts_data[idx - 1] for idx in filtered_indices]
                data_to_display = filtered_prompts
                indices_to_display = filtered_indices
            else:
                # Show all prompts
                data_to_display = self.all_prompts_data
                indices_to_display = list(range(1, len(self.all_prompts_data) + 1))
            
            # Calculate range for current page
            total_prompts = len(data_to_display)
            start_idx = (self.current_prompts_page - 1) * self.prompts_per_page
            end_idx = min(start_idx + self.prompts_per_page, total_prompts)
            
            # Recalculate total pages
            self.total_prompts_pages = max(1, (total_prompts + self.prompts_per_page - 1) // self.prompts_per_page)
            self.current_prompts_page = max(1, min(self.current_prompts_page, self.total_prompts_pages))
            
            # Get prompts for current page
            page_prompts = data_to_display[start_idx:end_idx]
            page_indices = indices_to_display[start_idx:end_idx]
            
            # Load prompts into table
            for i, prompt_text in enumerate(page_prompts):
                idx = page_indices[i]  # ✅ Use actual global index from filtered list
                row_pos = self.prompts_table.rowCount()
                self.prompts_table.insertRow(row_pos)
                
                # Checkbox
                chk = QCheckBox()
                chk.setChecked(False)
                chk_widget = QWidget()
                chk_layout = QHBoxLayout(chk_widget)
                chk_layout.addWidget(chk)
                chk_layout.setAlignment(Qt.AlignCenter)
                chk_layout.setContentsMargins(0, 0, 0, 0)
                self.prompts_table.setCellWidget(row_pos, 0, chk_widget)
                
                # ✅ HIỂN THỊ local index khi filter theo file, global index khi xem tất cả
                max_display_length = 120
                
                # ✅ BUG FIX: Hiển thị index đúng
                if hasattr(self, 'current_video_batch_filter') and self.current_video_batch_filter:
                    # Có filter → dùng local index từ mapping
                    display_idx = self.video_prompt_local_mapping.get(idx, row_pos + 1)
                else:
                    # Không filter → dùng global index
                    display_idx = idx
                
                if len(prompt_text) > max_display_length:
                    display_text = f'{display_idx}: {prompt_text[:max_display_length]}...'
                else:
                    display_text = f'{display_idx}: {prompt_text}'
                
                prompt_item = QTableWidgetItem(display_text)
                prompt_item.setData(Qt.UserRole, idx)  # Store global index
                prompt_item.setData(Qt.UserRole + 1, prompt_text)  # Store full text
                self.prompts_table.setItem(row_pos, 1, prompt_item)
                
                # ✅ Tiến độ (progress bar) - RESTORE from global storage
                # idx là global_index đúng, lấy progress theo global_index
                saved_progress = self.global_task_progress.get(idx, 0)  # idx = global_index
                
                # ✅ DEBUG: Log để verify logic
                if saved_progress > 0:
                    file_stem = self.video_prompt_file_mapping.get(idx, "unknown")
                    local_idx = self.video_prompt_local_mapping.get(idx, "?")
                    print(f"DEBUG: Restore progress {saved_progress}% for global_idx={idx} (file={file_stem}, local={local_idx})")
                
                progress_bar = self.create_progress_bar(saved_progress)
                self.prompts_table.setCellWidget(row_pos, 2, progress_bar)
                
                # ✅ Trạng thái text (column 3) - "Done" (xanh lá) hoặc "Error" (đỏ)
                status_item = QTableWidgetItem()
                status_item.setTextAlignment(Qt.AlignCenter)
                
                # Set màu: Done = xanh lá, Error = đỏ, còn lại = xám
                # ✅ BUG FIX: Phân biệt prompt mới (chưa chạy) vs prompt lỗi
                # Kiểm tra xem có trong global_task_progress không để phân biệt prompt mới vs prompt lỗi
                is_new_prompt = idx not in self.global_task_progress
                
                # ✅ Kiểm tra >= 100 để đảm bảo bắt được cả 100.0 và các giá trị làm tròn
                if saved_progress >= 100:
                    status_item.setText("Done")
                    status_item.setForeground(QColor("#4CAF50"))  # Xanh lá
                    # ✅ Force update để đảm bảo màu được áp dụng
                    status_item.setData(Qt.ForegroundRole, QColor("#4CAF50"))
                elif saved_progress == 0 and not is_new_prompt:
                    # Progress = 0 và đã từng có trong global_task_progress → Error
                    status_item.setText("Error")
                    status_item.setForeground(QColor("#F44336"))  # Đỏ
                    # ✅ Force update để đảm bảo màu được áp dụng
                    status_item.setData(Qt.ForegroundRole, QColor("#F44336"))
                else:
                    # Prompt mới hoặc đang xử lý
                    status_item.setText("Chờ xử lý" if is_new_prompt else "Đang xử lý...")
                    status_item.setForeground(QColor("#666666"))  # Xám
                    # ✅ Force update để đảm bảo màu được áp dụng
                    status_item.setData(Qt.ForegroundRole, QColor("#666666"))
                
                self.prompts_table.setItem(row_pos, 3, status_item)
                
                # Review button (column 4)
                review_container = self.create_review_container(idx)
                self.prompts_table.setCellWidget(row_pos, 4, review_container)
            
            # ✅ Update pagination UI với filter info
            if hasattr(self, 'current_video_batch_filter') and self.current_video_batch_filter:
                filter_name = self.current_video_batch_filter
                self.lbl_prompts_page_info.setText(f"Filter: {filter_name} - Trang {self.current_prompts_page}/{self.total_prompts_pages} ({len(page_prompts)}/{total_prompts} prompts)")
            else:
                self.lbl_prompts_page_info.setText(f"Trang {self.current_prompts_page}/{self.total_prompts_pages} ({len(page_prompts)}/{total_prompts} prompts)")
            
            self.lbl_prompts_current_page.setText(f"{self.current_prompts_page}/{self.total_prompts_pages}")
            
            # Enable/disable buttons
            self.btn_prompts_prev_page.setEnabled(self.current_prompts_page > 1)
            self.btn_prompts_next_page.setEnabled(self.current_prompts_page < self.total_prompts_pages)
            
            # ✅ DEBUG: Log mapping để verify
            if hasattr(self, 'current_video_batch_filter') and self.current_video_batch_filter:
                self.log(f"📄 Loaded page {self.current_prompts_page}/{self.total_prompts_pages}: {len(page_prompts)} prompts (Filter: {self.current_video_batch_filter})")
                # Log một vài mapping samples
                for i, idx in enumerate(page_indices[:3]):  # Log 3 đầu tiên
                    file_stem = self.video_prompt_file_mapping.get(idx, "?")
                    local_idx = self.video_prompt_local_mapping.get(idx, "?")
                    progress = self.global_task_progress.get(idx, 0)
                    self.log(f"  Sample {i+1}: global_idx={idx}, file={file_stem}, local={local_idx}, progress={progress}%")
            else:
                self.log(f"📄 Loaded page {self.current_prompts_page}/{self.total_prompts_pages}: {len(page_prompts)} prompts (No filter)")
            
        except Exception as e:
            self.log(f"❌ Error refreshing prompts table page: {e}")
    
    def verify_progress_integrity(self):
        """✅ DEBUG: Verify progress integrity và log chi tiết"""
        try:
            # ✅ Khởi tạo mappings nếu chưa có
            if not hasattr(self, 'video_prompt_file_mapping'):
                self.video_prompt_file_mapping = {}
            if not hasattr(self, 'video_prompt_local_mapping'):
                self.video_prompt_local_mapping = {}
            
            self.log("🔍 === PROGRESS INTEGRITY CHECK ===")
            
            # Check global progress storage
            if hasattr(self, 'global_task_progress'):
                self.log(f"📊 Global progress entries: {len(self.global_task_progress)}")
                for task_idx, progress in list(self.global_task_progress.items())[:5]:  # Log 5 đầu tiên
                    file_stem = self.video_prompt_file_mapping.get(task_idx, "?")
                    local_idx = self.video_prompt_local_mapping.get(task_idx, "?")
                    self.log(f"  Progress: global_idx={task_idx}, progress={progress}%, file={file_stem}, local={local_idx}")
            
            # Check current table
            self.log(f"📋 Current table rows: {self.prompts_table.rowCount()}")
            for row in range(min(3, self.prompts_table.rowCount())):  # Log 3 đầu tiên
                prompt_item = self.prompts_table.item(row, 1)
                if prompt_item:
                    global_idx = prompt_item.data(Qt.UserRole)
                    progress_bar = self.prompts_table.cellWidget(row, 2)
                    if isinstance(progress_bar, QProgressBar):
                        current_progress = progress_bar.value()
                        stored_progress = self.global_task_progress.get(global_idx, -1)
                        self.log(f"  Row {row}: global_idx={global_idx}, UI={current_progress}%, stored={stored_progress}%")
            
            self.log("🔍 === END INTEGRITY CHECK ===")
            
        except Exception as e:
            self.log(f"❌ Error in integrity check: {e}")
    
    def go_to_prev_prompts_page(self):
        """Chuyển sang trang trước của prompts table"""
        if self.current_prompts_page > 1:
            self.current_prompts_page -= 1
            self.refresh_prompts_table_page()
            self.log(f"◀ Chuyển sang trang {self.current_prompts_page}")
    
    def go_to_next_prompts_page(self):
        """Chuyển sang trang sau của prompts table"""
        if self.current_prompts_page < self.total_prompts_pages:
            self.current_prompts_page += 1
            self.refresh_prompts_table_page()
            self.log(f"▶ Chuyển sang trang {self.current_prompts_page}")
    
    def browse_batch_folder(self):
        """Browse folder và load TẤT CẢ file .txt vào batch table + prompts table"""
        folder = QFileDialog.getExistingDirectory(self, "Chọn thư mục batch")
        if folder:
            # ✅ XÓA ĐƯỜNG DẪN FILE TXT khi chọn Thư mục (như bên Whisk)
            self.txt_file.clear()
            self.batch_folder.setText(folder)
            self.log(f"📁 Thư mục batch: {folder} (đã xóa file TXT)")
            
            # Clear batch table
            self.batch_table.setRowCount(0)
            
            # Scan folder for .txt files
            try:
                txt_files = list(Path(folder).glob("*.txt"))
                txt_files = sorted(txt_files, key=lambda p: _alphanum_key(p.stem))
                
                self.log(f"🔍 Tìm thấy {len(txt_files)} file .txt")
                
                # ✅ Track prompts by source file (giống tab ảnh)
                if not hasattr(self, 'video_prompt_file_mapping'):
                    self.video_prompt_file_mapping = {}  # {prompt_index: file_stem}
                
                if not hasattr(self, 'video_batch_file_status'):
                    self.video_batch_file_status = {}  # {file_stem: {"total": N, "completed": 0}}
                
                # ✅ CLEAR ALL mappings và progress khi load folder mới
                self.video_prompt_file_mapping.clear()
                self.video_batch_file_status.clear()
                
                # ✅ FORCE CLEAR progress để tránh cross-contamination
                if hasattr(self, 'global_task_progress'):
                    old_count = len(self.global_task_progress)
                    self.global_task_progress.clear()
                    self.log(f"🧹 Cleared {old_count} old progress entries")
                else:
                    self.global_task_progress = {}
                    self.log("🧹 Initialized fresh progress storage")
                
                # ✅ Collect ALL prompts từ tất cả files - VỚI LOCAL INDEX cho từng file
                all_prompts = []
                prompt_global_index = 1
                
                # ✅ Thêm tracking local index trong từng file
                if not hasattr(self, 'video_prompt_local_mapping'):
                    self.video_prompt_local_mapping = {}  # {prompt_global_index: local_index_in_file}
                self.video_prompt_local_mapping.clear()
                
                for i, txt_file in enumerate(txt_files, 1):
                    file_stem = txt_file.stem
                    
                    # Count lines in file
                    try:
                        with open(txt_file, 'r', encoding='utf-8') as f:
                            lines = [line.strip() for line in f if line.strip()]
                        line_count = len(lines)
                        
                        # ✅ Track source file và local index cho từng prompt
                        for local_idx, line in enumerate(lines, 1):  # Local index bắt đầu từ 1
                            all_prompts.append(line)
                            self.video_prompt_file_mapping[prompt_global_index] = file_stem
                            self.video_prompt_local_mapping[prompt_global_index] = local_idx  # Lưu local index
                            
                            # ✅ DEBUG: Log mapping để verify
                            if local_idx <= 3:  # Log 3 đầu tiên của mỗi file
                                self.log(f"  Map: global_idx={prompt_global_index} → file={file_stem}, local={local_idx}")
                            
                            prompt_global_index += 1
                        
                        # Track file status
                        self.video_batch_file_status[file_stem] = {
                            "total": line_count,
                            "completed": 0
                        }
                    except:
                        line_count = 0
                    
                    # Add to batch table
                    row = self.batch_table.rowCount()
                    self.batch_table.insertRow(row)
                    self.batch_table.setItem(row, 0, QTableWidgetItem(str(i)))
                    self.batch_table.setItem(row, 1, QTableWidgetItem(txt_file.name))
                    
                    # ✅ Status với file_stem lưu trong UserRole
                    status_item = QTableWidgetItem(f"0/{line_count}")
                    status_item.setData(Qt.UserRole, file_stem)
                    self.batch_table.setItem(row, 2, status_item)
                
                # ✅ Connect click event để filter prompts theo file
                try:
                    self.batch_table.cellClicked.disconnect()  # Remove old connections
                except:
                    pass
                self.batch_table.cellClicked.connect(self.on_video_batch_table_clicked)
                
                self.log(f"✅ Loaded {len(txt_files)} files vào batch table")
                
                # LOAD NGAY vào Prompts table với pagination
                if all_prompts:
                    self.load_prompts_to_table(all_prompts)
                    self.log(f"✅ Đã hiển thị {len(all_prompts)} prompts trong bảng chính")
                    
                    # ✅ ENABLE nút Bắt đầu khi có file mới VÀ RESET STYLE
                    self.btn_start.setEnabled(True)
                    self.btn_start.setStyleSheet("")  # Clear any custom style (restore default)
                    
                    # ✅ FORCE UPDATE style để đảm bảo button sáng lên
                    self.btn_start.style().unpolish(self.btn_start)  # Clear cached style
                    self.btn_start.style().polish(self.btn_start)    # Reapply default style
                    
                    # ✅ CLEAR RETRY MODE khi chọn folder mới (back to normal mode)
                    self.is_retry_mode = False
                    
                    # ✅ CLEAR CURRENT_TASKS để ensure fresh start
                    self.current_tasks = []
                
            except Exception as e:
                self.log(f"❌ Lỗi scan folder: {e}")
    
    def on_video_batch_table_clicked(self, row, column):
        """✅ Handle click vào batch table row → filter prompts theo file đó"""
        try:
            # Get file stem from status column
            status_item = self.batch_table.item(row, 2)
            if not status_item:
                return
            
            file_stem = status_item.data(Qt.UserRole)
            file_name = self.batch_table.item(row, 1).text()
            
            # ✅ Chỉ apply filter, không toggle (không cần xem tất cả)
            self.current_video_batch_filter = file_stem
            self.log(f"📋 Filter prompts từ file: {file_name}")
            self.batch_table.selectRow(row)
            
            # Reset to page 1 and refresh
            self.current_prompts_page = 1
            self.refresh_prompts_table_page()
            
            # ✅ DEBUG: Verify integrity after filter
            self.verify_progress_integrity()
            
        except Exception as e:
            self.log(f"❌ Error handling video batch table click: {e}")
    
    def browse_output_folder(self):
        folder = QFileDialog.getExistingDirectory(self, "Chọn folder lưu")
        if folder:
            self.output_folder.setText(folder)
            self.log(f"Folder lưu: {folder}")
    
    class ManualCookieDialog(QDialog):
        """Dialog để nhập cookie thủ công - Hỗ trợ nhiều accounts (mỗi account 3 cookies)"""
        def __init__(self, parent=None, initial_email=""):
            super().__init__(parent)
            self.setWindowTitle("Nhập Cookie Thủ Công (Nhiều Accounts)")
            self.setMinimumSize(700, 600)
            self.parsed_accounts = []  # List of (email, cookie_list) tuples
            
            layout = QVBoxLayout(self)
            layout.setSpacing(12)
            
            # 1. Guide label
            lbl_guide = QLabel(
                "📋 Dán cookie vào bên dưới:\n"
                "• Mỗi account = 1 JSON array chứa 3 cookies\n"
                "• Có thể paste nhiều accounts (mỗi account cách nhau bởi blank line hoặc comma)\n"
                "• Username sẽ được tự động tạo cho mỗi account"
            )
            lbl_guide.setStyleSheet("color: #666; font-style: italic; font-size: 11px; padding: 8px; background: #f0f0f0; border-radius: 5px;")
            layout.addWidget(lbl_guide)
            
            # 2. Cookie Input Area
            self.txt_cookie = QPlainTextEdit()
            self.txt_cookie.setPlaceholderText(
                'Ví dụ 1 account:\n'
                '[\n'
                '    {"domain": "labs.google", "name": "__Host-next-auth.csrf-token", "value": "..."},\n'
                '    {"domain": "labs.google", "name": "__Secure-next-auth.callback-url", "value": "..."},\n'
                '    {"domain": "labs.google", "name": "__Secure-next-auth.session-token", "value": "..."}\n'
                ']\n\n'
                'Ví dụ nhiều accounts (cách nhau bởi blank line):\n'
                '[{...3 cookies...}]\n\n'
                '[{...3 cookies...}]\n\n'
                '[{...3 cookies...}]'
            )
            self.txt_cookie.setStyleSheet("font-family: Consolas; font-size: 11px;")
            self.txt_cookie.textChanged.connect(self._on_text_changed)
            layout.addWidget(self.txt_cookie)
            
            # 3. Validation Status
            self.lbl_status = QLabel("Trạng thái: Chưa có dữ liệu")
            self.lbl_status.setStyleSheet("color: #666; font-weight: bold;")
            layout.addWidget(self.lbl_status)
            
            # 4. Preview Accounts
            self.preview_area = QTextEdit()
            self.preview_area.setReadOnly(True)
            self.preview_area.setMaximumHeight(150)
            self.preview_area.setStyleSheet("font-family: Consolas; font-size: 11px; color: #28a745; background: #f0f0f0;")
            layout.addWidget(self.preview_area)
            
            # 5. Buttons
            btn_box = QHBoxLayout()
            btn_box.addStretch()
            
            self.btn_cancel = QPushButton("Hủy")
            self.btn_cancel.clicked.connect(self.reject)
            
            self.btn_save = QPushButton("💾 Lưu Tất Cả Accounts")
            self.btn_save.setStyleSheet("background-color: #6f42c1; color: white; font-weight: bold; padding: 8px 15px;")
            self.btn_save.setEnabled(False)
            self.btn_save.clicked.connect(self.accept)
            
            btn_box.addWidget(self.btn_cancel)
            btn_box.addWidget(self.btn_save)
            layout.addLayout(btn_box)
            
        def _on_text_changed(self):
            """Parse và validate nhiều cookie accounts realtime"""
            text = self.txt_cookie.toPlainText().strip()
            if not text:
                self.lbl_status.setText("Trạng thái: Chưa có dữ liệu")
                self.lbl_status.setStyleSheet("color: #666;")
                self.preview_area.clear()
                self.btn_save.setEnabled(False)
                self.parsed_accounts = []
                return

            try:
                import re
                import time
                
                # ✅ Strategy: Tách text thành các JSON arrays (mỗi array là 1 account)
                accounts = []
                
                # Method 1: Tách theo blank lines (2 newlines trở lên)
                if "\n\n" in text or text.count("\n") > 10:
                    # Split by blank lines
                    blocks = re.split(r'\n\s*\n+', text)
                    for block in blocks:
                        block = block.strip()
                        if not block:
                            continue
                        # Try parse as JSON array
                        try:
                            data = json.loads(block)
                            if isinstance(data, list) and len(data) > 0:
                                accounts.append(data)
                        except:
                            pass
                
                # Method 2: Nếu không tách được, thử parse toàn bộ text
                if not accounts:
                    try:
                        # Thử parse như 1 JSON array lớn
                        data = json.loads(text)
                        if isinstance(data, list):
                            # Check nếu là nested arrays (nhiều accounts)
                            if len(data) > 0 and isinstance(data[0], list):
                                # Format: [[cookie1, cookie2, cookie3], [cookie1, cookie2, cookie3], ...]
                                accounts = data
                            else:
                                # Format: [cookie1, cookie2, cookie3, cookie4, ...] - coi như 1 account
                                # Hoặc chia thành các nhóm 3 cookies
                                if len(data) >= 3:
                                    # Chia thành các nhóm 3 cookies
                                    for i in range(0, len(data), 3):
                                        group = data[i:i+3]
                                        if len(group) >= 3:
                                            accounts.append(group)
                                else:
                                    accounts = [data]
                    except:
                        pass
                
                # Method 3: Tách theo pattern "]["
                if not accounts:
                    # Tìm các JSON arrays riêng biệt
                    pattern = r'\[[^\]]*\][^\[]*'
                    matches = re.findall(r'\[.*?\]', text, re.DOTALL)
                    for match in matches:
                        try:
                            data = json.loads(match)
                            if isinstance(data, list) and len(data) > 0:
                                accounts.append(data)
                        except:
                            pass
                
                if not accounts:
                    self.lbl_status.setText("Trạng thái: ❌ Không tìm thấy cookie hợp lệ")
                    self.lbl_status.setStyleSheet("color: red;")
                    self.preview_area.clear()
                    self.btn_save.setEnabled(False)
                    self.parsed_accounts = []
                    return
                
                # ✅ Validate từng account và tạo username tự động
                self.parsed_accounts = []
                base_time = int(time.time())
                
                for idx, cookie_list in enumerate(accounts):
                    if not isinstance(cookie_list, list) or len(cookie_list) == 0:
                        continue
                    
                    # Validate: Mỗi account nên có 3 cookies
                    if len(cookie_list) < 3:
                        continue  # Skip accounts không đủ 3 cookies
                    
                    # Check có session-token không (quan trọng)
                    has_session = any(
                        c.get('name', '').endswith('session-token') or 
                        '__Secure-next-auth.session-token' in c.get('name', '')
                        for c in cookie_list if isinstance(c, dict)
                    )
                    
                    if not has_session:
                        continue  # Skip accounts không có session-token
                    
                    # Tạo username tự động
                    username = f"cookie_user_{base_time + idx}"
                    
                    self.parsed_accounts.append((username, cookie_list))
                
                # ✅ Update UI
                if self.parsed_accounts:
                    self._update_preview()
                    self.btn_save.setEnabled(True)
                else:
                    self.lbl_status.setText("Trạng thái: ❌ Không có account hợp lệ (cần 3 cookies/account và session-token)")
                    self.lbl_status.setStyleSheet("color: red;")
                    self.preview_area.clear()
                    self.btn_save.setEnabled(False)
                
            except Exception as e:
                self.lbl_status.setText(f"Trạng thái: ❌ Lỗi parse: {str(e)[:50]}")
                self.lbl_status.setStyleSheet("color: red;")
                self.preview_area.clear()
                self.btn_save.setEnabled(False)
                self.parsed_accounts = []
        
        def _update_preview(self):
            """Update preview area với thông tin các accounts"""
            if not self.parsed_accounts:
                self.preview_area.clear()
                return
            
            preview_text = f"✅ Đã phát hiện {len(self.parsed_accounts)} account(s):\n\n"
            
            REQUIRED_NAMES = [
                "__Host-next-auth.csrf-token",
                "__Secure-next-auth.callback-url", 
                "__Secure-next-auth.session-token"
            ]
            
            for idx, (username, cookie_list) in enumerate(self.parsed_accounts, 1):
                preview_text += f"📋 Account #{idx}: {username}\n"
                preview_text += f"   Cookies: {len(cookie_list)}\n"
                
                # Check các cookie quan trọng
                cookie_names = [c.get('name', '') for c in cookie_list if isinstance(c, dict)]
                for req_name in REQUIRED_NAMES:
                    if any(req_name in name for name in cookie_names):
                        preview_text += f"   ✅ {req_name}\n"
                    else:
                        preview_text += f"   ⚠️ {req_name} (thiếu)\n"
                
                preview_text += "\n"
            
            self.preview_area.setText(preview_text)
            
            # Update status
            self.lbl_status.setText(
                f"Trạng thái: ✅ {len(self.parsed_accounts)} account(s) hợp lệ "
                f"({sum(len(cookies) for _, cookies in self.parsed_accounts)} cookies tổng cộng)"
            )
            self.lbl_status.setStyleSheet("color: green; font-weight: bold;")
        
        def get_data(self):
            """Return list of (username, cookie_list) tuples"""
            return self.parsed_accounts

