    def browse_image_prompt_file(self):
        """Browse file prompt cho I2V và load vào Prompts table"""
        file_path, _ = QFileDialog.getOpenFileName(
            self, "Chọn file prompt", "", "Text Files (*.txt);;All Files (*)"
        )
        if file_path:
            self.txt_image_prompt_file.setText(file_path)
            # Clear folder và root folder khi chọn file
            self.txt_image_prompt_folder.clear()
            self.txt_image_root_folder.clear()
            
