                    prompt_item = self._create_prompt_table_item(display_text, prompt_text, task_idx)
                    self.prompts_table.setItem(row, 1, prompt_item)
                    
                    # Progress Bar (GIỐNG T2V, I2V)
                    progress_bar = self.create_progress_bar(0)
                    self.prompts_table.setCellWidget(row, 2, progress_bar)
                    
                    # ✅ Trạng thái text (column 3) - "Done" (xanh lá) hoặc "Error" (đỏ)
