                    status_item.setForeground(QColor("#666666"))  # Xám
                    self.prompts_table.setItem(row, 3, status_item)
                    
                    # Review
                    btn_review = QPushButton("Xem")
                    btn_review.setMaximumSize(70, 24)
                    btn_review.setObjectName("reviewLink")
