            # ✅ ENABLE nút Bắt đầu khi có preview mới VÀ RESET STYLE
            self.btn_start.setEnabled(True)
            self.btn_start.setStyleSheet("")  # Clear any custom style (restore default)
            
            # ✅ FORCE UPDATE style để đảm bảo button sáng lên
