    def retry_single_video_task(self, task_index):
        """✅ Retry 1 task Text to Video - Lấy prompt từ table, chạy lại với đúng model, folder, tên file"""
        try:
            self.log(f"🔄 Retry task #{task_index}")
            
            # ✅ Tìm task từ current_tasks hoặc table
            target_task = None
            target_row = None
            
            # Tìm row trong table
            for row in range(self.prompts_table.rowCount()):
                prompt_item = self.prompts_table.item(row, 1)
                if prompt_item:
                    prompt_text = self._get_full_prompt_from_item(prompt_item)
                    # Tìm theo task_index
                    if hasattr(prompt_item, 'data') and prompt_item.data(Qt.UserRole) == task_index:
                        target_row = row
                        break
            
            # Tìm task từ current_tasks
            if hasattr(self, 'current_tasks') and self.current_tasks:
                for task in self.current_tasks:
                    if hasattr(task, 'prompt_index') and task.prompt_index == task_index:
                        target_task = task
                        break
            
            if not target_task:
                # Tạo task mới từ table
                if target_row is not None:
                    prompt_item = self.prompts_table.item(target_row, 1)
                    if prompt_item:
                        prompt_text = self._get_full_prompt_from_item(prompt_item)
                        # PromptTask đã được import ở đầu file
                        target_task = PromptTask(
                            prompt_text=prompt_text,
                            prompt_index=task_index,
                            output_folder=None
                        )
                        # Restore metadata từ cache nếu có
                        self._restore_task_metadata_from_cache(target_task)
                else:
                    self.log(f"❌ Không tìm thấy task với index {task_index}")
                    return
            
            task = target_task
            
            # Map display text to actual model key - Veo 3.1 Full Models
            model_text = self.combo_model.currentText()
            is_portrait = "9:16" in model_text
            model_map = {
                # Landscape (16:9)
                "Fast (16:9)": "veo_3_1_t2v_fast_ultra",
                "Quality (16:9)": "veo_3_1_t2v",
                "Low Fast (16:9)": "veo_3_1_t2v_fast_ultra_relaxed",
                # Portrait (9:16)
                "Fast (9:16)": "veo_3_1_t2v_fast_portrait_ultra",
                "Quality (9:16)": "veo_3_1_t2v_portrait",
                "Low Fast (9:16)": "veo_3_1_t2v_fast_portrait_ultra_relaxed",
                # Legacy
                "Veo 2.1 Fast": "veo_2_1_fast_d_15_t2v",
                "Veo 3.1 Ultra": "veo_3_1_t2v_fast_ultra",
                "Veo 3.1 Relaxed": "veo_3_1_t2v_fast_ultra_relaxed",
            }
            model = model_map.get(model_text, "veo_3_1_t2v_fast_ultra")
            num_videos = 1  # Cố định = 1
            aspect = "16:9" if "16:9" in model_text else "9:16"  # Lấy aspect từ model text
            output_folder = self.output_folder.text().strip() or QStandardPaths.writableLocation(QStandardPaths.DownloadLocation)
            
            # ✅ Đảm bảo output_folder có giá trị
            if not task.output_folder:
                task.output_folder = output_folder
            
            # ✅ Tạo retry task
            # PromptTask đã được import ở đầu file
            retry_task = PromptTask(
                prompt_text=task.prompt_text,
                prompt_index=task_index,
                output_folder=task.output_folder
            )
            retry_task.source_file = getattr(task, 'source_file', None)
            retry_task.local_index = getattr(task, 'local_index', None)
            
            # ✅ Chọn cookie available
            num_cookies = len(self.cookies_list) if self.cookies_list else 1
            self._init_cookie_status()
            cookie_index = None
            for cookie_idx in range(num_cookies):
                if not self._is_cookie_active(cookie_idx):
                    continue
                task_client = self.build_client(cookie_idx)
                if task_client and task_client.fetch_access_token():
                    cookie_index = cookie_idx
                    break
            
            if cookie_index is None:
                self.log(f"❌ Không có cookie nào sẵn sàng cho retry task #{task_index}")
                QMessageBox.warning(self, "Cảnh báo", "Không có cookie nào sẵn sàng!")
                return
            
            # ✅ Đảm bảo model được set đúng cho cookie này
            client = self.build_client(cookie_index)
            if not client or not client.fetch_access_token():
                self.log(f"❌ Không thể khởi tạo client cho cookie #{cookie_index + 1}")
                return
            
            # ✅ Set model trước khi retry
            if not client.set_video_model_key(model):
                error_msg = getattr(client, "last_error_detail", "") or getattr(client, "last_error", "") or "Lỗi set model"
                self.log(f"❌ Set model thất bại: {error_msg}")
                QMessageBox.warning(self, "Lỗi", f"Không thể set model: {error_msg}")
                return
            
            self.log(f"✅ Đã set model {model} cho cookie #{cookie_index + 1}")
            
            # ✅ Chạy retry trong thread riêng
            retry_tasks = [retry_task]
            self.processing_thread = threading.Thread(
                target=self.run_processing_worker,
                args=(retry_tasks, model, num_videos, aspect, output_folder),
                daemon=True
            )
            self.processing_thread.start()
            
            self.log(f"✅ Đã bắt đầu retry task #{task_index} với prompt: {task.prompt_text[:50]}...")
            
        except Exception as e:
            self.log(f"❌ Lỗi retry single video task: {e}")
            import traceback
            self.log(traceback.format_exc())
    
    @Slot(int, str)
    def update_task_status(self, task_index, status):
        """Cập nhật status của task - SLOT (chỉ enable/disable retry button)"""
        try:
            # TÌM ROW dựa vào task_index (vì table có thể đã filter)
            target_row = None
            for row in range(self.prompts_table.rowCount()):
                if not self.prompts_table.isRowHidden(row):
                    prompt_item = self.prompts_table.item(row, 1)
                    if prompt_item:
                        prompt_text = prompt_item.text()
                        # ✅ Tìm theo format "index: prompt" hoặc chỉ "prompt" (nếu không có prefix)
                        if ':' in prompt_text:
                            try:
                                item_index = int(prompt_text.split(':')[0].strip())
                                if item_index == task_index:
                                    target_row = row
                                    break
                            except:
                                pass
                        else:
                            # ✅ Nếu không có prefix, dùng row + 1 làm index (vì row bắt đầu từ 0)
                            if row + 1 == task_index:
                                target_row = row
                                break
            
            if target_row is not None:
                # Update progress bar khi hoàn thành hoặc lỗi
                progress_bar = self.prompts_table.cellWidget(target_row, 2)
                if isinstance(progress_bar, QProgressBar):
                    if status == "Done":
                        progress_bar.setValue(100)
                        progress_bar.setStyleSheet("""
                            QProgressBar {
                                border: 1px solid #BDBDBD;
                                border-radius: 3px;
                                text-align: center;
                                background-color: #F5F5F5;
                                font-weight: bold;
                                font-size: 10px;
                            }
                            QProgressBar::chunk {
                                background-color: #4CAF50;
                                border-radius: 2px;
                            }
                        """)
                    elif status == "Fail":
                        progress_bar.setValue(0)
                        progress_bar.setStyleSheet("""
                            QProgressBar {
                                border: 1px solid #BDBDBD;
                                border-radius: 3px;
                                text-align: center;
                                background-color: #F5F5F5;
                                font-weight: bold;
                                font-size: 10px;
                            }
                            QProgressBar::chunk {
                                background-color: #F44336;
                                border-radius: 2px;
                            }
                        """)
                
                # ✅ Cập nhật cột trạng thái (column 3) - "Done" (xanh lá) hoặc "Error" (đỏ)
                status_item = self.prompts_table.item(target_row, 3)
                if not status_item:
                    status_item = QTableWidgetItem()
                    status_item.setTextAlignment(Qt.AlignCenter)
                    self.prompts_table.setItem(target_row, 3, status_item)
                
                if status == "Done":
                    status_item.setText("Done")
                    status_item.setForeground(QColor("#4CAF50"))  # Xanh lá
                    # ✅ Force update để đảm bảo màu được áp dụng
                    status_item.setData(Qt.ForegroundRole, QColor("#4CAF50"))
                elif status == "Fail" or "Lỗi" in status or "Thất bại" in status:
                    status_item.setText("Error")
                    status_item.setForeground(QColor("#F44336"))  # Đỏ
                    # ✅ Force update để đảm bảo màu được áp dụng
                    status_item.setData(Qt.ForegroundRole, QColor("#F44336"))
                else:
                    status_item.setText("Đang xử lý...")
                    status_item.setForeground(QColor("#666666"))  # Xám
                    # ✅ Force update để đảm bảo màu được áp dụng
                    status_item.setData(Qt.ForegroundRole, QColor("#666666"))
                
                # ✅ Enable/Disable nút "Chạy lại" (column 5) - chỉ enable khi task Done hoặc Fail (sau 3 lần retry)
                btn_retry = self.prompts_table.cellWidget(target_row, 5)
                if isinstance(btn_retry, QPushButton):
                    # Chỉ enable khi task đã Done hoặc Fail (sau khi đã retry 3 lần, không phải 429)
                    # Disable tất cả các trường hợp khác: "Đang xử lý", "Retry X/3", "Cookie lỗi", v.v.
                    if status == "Done":
                        btn_retry.setEnabled(True)
                    elif status == "Fail":
                        # Chỉ enable nếu là Fail sau 3 lần retry (không phải 429)
                        # Status "Fail" được emit sau khi retry 3 lần không thành công
                        btn_retry.setEnabled(True)
                    else:
                        # Tất cả các trường hợp khác → disable
                        # Bao gồm: "Đang xử lý", "Retry 1/3", "Retry 2/3", "Retry 3/3", "Cookie lỗi", v.v.
                        btn_retry.setEnabled(False)
                
                # ✅ Không cần update review buttons nữa vì chỉ có nút "Xem" mở folder
        except Exception as e:
            self.log(f"❌ Lỗi update status: {e}")
    
