    # BỎ update_batch_progress vì dùng signal trực tiếp
    
    @Slot(int, int)
    def _update_batch_progress_ui(self, current, total):
        """Update batch progress (UI thread) - SLOT"""
        try:
            print(f"DEBUG: update_batch_progress: {current}/{total}")  # Debug
            if self.batch_table.rowCount() > 0:
                # Single file mode
                if self.batch_table.rowCount() == 1:
                    status_item = self.batch_table.item(0, 2)
                    if status_item:
                        status_item.setText(f"{current}/{total}")
                else:
                    # Multiple files - tính file nào đang xử lý
                    # Giả sử mỗi file có số prompts đều nhau
                    for row in range(self.batch_table.rowCount()):
                        status_text = self.batch_table.item(row, 2).text()
                        # Parse "current/total" từ status
                        if "/" in status_text:
                            file_total = int(status_text.split("/")[1])
                            # Update row đầu tiên chưa hoàn thành
                            file_current = int(status_text.split("/")[0])
                            if file_current < file_total:
                                # Update this row
                                new_current = min(file_current + 1, file_total)
                                self.batch_table.item(row, 2).setText(f"{new_current}/{file_total}")
                                break
        except Exception as e:
            pass
    
