    def show_review_menu(self, task_index, button):
        """Mở video trực tiếp nếu đã tải về, hoặc hiển thị menu nếu có nhiều video"""
        from PySide6.QtWidgets import QMenu
        from PySide6.QtCore import QPoint
        
        # Get video paths for this task
        video_paths = self.task_video_paths.get(task_index, [])
        
        if not video_paths:
            self.log(f"⚠️ Chưa có video cho task #{task_index}")
            return
        
        # ✅ Nếu chỉ có 1 video và đã tải về → mở trực tiếp
        if len(video_paths) == 1:
            video_path = video_paths[0]
            video_file = Path(video_path)
            if video_file.exists():
                # Kiểm tra file size (phải > 100KB)
                try:
                    file_size = video_file.stat().st_size
                    if file_size >= 100 * 1024:  # >= 100KB
                        self.open_video(video_path)
                        return
                except Exception:
                    pass
        
        # ✅ Nếu có nhiều video hoặc chưa tải về → hiển thị menu
        # Create menu với style gọn gàng
        menu = QMenu(self)
        menu.setStyleSheet("""
            QMenu {
                background-color: white;
                border: 1px solid #BDBDBD;
                border-radius: 4px;
                padding: 4px;
            }
            QMenu::item {
                background-color: transparent;
                color: #333333;
                padding: 6px 20px;
                margin: 2px 4px;
                border-radius: 3px;
            }
            QMenu::item:selected {
                background-color: #E3F2FD;
                color: #1976D2;
            }
            QMenu::item:pressed {
                background-color: #BBDEFB;
            }
        """)
        
        # Add actions với icon
        for i, video_path in enumerate(video_paths, 1):
            action = menu.addAction(f"▶ v{i}")
            action.triggered.connect(lambda checked, path=video_path: self.open_video(path))
        
        # ✅ Show menu ngay cạnh button - Vị trí chính xác, luôn nằm cạnh nút Xem
        # Lấy vị trí góc dưới bên phải của button trong tọa độ global
        button_rect = button.geometry()
        button_bottom_right = button.mapToGlobal(QPoint(button_rect.width(), button_rect.height()))
        
        # Hiện menu ngay cạnh bên phải button, căn trên với button
        menu_pos = QPoint(button_bottom_right.x() + 5, button_bottom_right.y() - button_rect.height())
        
        # ✅ Đảm bảo menu không bị tràn ra ngoài màn hình
        screen = QApplication.primaryScreen().availableGeometry()
        
        # Ước tính kích thước menu (mỗi item ~30px height, width ~150px)
        estimated_menu_width = 150
        estimated_menu_height = len(video_paths) * 30 + 10  # padding
        
        # Nếu menu bị tràn bên phải → hiện bên trái button
        if menu_pos.x() + estimated_menu_width > screen.right():
            menu_pos.setX(button_bottom_right.x() - estimated_menu_width - 5)
        
        # Nếu menu bị tràn phía dưới → hiện phía trên button
        if menu_pos.y() + estimated_menu_height > screen.bottom():
            menu_pos.setY(button_bottom_right.y() - estimated_menu_height - 5)
        
        # Đảm bảo không bị tràn bên trái
        if menu_pos.x() < screen.left():
            menu_pos.setX(screen.left() + 5)
        
        # Đảm bảo không bị tràn phía trên
        if menu_pos.y() < screen.top():
            menu_pos.setY(screen.top() + 5)
        
        # Hiển thị menu tại vị trí đã tính toán
        menu.exec(menu_pos)
    
    def open_video(self, video_path):
        """Mở video bằng player mặc định - CHỈ KHI DOWNLOAD XONG"""
        try:
            video_file = Path(video_path)
            
            if not video_file.exists():
                self.log(f"❌ Video không tồn tại: {video_file.name}")
                QMessageBox.warning(
                    self,
                    "⚠️ Không tìm thấy file",
                    f"Video chưa được tải về:\n{video_file.name}\n\n"
                    "Vui lòng đợi download hoàn tất."
                )
                return
            
            # CHECK: File đang download chưa? (size < 100KB → chưa xong)
            try:
                file_size = video_file.stat().st_size
                if file_size < 100 * 1024:  # < 100KB
                    self.log(f"⏳ File đang tải, vui lòng đợi: {video_file.name}")
                    QMessageBox.information(
                        self,
                        "⏳ Đang tải...",
                        f"Video đang được tải về:\n{video_file.name}\n\n"
                        f"Tiến trình: {file_size // 1024}KB\n"
                        "Vui lòng đợi download hoàn tất trước khi xem."
                    )
                    return
            except Exception as e:
                self.log(f"⚠️ Không thể kiểm tra file size: {e}")
            
            # CHECK: File đã sẵn sàng để mở (không bị lock bởi download worker)
            # Thử mở file để check xem có bị lock không
            try:
                with open(video_file, 'rb') as test_file:
                    # Nếu mở được → file không bị lock
                    pass
            except (PermissionError, IOError):
                self.log(f"⏳ File đang bị lock (đang download), vui lòng đợi: {video_file.name}")
                QMessageBox.information(
                    self,
                    "⏳ Đang xử lý...",
                    f"File đang được xử lý:\n{video_file.name}\n\n"
                    "Vui lòng đợi vài giây và thử lại."
                )
                return
            
            import platform
            import subprocess
            
            system = platform.system()
            
            if system == "Windows":
                import os
                os.startfile(str(video_path))
            elif system == "Darwin":  # macOS
                subprocess.run(["open", str(video_path)])
            else:  # Linux
                subprocess.run(["xdg-open", str(video_path)])
            
            self.log(f"▶️ Đang mở: {video_file.name}")
            
        except Exception as e:
            self.log(f"❌ Lỗi mở video: {e}")
            QMessageBox.critical(
                self,
                "❌ Lỗi",
                f"Không thể mở video:\n{e}\n\n"
                "File có thể đang được tải về, vui lòng thử lại sau."
            )
    
    @Slot()
    def finish_processing(self):
        """Kết thúc xử lý - SLOT"""
        print(f"DEBUG: finish_processing called, image_processing={self.image_processing}, stopped_by_user={getattr(self, '_image_stopped_by_user', False)}")  # Debug

        # ✅ BUG FIX: Nếu image bị dừng bởi user, không xử lý finished signal
        if getattr(self, '_image_stopped_by_user', False):
            print(f"DEBUG: Image stopped by user, ignore finish_processing signal")
            self._image_stopped_by_user = False  # Reset flag
            return
        
        # Check if this is video or image processing
        if self.image_processing:
            # Image processing finished
            self.image_processing = False
            self.btn_image_start.setEnabled(True)
            self.btn_image_stop.setEnabled(False)
            
            # ✅ Reset active tasks counter khi hoàn thành batch
            with self.active_image_tasks_lock:
                self.active_image_tasks = 0
                self.log(f"📊 Reset active tasks counter (batch completed)")

            # ✅ Dùng QTimer để đợi UI cập nhật status (không block main thread)
            # QTimer đã được import ở đầu file (dòng 29)
            def check_and_show_completion():
                # Show completion summary
                success_count = 0
                failed_count = 0
                for row in range(self.image_results_table.rowCount()):
                    status_item = self.image_results_table.item(row, 1)
                    if status_item:
                        status = status_item.text()
                        # ✅ Kiểm tra nhiều dạng status text
                        if "Hoàn thành" in status or "Completed" in status or "✅" in status:
                            success_count += 1
                        elif "Thất bại" in status or "Failed" in status or "Lỗi" in status or "❌" in status:
                            # Chỉ đếm là failed nếu không phải đang xử lý
                            if "Đang tạo" not in status and "Chờ xử lý" not in status:
                                failed_count += 1

                self.log(f"🎉 Tạo ảnh hoàn tất! ✅ Thành công: {success_count}, ❌ Thất bại: {failed_count}")
                
                # ✅ Enable nút "Retry All Lỗi" chỉ sau khi hoàn thành tất cả prompts
                if failed_count > 0:
                    self.btn_image_retry_all.setEnabled(True)
                    self.log(f"✅ Đã enable nút 'Retry All Lỗi' ({failed_count} lỗi)")
                else:
                    self.btn_image_retry_all.setEnabled(False)
                    # ✅ POPUP THÔNG BÁO THÀNH CÔNG (chỉ khi tất cả thành công)
                    if success_count > 0:
                        try:
                            msg = QMessageBox(self)
                            msg.setIcon(QMessageBox.Information)
                            msg.setWindowTitle("🎉 Hoàn thành!")
                            msg.setText(f"Tất cả {success_count} ảnh đã tạo thành công!")
                            msg.setInformativeText("Ảnh đã được tải về thư mục đầu ra.")
                            msg.exec()
                        except Exception:
                            pass
            
            # Đợi 500ms để UI kịp cập nhật status trước khi đếm
            QTimer.singleShot(500, check_and_show_completion)
        else:
            # Video processing finished
            self.processing = False
            self.btn_start.setEnabled(True)
            self.btn_pause.setEnabled(False)
            
            # Count success/failed tasks
            success_count = 0
            failed_count = 0
            # ✅ Các status được coi là lỗi
            error_keywords = ["Fail", "Cookie lỗi", "Cookie lỗi - Dừng", "Fail (Cookie lỗi)", 
                            "Không có cookie", "Thất bại", "Failed", "Lỗi"]
            
            for row in range(self.prompts_table.rowCount()):
                progress_bar = self.prompts_table.cellWidget(row, 2)
                if isinstance(progress_bar, QProgressBar):
                    progress_value = progress_bar.value()
                    status_text = progress_bar.text() if hasattr(progress_bar, 'text') else ""
                    
                    if progress_value == 100:
                        success_count += 1
                    elif progress_value == 0:
                        # Check nếu không phải đang xử lý
                        if "Đang xử lý" not in status_text and "Đang tạo" not in status_text:
                            # Check nếu có error keyword trong status
                            is_error = any(keyword in status_text for keyword in error_keywords)
                            if is_error or progress_value == 0:
                                failed_count += 1
            
            # ✅ Snapshot task metadata before clearing for retry dialogs
            self._update_task_metadata_cache()
            
            # ✅ CLEAR current_tasks sau khi hoàn thành - KHÔNG tự động start lại
            # Clear để tránh tự động start khi chuyển chất lượng hoặc thao tác khác
            # User phải bấm nút "Bắt đầu" mới chạy lại
            self.current_tasks = []
            self.log("✅ Đã clear current_tasks - Cần bấm 'Bắt đầu' để chạy lại")
            
            total = success_count + failed_count
            
            # ✅ ENABLE nút "Sửa File Lỗi" nếu có failed tasks (Text to Video hoặc Image to Video)
            has_i2v_failed = len(self.i2v_failed_tasks) > 0 if hasattr(self, 'i2v_failed_tasks') else False
            self.btn_fix_all.setEnabled(failed_count > 0 or has_i2v_failed)
            if has_i2v_failed:
                self.log(f"⚠️ Có {len(self.i2v_failed_tasks)} Image to Video tasks lỗi, có thể retry")
            
            # ✅ Không hiển thị popup - chỉ log (theo yêu cầu người dùng)
            def show_completion_summary():
                if failed_count == 0 and success_count > 0:
                    # TẤT CẢ thành công - hiển thị thông báo popup
                    self.log(f"✅ Xử lý hoàn tất - Tất cả {success_count} tasks thành công!")
                    # ✅ POPUP THÔNG BÁO THÀNH CÔNG
                    try:
                        msg = QMessageBox(self)
                        msg.setIcon(QMessageBox.Information)
                        msg.setWindowTitle("🎉 Hoàn thành!")
                        msg.setText(f"Tất cả {success_count} tasks đã hoàn thành thành công!")
                        msg.setInformativeText("Video đã được tải về thư mục đầu ra.")
                        msg.exec()
                    except Exception:
                        pass
                elif success_count == 0:
                    # TẤT CẢ thất bại - chỉ log (không popup lỗi)
                    self.log(f"❌ Xử lý hoàn tất - TẤT CẢ {failed_count} tasks đều thất bại!")
                    self.log("💡 Vui lòng kiểm tra: Cookie còn hạn không? Kết nối mạng ổn định không? Xem logs để biết chi tiết lỗi")
                else:
                    # MỘT SỐ thành công, một số thất bại - chỉ log (không popup)
                    self.log(f"⚠️ Xử lý hoàn tất - {success_count} thành công, {failed_count} thất bại")
                    self.log("💡 Dùng 'Sửa All File Lỗi' hoặc 'Chạy Lại Tùy Chọn' để retry các task lỗi")
            
            # Đợi 500ms để UI kịp cập nhật status trước khi log
            # ✅ Sử dụng QTimer đã import ở đầu file (dòng 29)
            QTimer.singleShot(500, show_completion_summary)
            
            # ✅ FORCE ENABLE nút start - đảm bảo user có thể bấm lại
            self.btn_start.setEnabled(True)
            self.log("✅ Đã enable nút 'Bắt đầu' - Sẵn sàng cho lần chạy tiếp theo")
            
            # EFFECT: NỔI LÊN khi hoàn thành (restore style) - FORCE CLEAR
            self.btn_start.setStyleSheet("")  # Clear custom style completely
            
            # ✅ FORCE UPDATE style để đảm bảo button sáng trở lại
            self.btn_start.style().unpolish(self.btn_start)  # Clear cached style
            self.btn_start.style().polish(self.btn_start)    # Reapply default style   
        
        # Update batch table to show all completed
        try:
            for row in range(self.batch_table.rowCount()):
                status_item = self.batch_table.item(row, 2)
                if status_item and "/" in status_item.text():
                    parts = status_item.text().split("/")
                    total = parts[1]
                    status_item.setText(f"{total}/{total}")  # Mark as complete
        except Exception:
            pass
    
    def on_logout(self):
        """Đăng xuất - XÓA HOÀN TOÀN token và ĐÓNG APP"""
        reply = QMessageBox.question(
            self, 'Xác nhận', 'Bạn có chắc muốn đăng xuất?',
            QMessageBox.Yes | QMessageBox.No
        )
        
        if reply == QMessageBox.Yes:
            try:
                # Dừng mọi tác vụ đang chạy
                self.stop_event.set()
                if hasattr(self, 'executor') and self.executor:
                    self.executor.shutdown(wait=False, cancel_futures=True)
                
                # Dừng subscription monitoring và cookie refresh
                self.stop_subscription_monitoring()
                self.stop_cookie_refresh()
                
                # Clear extension cookies cho Ultra user
                if self.is_ultra_user:
                    self.clear_extension_cookies()
                    self.delete_user_id_file()
                
                # Logout API
                api = ItingAPI()
                token = api.load_auth_token()
                
                if token:
                    try:
                        logout_iting_user(session_token=token, logout_type="manual")
                    except:
                        pass
                
                # XÓA HOÀN TOÀN file auth token ở TẤT CẢ VỊ TRÍ
                api.clear_auth_token(clear_all=True)
                
                # ✅ XÓA SAVED CREDENTIALS khi logout
                try:
                    cred_file = Path.cwd() / ".login_temp"
                    if cred_file.exists():
                        cred_file.unlink()
                except:
                    pass
                
                # XÓA THÊM tại nhiều locations (cho .exe)
                import sys
                possible_paths = [
                    Path.cwd() / ".auth_token",
                    Path(__file__).parent / ".auth_token" if hasattr(__file__, '__file__') else None,
                    Path(sys.executable).parent / ".auth_token",
                    Path(sys.argv[0]).parent / ".auth_token" if sys.argv else None,
                    Path.home() / ".auth_token",
                ]
                
                try:
                    import iting_api
                    possible_paths.append(Path(iting_api.__file__).parent / ".auth_token")
                except:
                    pass
                
                for file_path in possible_paths:
                    if file_path is None:
                        continue
                    try:
                        if file_path.exists():
                            file_path.unlink()
                    except:
                        pass
                
                # XÓA session cache trong memory
                if hasattr(self, 'user_info'):
                    self.user_info = {}
                if hasattr(self, 'subscription_info'):
                    self.subscription_info = {}
                
                # Hiện thông báo và ĐÓNG APP HOÀN TOÀN
                QMessageBox.information(
                    self, "Đăng xuất thành công", 
                    "Đã đăng xuất thành công!\n\nỨng dụng sẽ đóng.\nVui lòng mở lại để đăng nhập."
                )
                
                # ĐÓNG APP HOÀN TOÀN (không chỉ quit)
                import sys
                sys.exit(0)
                
            except Exception as e:
                self.log(f"❌ Lỗi đăng xuất: {e}")
                # Vẫn cố đóng app nếu có lỗi
                import sys
                sys.exit(0)
    
