    def update_model_credit_hint(self):
        """Hiển thị thông tin credits theo model đang chọn (UI-only)."""
        if not hasattr(self, "model_credit_label"):
            return
        
        try:
            current_model = self.combo_model.currentText()
        except Exception:
            current_model = ""
        
        # Trích xuất thông tin từ format mới: "Fast (16:9) - 10 credits"
        # Nếu đã có thông tin credits trong tên thì hiển thị luôn
        if "credits" in current_model:
            # Format mới đã có sẵn thông tin credits
            self.model_credit_label.setText(current_model)
            return
        
        # Legacy logic cho backward compatibility
        credit_map = {
            "Fast": "- 10 credits",
            "Quality": "- 100 credits",
            "Low Fast": "- 0 credits",
            # Legacy names (backward compatibility)
            "Veo 3.1 Ultra": "- 10 credits",
            "Veo 3.1 Standard": "- 100 credits",
            "Veo 3.1 Relaxed": "- 0 credits",
        }
        suffix = credit_map.get(current_model, "")
        
        if suffix:
            self.model_credit_label.setText(f"{current_model} {suffix}")
        else:
            self.model_credit_label.setText("")
    
    def show_login_form(self):
        """Hiển thị form login NGAY - ĐƠN GIẢN và ĐÁNG TIN CẬY"""
        dialog = QDialog()
        dialog.setWindowTitle("Đăng nhập - Google Labs Flow")
        dialog.setFixedSize(450, 420)  # Tăng chiều cao để chứa error message
        dialog.setWindowModality(Qt.ApplicationModal)
        
        # Đảm bảo dialog hiển thị lên trên và focus
        dialog.setWindowFlags(Qt.Dialog | Qt.WindowStaysOnTopHint)
        dialog.raise_()
        dialog.activateWindow()
        
        # Clean style
        dialog.setStyleSheet("""
            QDialog {
                background-color: #ffffff;
            }
        """)
        
        layout = QVBoxLayout(dialog)
        layout.setContentsMargins(40, 30, 40, 30)
        layout.setSpacing(15)
        
        # Title
        title = QLabel("🚀 Google Labs Flow")
        title.setStyleSheet("font-size: 20px; font-weight: bold; color: #2c3e50;")
        title.setAlignment(Qt.AlignCenter)
        layout.addWidget(title)
        
        # Username
        layout.addWidget(QLabel("Tên đăng nhập:"))
        username_input = QLineEdit()
        username_input.setPlaceholderText("Nhập tên đăng nhập")
        username_input.setStyleSheet("padding: 8px; border: 1px solid #ddd; border-radius: 4px; font-size: 13px;")
        
        # ✅ AUTO-FILL nếu đã ghi nhớ
        if self.saved_username:
            username_input.setText(self.saved_username)
        
        layout.addWidget(username_input)
        
        # Password
        layout.addWidget(QLabel("Mật khẩu:"))
        password_input = QLineEdit()
        password_input.setEchoMode(QLineEdit.Password)
        password_input.setPlaceholderText("Nhập mật khẩu")
        password_input.setStyleSheet("padding: 8px; border: 1px solid #ddd; border-radius: 4px; font-size: 13px;")
        
        # ✅ AUTO-FILL nếu đã ghi nhớ
        if self.saved_password:
            password_input.setText(self.saved_password)
        
        layout.addWidget(password_input)
        
        # Machine code (mã máy) - điền sẵn để dễ copy
        machine_label = QLabel("Mã máy (cố định cho 1 máy):")
        layout.addWidget(machine_label)
        
        from iting_api import ItingAPI
        try:
            api = ItingAPI()
            current_machine_code = api._get_machine_secret()
        except Exception:
            current_machine_code = "UNKNOWN"
        
        # Container cho machine code với nút copy
        machine_code_container = QHBoxLayout()
        machine_code_input = QLineEdit()
        machine_code_input.setText(current_machine_code)
        machine_code_input.setPlaceholderText("Mã máy do admin gắn. Có thể copy và gửi cho admin.")
        machine_code_input.setReadOnly(True)
        machine_code_input.setStyleSheet("padding: 8px; border: 1px solid #ddd; border-radius: 4px; font-size: 13px;")
        
        # Nút copy clipboard
        copy_btn = QPushButton("📋")
        copy_btn.setToolTip("Copy mã máy vào clipboard")
        copy_btn.setFixedWidth(40)
        copy_btn.setStyleSheet("padding: 8px; background: #3498db; color: white; border: none; border-radius: 4px; font-size: 14px;")
        
        # Function copy clipboard
        def copy_machine_code():
            from PySide6.QtGui import QClipboard
            clipboard = QApplication.clipboard()
            clipboard.setText(current_machine_code)
            copy_btn.setText("✓")
            copy_btn.setStyleSheet("padding: 8px; background: #27ae60; color: white; border: none; border-radius: 4px; font-size: 14px;")
            QTimer.singleShot(2000, lambda: (copy_btn.setText("📋"), copy_btn.setStyleSheet("padding: 8px; background: #3498db; color: white; border: none; border-radius: 4px; font-size: 14px;")))
        
        copy_btn.clicked.connect(copy_machine_code)
        
        # Double-click để copy
        def on_double_click(event):
            QLineEdit.mouseDoubleClickEvent(machine_code_input, event)
            copy_machine_code()
        
        machine_code_input.mouseDoubleClickEvent = on_double_click
        
        machine_code_container.addWidget(machine_code_input)
        machine_code_container.addWidget(copy_btn)
        layout.addLayout(machine_code_container)
        
        # ✅ CHECKBOX GHI NHỚ
        remember_checkbox = QCheckBox("🔒 Ghi nhớ đăng nhập (lưu trong RAM)")
        remember_checkbox.setChecked(self.remember_login)
        remember_checkbox.setStyleSheet("font-size: 12px; color: #666;")
        layout.addWidget(remember_checkbox)
        
        # Error message với chiều cao cố định (gấp đôi) để không làm dịch chuyển UI
        # Luôn chiếm không gian để không làm UI bị dịch chuyển
        msg_label = QLabel("")
        msg_label.setWordWrap(True)
        msg_label.setFixedHeight(60)  # Chiều cao cố định gấp đôi (30px -> 60px)
        msg_label.setStyleSheet("""
            color: transparent; 
            font-size: 12px;
            background: transparent;
            border: none;
            border-radius: 6px;
            padding: 8px 12px;
            margin: 8px 0px;
        """)
        layout.addWidget(msg_label)
        
        # Function để hiển thị/ẩn error message
        def show_error(text):
            if text:
                msg_label.setText(text)
                msg_label.setStyleSheet("""
                    color: #dc3545; 
                    font-size: 12px;
                    background: #f8d7da;
                    border: 1px solid #f5c6cb;
                    border-radius: 6px;
                    padding: 8px 12px;
                    margin: 8px 0px;
                """)
            else:
                msg_label.setText("")
                msg_label.setStyleSheet("""
                    color: transparent; 
                    font-size: 12px;
                    background: transparent;
                    border: none;
                    border-radius: 6px;
                    padding: 8px 12px;
                    margin: 8px 0px;
                """)
        
        # Buttons
        btn_layout = QHBoxLayout()
        
        cancel_btn = QPushButton("❌ Thoát")
        cancel_btn.setStyleSheet("padding: 8px 20px; background: #95a5a6; color: white; border: none; border-radius: 4px;")
        btn_layout.addWidget(cancel_btn)
        
        login_btn = QPushButton("🚀 Đăng nhập")
        login_btn.setStyleSheet("padding: 8px 20px; background: #3498db; color: white; border: none; border-radius: 4px; font-weight: bold;")
        btn_layout.addWidget(login_btn)
        
        layout.addLayout(btn_layout)
        
        # Login logic
        login_success = [False]
        
        def do_login():
            username = username_input.text().strip()
            password = password_input.text().strip()
            
            # Luôn lấy mã máy trực tiếp từ thiết bị (không cho user sửa tay)
            try:
                machine_code = ItingAPI()._get_machine_secret()
            except Exception:
                machine_code = machine_code_input.text().strip()
            
            if not username or not password or not machine_code:
                show_error("⚠️ Vui lòng nhập đầy đủ tên đăng nhập, mật khẩu và mã máy")
                return
            
            # Ẩn error message khi bắt đầu login
            show_error("")
            
            # Loading state
            login_btn.setText("⏳ Đang đăng nhập...")
            login_btn.setEnabled(False)
            
            # Call API (truyền thêm mã máy)
            success, message, data = authenticate_iting_user(username, password, machine_code)
            
            if success:
                # ✅ ĐĂNG NHẬP THÀNH CÔNG
                
                # Ghi nhớ credentials nếu user chọn
                if remember_checkbox.isChecked():
                    self.saved_username = username
                    self.saved_password = password
                    self.remember_login = True
                else:
                    # Xóa ghi nhớ nếu user bỏ tick
                    self.saved_username = ""
                    self.saved_password = ""
                    self.remember_login = False
                
                # Update account info
                self.update_account_info(username, data)
                
                login_success[0] = True
                dialog.accept()
                
            else:
                # ❌ ĐĂNG NHẬP THẤT BẠI
                show_error(f"❌ {message}")
                login_btn.setText("🚀 Đăng nhập")
                login_btn.setEnabled(True)
                password_input.setFocus()
        
        # Connect events
        login_btn.clicked.connect(do_login)
        cancel_btn.clicked.connect(dialog.reject)
        password_input.returnPressed.connect(do_login)
        username_input.returnPressed.connect(lambda: password_input.setFocus())
        
        # Focus
        if self.saved_username:
            password_input.setFocus()  # Username đã fill, focus vào password
        else:
            username_input.setFocus()   # Chưa có gì, focus vào username
        
        # Show dialog và return kết quả
        result = dialog.exec()
        return result == QDialog.Accepted and login_success[0]
    
    def check_session_only(self):
        """CHỈ check session để tránh đăng nhập nơi khác - KHÔNG TỰ ĐỘNG ĐĂNG NHẬP"""
        try:
            session_valid, session_data = check_iting_session()
            
            if session_valid:
                self.log("✅ Session hợp lệ")
                return True, session_data
            else:
                self.log("⚠️ Session không hợp lệ hoặc đã hết hạn")
                return False, session_data
        except Exception as e:
            self.log(f"❌ Lỗi check session: {e}")
            return False, {"error": str(e)}
    
