    def update_account_info(self, username: str, session_data: Dict):
        """Update account display - SAFE khi UI chưa sẵn sàng"""
        try:
            # Store data first
            self.user_info = session_data
            self.subscription_info = session_data.get("subscription", {})
            
            # ✅ KIỂM TRA NẾU LÀ KEY LOGIN
            user_data = session_data.get("user", {})
            is_key_login = user_data.get("is_key_login", False) or session_data.get("is_key_login", False)
            key_info = session_data.get("key_info", {})
            activation_key = key_info.get("activation_key") if key_info else None
            
            # Lưu flag key login và activation key
            if is_key_login:
                self.is_key_login = True
                # Lưu activation_key từ key_info, hoặc giữ lại giá trị cũ nếu đã có
                if activation_key:
                    self.activation_key = activation_key
                elif not hasattr(self, 'activation_key'):
                    self.activation_key = None
            else:
                # Không phải key login, reset flags
                self.is_key_login = False
                if hasattr(self, 'activation_key'):
                    self.activation_key = None
            
            # Lưu user_id - KIỂM TRA NHIỀU CÁCH
            self.current_user_id = session_data.get("user_id")  # Cách 1
            
            if not self.current_user_id:
                # Thử tìm trong user dict
                self.current_user_id = user_data.get("id") if user_data else None
                
            # Thử lấy từ session token nếu vẫn chưa có
            if not self.current_user_id:
                try:
                    api = ItingAPI()
                    token = api.load_auth_token()
                    if token:
                        from supabase_manager import supabase_manager
                        user_id_from_session = supabase_manager.get_user_id_from_session(token)
                        if user_id_from_session:
                            self.current_user_id = user_id_from_session
                except Exception:
                    pass
            
            # Update UI nếu các elements đã tồn tại
            if hasattr(self, 'lbl_account') and self.lbl_account:
                self.lbl_account.setText(f"Tài khoản: {username}")
            
                subscription = session_data.get("subscription", {})
            subscription_type = normalize_subscription_type(subscription.get("subscription_type", "free"))
            self.set_user_plan(subscription_type, subscription.get("limits"))
            
            
            if hasattr(self, 'lbl_expire') and self.lbl_expire:
                days_remaining = subscription.get("days_remaining", 9999)
                if days_remaining is not None:
                    if days_remaining == 999999:
                        self.lbl_expire.setText("Hết hạn: Vĩnh viễn")
                    else:
                        self.lbl_expire.setText(f"Hết hạn: Còn {days_remaining} ngày")
                else:
                    self.lbl_expire.setText("Hết hạn: Không xác định")
            
            # BẮT ĐẦU SUBSCRIPTION MONITORING sau khi có user_id
            if self.current_user_id:
                self.start_subscription_monitoring()
                
                # Sau login: đảm bảo đang ở tab Tạo Video và mode Text to Video
                try:
                    QTimer.singleShot(0, lambda: self.switch_main_tab(0))
                    QTimer.singleShot(50, lambda: self.switch_video_mode("Text to Video"))
                except Exception:
                    pass
                
                # CHECK ULTRA USER và start cookie refresh
                plan_key = getattr(self, "user_plan_key", "free")
                
                if plan_key in ("ultra", "enterprise"):
                    self.is_ultra_user = True
                    self.log("🌟 Ultra user detected - Auto cookie system enabled")
                    
                    # Gửi user_id cho extension
                    self.send_user_id_to_extension(self.current_user_id)
                    
                    # Tạo file user_id.txt cho extension
                    self.create_user_id_file(self.current_user_id)
                    
                    # TỰ ĐỘNG load cookies từ server ngay
                    if self.load_cookies_from_server():
                        self.log("✅ Cookies auto-loaded from server for Ultra user")
                    else:
                        self.log("⚠️ No cookies found on server - Ultra user can still input manually")
                    
                    # Start auto-refresh thread
                    self.start_cookie_refresh()
                else:
                    self.is_ultra_user = False
            
            # Load Gemini API key list khi đã có user_id
            self._refresh_gemini_keys_from_server()
            
        except Exception as e:
            # Không log error nếu UI chưa sẵn sàng
            pass
    
    @Slot(str)
    def append_log_safe(self, text: str):
        """Append log (thread-safe)"""
        try:
            if hasattr(self, 'logs_display') and self.logs_display:
                self.logs_display.append(text)
                scrollbar = self.logs_display.verticalScrollBar()
                scrollbar.setValue(scrollbar.maximum())
            else:
                # Fallback: print to console nếu logs_display chưa sẵn sàng
                print(f"[LOG] {text}")
        except Exception as e:
            print(f"[LOG ERROR] {e}: {text}")
    
    def log(self, message: str):
        """Log with timestamp"""
        timestamp = datetime.now().strftime("[%Y-%m-%d %H:%M:%S]")
        self.signals.new_log.emit(f"{timestamp} {message}")
    
    def _update_task_metadata_cache(self, tasks=None, reset=False):
        """Snapshot task metadata for retry flows (integrate, custom modes, etc.)."""
        try:
            if reset or not hasattr(self, "task_retry_metadata"):
                self.task_retry_metadata = {}
            task_list = tasks if tasks is not None else getattr(self, "current_tasks", [])
            if not task_list:
                return
            for task in task_list:
                if not task:
                    continue
                index = getattr(task, "prompt_index", None)
                if index is None:
                    index = getattr(task, "task_index", None)
                if not index:
                    continue
                meta = {
                    "prompt_text": getattr(task, "prompt_text", ""),
                    "output_folder": getattr(task, "output_folder", None),
                    "source_file": getattr(task, "source_file", None),
                    "local_index": getattr(task, "local_index", None),
                    "integrate_images": list(getattr(task, "integrate_images", []) or []),
                    "is_custom_integrate": getattr(task, "is_custom_integrate", False),
                    "image_path": getattr(task, "image_path", None),
                    "end_image_path": getattr(task, "end_image_path", None),
                }
                self.task_retry_metadata[index] = meta
        except Exception as e:
            print(f"[TASK CACHE] Failed to snapshot metadata: {e}")
    
    def _restore_task_metadata_from_cache(self, task):
        """Restore cached metadata (integrate images, source_file, etc.) for rebuilt tasks."""
        index = None
        try:
            if not task or not hasattr(self, "task_retry_metadata"):
                return
            index = getattr(task, "prompt_index", None)
            if index is None:
                index = getattr(task, "task_index", None)
            if not index:
                return
            meta = self.task_retry_metadata.get(index)
            if not meta:
                return
            if meta.get("output_folder") and not getattr(task, "output_folder", None):
                task.output_folder = meta["output_folder"]
            if meta.get("source_file") and not getattr(task, "source_file", None):
                task.source_file = meta["source_file"]
            if meta.get("local_index") and not getattr(task, "local_index", None):
                task.local_index = meta["local_index"]
            if meta.get("integrate_images"):
                task.integrate_images = list(meta["integrate_images"])
            if "is_custom_integrate" in meta:
                task.is_custom_integrate = meta["is_custom_integrate"]
            if meta.get("image_path") and not getattr(task, "image_path", None):
                task.image_path = meta["image_path"]
            if meta.get("end_image_path") and not getattr(task, "end_image_path", None):
                task.end_image_path = meta["end_image_path"]
        except Exception as e:
            label = index if index is not None else "?"
            print(f"[TASK CACHE] Failed to restore metadata for task #{label}: {e}")
    
    def _refresh_gemini_keys_from_server(self):
        """Load Gemini API key list from Supabase"""
        try:
            from supabase_manager import supabase_manager
            self.integrate_gemini_api_keys = []
            if not self.current_user_id:
                return
            success, keys = supabase_manager.get_gemini_api_keys(self.current_user_id)
            if success and keys is not None:
                self.integrate_gemini_api_keys = list(keys)
        except Exception as e:
            self.log(f"⚠️ Không thể load Gemini keys: {e}")
            self.integrate_gemini_api_keys = []
    
    def save_integrate_gemini_keys(self, keys: List[str]) -> bool:
        """Save Gemini API keys for current user"""
        try:
            from supabase_manager import supabase_manager
            if not self.current_user_id:
                self.log("⚠️ Không thể lưu Gemini key vì chưa xác định user_id")
                return False
            cleaned = [k.strip() for k in keys if k and k.strip()]
            success, result = supabase_manager.upsert_gemini_api_keys(self.current_user_id, cleaned)
            if success:
                self.integrate_gemini_api_keys = cleaned
                return True
            error_msg = result.get("error") if isinstance(result, dict) else str(result)
            self.log(f"❌ Lưu Gemini key thất bại: {error_msg}")
            return False
        except Exception as e:
            self.log(f"❌ Lưu Gemini key lỗi: {e}")
            return False
    
    def load_extension_id(self):
        """Load Extension ID từ file"""
        try:
            import json
            from pathlib import Path
            
            config_file = Path.cwd() / ".extension_config"
            if config_file.exists():
                with open(config_file, 'r', encoding='utf-8') as f:
                    config = json.load(f)
                    self.extension_id = config.get('extension_id', '')
                    if self.extension_id:
                        self.log(f"🔗 Extension ID loaded: {self.extension_id}")
        except Exception as e:
            self.log(f"⚠️ Error loading extension ID: {e}")
    
    def load_gemini_api_key(self):
        """✅ Load Gemini API Key từ file config (giống cookie)"""
        try:
            import json
            from pathlib import Path
            import os
            
            # ✅ Dùng cùng thư mục với cookie (GetCookieVeo3)
            app_data_dir = Path(os.environ.get('LOCALAPPDATA', os.path.expanduser('~'))) / "GetCookieVeo3"
            config_file = app_data_dir / "gemini_config.json"
            
            if config_file.exists():
                with open(config_file, 'r', encoding='utf-8') as f:
                    config = json.load(f)
                    gemini_key = config.get('gemini_api_key', '')
                    if gemini_key:
                        self.gemini_api_key = gemini_key
                        self.log(f"🔑 Gemini API Key loaded từ config")
                        return gemini_key
        except Exception as e:
            self.log(f"⚠️ Error loading Gemini API Key: {e}")
        return None
    
    def save_gemini_api_key(self, gemini_key: str):
        """✅ Lưu Gemini API Key vào file config (giống cookie)"""
        try:
            import json
            from pathlib import Path
            import os
            
            # ✅ Dùng cùng thư mục với cookie (GetCookieVeo3)
            app_data_dir = Path(os.environ.get('LOCALAPPDATA', os.path.expanduser('~'))) / "GetCookieVeo3"
            app_data_dir.mkdir(parents=True, exist_ok=True)
            config_file = app_data_dir / "gemini_config.json"
            
            config = {"gemini_api_key": gemini_key}
            with open(config_file, 'w', encoding='utf-8') as f:
                json.dump(config, f, indent=2)
            
            self.gemini_api_key = gemini_key
            self.log(f"💾 Gemini API Key saved")
            return True
        except Exception as e:
            self.log(f"❌ Error saving Gemini API Key: {e}")
            return False
    
    def save_extension_id(self):
        """Lưu Extension ID từ input"""
        try:
            if hasattr(self, 'extension_id_input'):
                extension_id = self.extension_id_input.text().strip()
                if extension_id:
                    self.extension_id = extension_id
                    
                    # Lưu vào file
                    import json
                    from pathlib import Path
                    
                    config_file = Path.cwd() / ".extension_config"
                    config = {"extension_id": extension_id}
                    with open(config_file, 'w', encoding='utf-8') as f:
                        json.dump(config, f)
                    
                    self.log(f"💾 Extension ID saved: {extension_id}")
                    QMessageBox.information(self, "✅ Thành công", f"Extension ID đã được lưu: {extension_id}")
                else:
                    QMessageBox.warning(self, "⚠️ Cảnh báo", "Vui lòng nhập Extension ID!")
        except Exception as e:
            self.log(f"❌ Error saving extension ID: {e}")
    
    def _fill_gemini_api_keys_to_inputs(self):
        """✅ Tự động fill Gemini API Key vào tất cả các input fields"""
        try:
            # Sử dụng gemini_api_keys (list) thay vì gemini_api_key (single)
            if not hasattr(self, 'gemini_api_keys') or not self.gemini_api_keys:
                return
            
            # Join các keys thành text (mỗi key một dòng)
            keys_text = "\n".join(self.gemini_api_keys)
            first_key = self.gemini_api_keys[0] if self.gemini_api_keys else ""
            
            # ✅ Fill vào txt_gemini_api_key (Integrate tab) - dùng multi-line
            if hasattr(self, 'txt_gemini_api_key') and self.txt_gemini_api_key:
                self.txt_gemini_api_key.setPlainText(keys_text)
            
            # ✅ Fill vào txt_sync_gemini_key (Sync tab) - dùng single key
            if hasattr(self, 'txt_sync_gemini_key') and self.txt_sync_gemini_key:
                self.txt_sync_gemini_key.setText(first_key)
            
            # ✅ Fill vào txt_rewrite_gemini_key (Rewrite tab) - dùng single key
            if hasattr(self, 'txt_rewrite_gemini_key') and self.txt_rewrite_gemini_key:
                self.txt_rewrite_gemini_key.setText(first_key)
            
            # ✅ Cập nhật integrate_gemini_api_keys
            if hasattr(self, 'integrate_gemini_api_keys'):
                self.integrate_gemini_api_keys = self.gemini_api_keys.copy()
            
            self.log(f"✅ Đã tự động fill {len(self.gemini_api_keys)} Gemini API Key(s) vào các input fields")
        except Exception as e:
            self.log(f"⚠️ Error filling Gemini API Key: {e}")
    
    def _auto_save_gemini_key_from_input(self, input_field, field_name: str):
        """✅ Tự động lưu Gemini API Key khi user nhập vào input field"""
        try:
            if isinstance(input_field, QLineEdit):
                key = input_field.text().strip()
            elif isinstance(input_field, QPlainTextEdit):
                key = input_field.toPlainText().strip().split('\n')[0]  # Lấy dòng đầu tiên
            else:
                return
            
            if key and len(key) > 10:  # Chỉ lưu nếu key hợp lệ (ít nhất 10 ký tự)
                self.save_gemini_api_key(key)
                self.log(f"💾 Đã tự động lưu Gemini API Key từ {field_name}")
        except Exception as e:
            self.log(f"⚠️ Error auto-saving Gemini API Key: {e}")
    
