    def create_user_id_file(self, user_id: int):
        """Tạo file user_id.txt cho extension đọc"""
        try:
            from pathlib import Path
            
            # Tạo file user_id.txt trong thư mục extension
            extension_dir = Path(__file__).parent / "extension"
            extension_dir.mkdir(exist_ok=True)
            
            user_id_file = extension_dir / "user_id.txt"
            with open(user_id_file, 'w', encoding='utf-8') as f:
                f.write(str(user_id))
            
            self.log(f"📄 Created user_id.txt: {user_id}")
            
        except Exception as e:
            self.log(f"❌ Error creating user_id file: {e}")
    
