    def on_image_mode_change(self):
        """Switch between Text-to-Image, Image-to-Image, and Multiple-to-Image modes"""
        if self.rb_text_to_image.isChecked():
            self.current_image_mode = "Text-to-Image"
            self.text_to_image_group.setVisible(True)
            self.image_to_image_group.setVisible(False)
            self.multiple_to_image_group.setVisible(False)
        elif self.rb_image_to_image.isChecked():
            self.current_image_mode = "Image-to-Image"
            self.text_to_image_group.setVisible(False)
            self.image_to_image_group.setVisible(True)
            self.multiple_to_image_group.setVisible(False)
        elif self.rb_multiple_to_image.isChecked():
            self.current_image_mode = "Multiple-to-Image"
            self.text_to_image_group.setVisible(False)
            self.image_to_image_group.setVisible(False)
            self.multiple_to_image_group.setVisible(True)
        
        self.log(f"Image mode: {self.current_image_mode}")
    
    def browse_whisk_prompt_file(self):
        """Browse file chứa nhiều prompts cho Whisk Image tab - Chỉ chấp nhận file .txt"""
        file_path, _ = QFileDialog.getOpenFileName(
            self, "Chọn file prompt (chỉ chấp nhận file .txt)", "", "Text Files (*.txt);;All Files (*)"
        )
        if file_path:
            # Kiểm tra extension
            if not file_path.lower().endswith('.txt'):
                QMessageBox.warning(self, "Cảnh báo", "Chỉ chấp nhận file .txt!")
                return
            # Tự động điền path vào input (read-only)
            self.txt_whisk_prompt_file.setText(file_path)
            # Xóa folder nếu đã chọn file
            self.txt_t2i_prompt_folder.clear()
            
            # ✅ Thêm single file vào batch table
            self.populate_image_batch_table(self.t2i_batch_table, [Path(file_path)])
            
            self.log(f"📄 File prompt ảnh Whisk: {file_path}")
    
    def browse_t2i_prompt_folder(self):
        """Browse folder chứa nhiều file .txt cho Text-to-Image"""
        folder_path = QFileDialog.getExistingDirectory(
            self, "Chọn thư mục chứa file .txt"
        )
        if folder_path:
            # Kiểm tra có file .txt không
            txt_files = sorted(Path(folder_path).glob("*.txt"))
            if not txt_files:
                QMessageBox.warning(self, "Cảnh báo", f"Thư mục '{folder_path}' không chứa file .txt nào!")
                return
            
            self.txt_t2i_prompt_folder.setText(folder_path)
            # ✅ Xóa single file và clear batch table khi chọn folder
            self.txt_whisk_prompt_file.clear()
            self.log(f"📁 T2I Folder: {folder_path} ({len(txt_files)} file .txt)")
            
            # ✅ Populate batch table
            self.populate_image_batch_table(self.t2i_batch_table, txt_files)
    
