    def update_reference_image_preview(self, image_type):
        """Update preview của reference image (subject/scene/style)"""
        try:
            from PySide6.QtGui import QPixmap
            import os
            
            if image_type == 'subject':
                image_path = self.txt_subject_image.text().strip()
                label = self.label_subject_preview
            elif image_type == 'scene':
                image_path = self.txt_scene_image.text().strip()
                label = self.label_scene_preview
            elif image_type == 'style':
                image_path = self.txt_style_image.text().strip()
                label = self.label_style_preview
            else:
                return
            
            if image_path and os.path.exists(image_path):
                try:
                    pixmap = QPixmap(image_path)
                    if not pixmap.isNull():
                        # Scale to fit preview size
                        scaled = pixmap.scaled(60, 60, Qt.KeepAspectRatio, Qt.SmoothTransformation)
                        label.setPixmap(scaled)
                        
                        # ✅ Kiểm tra xem đã upload chưa (có mediaGenerationId chưa) - Check tất cả cookies
                        image_path_abs = str(Path(image_path).resolve())
                        found_in_cache = False
                        for cookie_hash, cookie_cache in self.reference_image_media_ids.items():
                            if isinstance(cookie_cache, dict) and image_path_abs in cookie_cache:
                                found_in_cache = True
                                break
                        
                        if found_in_cache:
                            label.setToolTip(f"✅ {Path(image_path).name}\n📎 Đã upload")
                        else:
                            label.setToolTip(f"📷 {Path(image_path).name}\n⏳ Chưa upload")
                    else:
                        label.setText("❌")
                        label.setToolTip("Không thể load ảnh")
                except Exception as e:
                    self.log(f"⚠️ Lỗi load preview {image_type}: {e}")
                    label.setText("❌")
            else:
                # Clear preview
                label.clear()
                label.setText("📷")
                label.setToolTip("Chưa chọn ảnh")
        except Exception as e:
            self.log(f"⚠️ Lỗi update preview: {e}")
    
    def log_upload_request_to_file(self, image_type, image_path):
        """Log upload request ra file"""
        try:
            import json
            from datetime import datetime
            
            log_dir = Path("logs")
            log_dir.mkdir(exist_ok=True)
            
            log_file = log_dir / f"upload_requests_{datetime.now().strftime('%Y%m%d')}.jsonl"
            
            log_entry = {
                "timestamp": datetime.now().isoformat(),
                "type": "upload_image",
                "image_type": image_type,
                "image_path": str(Path(image_path).resolve()),
                "image_name": Path(image_path).name
            }
            
            with open(log_file, 'a', encoding='utf-8') as f:
                f.write(json.dumps(log_entry, ensure_ascii=False) + "\n")
            
            self.log(f"📝 Logged upload request: {log_file.name}")
        except Exception as e:
            self.log(f"⚠️ Error logging upload request: {e}")
    
    def log_request_to_file(self, api_type, **kwargs):
        """Log API request ra file (runImageRecipe hoặc generateImage)"""
        try:
            import json
            from datetime import datetime
            
            log_dir = Path("logs")
            log_dir.mkdir(exist_ok=True)
            
            log_file = log_dir / f"api_requests_{datetime.now().strftime('%Y%m%d')}.jsonl"
            
            # Build payload structure
            payload = {}
            if api_type == "runImageRecipe":
                payload = {
                    "api": "whisk:runImageRecipe",
                    "url": "https://aisandbox-pa.googleapis.com/v1/whisk:runImageRecipe",
                    "workflow_id": kwargs.get("workflow_id"),
                    "prompt": kwargs.get("prompt"),
                    "image_model": kwargs.get("model"),
                    "aspect_ratio": kwargs.get("aspect_ratio"),
                    "subject_mgid": kwargs.get("subject_mgid"),
                    "scene_mgid": kwargs.get("scene_mgid"),
                    "style_mgid": kwargs.get("style_mgid"),
                    "recipeMediaInputs": []
                }
                # Build recipeMediaInputs
                if kwargs.get("subject_mgid"):
                    payload["recipeMediaInputs"].append({
                        "caption": "Subject image",
                        "mediaInput": {
                            "mediaCategory": "MEDIA_CATEGORY_SUBJECT",
                            "mediaGenerationId": kwargs.get("subject_mgid")
                        }
                    })
                if kwargs.get("scene_mgid"):
                    payload["recipeMediaInputs"].append({
                        "caption": "Scene image",
                        "mediaInput": {
                            "mediaCategory": "MEDIA_CATEGORY_SCENE",
                            "mediaGenerationId": kwargs.get("scene_mgid")
                        }
                    })
                if kwargs.get("style_mgid"):
                    payload["recipeMediaInputs"].append({
                        "caption": "Style image",
                        "mediaInput": {
                            "mediaCategory": "MEDIA_CATEGORY_STYLE",
                            "mediaGenerationId": kwargs.get("style_mgid")
                        }
                    })
            elif api_type == "generateImage":
                payload = {
                    "api": "whisk:generateImage",
                    "url": "https://aisandbox-pa.googleapis.com/v1/whisk:generateImage",
                    "workflow_id": kwargs.get("workflow_id"),
                    "prompt": kwargs.get("prompt"),
                    "image_model": kwargs.get("model"),
                    "aspect_ratio": kwargs.get("aspect_ratio")
                }
            
            log_entry = {
                "timestamp": datetime.now().isoformat(),
                "api_type": api_type,
                "payload": payload
            }
            
            with open(log_file, 'a', encoding='utf-8') as f:
                f.write(json.dumps(log_entry, ensure_ascii=False, indent=2) + "\n")
            
            self.log(f"📝 Logged {api_type} request: {log_file.name}")
        except Exception as e:
            self.log(f"⚠️ Error logging request: {e}")
    
    def upload_single_reference_image(self, image_type, image_path):
        """Upload single reference image ngay khi user chọn - Chạy trong thread riêng để không block UI"""
        try:
            if not image_path or not Path(image_path).exists():
                self.log(f"❌ {image_type.capitalize()} image không tồn tại: {image_path}")
                return
            
            # ✅ Upload trong thread riêng để không block UI
            def upload_worker():
                try:
                    # Get client
                    available_cookies = []
                    if self.cookies_list:
                        available_cookies = self.cookies_list
                    elif self.cookie_value:
                        available_cookies = [self.cookie_value]
                    
                    if not available_cookies:
                        self.log(f"⚠️ Không có cookie để upload {image_type} - Vui lòng cài đặt cookie trước")
                        return
                    
                    # Build client
                    from complete_flow import LabsFlowClient, _parse_cookie_string
                    cookies = _parse_cookie_string(available_cookies[0])
                    client = LabsFlowClient(cookies)
                    
                    # Get access token
                    if not client.fetch_access_token():
                        self.log(f"❌ Không lấy được access token để upload {image_type}")
                        return
                    
                    # ✅ Lấy cookie hash từ client để cache theo cookie
                    cookie_hash = getattr(client, '_cookie_hash', None)
                    if not cookie_hash:
                        # ✅ LabsFlowClient đã được import ở đầu file, không cần import lại
                        cookie_hash = LabsFlowClient._get_cookie_hash(client.cookies if hasattr(client, 'cookies') else {})
                    
                    # ✅ Khởi tạo cache cho cookie này nếu chưa có
                    if cookie_hash not in self.reference_image_media_ids:
                        self.reference_image_media_ids[cookie_hash] = {}
                    cookie_cache = self.reference_image_media_ids[cookie_hash]
                    
                    # ✅ Check cache THEO COOKIE
                    image_path_abs = str(Path(image_path).resolve())
                    if image_path_abs in cookie_cache:
                        mgid = cookie_cache[image_path_abs]
                        self.log(f"♻️ {image_type.capitalize()} đã có trong cache (cookie {cookie_hash[:8]}...): {Path(image_path).name}")
                        # ✅ Update preview để hiển thị status - Dùng signal để thread-safe
                        self.signals.update_reference_image_preview_signal.emit(image_type)
                        return
                    
                    # Upload image
                    self.log(f"📤 Đang upload {image_type.capitalize()} (cookie {cookie_hash[:8]}...): {Path(image_path).name}...")
                    # ✅ Log upload request ra file
                    self.log_upload_request_to_file(image_type, image_path)
                    # ✅ FIX: Dùng upload_image() thay vì upload_image_to_whisk()
                    mgid = client.upload_image(image_path)
                    
                    if mgid:
                        # ✅ Cache mediaGenerationId THEO COOKIE
                        cookie_cache[image_path_abs] = mgid
                        self.log(f"✅ Uploaded {image_type.capitalize()} (cookie {cookie_hash[:8]}...): {Path(image_path).name}")
                        # ✅ Update preview để hiển thị status - Dùng signal để thread-safe
                        self.signals.update_reference_image_preview_signal.emit(image_type)
                    else:
                        self.log(f"❌ Failed to upload {image_type.capitalize()}: {Path(image_path).name} - Không có mediaGenerationId trả về")
                        self.log(f"💡 Có thể do: Cookie không có quyền upload, file ảnh không hợp lệ, hoặc lỗi network")
                
                except Exception as e:
                    self.log(f"❌ Error uploading {image_type}: {e}")
                    import traceback
                    self.log(f"🔍 Traceback: {traceback.format_exc()}")
            
            # Start upload in background thread
            import threading
            threading.Thread(target=upload_worker, daemon=True).start()
            
        except Exception as e:
            self.log(f"❌ Error in upload_single_reference_image: {e}")
    
