    def populate_image_batch_table(self, table_widget, txt_files):
        """Populate batch table với danh sách file .txt và số prompts trong mỗi file
        
        Bao gồm tracking status: completed/total
        """
        try:
            table_widget.setRowCount(0)  # Clear existing rows
            
            # ✅ Initialize batch file tracking dict {file_stem: {"total": N, "completed": 0}}
            if not hasattr(self, 'image_batch_file_status'):
                self.image_batch_file_status = {}
            
            for idx, txt_file in enumerate(txt_files, 1):
                # Đếm số prompts trong file
                try:
                    with open(txt_file, 'r', encoding='utf-8') as f:
                        prompts = [line.strip() for line in f if line.strip()]
                    num_prompts = len(prompts)
                except Exception as e:
                    self.log(f"❌ Lỗi đọc {txt_file.name}: {e}")
                    num_prompts = 0
                
                # ✅ Track file status
                file_stem = txt_file.stem
                self.image_batch_file_status[file_stem] = {
                    "total": num_prompts,
                    "completed": 0
                }
                
                # Add row
                row = table_widget.rowCount()
                table_widget.insertRow(row)
                
                # STT
                table_widget.setItem(row, 0, QTableWidgetItem(str(idx)))
                
                # Tên file
                table_widget.setItem(row, 1, QTableWidgetItem(txt_file.name))
                
                # Số prompts
                table_widget.setItem(row, 2, QTableWidgetItem(str(num_prompts)))
                
                # ✅ Status (0/N)
                status_item = QTableWidgetItem(f"0/{num_prompts}")
                status_item.setData(Qt.UserRole, file_stem)  # Store file stem for updates
                table_widget.setItem(row, 3, status_item)
            
            # ✅ Connect click event để filter cards
            if table_widget == self.i2i_batch_table:
                table_widget.cellClicked.connect(self.on_i2i_batch_table_clicked)
            elif table_widget == self.m2i_batch_table:
                table_widget.cellClicked.connect(self.on_m2i_batch_table_clicked)
            else:
                # Default handler for other tables
                table_widget.cellClicked.connect(self.on_batch_table_cell_clicked)
        except Exception as e:
            self.log(f"❌ Lỗi: {e}")
            
    
