    def on_m2i_batch_table_clicked(self, row, col):
        """Handle click on M2I batch table - filter cards by file"""
        try:
            if row < 0 or row >= self.m2i_batch_table.rowCount():
                return
            file_item = self.m2i_batch_table.item(row, 1)
            if not file_item:
                return
            file_name = file_item.text()
            file_stem = Path(file_name).stem
            self.current_image_batch_filter = file_stem
            self.log(f"🔍 Filter cards by file: {file_stem}")
            self.refresh_image_cards_display()
        except Exception as e:
            self.log(f"❌ Error handling M2I batch table click: {e}")
            table_widget.cellClicked.connect(self.on_batch_table_cell_clicked)
            
            self.log(f"📋 Đã load {len(txt_files)} file vào batch table")
            
        except Exception as e:
            self.log(f"❌ Lỗi populate batch table: {e}")
    
    def on_batch_table_cell_clicked(self, row, column):
        """Handle click vào batch table row → filter cards theo file đó"""
        try:
            # Get table widget (determine which table based on current mode)
            if self.current_image_mode == "Text-to-Image":
                table_widget = self.t2i_batch_table
            else:
                table_widget = self.i2i_batch_table
            
            # Get file stem from status column
            status_item = table_widget.item(row, 3)
            if not status_item:
                return
            
            file_stem = status_item.data(Qt.UserRole)
            file_name = table_widget.item(row, 1).text()
            
            # Toggle filter: nếu click vào file đang filter → show all
            if self.current_batch_filter == file_stem:
                # Clear filter
                self.current_batch_filter = None
                self.lbl_image_filter.setText("Hiển thị: Tất cả")
                self.log(f"📋 Hiển thị tất cả cards")
                
                # Clear selection
                table_widget.clearSelection()
            else:
                # Apply filter
                self.current_batch_filter = file_stem
                self.lbl_image_filter.setText(f"Hiển thị: {file_name}")
                self.log(f"📋 Filter cards từ file: {file_name}")
                
                # Highlight selected row
                table_widget.selectRow(row)
            
            # Reset to page 1 and refresh display
            self.current_image_page = 1
            self.refresh_image_cards_display()
            
        except Exception as e:
            self.log(f"❌ Error handling batch table click: {e}")
    
    def update_batch_file_status(self, source_file_name):
        """Update batch file status khi 1 prompt hoàn thành
        
        Args:
            source_file_name: Tên file txt (stem, không có extension)
        """
        try:
            if not hasattr(self, 'image_batch_file_status'):
                return
            
            if source_file_name not in self.image_batch_file_status:
                return
            
            # Increment completed count
            self.image_batch_file_status[source_file_name]["completed"] += 1
            completed = self.image_batch_file_status[source_file_name]["completed"]
            total = self.image_batch_file_status[source_file_name]["total"]
            
            # Update batch table (find row by file stem)
            # Determine which table to update based on current mode
            if self.current_image_mode == "Text-to-Image":
                table_widget = self.t2i_batch_table
            else:
                table_widget = self.i2i_batch_table
            
            # Find and update the row
            for row in range(table_widget.rowCount()):
                status_item = table_widget.item(row, 3)
                if status_item and status_item.data(Qt.UserRole) == source_file_name:
                    # Update status column
                    status_item.setText(f"{completed}/{total}")
                    
                    # Change color if completed
                    if completed >= total:
                        status_item.setForeground(QColor("#28a745"))  # Green
                        status_item.setText(f"✅ {completed}/{total}")
                    else:
                        status_item.setForeground(QColor("#007bff"))  # Blue
                    
                    break
            
        except Exception as e:
            self.log(f"❌ Error updating batch file status: {e}")
    
    def refresh_image_cards_display(self):
        """✅ Refresh hiển thị cards với pagination và filter
        
        Chỉ hiển thị cards của trang hiện tại và file được filter
        """
        try:
            # Get all card indices (sorted by file + local index để giữ đúng thứ tự hiển thị)
            def _sort_key(idx: int):
                file_name = self.image_prompt_file_mapping.get(idx, "")
                local_idx = self.image_prompt_local_mapping.get(idx, idx)
                return (file_name, local_idx, idx)
            
            all_indices = sorted(self.image_widgets.keys(), key=_sort_key)
            
            # ✅ Filter by batch file if needed
            if self.current_batch_filter:
                filtered_indices = [
                    idx for idx in all_indices 
                    if self.image_prompt_file_mapping.get(idx) == self.current_batch_filter
                ]
            else:
                filtered_indices = all_indices
            
            # Calculate pagination
            total_cards = len(filtered_indices)
            self.total_image_pages = max(1, (total_cards + self.image_cards_per_page - 1) // self.image_cards_per_page)
            
            # Clamp current page
            self.current_image_page = max(1, min(self.current_image_page, self.total_image_pages))
            
            # Get cards for current page
            start_idx = (self.current_image_page - 1) * self.image_cards_per_page
            end_idx = start_idx + self.image_cards_per_page
            page_indices = filtered_indices[start_idx:end_idx]
            
            # Hide all cards trước khi sắp xếp lại
            for widget in self.image_widgets.values():
                widget.setVisible(False)
            
            # ✅ Clear layout positions (không xóa widget)
            while self.image_grid_layout.count():
                item = self.image_grid_layout.takeAt(0)
                if item and item.widget():
                    # Giữ parent để widget không bị destroy
                    item.widget().setParent(self.image_grid_widget)

            # ✅ Tính số cột dựa trên độ rộng hiện tại (mặc định 3 để rộng rãi)
            card_width = 260  # Ước lượng chiều rộng card + spacing
            columns = 3

            viewport = self.image_grid_widget.parentWidget()
            available_width = 0
            if viewport:
                available_width = viewport.width()
            if available_width == 0:
                available_width = self.image_grid_widget.width()

            if available_width and available_width < columns * card_width:
                if available_width >= 3 * card_width:
                    columns = 3
                else:
                    calculated = max(1, available_width // card_width)
                    columns = max(1, min(3, calculated))

            columns = max(1, min(columns, 3))

            # ✅ Re-add cards for current page theo thứ tự liên tục
            for pos, idx in enumerate(page_indices):
                widget = self.image_widgets.get(idx)
                if not widget:
                    continue

                row = pos // columns
                col = pos % columns
                self.image_grid_layout.addWidget(widget, row, col)
                widget.setVisible(True)

            # ✅ Update stretch để cards giãn đều
            max_columns = max(columns, 4)
            for c in range(max_columns):
                stretch = 1 if c < columns else 0
                self.image_grid_layout.setColumnStretch(c, stretch)
            
            # Update pagination UI
            self.lbl_image_page_info.setText(f"Trang {self.current_image_page}/{self.total_image_pages} ({len(page_indices)}/{total_cards} cards)")
            self.btn_image_prev_page.setEnabled(self.current_image_page > 1)
            self.btn_image_next_page.setEnabled(self.current_image_page < self.total_image_pages)
            
            # Force update
            self.image_grid_widget.update()
            
            self.log(f"📄 Page {self.current_image_page}/{self.total_image_pages}: Hiển thị {len(page_indices)} cards")
            
        except Exception as e:
            self.log(f"❌ Error refreshing cards display: {e}")
    
    def go_to_prev_image_page(self):
        """Chuyển sang trang trước"""
        if self.current_image_page > 1:
            self.current_image_page -= 1
            self.refresh_image_cards_display()
    
    def go_to_next_image_page(self):
        """Chuyển sang trang sau"""
        if self.current_image_page < self.total_image_pages:
            self.current_image_page += 1
            self.refresh_image_cards_display()
    
    def browse_image_output(self):
        """Browse output directory for images"""
        folder = QFileDialog.getExistingDirectory(self, "Chọn thư mục lưu ảnh")
        if folder:
            self.txt_image_output.setText(folder)
            self.log(f"📁 Thư mục lưu ảnh: {folder}")

    
    def upload_and_cache_reference_images(self, client):
        """Upload reference images và cache media_id THEO COOKIE - ✅ BẮT BUỘC UPLOAD TRƯỚC KHI GEN"""
        try:
            subj_mgid = scene_mgid = style_mgid = None
            
            # ✅ Lấy cookie hash từ client để cache theo cookie
            cookie_hash = getattr(client, '_cookie_hash', None)
            if not cookie_hash:
                # ✅ LabsFlowClient đã được import ở đầu file, không cần import lại
                cookie_hash = LabsFlowClient._get_cookie_hash(client.cookies if hasattr(client, 'cookies') else {})
            
            # ✅ Khởi tạo cache cho cookie này nếu chưa có
            if cookie_hash not in self.reference_image_media_ids:
                self.reference_image_media_ids[cookie_hash] = {}
            
            cookie_cache = self.reference_image_media_ids[cookie_hash]
            
            # ✅ DEBUG: Log các ảnh đã chọn
            subject_path = self.txt_subject_image.text().strip()
            scene_path = self.txt_scene_image.text().strip()
            style_path = self.txt_style_image.text().strip()
            
            self.log(f"🔍 Checking reference images (cookie: {cookie_hash[:8]}...):")
            self.log(f"  Subject: {subject_path if subject_path else 'Not selected'}")
            self.log(f"  Scene: {scene_path if scene_path else 'Not selected'}")
            self.log(f"  Style: {style_path if style_path else 'Not selected'}")
            
            # Upload Subject image
            if subject_path:
                if not Path(subject_path).exists():
                    self.log(f"❌ Subject image không tồn tại: {subject_path}")
                else:
                    # ✅ Check cache THEO COOKIE
                    subject_path_abs = str(Path(subject_path).resolve())
                    if subject_path_abs in cookie_cache:
                        subj_mgid = cookie_cache[subject_path_abs]
                        self.log(f"♻️ Reusing cached Subject (cookie {cookie_hash[:8]}...): {Path(subject_path).name}")
                    else:
                        # ✅ UPLOAD VÀ CACHE THEO COOKIE
                        self.log(f"📤 Đang upload Subject (cookie {cookie_hash[:8]}...): {Path(subject_path).name}...")
                        try:
                            subj_mgid = client.upload_image(subject_path)
                            if subj_mgid:
                                cookie_cache[subject_path_abs] = subj_mgid  # ✅ Lưu vào cache của cookie này
                                self.log(f"✅ Uploaded Subject (cookie {cookie_hash[:8]}...): {Path(subject_path).name}")
                            else:
                                self.log(f"❌ Failed to upload Subject: {Path(subject_path).name} - Không có mediaGenerationId trả về")
                                self.log(f"💡 Có thể do: Cookie không có quyền upload, file ảnh không hợp lệ, hoặc lỗi network")
                        except Exception as e:
                            self.log(f"❌ Error uploading Subject: {e}")
                            import traceback
                            self.log(f"🔍 Traceback: {traceback.format_exc()}")
            
            # Upload Scene image  
            if scene_path:
                if not Path(scene_path).exists():
                    self.log(f"❌ Scene image không tồn tại: {scene_path}")
                else:
                    # ✅ Check cache THEO COOKIE
                    scene_path_abs = str(Path(scene_path).resolve())
                    if scene_path_abs in cookie_cache:
                        scene_mgid = cookie_cache[scene_path_abs]
                        self.log(f"♻️ Reusing cached Scene (cookie {cookie_hash[:8]}...): {Path(scene_path).name}")
                    else:
                        # ✅ UPLOAD VÀ CACHE THEO COOKIE
                        self.log(f"📤 Đang upload Scene (cookie {cookie_hash[:8]}...): {Path(scene_path).name}...")
                        try:
                            scene_mgid = client.upload_image(scene_path)
                            if scene_mgid:
                                cookie_cache[scene_path_abs] = scene_mgid  # ✅ Lưu vào cache của cookie này
                                self.log(f"✅ Uploaded Scene (cookie {cookie_hash[:8]}...): {Path(scene_path).name}")
                            else:
                                self.log(f"❌ Failed to upload Scene: {Path(scene_path).name} - Không có mediaGenerationId trả về")
                                self.log(f"💡 Có thể do: Cookie không có quyền upload, file ảnh không hợp lệ, hoặc lỗi network")
                        except Exception as e:
                            self.log(f"❌ Error uploading Scene: {e}")
                            import traceback
                            self.log(f"🔍 Traceback: {traceback.format_exc()}")
            
            # Upload Style image
            if style_path:
                if not Path(style_path).exists():
                    self.log(f"❌ Style image không tồn tại: {style_path}")
                else:
                    # ✅ Check cache THEO COOKIE
                    style_path_abs = str(Path(style_path).resolve())
                    if style_path_abs in cookie_cache:
                        style_mgid = cookie_cache[style_path_abs]
                        self.log(f"♻️ Reusing cached Style (cookie {cookie_hash[:8]}...): {Path(style_path).name}")
                    else:
                        # ✅ UPLOAD VÀ CACHE THEO COOKIE
                        self.log(f"📤 Đang upload Style (cookie {cookie_hash[:8]}...): {Path(style_path).name}...")
                        try:
                            style_mgid = client.upload_image(style_path)
                            if style_mgid:
                                cookie_cache[style_path_abs] = style_mgid  # ✅ Lưu vào cache của cookie này
                                self.log(f"✅ Uploaded Style (cookie {cookie_hash[:8]}...): {Path(style_path).name}")
                            else:
                                self.log(f"❌ Failed to upload Style: {Path(style_path).name} - Không có mediaGenerationId trả về")
                                self.log(f"💡 Có thể do: Cookie không có quyền upload, file ảnh không hợp lệ, hoặc lỗi network")
                        except Exception as e:
                            self.log(f"❌ Error uploading Style: {e}")
                            import traceback
                            self.log(f"🔍 Traceback: {traceback.format_exc()}")
            
            # ✅ Kiểm tra nếu có ít nhất 1 ảnh được upload thành công
            if not any([subj_mgid, scene_mgid, style_mgid]):
                self.log("⚠️ ⚠️ ⚠️ WARNING: Không có ảnh tham chiếu nào được upload thành công!")
                self.log("💡 Hãy kiểm tra:")
                self.log("   1. Đã chọn ảnh Subject/Scene/Style chưa?")
                self.log("   2. File ảnh có tồn tại không?")
                self.log("   3. Cookie có quyền upload không?")
                self.log("   4. Kết nối mạng ổn định không?")
                self.log("   5. File ảnh có định dạng hợp lệ không? (jpg, png, webp, ...)")
            else:
                self.log(f"✅ Tổng kết upload: {sum([bool(subj_mgid), bool(scene_mgid), bool(style_mgid)])} ảnh thành công")
            
            return subj_mgid, scene_mgid, style_mgid
            
        except Exception as e:
            self.log(f"❌ Error uploading reference images: {e}")
            return None, None, None
    
    def _get_image_prompt_meta(self, prompt_index):
        """Helper: trả về (source_file, local_index) cho prompt ảnh"""
        source_file = None
        local_index = None
        if hasattr(self, 'image_prompt_file_mapping'):
            source_file = self.image_prompt_file_mapping.get(prompt_index)
        if hasattr(self, 'image_prompt_local_mapping'):
            local_index = self.image_prompt_local_mapping.get(prompt_index)
        return source_file, local_index

    def _format_image_prompt_full_text(self, prompt_index, prompt_text):
        """Xây dựng chuỗi hiển thị đầy đủ với nhãn file và STT"""
        source_file, local_index = self._get_image_prompt_meta(prompt_index)
        prefix = ""
        if source_file:
            prefix = f"[{source_file}"
            if local_index is not None:
                prefix += f" #{local_index:03d}"
            prefix += "] "
        return f"{prefix}{prompt_text}"

    def _format_image_prompt_table_text(self, prompt_index, prompt_text, max_len=50):
        """Chuỗi rút gọn cho bảng kết quả"""
        full_text = self._format_image_prompt_full_text(prompt_index, prompt_text)
        return full_text if len(full_text) <= max_len else full_text[:max_len] + "..."

    def _create_prompt_table_item(self, display_text, full_text, global_index=None):
        """Utility: create prompt table item that preserves full prompt in data roles."""
        item = QTableWidgetItem(display_text)
        if global_index is not None:
            item.setData(Qt.UserRole, global_index)
        item.setData(Qt.UserRole + 1, full_text)
        return item

    def _get_full_prompt_from_item(self, prompt_item):
        """Utility: extract full prompt text from table item (fallback to displayed text)."""
        if not prompt_item:
            return ""
        full_text = prompt_item.data(Qt.UserRole + 1)
        if full_text:
            return full_text
        text = prompt_item.text() or ""
        if ': ' in text:
            prefix, remainder = text.split(': ', 1)
            if prefix.strip().isdigit():
                return remainder.strip()
        elif ':' in text:
            prefix, remainder = text.split(':', 1)
            if prefix.strip().isdigit():
                return remainder.strip()
        return text.strip()

