    def on_image_start(self):
        """Start image generation with proper multi-threading and queue management"""
        if self.image_processing:
            QMessageBox.warning(self, "Cảnh báo", "Đang xử lý ảnh, vui lòng chờ!")
            return

        # ✅ BUG FIX: Clear stop_event khi bắt đầu lại (nếu đã dừng trước đó)
        self.stop_event.clear()
        self.log("🔄 Đã reset stop_event - sẵn sàng tạo ảnh mới")

        # Validate cookie (Ultra user auto-load if empty)
        available_cookies = []
        if self.cookies_list:
            available_cookies = self.cookies_list
        elif self.cookie_value:
            available_cookies = [self.cookie_value]

        if not available_cookies:
            if self.is_ultra_user:
                # Ultra user - thử load từ server
                if self.load_cookies_from_server():
                    available_cookies = self.cookies_list if self.cookies_list else [self.cookie_value]
                    self.log("✅ Auto-loaded cookies from server for Ultra user")
                else:
                    QMessageBox.warning(self, "Cảnh báo Ultra", "Không tìm thấy cookies trên server!\nVui lòng liên hệ admin.")
                    return
            else:
                QMessageBox.warning(self, "Cảnh báo", "Vui lòng cài đặt Cookie trước!")
                return

        # ✅ Multiple-to-Image: Validate folders
        if self.current_image_mode == "Multiple-to-Image":
            subject_folder = self.txt_subject_folder.text().strip()
            scene_folder = self.txt_scene_folder.text().strip()
            style_folder = self.txt_style_folder.text().strip()
            
            if not any([subject_folder, scene_folder, style_folder]):
                QMessageBox.warning(self, "Cảnh báo", "Vui lòng chọn ít nhất 1 folder chứa ảnh (Subject/Scene/Style) cho Multiple-to-Image!")
                return
            
            # Check if folders exist and have images
            image_exts = ['*.jpg', '*.jpeg', '*.png', '*.bmp', '*.gif', '*.webp']
            total_images = 0
            for folder_path in [subject_folder, scene_folder, style_folder]:
                if folder_path and Path(folder_path).exists():
                    for ext in image_exts:
                        total_images += len(list(Path(folder_path).glob(ext)))
            
            if total_images == 0:
                QMessageBox.warning(self, "Cảnh báo", "Không tìm thấy ảnh nào trong các folder đã chọn!")
                return
        
        # Collect prompts (returns list of tuples: [(prompt, source_file_name, local_index), ...])
        prompt_tuples = self.collect_image_prompts()
        if not prompt_tuples:
            if self.current_image_mode == "Image-to-Image":
                QMessageBox.warning(self, "Cảnh báo", "Vui lòng chọn file prompt cho Image-to-Image!")
            elif self.current_image_mode == "Multiple-to-Image":
                QMessageBox.warning(self, "Cảnh báo", "Vui lòng chọn file prompt cho Multiple-to-Image!")
            else:
                QMessageBox.warning(self, "Cảnh báo", "Vui lòng chọn file prompt (.txt) cho Text-to-Image!")
            return
        
        # ✅ GIỮ LẠI KẾT QUẢ CŨ - Không xóa widgets và table rows
        # Chỉ thêm prompts mới vào table
        
        # ✅ FIX: Mỗi lần chạy mới, prompt_index bắt đầu từ 1 để đảm bảo thứ tự đúng với file txt
        # Tìm index bắt đầu cho prompts mới (luôn bắt đầu từ 1 cho mỗi batch mới)
        start_index = 1
        
        # Extract prompts and build mapping
        prompts = []
        for idx, (prompt, source_name, local_index) in enumerate(prompt_tuples, start_index):
            prompts.append(prompt)
            # ✅ Overwrite mapping nếu đã có (để đảm bảo thứ tự đúng)
            self.image_prompt_file_mapping[idx] = source_name
            self.image_prompt_local_mapping[idx] = local_index

        # Validate output directory
        output_dir = self.txt_image_output.text().strip()
        if not output_dir:
            QMessageBox.warning(self, "Cảnh báo", "Vui lòng chọn thư mục lưu ảnh!")
            return

        # Simple validation (giống gui_app.py)
        self.log(f"🚀 Bắt đầu tạo {len(prompts)} ảnh ({self.current_image_mode})...")
        
        # ✅ Disable nút "Retry All Lỗi" khi bắt đầu xử lý
        self.btn_image_retry_all.setEnabled(False)

        # ✅ Số công việc đồng thời = số cookie × 1 (QUY TẮC MỚI)
        num_cookies = len(available_cookies)
        actual_concurrent = num_cookies * 1  # Max concurrent = số cookie × 1
        
        self.log(f"⚙️ Whisk: Nối đuôi với {actual_concurrent} công việc đồng thời ({num_cookies} cookie(s) × 1)")
        self.log(f"🔑 Sử dụng {num_cookies} cookie(s)")
        
        # ✅ KHÔNG LOAD TẤT CẢ CARDS NGAY - Chỉ load khi xử lý để tránh crash
        # Lý do: Nếu có 1000+ prompts → tạo 1000+ cards ngay → RAM overflow → crash
        # Giải pháp: Load cards động trong worker thread khi đang xử lý prompt đó
        
        self.log(f"📋 Sẽ load cards động khi xử lý (tránh crash với {len(prompts)} prompts)")
        self.log(f"💡 Cards sẽ xuất hiện từ từ theo tiến độ xử lý")

        # Disable buttons
        self.btn_image_start.setEnabled(False)
        self.btn_image_stop.setEnabled(True)
        self.image_processing = True
        self._image_stopped_by_user = False  # ✅ Reset flag khi bắt đầu mới

        # ✅ Tăng số threads đang chạy (chỉ đếm concurrent threads, không phải số prompts)
        with self.active_image_tasks_lock:
            self.active_image_tasks += actual_concurrent
            self.log(f"📊 Starting {actual_concurrent} concurrent threads (Total prompts: {len(prompts)}, Active threads: {self.active_image_tasks})")

        # Start processing with proper queue management
        self.log(f"🚀 Starting worker với {actual_concurrent} threads...")
        # Pass start_index để worker dùng đúng index
        threading.Thread(
            target=self.run_image_generation_worker_v2_with_decrement_batch,
            args=(prompts, Path(output_dir), actual_concurrent, available_cookies, start_index),
            daemon=True
        ).start()
    
    def run_image_generation_worker_v2_with_decrement_batch(self, prompts, output_dir, concurrent, available_cookies, start_index=1):
        """Wrapper cho batch processing - Tự động giảm active_image_tasks và process queue khi xong"""
        try:
            # Chạy worker
            self.run_image_generation_worker_v2(prompts, output_dir, concurrent, available_cookies, start_index)
        finally:
            # ✅ Giảm số threads đang chạy (chỉ giảm số concurrent threads, không phải số prompts)
            with self.active_image_tasks_lock:
                if self.active_image_tasks >= concurrent:
                    self.active_image_tasks -= concurrent
                else:
                    self.active_image_tasks = 0
                self.log(f"📊 Batch completed. Active threads: {self.active_image_tasks}")
            
            # ✅ Tự động process retry queue nếu có slot trống
            self.process_image_retry_queue()
    
    def on_image_stop(self):
        """Stop image generation"""
        self.stop_event.set()
        self.log("🛑 Đang dừng tạo ảnh...")
        
        # ✅ BUG FIX: Reset image_processing flag và enable/disable buttons đúng cách
        self.image_processing = False
        self._image_stopped_by_user = True  # ✅ Đánh dấu đã dừng bởi user
        self.btn_image_start.setEnabled(True)
        self.btn_image_stop.setEnabled(False)
        
        # ✅ Reset active tasks counter
        with self.active_image_tasks_lock:
            self.active_image_tasks = 0
            self.log(f"📊 Reset active tasks counter (stopped by user)")
    
    def on_image_clear_results(self):
        """Clear tất cả kết quả ảnh từ table và grid"""
        try:
            reply = QMessageBox.question(
                self,
                "Xác nhận",
                "Bạn có chắc muốn xóa tất cả kết quả ảnh?",
                QMessageBox.Yes | QMessageBox.No,
                QMessageBox.No
            )
            
            if reply == QMessageBox.Yes:
                # Clear image results table
                self.image_results_table.setRowCount(0)
                
                # Clear image grid - xóa tất cả widgets
                for i in reversed(range(self.image_grid_layout.count())):
                    widget = self.image_grid_layout.itemAt(i).widget()
                    if widget:
                        widget.setParent(None)
                        widget.deleteLater()
                
                # Clear image widgets dict
                self.image_widgets.clear()
                
                # ✅ Clear batch file status
                if hasattr(self, 'image_batch_file_status'):
                    self.image_batch_file_status.clear()
                
                # ✅ Clear prompt-file mapping
                if hasattr(self, 'image_prompt_file_mapping'):
                    self.image_prompt_file_mapping.clear()
                if hasattr(self, 'image_prompt_local_mapping'):
                    self.image_prompt_local_mapping.clear()
                
                # ✅ Reset pagination
                self.current_image_page = 1
                self.total_image_pages = 1
                self.current_batch_filter = None
                self.lbl_image_filter.setText("Hiển thị: Tất cả")
                self.lbl_image_page_info.setText("Trang 1/1")
                
                # ✅ Clear batch tables
                self.t2i_batch_table.setRowCount(0)
                self.i2i_batch_table.setRowCount(0)
                
                self.log("🗑️ Đã xóa tất cả kết quả ảnh, batch status, và reset pagination")
                
        except Exception as e:
            self.log(f"❌ Lỗi clear results: {e}")
    
    def on_image_retry_all_errors(self):
        """Retry tất cả ảnh bị lỗi - Hiển thị dialog danh sách để sửa và chọn"""
        try:
            # ✅ Tìm tất cả các ảnh bị lỗi với thông tin đầy đủ
            # CHỈ lấy các status thực sự lỗi, không lấy "Hoàn thành", "Đang tạo", "Chờ xử lý"
            error_tasks = []
            error_keywords = ["Lỗi", "Thất bại", "❌", "Failed", "Fail", "Error"]
            exclude_keywords = ["Hoàn thành", "Completed", "✅", "Đang tạo", "Đang xử lý", "Chờ xử lý", "Processing"]
            
            for row in range(self.image_results_table.rowCount()):
                status_item = self.image_results_table.item(row, 1)
                if status_item:
                    status = status_item.text().strip()
                    
                    # ✅ Kiểm tra kỹ: chỉ lấy status thực sự lỗi
                    is_error = any(keyword in status for keyword in error_keywords)
                    is_not_processing = not any(keyword in status for keyword in exclude_keywords)
                    
                    if is_error and is_not_processing:
                        index = row + 1  # index bắt đầu từ 1
                        
                        # Lấy prompt từ table
                        prompt_item = self.image_results_table.item(row, 0)
                        prompt = ""
                        if prompt_item:
                            # Lấy full prompt từ UserRole hoặc text
                            prompt = prompt_item.data(Qt.UserRole) or prompt_item.text()
                        
                        # ✅ Lấy metadata (source_file, local_index) để preserve khi retry
                        source_file, local_index = self._get_image_prompt_meta(index)
                        
                        if not source_file:
                            source_file = "default"
                        
                        error_tasks.append({
                            'index': index,
                            'row': row,
                            'prompt': prompt,
                            'status': status,
                            'source_file': source_file,
                            'local_index': local_index
                        })
            
            if not error_tasks:
                QMessageBox.information(
                    self,
                    "Thông báo",
                    "Không có ảnh nào bị lỗi để retry!"
                )
                return
            
            # Hiển thị dialog để sửa và chọn prompts
            self.show_image_retry_dialog(error_tasks)
                
        except Exception as e:
            self.log(f"❌ Lỗi retry all errors: {e}")
            QMessageBox.critical(self, "Lỗi", f"Lỗi khi retry all errors: {e}")
    
    def show_image_retry_dialog(self, error_tasks):
        """Hiển thị dialog để sửa và retry các prompts bị lỗi"""
        try:
            dialog = QDialog(self)
            dialog.setWindowTitle(f"🔄 Retry {len(error_tasks)} Prompt Lỗi (Whisk)")
            dialog.setMinimumSize(1100, 750)
            
            layout = QVBoxLayout(dialog)
            layout.setSpacing(18)
            layout.setContentsMargins(20, 20, 20, 20)
            
            title = QLabel(f"📝 Sửa {len(error_tasks)} Prompt Lỗi")
            title.setStyleSheet("font-size: 20px; font-weight: 700; color: #1f2937;")
            layout.addWidget(title)
            
            info = QLabel("Chỉnh sửa prompt → Nhấn 'Lưu & Chạy Lại' để chỉ retry các prompt đã sửa. File TXT gốc KHÔNG bị thay đổi.")
            info.setWordWrap(True)
            info.setStyleSheet("color: #6b7280; font-size: 13px;")
            layout.addWidget(info)
            
            scroll_area = QScrollArea()
            scroll_area.setWidgetResizable(True)
            scroll_area.setStyleSheet("QScrollArea { border: 1px solid #e5e7eb; border-radius: 10px; }")
            scroll_widget = QWidget()
            scroll_layout = QVBoxLayout(scroll_widget)
            scroll_layout.setSpacing(12)
            
            prompt_editors = []
            for task in error_tasks:
                source_file = task.get('source_file') or "default"
                display_file = f"{source_file}.txt" if source_file and not str(source_file).endswith(".txt") else source_file
                local_index = task.get('local_index') or "?"
                
                card = QFrame()
                card.setStyleSheet("""
                    QFrame {
                        border: 1px solid #dbeafe;
                        border-radius: 10px;
                        background-color: #f8fbff;
                    }
                """)
                card_layout = QVBoxLayout(card)
                card_layout.setSpacing(8)
                
                meta_label = QLabel(f"📄 {display_file} • Dòng {local_index}")
                meta_label.setStyleSheet("font-weight: 600; color: #1d4ed8;")
                card_layout.addWidget(meta_label)
                
                prompt_edit = QTextEdit()
                prompt_edit.setPlainText(task.get('prompt', ''))
                prompt_edit.setMinimumHeight(120)
                prompt_edit.setStyleSheet("""
                    QTextEdit {
                        border: 1px solid #cbd5f5;
                        border-radius: 6px;
                        padding: 10px;
                        font-size: 13px;
                        background: #ffffff;
                    }
                    QTextEdit:focus {
                        border: 1px solid #4c8bf5;
                    }
                """)
                card_layout.addWidget(prompt_edit)
                
                # ✅ Lưu đầy đủ metadata để preserve khi retry
                prompt_editors.append({
                    'index': task['index'],
                    'row': task['row'],
                    'editor': prompt_edit,
                    'source_file': source_file,  # Preserve để lưu đúng folder
                    'local_index': local_index    # Preserve để lưu đúng tên file
                })
                
                scroll_layout.addWidget(card)
            
            scroll_layout.addStretch()
            scroll_area.setWidget(scroll_widget)
            layout.addWidget(scroll_area)
            
            btn_layout = QHBoxLayout()
            btn_layout.addStretch()
            
            btn_save = QPushButton("💾 Lưu & Chạy Lại")
            btn_save.setObjectName("startButton")
            btn_save.setStyleSheet("QPushButton { padding: 12px 26px; font-size: 14px; font-weight: 600; }")
            # ✅ Fix closure bug: dùng default argument để capture đúng giá trị
            btn_save.clicked.connect(
                lambda checked=False, d=dialog, pe=prompt_editors: 
                self.save_and_retry_image_failed(d, pe)
            )
            btn_layout.addWidget(btn_save)
            
            btn_cancel = QPushButton("❌ Hủy")
            btn_cancel.setStyleSheet("QPushButton { padding: 12px 26px; font-size: 14px; }")
            btn_cancel.clicked.connect(dialog.reject)
            btn_layout.addWidget(btn_cancel)
            
            layout.addLayout(btn_layout)
            
            dialog.exec()
            
        except Exception as e:
            self.log(f"❌ Lỗi show image retry dialog: {e}")
            import traceback
            self.log(f"🔍 Traceback: {traceback.format_exc()}")
            QMessageBox.critical(self, "Lỗi", f"Lỗi khi hiển thị dialog: {e}")

    def save_and_retry_image_failed(self, dialog, prompt_editors):
        """Lưu prompts đã sửa và retry từng prompt (không ảnh hưởng file gốc)"""
        try:
            updated_tasks = []
            for editor_info in prompt_editors:
                index = editor_info['index']
                row = editor_info['row']
                editor = editor_info['editor']
                new_prompt = editor.toPlainText().strip()
                
                if not new_prompt:
                    continue
                
                # ✅ Lấy metadata từ editor_info để preserve khi retry
                source_file = editor_info.get('source_file') or "default"
                local_index = editor_info.get('local_index')
                
                # ✅ Update mapping để đảm bảo lưu đúng folder và tên file
                if source_file and source_file != "default":
                    self.image_prompt_file_mapping[index] = source_file
                if local_index is not None:
                    self.image_prompt_local_mapping[index] = local_index
                
                # Update table display với label đầy đủ
                prompt_item = self.image_results_table.item(row, 0)
                if prompt_item:
                    table_text = self._format_image_prompt_table_text(index, new_prompt)
                    prompt_item.setText(table_text)
                    prompt_item.setData(Qt.UserRole, new_prompt)
                
                updated_tasks.append({
                    'index': index,
                    'row': row,
                    'prompt': new_prompt,
                    'source_file': source_file,
                    'local_index': local_index
                })
            
            if not updated_tasks:
                QMessageBox.warning(dialog, "Cảnh báo", "Không có prompt hợp lệ để cập nhật!")
                return
            
            dialog.accept()
            
            # ✅ Hiển thị dialog cookie chính (giống nút cài đặt cookie) trước khi retry - KHÔNG CLEAR
            self.show_cookie_dialog()
            
            # ✅ Kiểm tra cookies sau khi đóng dialog
            if not (self.cookie_value or self.cookies_list):
                self.log("⚠️ Người dùng không nhập cookie, dừng retry")
                QMessageBox.warning(self, "Cảnh báo", "Vui lòng nhập cookie trước khi retry!")
                return
            
            self.log(f"🔄 Bắt đầu retry {len(updated_tasks)} prompts đã sửa...")
            
            # ✅ BỎ DELAY - Không còn delay giữa các request (nối đuôi liên tục)
            # delay_seconds = self.spin_image_delay.value()  # Comment lại vì không dùng nữa
            
            # ✅ Chạy retry trong background thread để không block UI
            def retry_worker():
                # import time  # Comment lại vì không dùng delay nữa
                for idx, task_info in enumerate(updated_tasks, 1):
                    try:
                        # ✅ BỎ DELAY - Không còn delay giữa các retry requests (nối đuôi liên tục)
                        # if idx > 1:  # Comment lại vì không dùng delay nữa
                        #     self.log(f"⏱️ Đợi {delay_seconds}s trước khi retry prompt tiếp theo...")
                        #     time.sleep(delay_seconds)
                        
                        self.execute_retry_with_new_prompt(
                            task_info['index'], 
                            task_info['prompt'], 
                            task_info['row'],
                            source_file=task_info.get('source_file'),
                            local_index=task_info.get('local_index')
                        )
                    except Exception as e:
                        self.log(f"❌ Lỗi khi retry prompt #{task_info['index']}: {e}")
            
            # Start retry trong background thread
            import threading
            threading.Thread(target=retry_worker, daemon=True).start()
            
        except Exception as e:
            self.log(f"❌ Lỗi save_and_retry_image_failed: {e}")
            import traceback
            self.log(traceback.format_exc())
            QMessageBox.critical(self, "Lỗi", f"Không thể retry prompts đã sửa:\n{e}")
    
    def on_image_open_folder(self):
        """Mở folder lưu ảnh"""
        try:
            output_folder = self.txt_image_output.text().strip()
            
            if not output_folder:
                QMessageBox.warning(
                    self,
                    "⚠️ Cảnh Báo",
                    "Chưa chọn thư mục lưu ảnh!"
                )
                return
            
            folder_path = Path(output_folder)
            
            if not folder_path.exists():
                QMessageBox.warning(
                    self,
                    "⚠️ Cảnh Báo",
                    f"Thư mục không tồn tại:\n{folder_path}\n\nVui lòng chọn thư mục hợp lệ."
                )
                return
            
            # Mở folder (cross-platform)
            import platform
            import subprocess
            
            system = platform.system()
            if system == "Windows":
                import os
                os.startfile(str(folder_path))
            elif system == "Darwin":  # macOS
                subprocess.run(['open', str(folder_path)])
            else:  # Linux
                subprocess.run(['xdg-open', str(folder_path)])
            
            self.log(f"📁 Đã mở folder: {output_folder}")
            
        except Exception as e:
            self.log(f"❌ Lỗi mở folder: {e}")
            QMessageBox.critical(
                self,
                "❌ Lỗi",
                f"Không thể mở folder:\n{e}"
            )
    
    def collect_image_prompts(self):
        """Collect prompts cho Whisk Image tab - giữ nguyên thứ tự trong từng file
        
        Hỗ trợ 2 nguồn:
        1. Single file .txt (1 prompt/dòng)
        2. Folder chứa nhiều file .txt (mỗi file = 1 prompt hoặc nhiều prompts)
        
        Returns:
            List of tuples: [(prompt_text, source_file_name, local_index), ...]
        """
        prompts = []  # Format: [(prompt, source_file_name, local_index), ...]
        
        # ✅ Store prompt-to-file mapping for organizing output
        self.image_prompt_file_mapping = {}  # {prompt_index: source_file_name}
        self.image_prompt_local_mapping = {}  # {prompt_index: local_index_in_file}

        if self.current_image_mode == "Text-to-Image":
            # Text-to-Image mode - CHỈ chấp nhận file hoặc folder, không nhập prompt text
            
            # ✅ Ưu tiên folder nếu đã chọn
            folder_path = self.txt_t2i_prompt_folder.text().strip()
            if folder_path and Path(folder_path).exists():
                try:
                    txt_files = sorted(Path(folder_path).glob("*.txt"))
                    self.log(f"📁 T2I Folder: Tìm thấy {len(txt_files)} file .txt")
                    
                    for txt_file in txt_files:
                        try:
                            with open(txt_file, 'r', encoding='utf-8') as f:
                                lines = [line.strip() for line in f if line.strip()]
                            
                            # Track source file for each prompt
                            source_name = txt_file.stem  # filename without extension
                            for local_idx, line in enumerate(lines, 1):
                                prompts.append((line, source_name, local_idx))
                            
                            self.log(f"  📄 {txt_file.name}: {len(lines)} prompts")
                        except Exception as e:
                            self.log(f"  ❌ Lỗi đọc {txt_file.name}: {e}")
                    
                    self.log(f"✅ T2I: Tổng cộng {len(prompts)} prompts từ {len(txt_files)} file")
                except Exception as e:
                    self.log(f"❌ Lỗi đọc folder T2I: {e}")
                    return []
            
            # Nếu không có folder, dùng single file
            else:
                prompt_file = self.txt_whisk_prompt_file.text().strip()
                if prompt_file and Path(prompt_file).exists():
                    try:
                        source_name = Path(prompt_file).stem
                        with open(prompt_file, 'r', encoding='utf-8') as f:
                            lines = [line.strip() for line in f if line.strip()]
                        
                        for local_idx, line in enumerate(lines, 1):
                            prompts.append((line, source_name, local_idx))
                        
                        self.log(f"📄 T2I: Đọc {len(lines)} prompts từ file")
                    except Exception as e:
                        self.log(f"❌ Lỗi đọc file T2I: {e}")
                else:
                    self.log(f"⚠️ T2I: Vui lòng chọn file hoặc folder chứa prompts (.txt)!")
                    return []  # Return empty để báo lỗi

        elif self.current_image_mode == "Image-to-Image":
            # ✅ Ưu tiên folder nếu đã chọn
            folder_path = self.txt_i2i_prompt_folder.text().strip()
            if folder_path and Path(folder_path).exists():
                try:
                    txt_files = sorted(Path(folder_path).glob("*.txt"))
                    self.log(f"📁 I2I Folder: Tìm thấy {len(txt_files)} file .txt")
                    
                    for txt_file in txt_files:
                        try:
                            with open(txt_file, 'r', encoding='utf-8') as f:
                                lines = [line.strip() for line in f if line.strip()]
                            
                            # Track source file for each prompt
                            source_name = txt_file.stem
                            for local_idx, line in enumerate(lines, 1):
                                prompts.append((line, source_name, local_idx))
                            
                            self.log(f"  📄 {txt_file.name}: {len(lines)} prompts")
                        except Exception as e:
                            self.log(f"  ❌ Lỗi đọc {txt_file.name}: {e}")
                    
                    self.log(f"✅ I2I: Tổng cộng {len(prompts)} prompts từ {len(txt_files)} file")
                except Exception as e:
                    self.log(f"❌ Lỗi đọc folder I2I: {e}")
                    return []
            
            # Nếu không có folder, dùng single file
            else:
                prompt_file = self.txt_i2i_prompt_file.text().strip()
                if prompt_file and Path(prompt_file).exists():
                    try:
                        source_name = Path(prompt_file).stem
                        with open(prompt_file, 'r', encoding='utf-8') as f:
                            lines = [line.strip() for line in f if line.strip()]
                        
                        for local_idx, line in enumerate(lines, 1):
                            prompts.append((line, source_name, local_idx))
                        
                        self.log(f"📄 I2I: Đọc {len(lines)} prompts từ file")
                    except Exception as e:
                        self.log(f"❌ Lỗi đọc file I2I: {e}")
                else:
                    self.log(f"⚠️ I2I: Vui lòng chọn file hoặc folder chứa prompts!")
                    return []  # Return empty để báo lỗi

        elif self.current_image_mode == "Multiple-to-Image":
            # ✅ Ưu tiên folder nếu đã chọn
            folder_path = self.txt_m2i_prompt_folder.text().strip()
            if folder_path and Path(folder_path).exists():
                try:
                    txt_files = sorted(Path(folder_path).glob("*.txt"), key=lambda p: _alphanum_key(p.stem))
                    self.log(f"📁 M2I Folder: Tìm thấy {len(txt_files)} file .txt")
                    
                    for txt_file in txt_files:
                        try:
                            with open(txt_file, 'r', encoding='utf-8') as f:
                                lines = [line.strip() for line in f if line.strip()]
                            
                            # Track source file for each prompt
                            source_name = txt_file.stem
                            for local_idx, line in enumerate(lines, 1):
                                prompts.append((line, source_name, local_idx))
                            
                            self.log(f"  📄 {txt_file.name}: {len(lines)} prompts")
                        except Exception as e:
                            self.log(f"  ❌ Lỗi đọc {txt_file.name}: {e}")
                    
                    self.log(f"✅ M2I: Tổng cộng {len(prompts)} prompts từ {len(txt_files)} file")
                except Exception as e:
                    self.log(f"❌ Lỗi đọc folder M2I: {e}")
                    return []
            
            # Nếu không có folder, dùng single file
            else:
                prompt_file = self.txt_m2i_prompt_file.text().strip()
                if prompt_file and Path(prompt_file).exists():
                    try:
                        source_name = Path(prompt_file).stem
                        with open(prompt_file, 'r', encoding='utf-8') as f:
                            lines = [line.strip() for line in f if line.strip()]
                        
                        for local_idx, line in enumerate(lines, 1):
                            prompts.append((line, source_name, local_idx))
                        
                        self.log(f"📄 M2I: Đọc {len(lines)} prompts từ file")
                    except Exception as e:
                        self.log(f"❌ Lỗi đọc file M2I: {e}")
                else:
                    self.log(f"⚠️ M2I: Vui lòng chọn file hoặc folder chứa prompts!")
                    return []  # Return empty để báo lỗi

        return prompts  # KHÔNG giới hạn, xử lý tất cả prompts
    
    def run_image_generation_worker_v2(self, prompts, output_dir, concurrent, available_cookies, start_index=1):
        """Enhanced worker thread for image generation - LOGIC GIỐNG gui_app.py"""
        try:
            self.log(f"🔄 Starting image generation: {len(prompts)} prompts, {concurrent} threads, start_index={start_index}")
            self._reset_delay_state("Whisk")

            # Get first client for setup and reference images upload
            if not available_cookies:
                self.log("❌ Không có cookies")
                return

            cookies = _parse_cookie_string(available_cookies[0])
            main_client = LabsFlowClient(cookies)

            # Get access token
            if not main_client.fetch_access_token():
                self.log("❌ Không lấy được access token")
                return

            # Create workflow
            workflow_id = main_client.create_whisk_workflow()
            if not workflow_id:
                # Log chi tiết lỗi từ client (thường là do token / cookies / recaptcha)
                error_detail = getattr(main_client, "last_error_detail", None) or getattr(main_client, "last_error", None) or "Không rõ nguyên nhân (không có chi tiết từ server)"
                self.log(f"❌ Không tạo được workflow: {error_detail}")
                return
            
            self.log(f"✅ Workflow ID: {workflow_id[:20]}...")

            # ✅ BẮT BUỘC upload reference images TRƯỚC khi gen (nếu là Image-to-Image mode)
            # Lấy từ cache nếu đã upload trước đó (từ browse_subject_image, etc.)
            subj_mgid = scene_mgid = style_mgid = None
            use_recipe = False
            
            # ✅ DEBUG: Log current mode
            self.log(f"🔍 Current image mode: {self.current_image_mode}")
            
            # ✅ Multiple-to-Image: Load và map images từ 3 folders
            if self.current_image_mode == "Multiple-to-Image":
                self.log("📤 Multiple-to-Image mode detected - Loading images from folders...")
                self.m2i_image_mapping = {}  # Clear previous mapping
                
                # Load images từ 3 folders
                subject_folder = self.txt_subject_folder.text().strip()
                scene_folder = self.txt_scene_folder.text().strip()
                style_folder = self.txt_style_folder.text().strip()
                
                # Load và sort images từ mỗi folder
                subject_images = []
                scene_images = []
                style_images = []
                
                image_exts = ['*.jpg', '*.jpeg', '*.png', '*.bmp', '*.gif', '*.webp']
                
                if subject_folder and Path(subject_folder).exists():
                    for ext in image_exts:
                        subject_images.extend(Path(subject_folder).glob(ext))
                    subject_images = natural_sort_paths(subject_images)
                    self.log(f"📁 Subject folder: {len(subject_images)} ảnh")
                
                if scene_folder and Path(scene_folder).exists():
                    for ext in image_exts:
                        scene_images.extend(Path(scene_folder).glob(ext))
                    scene_images = natural_sort_paths(scene_images)
                    self.log(f"📁 Scene folder: {len(scene_images)} ảnh")
                
                if style_folder and Path(style_folder).exists():
                    for ext in image_exts:
                        style_images.extend(Path(style_folder).glob(ext))
                    style_images = natural_sort_paths(style_images)
                    self.log(f"📁 Style folder: {len(style_images)} ảnh")
                
                # Map images theo prompt index (1-based)
                max_images = max(len(subject_images), len(scene_images), len(style_images))
                if max_images == 0:
                    self.log("⚠️ ⚠️ ⚠️ WARNING: Không có ảnh nào trong các folder!")
                    self.log("💡 Hãy chọn ít nhất 1 folder chứa ảnh Subject/Scene/Style")
                    return
                
                # Map images cho từng prompt (index bắt đầu từ 1)
                for prompt_idx in range(1, len(prompts) + 1):
                    image_idx = prompt_idx - 1  # 0-based index
                    mapping = {}
                    
                    if image_idx < len(subject_images):
                        mapping['subject_path'] = str(subject_images[image_idx].resolve())
                    if image_idx < len(scene_images):
                        mapping['scene_path'] = str(scene_images[image_idx].resolve())
                    if image_idx < len(style_images):
                        mapping['style_path'] = str(style_images[image_idx].resolve())
                    
                    # Chỉ thêm mapping nếu có ít nhất 1 ảnh
                    if mapping:
                        self.m2i_image_mapping[prompt_idx] = mapping
                        self.log(f"📋 Mapped prompt {prompt_idx}: Subject={bool(mapping.get('subject_path'))}, Scene={bool(mapping.get('scene_path'))}, Style={bool(mapping.get('style_path'))}")
                
                self.log(f"✅ Đã map {len(self.m2i_image_mapping)} prompts với images")
                
                # Upload tất cả images và cache media IDs
                self.log("📤 Đang upload tất cả images từ folders...")
                for prompt_idx, mapping in self.m2i_image_mapping.items():
                    # Upload Subject
                    if 'subject_path' in mapping:
                        subject_path = mapping['subject_path']
                        subject_path_abs = str(Path(subject_path).resolve())
                        # ✅ Kiểm tra cache trước
                        if subject_path_abs in self.reference_image_media_ids:
                            mapping['subject_mgid'] = self.reference_image_media_ids[subject_path_abs]
                            self.log(f"♻️ Subject {prompt_idx} từ cache: {Path(subject_path).name} → {mapping['subject_mgid'][:30]}...")
                        else:
                            # Chưa có trong cache, upload
                            self.log(f"📤 Uploading Subject {prompt_idx}: {Path(subject_path).name}...")
                            mgid = main_client.upload_image(subject_path)
                            if mgid:
                                self.reference_image_media_ids[subject_path_abs] = mgid
                                mapping['subject_mgid'] = mgid
                                self.log(f"✅ Subject {prompt_idx} uploaded")
                            else:
                                self.log(f"❌ Failed to upload Subject {prompt_idx}: {Path(subject_path).name}")
                                # ✅ Retry 1 lần nữa
                                self.log(f"🔄 Retrying upload Subject {prompt_idx}...")
                                mgid = main_client.upload_image(subject_path)
                                if mgid:
                                    self.reference_image_media_ids[subject_path_abs] = mgid
                                    mapping['subject_mgid'] = mgid
                                    self.log(f"✅ Subject {prompt_idx} uploaded (retry)")
                                else:
                                    self.log(f"❌ Failed to upload Subject {prompt_idx} after retry")
                    
                    # Upload Scene
                    if 'scene_path' in mapping:
                        scene_path = mapping['scene_path']
                        scene_path_abs = str(Path(scene_path).resolve())
                        # ✅ Kiểm tra cache trước
                        if scene_path_abs in self.reference_image_media_ids:
                            mapping['scene_mgid'] = self.reference_image_media_ids[scene_path_abs]
                            self.log(f"♻️ Scene {prompt_idx} từ cache: {Path(scene_path).name}")
                        else:
                            # Chưa có trong cache, upload
                            self.log(f"📤 Uploading Scene {prompt_idx}: {Path(scene_path).name}...")
                            mgid = main_client.upload_image(scene_path)
                            if mgid:
                                self.reference_image_media_ids[scene_path_abs] = mgid
                                mapping['scene_mgid'] = mgid
                                self.log(f"✅ Scene {prompt_idx} uploaded")
                            else:
                                self.log(f"❌ Failed to upload Scene {prompt_idx}: {Path(scene_path).name}")
                                # ✅ Retry 1 lần nữa
                                self.log(f"🔄 Retrying upload Scene {prompt_idx}...")
                                mgid = main_client.upload_image(scene_path)
                                if mgid:
                                    self.reference_image_media_ids[scene_path_abs] = mgid
                                    mapping['scene_mgid'] = mgid
                                    self.log(f"✅ Scene {prompt_idx} uploaded (retry)")
                                else:
                                    self.log(f"❌ Failed to upload Scene {prompt_idx} after retry")
                    
                    # Upload Style
                    if 'style_path' in mapping:
                        style_path = mapping['style_path']
                        style_path_abs = str(Path(style_path).resolve())
                        # ✅ Kiểm tra cache trước
                        if style_path_abs in self.reference_image_media_ids:
                            mapping['style_mgid'] = self.reference_image_media_ids[style_path_abs]
                            self.log(f"♻️ Style {prompt_idx} từ cache: {Path(style_path).name}")
                        else:
                            # Chưa có trong cache, upload
                            self.log(f"📤 Uploading Style {prompt_idx}: {Path(style_path).name}...")
                            mgid = main_client.upload_image(style_path)
                            if mgid:
                                self.reference_image_media_ids[style_path_abs] = mgid
                                mapping['style_mgid'] = mgid
                                self.log(f"✅ Style {prompt_idx} uploaded")
                            else:
                                self.log(f"❌ Failed to upload Style {prompt_idx}: {Path(style_path).name}")
                                # ✅ Retry 1 lần nữa
                                self.log(f"🔄 Retrying upload Style {prompt_idx}...")
                                mgid = main_client.upload_image(style_path)
                                if mgid:
                                    self.reference_image_media_ids[style_path_abs] = mgid
                                    mapping['style_mgid'] = mgid
                                    self.log(f"✅ Style {prompt_idx} uploaded (retry)")
                                else:
                                    self.log(f"❌ Failed to upload Style {prompt_idx} after retry")
                
                self.log(f"✅ Đã upload và cache images cho {len(self.m2i_image_mapping)} prompts")
            
            elif self.current_image_mode == "Image-to-Image":
                self.log("📤 Image-to-Image mode detected - Getting reference images from cache or uploading...")
                
                # ✅ Lấy từ cache trước (đã upload khi user chọn ảnh)
                subject_path = self.txt_subject_image.text().strip()
                scene_path = self.txt_scene_image.text().strip()
                style_path = self.txt_style_image.text().strip()
                
                self.log(f"🔍 Checking reference images:")
                self.log(f"  Subject: {subject_path if subject_path else 'Not selected'}")
                self.log(f"  Scene: {scene_path if scene_path else 'Not selected'}")
                self.log(f"  Style: {style_path if style_path else 'Not selected'}")
                
                # ✅ Lấy cookie hash từ main_client để cache theo cookie
                cookie_hash = getattr(main_client, '_cookie_hash', None)
                if not cookie_hash:
                    # ✅ LabsFlowClient đã được import ở đầu file, không cần import lại
                    cookie_hash = LabsFlowClient._get_cookie_hash(main_client.cookies if hasattr(main_client, 'cookies') else {})
                
                # ✅ Khởi tạo cache cho cookie này nếu chưa có
                if cookie_hash not in self.reference_image_media_ids:
                    self.reference_image_media_ids[cookie_hash] = {}
                cookie_cache = self.reference_image_media_ids[cookie_hash]
                
                # Get từ cache THEO COOKIE nếu có
                if subject_path and Path(subject_path).exists():
                    subject_path_abs = str(Path(subject_path).resolve())
                    if subject_path_abs in cookie_cache:
                        subj_mgid = cookie_cache[subject_path_abs]
                        self.log(f"✅ Subject từ cache (cookie {cookie_hash[:8]}...): {Path(subject_path).name}")
                
                if scene_path and Path(scene_path).exists():
                    scene_path_abs = str(Path(scene_path).resolve())
                    if scene_path_abs in cookie_cache:
                        scene_mgid = cookie_cache[scene_path_abs]
                        self.log(f"✅ Scene từ cache (cookie {cookie_hash[:8]}...): {Path(scene_path).name}")
                
                if style_path and Path(style_path).exists():
                    style_path_abs = str(Path(style_path).resolve())
                    if style_path_abs in cookie_cache:
                        style_mgid = cookie_cache[style_path_abs]
                        self.log(f"✅ Style từ cache (cookie {cookie_hash[:8]}...): {Path(style_path).name}")
                
                # ✅ Nếu chưa có trong cache, upload ngay (fallback)
                if not any([subj_mgid, scene_mgid, style_mgid]):
                    self.log("⚠️ Không có ảnh trong cache - Uploading reference images ngay...")
                    subj_mgid, scene_mgid, style_mgid = self.upload_and_cache_reference_images(main_client)
                else:
                    # Có một số ảnh trong cache, nhưng có thể thiếu - upload những ảnh còn thiếu
                    uploaded_subj, uploaded_scene, uploaded_style = self.upload_and_cache_reference_images(main_client)
                    if not subj_mgid and uploaded_subj:
                        subj_mgid = uploaded_subj
                    if not scene_mgid and uploaded_scene:
                        scene_mgid = uploaded_scene
                    if not style_mgid and uploaded_style:
                        style_mgid = uploaded_style
                
                use_recipe = any([subj_mgid, scene_mgid, style_mgid])
                
                # ✅ DEBUG: Log kết quả
                self.log(f"📊 Final reference images: Subject={bool(subj_mgid)}, Scene={bool(scene_mgid)}, Style={bool(style_mgid)}")
                
                if use_recipe:
                    self.log("✅ Reference images ready - will use runImageRecipe (Image-to-Image) for ALL prompts")
                else:
                    self.log("⚠️ ⚠️ ⚠️ WARNING: No reference images - will use generateImage (Text-to-Image) instead!")
                    self.log("💡 Hãy chọn ảnh Subject/Scene/Style và đợi upload xong trước khi generate")
            else:
                self.log(f"📝 Text-to-Image mode - Không cần reference images")

            # Results storage
            completed_count = 0
            failed_count = 0

            # Thread-safe counters
            cookie_lock = threading.Lock()
            cookie_counter = Counter()
            completion_lock = threading.Lock()
            
            # ✅ Retry tracking cho từng prompt (tránh vòng lặp vô hạn)
            retry_tracking = {}  # {prompt_index: {"retry_count_non_429": int, "failed_cookies_429": set}}
            retry_tracking_lock = threading.Lock()

            # ✅ QUEUE ROLLING: Dùng ThreadPoolExecutor để tự động quản lý queue
            # Khi 1 task xong → tự động submit task tiếp theo (rolling queue)
            
            # Get settings
            model = self.combo_image_model.currentText()
            aspect = self.combo_image_aspect.currentText()
            num_images = self.spin_num_images.value()
            
            # ✅ Seed settings: tự động random 1 seed cho toàn bộ phiên tạo ảnh
            import random
            auto_seed_value = random.randint(0, 999_999_999)
            self.current_whisk_seed = auto_seed_value
            self.log(f"🎲 Seed tự động: {auto_seed_value} (áp dụng cho toàn bộ ảnh trong phiên này)")

            aspect_map = {
                "16:9": "IMAGE_ASPECT_RATIO_LANDSCAPE",
                "9:16": "IMAGE_ASPECT_RATIO_PORTRAIT",
                "1:1": "IMAGE_ASPECT_RATIO_SQUARE"
            }
            aspect_value = aspect_map.get(aspect, "IMAGE_ASPECT_RATIO_LANDSCAPE")
            
            def get_seed_for_image(img_idx: int, prompt_idx: int) -> int:
                """Get seed value cho ảnh hiện tại (mọi ảnh dùng cùng seed tự động)"""
                return auto_seed_value

            def process_single_prompt(prompt_data, wave_pos=1):
                """Process single prompt - được gọi bởi ThreadPoolExecutor - VỚI RETRY LOGIC"""
                nonlocal completed_count, failed_count
                
                prompt_index, prompt = prompt_data
                thread_id = threading.current_thread().ident % 10000  # Thread ID đơn giản
                
                # ✅ Lấy retry tracking cho prompt này
                with retry_tracking_lock:
                    if prompt_index not in retry_tracking:
                        retry_tracking[prompt_index] = {
                            "retry_count_non_429": 0,
                            "failed_cookies_429": set()
                        }
                    prompt_retry = retry_tracking[prompt_index]
                    retry_count_non_429 = prompt_retry["retry_count_non_429"]
                    failed_cookies_429 = prompt_retry["failed_cookies_429"]
                    max_retries = 6
                
                try:
                    # ✅ Vòng lặp retry: 429 không giới hạn (chỉ dừng khi hết cookie), lỗi khác retry tối đa 6 lần
                    while True:
                        # Get cookie for this task (round-robin, tránh cookie đã bị 429)
                        cookie_index = None
                        with cookie_lock:
                            # Tìm cookie không bị 429
                            for _ in range(len(available_cookies)):
                                temp_index = cookie_counter['count'] % len(available_cookies)
                                cookie_counter['count'] += 1
                                if temp_index not in failed_cookies_429:
                                    cookie_index = temp_index
                                    break
                            
                            # Nếu không tìm thấy, thử cookie đã bị 429
                            if cookie_index is None:
                                cookie_index = cookie_counter['count'] % len(available_cookies)
                                cookie_counter['count'] += 1
                        
                        cookie_str = available_cookies[cookie_index]

                        # Build client for this task
                        thread_cookies = _parse_cookie_string(cookie_str)  
                        thread_client = LabsFlowClient(thread_cookies)

                        # ✅ Bỏ qua cookie không fetch được token (giống tab video)
                        if not thread_client.fetch_access_token():
                            self.log(f"⚠️ Prompt {prompt_index}: Cookie {cookie_index+1} không fetch được token, thử cookie khác")
                            # Thử cookie tiếp theo (nếu có)
                            if len(available_cookies) > 1:
                                continue
                            else:
                                self.log(f"❌ Prompt {prompt_index}: Không có cookie hợp lệ")
                                with completion_lock:
                                    self.signals.update_image_status.emit(prompt_index, "Thất bại")
                                    failed_count += 1
                                return None
                        
                        # Cookie hợp lệ, break khỏi while loop để tiếp tục xử lý
                        break

                    # ✅ Card đã được tạo ở bước 1, không cần tạo lại
                    self.log(f"🖼️ Processing prompt {prompt_index} (Thread {thread_id}, Cookie {cookie_index+1})")
                    self.signals.update_image_status.emit(prompt_index, "Đang tạo")
                    # Update progress: 0/num_images
                    self.signals.update_image_progress.emit(prompt_index, 0, num_images)

                    # ✅ Multiple-to-Image: Lấy images từ mapping theo prompt_index
                    prompt_subj_mgid = prompt_scene_mgid = prompt_style_mgid = None
                    prompt_use_recipe = False
                    
                    if self.current_image_mode == "Multiple-to-Image":
                        if prompt_index in self.m2i_image_mapping:
                            mapping = self.m2i_image_mapping[prompt_index]
                            # ✅ Chỉ lấy mgid nếu có (không phải None hoặc empty string)
                            prompt_subj_mgid = mapping.get('subject_mgid') if mapping.get('subject_mgid') else None
                            prompt_scene_mgid = mapping.get('scene_mgid') if mapping.get('scene_mgid') else None
                            prompt_style_mgid = mapping.get('style_mgid') if mapping.get('style_mgid') else None
                            prompt_use_recipe = any([prompt_subj_mgid, prompt_scene_mgid, prompt_style_mgid])
                            self.log(f"🔍 Prompt {prompt_index} M2I: Subject={bool(prompt_subj_mgid)}, Scene={bool(prompt_scene_mgid)}, Style={bool(prompt_style_mgid)}")
                            if not prompt_use_recipe:
                                self.log(f"⚠️ Prompt {prompt_index}: Có mapping nhưng không có mgid hợp lệ, sẽ dùng Text-to-Image")
                        else:
                            self.log(f"⚠️ Prompt {prompt_index}: Không có mapping images (có thể do folder không đủ ảnh), sẽ dùng Text-to-Image")
                    elif self.current_image_mode == "Image-to-Image":
                        prompt_subj_mgid = subj_mgid
                        prompt_scene_mgid = scene_mgid
                        prompt_style_mgid = style_mgid
                        prompt_use_recipe = use_recipe

                    # Generate images
                    generated_files = []
                    for img_idx in range(num_images):
                        if self.stop_event.is_set():
                            break
                            
                        try:
                            # ✅ Update progress: đang tạo ảnh img_idx+1/num_images
                            self.signals.update_image_progress.emit(prompt_index, img_idx, num_images)
                            self.log(f"🖼️ Prompt {prompt_index}: Đang tạo ảnh {img_idx + 1}/{num_images}")
                            
                            # ✅ DEBUG: Log mode và recipe status
                            self.log(f"🔍 Prompt {prompt_index}: use_recipe={prompt_use_recipe}, subj={bool(prompt_subj_mgid)}, scene={bool(prompt_scene_mgid)}, style={bool(prompt_style_mgid)}")
                            
                            # ✅ QUYẾT ĐỊNH: Dùng recipe nếu có BẤT KỲ reference image nào
                            if prompt_use_recipe and any([prompt_subj_mgid, prompt_scene_mgid, prompt_style_mgid]):
                                # Image-to-Image hoặc Multiple-to-Image with cached references - ✅ Dùng model từ combobox
                                mode_name = "Multiple-to-Image" if self.current_image_mode == "Multiple-to-Image" else "Image-to-Image"
                                self.log(f"🎨 Prompt {prompt_index}: Using runImageRecipe ({mode_name}) với model={model}")
                                
                                # ✅ Get seed value
                                seed_value = get_seed_for_image(img_idx, prompt_index)
                                self.log(f"  🎲 Seed tự động: {seed_value} (img {img_idx + 1}/{num_images}, prompt {prompt_index})")
                                
                                # ✅ Vòng lặp retry cho từng lần gọi API - dùng retry_tracking để tránh vòng lặp vô hạn
                                result = None
                                max_api_retries = 3
                                current_cookie_idx = cookie_index
                                current_client = thread_client
                                
                                # ✅ Lấy retry count từ tracking (không reset khi đổi cookie)
                                with retry_tracking_lock:
                                    api_key = f"{prompt_index}_img{img_idx}_recipe"
                                    if api_key not in retry_tracking:
                                        retry_tracking[api_key] = {"retry_count_non_429": 0, "failed_cookies_429": set()}
                                    api_retry = retry_tracking[api_key]
                                    api_retry_count = api_retry["retry_count_non_429"]
                                    api_failed_cookies = api_retry["failed_cookies_429"]
                                
                                while api_retry_count <= max_api_retries:
                                    try:
                                        # ✅ Log request ra file trước khi gọi API
                                        self.log_request_to_file(
                                            "runImageRecipe",
                                            workflow_id=workflow_id,
                                            prompt=prompt,
                                            model=model,
                                            aspect_ratio=aspect_value,
                                            subject_mgid=prompt_subj_mgid,
                                            scene_mgid=prompt_scene_mgid,
                                            style_mgid=prompt_style_mgid
                                        )
                                        
                                        # ✅ DEBUG: Log seed trước khi gọi API
                                        if seed_value is not None:
                                            self.log(f"  📤 Sending API request with seed={seed_value}")
                                        
                                        result = current_client.run_image_recipe(
                                            workflow_id=workflow_id,
                                            prompt=prompt,
                                            image_model=model,  # ✅ FIX: Dùng model từ combobox (GEM_PIX, IMAGEN_3_5, IMAGEN_3)
                                            aspect_ratio=aspect_value,
                                            subject_mgid=prompt_subj_mgid,
                                            scene_mgid=prompt_scene_mgid,
                                            style_mgid=prompt_style_mgid,
                                            seed=seed_value  # ✅ Truyền seed (None nếu tắt, hoặc giá trị seed nếu bật)
                                        )
                                        if result:
                                            break  # Thành công, thoát vòng lặp
                                        
                                        # Kiểm tra lỗi
                                        error_detail = getattr(current_client, "last_error_detail", "") or getattr(current_client, "last_error", "")
                                        if self._check_is_429_or_high_traffic(str(error_detail)):
                                            # 429 - đổi cookie (KHÔNG reset retry count)
                                            with retry_tracking_lock:
                                                api_failed_cookies.add(current_cookie_idx)
                                                retry_tracking[api_key]["failed_cookies_429"] = api_failed_cookies
                                            
                                            self.log(f"⚠️ Prompt {prompt_index} img {img_idx+1}: Cookie {current_cookie_idx+1} bị 429, đổi cookie...")
                                            import time
                                            time.sleep(6)
                                            
                                            # Tìm cookie khác
                                            new_cookie_idx = None
                                            with cookie_lock:
                                                for _ in range(len(available_cookies)):
                                                    temp_idx = cookie_counter['count'] % len(available_cookies)
                                                    cookie_counter['count'] += 1
                                                    if temp_idx not in api_failed_cookies:
                                                        new_cookie_idx = temp_idx
                                                        break
                                            
                                            if new_cookie_idx is not None:
                                                current_cookie_idx = new_cookie_idx
                                                new_cookies = _parse_cookie_string(available_cookies[new_cookie_idx])
                                                current_client = LabsFlowClient(new_cookies)
                                                if current_client.fetch_access_token():
                                                    self.log(f"✅ Prompt {prompt_index} img {img_idx+1}: Chuyển sang cookie {new_cookie_idx+1}")
                                                    continue  # Retry với cookie mới (KHÔNG reset retry count)
                                            
                                            # Không tìm thấy cookie khác, thử lại với cookie đã bị 429
                                            self.log(f"⚠️ Prompt {prompt_index} img {img_idx+1}: Không tìm thấy cookie khác, thử lại cookie đã bị 429")
                                            continue
                                        else:
                                            # Lỗi khác - retry với cùng cookie
                                            api_retry_count += 1
                                            with retry_tracking_lock:
                                                retry_tracking[api_key]["retry_count_non_429"] = api_retry_count
                                            if api_retry_count <= max_api_retries:
                                                self.log(f"⚠️ Prompt {prompt_index} img {img_idx+1}: Lỗi không phải 429, retry {api_retry_count}/{max_api_retries}")
                                                continue
                                            else:
                                                # Reset khi fail hoàn toàn
                                                with retry_tracking_lock:
                                                    retry_tracking[api_key]["retry_count_non_429"] = 0
                                                self.log(f"❌ Prompt {prompt_index} img {img_idx+1}: Lỗi sau {max_api_retries} lần retry")
                                                result = None
                                                break
                                    except Exception as e:
                                        error_str = str(e)
                                        if self._check_is_429_or_high_traffic(error_str):
                                            # 429 - đổi cookie (KHÔNG reset retry count)
                                            with retry_tracking_lock:
                                                api_failed_cookies.add(current_cookie_idx)
                                                retry_tracking[api_key]["failed_cookies_429"] = api_failed_cookies
                                            
                                            self.log(f"⚠️ Prompt {prompt_index} img {img_idx+1}: Exception 429 với cookie {current_cookie_idx+1}, đổi cookie...")
                                            import time
                                            time.sleep(6)
                                            
                                            # Tìm cookie khác
                                            new_cookie_idx = None
                                            with cookie_lock:
                                                for _ in range(len(available_cookies)):
                                                    temp_idx = cookie_counter['count'] % len(available_cookies)
                                                    cookie_counter['count'] += 1
                                                    if temp_idx not in api_failed_cookies:
                                                        new_cookie_idx = temp_idx
                                                        break
                                            
                                            if new_cookie_idx is not None:
                                                current_cookie_idx = new_cookie_idx
                                                new_cookies = _parse_cookie_string(available_cookies[new_cookie_idx])
                                                current_client = LabsFlowClient(new_cookies)
                                                if current_client.fetch_access_token():
                                                    self.log(f"✅ Prompt {prompt_index} img {img_idx+1}: Chuyển sang cookie {new_cookie_idx+1}")
                                                    continue  # Retry với cookie mới (KHÔNG reset retry count)
                                            
                                            # Không tìm thấy cookie khác
                                            self.log(f"⚠️ Prompt {prompt_index} img {img_idx+1}: Không tìm thấy cookie khác, thử lại cookie đã bị 429")
                                            continue
                                        else:
                                            # Lỗi khác
                                            api_retry_count += 1
                                            with retry_tracking_lock:
                                                retry_tracking[api_key]["retry_count_non_429"] = api_retry_count
                                            if api_retry_count <= max_api_retries:
                                                self.log(f"⚠️ Prompt {prompt_index} img {img_idx+1}: Exception, retry {api_retry_count}/{max_api_retries}: {error_str[:100]}")
                                                continue
                                            else:
                                                # Reset khi fail hoàn toàn
                                                with retry_tracking_lock:
                                                    retry_tracking[api_key]["retry_count_non_429"] = 0
                                                self.log(f"❌ Prompt {prompt_index} img {img_idx+1}: Exception sau {max_api_retries} lần retry: {error_str[:100]}")
                                                import traceback
                                                self.log(f"🔍 Traceback: {traceback.format_exc()}")
                                                result = None
                                                break
                            else:
                                # Text-to-Image
                                self.log(f"📝 Prompt {prompt_index}: Using generateImage (Text-to-Image) với model={model}")
                                if self.current_image_mode in ["Image-to-Image", "Multiple-to-Image"]:
                                    self.log(f"⚠️ ⚠️ ⚠️ WARNING: {self.current_image_mode} mode nhưng không có reference images!")
                                    if self.current_image_mode == "Multiple-to-Image":
                                        self.log(f"💡 Có thể do: Chưa chọn folder, folder không có ảnh, hoặc upload thất bại")
                                    else:
                                        self.log(f"💡 Có thể do: Chưa chọn ảnh, upload chưa xong, hoặc upload thất bại")
                                
                                # ✅ Get seed value
                                seed_value = get_seed_for_image(img_idx, prompt_index)
                                self.log(f"  🎲 Seed tự động: {seed_value} (img {img_idx + 1}/{num_images}, prompt {prompt_index})")
                                
                                # ✅ Vòng lặp retry cho từng lần gọi API - dùng retry_tracking để tránh vòng lặp vô hạn
                                result = None
                                max_api_retries = 3
                                current_cookie_idx = cookie_index
                                current_client = thread_client
                                
                                # ✅ Lấy retry count từ tracking (không reset khi đổi cookie)
                                with retry_tracking_lock:
                                    api_key = f"{prompt_index}_img{img_idx}_generate"
                                    if api_key not in retry_tracking:
                                        retry_tracking[api_key] = {"retry_count_non_429": 0, "failed_cookies_429": set()}
                                    api_retry = retry_tracking[api_key]
                                    api_retry_count = api_retry["retry_count_non_429"]
                                    api_failed_cookies = api_retry["failed_cookies_429"]
                                
                                while api_retry_count <= max_api_retries:
                                    try:
                                        # ✅ Log request ra file trước khi gọi API
                                        self.log_request_to_file(
                                            "generateImage",
                                            workflow_id=workflow_id,
                                            prompt=prompt,
                                            model=model,
                                            aspect_ratio=aspect_value
                                        )
                                        
                                        # ✅ DEBUG: Log seed trước khi gọi API
                                        if seed_value is not None:
                                            self.log(f"  📤 Sending API request with seed={seed_value}")
                                        
                                        result = current_client.generate_image_from_text(
                                            workflow_id=workflow_id,
                                            prompt=prompt,
                                            image_model=model,
                                            aspect_ratio=aspect_value,
                                            seed=seed_value  # ✅ Truyền seed (None nếu tắt, hoặc giá trị seed nếu bật)
                                        )
                                        if result:
                                            break  # Thành công, thoát vòng lặp
                                        
                                        # Kiểm tra lỗi
                                        error_detail = getattr(current_client, "last_error_detail", "") or getattr(current_client, "last_error", "")
                                        if self._check_is_429_or_high_traffic(str(error_detail)):
                                            # 429 - đổi cookie (KHÔNG reset retry count)
                                            with retry_tracking_lock:
                                                api_failed_cookies.add(current_cookie_idx)
                                                retry_tracking[api_key]["failed_cookies_429"] = api_failed_cookies
                                            
                                            self.log(f"⚠️ Prompt {prompt_index} img {img_idx+1}: Cookie {current_cookie_idx+1} bị 429, đổi cookie...")
                                            import time
                                            time.sleep(6)
                                            
                                            # Tìm cookie khác
                                            new_cookie_idx = None
                                            with cookie_lock:
                                                for _ in range(len(available_cookies)):
                                                    temp_idx = cookie_counter['count'] % len(available_cookies)
                                                    cookie_counter['count'] += 1
                                                    if temp_idx not in api_failed_cookies:
                                                        new_cookie_idx = temp_idx
                                                        break
                                            
                                            if new_cookie_idx is not None:
                                                current_cookie_idx = new_cookie_idx
                                                new_cookies = _parse_cookie_string(available_cookies[new_cookie_idx])
                                                current_client = LabsFlowClient(new_cookies)
                                                if current_client.fetch_access_token():
                                                    self.log(f"✅ Prompt {prompt_index} img {img_idx+1}: Chuyển sang cookie {new_cookie_idx+1}")
                                                    continue  # Retry với cookie mới (KHÔNG reset retry count)
                                            
                                            # Không tìm thấy cookie khác, thử lại với cookie đã bị 429
                                            self.log(f"⚠️ Prompt {prompt_index} img {img_idx+1}: Không tìm thấy cookie khác, thử lại cookie đã bị 429")
                                            continue
                                        else:
                                            # Lỗi khác - retry với cùng cookie
                                            api_retry_count += 1
                                            with retry_tracking_lock:
                                                retry_tracking[api_key]["retry_count_non_429"] = api_retry_count
                                            if api_retry_count <= max_api_retries:
                                                self.log(f"⚠️ Prompt {prompt_index} img {img_idx+1}: Lỗi không phải 429, retry {api_retry_count}/{max_api_retries}")
                                                continue
                                            else:
                                                # Reset khi fail hoàn toàn
                                                with retry_tracking_lock:
                                                    retry_tracking[api_key]["retry_count_non_429"] = 0
                                                self.log(f"❌ Prompt {prompt_index} img {img_idx+1}: Lỗi sau {max_api_retries} lần retry")
                                                result = None
                                                break
                                    except Exception as e:
                                        error_str = str(e)
                                        if self._check_is_429_or_high_traffic(error_str):
                                            # 429 - đổi cookie (KHÔNG reset retry count)
                                            with retry_tracking_lock:
                                                api_failed_cookies.add(current_cookie_idx)
                                                retry_tracking[api_key]["failed_cookies_429"] = api_failed_cookies
                                            
                                            self.log(f"⚠️ Prompt {prompt_index} img {img_idx+1}: Exception 429 với cookie {current_cookie_idx+1}, đổi cookie...")
                                            import time
                                            time.sleep(6)
                                            
                                            # Tìm cookie khác
                                            new_cookie_idx = None
                                            with cookie_lock:
                                                for _ in range(len(available_cookies)):
                                                    temp_idx = cookie_counter['count'] % len(available_cookies)
                                                    cookie_counter['count'] += 1
                                                    if temp_idx not in api_failed_cookies:
                                                        new_cookie_idx = temp_idx
                                                        break
                                            
                                            if new_cookie_idx is not None:
                                                current_cookie_idx = new_cookie_idx
                                                new_cookies = _parse_cookie_string(available_cookies[new_cookie_idx])
                                                current_client = LabsFlowClient(new_cookies)
                                                if current_client.fetch_access_token():
                                                    self.log(f"✅ Prompt {prompt_index} img {img_idx+1}: Chuyển sang cookie {new_cookie_idx+1}")
                                                    continue  # Retry với cookie mới (KHÔNG reset retry count)
                                            
                                            # Không tìm thấy cookie khác
                                            self.log(f"⚠️ Prompt {prompt_index} img {img_idx+1}: Không tìm thấy cookie khác, thử lại cookie đã bị 429")
                                            continue
                                        else:
                                            # Lỗi khác
                                            api_retry_count += 1
                                            with retry_tracking_lock:
                                                retry_tracking[api_key]["retry_count_non_429"] = api_retry_count
                                            if api_retry_count <= max_api_retries:
                                                self.log(f"⚠️ Prompt {prompt_index} img {img_idx+1}: Exception, retry {api_retry_count}/{max_api_retries}: {error_str[:100]}")
                                                continue
                                            else:
                                                # Reset khi fail hoàn toàn
                                                with retry_tracking_lock:
                                                    retry_tracking[api_key]["retry_count_non_429"] = 0
                                                self.log(f"❌ Prompt {prompt_index} img {img_idx+1}: Exception sau {max_api_retries} lần retry: {error_str[:100]}")
                                                import traceback
                                                self.log(f"🔍 Traceback: {traceback.format_exc()}")
                                                result = None
                                                break

                            # Handle result
                            if result:
                                try:
                                    image_path = self.handle_image_result(
                                        result, prompt, prompt_index, img_idx + 1, output_dir
                                    )
                                    if image_path:
                                        generated_files.append(image_path)
                                        # ✅ Update progress: đã tạo xong ảnh img_idx+1
                                        self.signals.update_image_progress.emit(prompt_index, img_idx + 1, num_images)
                                        self.log(f"✅ Prompt {prompt_index}: Saved {img_idx+1}: {Path(image_path).name}")
                                    else:
                                        self.log(f"❌ Prompt {prompt_index}: Failed to save image {img_idx+1} - handle_image_result returned None")
                                        self.log(f"💡 Có thể do: Không extract được ảnh từ response, lỗi download, hoặc lỗi lưu file")
                                except Exception as e:
                                    self.log(f"❌ Prompt {prompt_index}: Error handling result for image {img_idx+1}: {e}")
                                    import traceback
                                    self.log(f"🔍 Traceback: {traceback.format_exc()}")
                            else:
                                self.log(f"❌ Prompt {prompt_index}: No result returned for image {img_idx+1}")
                                self.log(f"💡 Có thể do: API request failed, lỗi network, hoặc lỗi từ server")

                            # Small delay between images
                            if img_idx < num_images - 1:
                                import time
                                time.sleep(1)

                        except Exception as e:
                            self.log(f"❌ Prompt {prompt_index}: Error img {img_idx+1}: {e}")
                            import traceback
                            self.log(f"🔍 Traceback: {traceback.format_exc()}")

                    # Update final result
                    with completion_lock:
                        if generated_files:
                            # ✅ Reset retry tracking khi thành công
                            with retry_tracking_lock:
                                if prompt_index in retry_tracking:
                                    retry_tracking[prompt_index]["retry_count_non_429"] = 0
                                    retry_tracking[prompt_index]["failed_cookies_429"] = set()
                            
                            self.signals.update_image_status.emit(prompt_index, "Hoàn thành")
                            # ✅ Update progress: hoàn thành tất cả (current = total)
                            self.signals.update_image_progress.emit(prompt_index, num_images, num_images)
                            self.signals.update_image_path.emit(prompt_index, "; ".join(generated_files))
                            completed_count += 1
                            self.log(f"✅ Prompt {prompt_index} COMPLETED ({len(generated_files)} images)")
                            
                            # ✅ Update batch file status
                            source_file_name = self.image_prompt_file_mapping.get(prompt_index, None)
                            if source_file_name:
                                self.update_batch_file_status(source_file_name)
                        else:
                            # ✅ Reset retry tracking khi fail hoàn toàn để tránh vòng lặp
                            with retry_tracking_lock:
                                if prompt_index in retry_tracking:
                                    retry_tracking[prompt_index]["retry_count_non_429"] = 0
                            
                            self.signals.update_image_status.emit(prompt_index, "Thất bại")
                            # ✅ Reset progress khi thất bại
                            self.signals.update_image_progress.emit(prompt_index, 0, num_images)
                            failed_count += 1
                            self.log(f"❌ Prompt {prompt_index} FAILED")
                    
                        # ✅ Thành công hoặc thất bại - break khỏi vòng lặp while True và return
                    return prompt_index, generated_files

                except Exception as e:
                    self.log(f"❌ Prompt {prompt_index}: Error: {e}")
                    import traceback
                    self.log(f"🔍 Traceback: {traceback.format_exc()}")
                    # ✅ Reset retry tracking khi có exception
                    with retry_tracking_lock:
                        if prompt_index in retry_tracking:
                            retry_tracking[prompt_index]["retry_count_non_429"] = 0
                    with completion_lock:
                        self.signals.update_image_status.emit(prompt_index, "Thất bại")
                        failed_count += 1
                    return None

            # ✅ ENSURE EXACT NUMBER OF THREADS
            if concurrent <= 0:
                concurrent = 1
                
            # ✅ Prepare prompt data với index đúng (bắt đầu từ start_index)
            prompt_data_list = [(i, prompt) for i, prompt in enumerate(prompts, start_index)]
            
            # ✅ BỎ DELAY - Không còn delay giữa các request (nối đuôi liên tục)
            # delay_seconds = self.spin_image_delay.value()  # Comment lại vì không dùng nữa
            
            self.log(f"🚀 Starting image generation: {len(prompt_data_list)} prompts")
            self.log(f"⚙️ Whisk: Nối đuôi với {concurrent} công việc đồng thời ({len(available_cookies)} cookie(s) × 1)")
            # ✅ BỎ DELAY - Không còn delay giữa các prompt
            
            import time as _t
            
            # ✅ BƯỚC 1: Khởi tạo tất cả cards cùng lúc (không delay)
            self.log(f"📋 Khởi tạo {len(prompt_data_list)} cards cùng lúc...")
            for prompt_index, prompt in prompt_data_list:
                try:
                    self.signals.create_image_card.emit(prompt_index, prompt, num_images)
                except Exception as e:
                    self.log(f"⚠️ Warning: Không thể tạo card cho prompt {prompt_index}: {e}")
            
            # Small delay để UI kịp render tất cả cards
            _t.sleep(0.2)
            self.log(f"✅ Đã khởi tạo tất cả {len(prompt_data_list)} cards")
            
            # ✅ BƯỚC 2: Xử lý prompts với QUY TRÌNH MỚI - Nối đuôi không delay (giống tab video)
            self.log(f"🖼️ Bắt đầu xử lý {len(prompt_data_list)} prompts với {concurrent} công việc đồng thời")
            # ✅ BỎ DELAY - Không còn delay giữa các request (nối đuôi liên tục)
            
            # ✅ Dùng ThreadPoolExecutor để tự động quản lý queue (giống tab video)
            from concurrent.futures import ThreadPoolExecutor, as_completed
            
            with ThreadPoolExecutor(max_workers=concurrent) as executor:
                # Submit tất cả tasks vào executor (sẽ tự động giới hạn concurrent)
                future_to_prompt = {}
                for prompt_data in prompt_data_list:
                    if self.stop_event.is_set():
                        break
                    future = executor.submit(process_single_prompt, prompt_data, wave_pos=1)
                    future_to_prompt[future] = prompt_data
                
                # Xử lý kết quả khi task hoàn thành
                for future in as_completed(future_to_prompt):
                    prompt_data = future_to_prompt[future]
                    prompt_index, prompt = prompt_data
                    try:
                        result = future.result()
                        if result:
                            self.log(f"✅ Prompt {prompt_index} hoàn thành")
                        else:
                            self.log(f"❌ Prompt {prompt_index} thất bại")
                    except Exception as e:
                        self.log(f"❌ Prompt {prompt_index} exception: {e}")
                        import traceback
                        self.log(traceback.format_exc())
                    
                    if self.stop_event.is_set():
                        break

            self.log(f"🎉 ALL DONE! Success: {completed_count}, Failed: {failed_count}")

        except Exception as e:
            self.log(f"❌ Worker error: {e}")
            import traceback
            self.log(f"🔍 Traceback: {traceback.format_exc()}")
        finally:
            self.signals.finished.emit()

    def handle_image_result(self, result, prompt, prompt_index, img_number, output_dir):
        """Handle image generation result - ƯU TIÊN BASE64, FALLBACK URL
        
        ✅ TỰ ĐỘNG TẠO SUBFOLDER THEO TÊN FILE TXT
        """
        try:
            # ✅ Get source file name from mapping
            source_file_name = self.image_prompt_file_mapping.get(prompt_index, "default")
            local_index = None
            if hasattr(self, 'image_prompt_local_mapping'):
                local_index = self.image_prompt_local_mapping.get(prompt_index, None)
            
            # ✅ Create subfolder with source file name
            subfolder = Path(output_dir) / source_file_name
            subfolder.mkdir(parents=True, exist_ok=True)
            
            # ✅ KIỂM TRA BASE64 DATA TRƯỚC (ưu tiên cao nhất - nhanh hơn, không cần download)
            image_bytes, ext = self.extract_base64_image(result)
            
            if image_bytes:
                # Có base64 data → save ngay, KHÔNG CẦN download hay polling
                # ✅ Format: {prompt_index}_image{img_number}.{ext} trong subfolder
                display_index = local_index if local_index else prompt_index
                filename = subfolder / f"{display_index:03d}_image{img_number}.{ext}"
                
                try:
                    with open(filename, 'wb') as f:
                        f.write(image_bytes)

                    self.log(f"✅ Saved base64 image: {source_file_name}/{filename.name} ({len(image_bytes)} bytes)")
                    return str(filename)
                except Exception as e:
                    self.log(f"❌ Failed to save base64 data: {e}")
                    # Fall through to URL method
            
            # FALLBACK: Nếu không có base64 → thử extract URLs và download
            image_url = self.extract_image_url(result)
            
            if image_url:
                # Direct URL - download
                # ✅ Format: {prompt_index}_image{img_number}.png trong subfolder
                display_index = local_index if local_index else prompt_index
                filename = subfolder / f"{display_index:03d}_image{img_number}.png"
                
                if self.download_image_sync(image_url, filename):
                    self.log(f"✅ Downloaded from URL: {source_file_name}/{filename.name}")
                    return str(filename)
                else:
                    self.log(f"❌ Failed to download image from URL: {image_url}")
            
            # ❌ Không có cả base64 lẫn URL hợp lệ → KHÔNG POLLING (tránh chờ không cần thiết)
            self.log(f"❌ No base64 data or valid URL found - skipping polling")
            return None

        except Exception as e:
            self.log(f"❌ Error handling image result: {e}")
            return None



    def run_image_generation_worker(self, prompts, output_dir, concurrent=1):
        """Worker thread for image generation (legacy - kept for compatibility)"""
        self.run_image_generation_worker_v2(prompts, output_dir, concurrent, [self.cookie_value] if self.cookie_value else [])

