    def execute_retry_with_new_prompt(self, index, new_prompt, row, source_file=None, local_index=None):
        """Thực thi retry với prompt mới đã chỉnh sửa - Kiểm tra concurrent limit
        
        Args:
            index: Prompt index
            new_prompt: Prompt mới đã sửa
            row: Table row
            source_file: Tên file txt gốc (để lưu đúng folder)
            local_index: Index trong file txt (để lưu đúng tên file)
        """
        try:
            # ✅ Preserve metadata nếu được truyền vào
            if source_file:
                self.image_prompt_file_mapping[index] = source_file
            if local_index is not None:
                self.image_prompt_local_mapping[index] = local_index
            
            # ✅ Đơn giản: Dùng cookies có sẵn, không test trước (đã có logic bỏ qua cookie lỗi trong worker)
            available_cookies = []
            if self.cookies_list:
                available_cookies = self.cookies_list
            elif self.cookie_value:
                available_cookies = [self.cookie_value]
            
            if not available_cookies:
                QMessageBox.warning(self, "Cảnh báo", "Vui lòng cài đặt Cookie trước!")
                return
            
            # Validate output directory
            output_dir = self.txt_image_output.text().strip()
            if not output_dir:
                QMessageBox.warning(self, "Cảnh báo", "Vui lòng chọn thư mục lưu ảnh!")
                return
            
            # ✅ Tính toán giới hạn concurrent dựa trên số cookies
            num_cookies = len(available_cookies)
            max_jobs_per_cookie = 1  # 1 cookie = 1 job max cho image
            total_max_jobs = num_cookies * max_jobs_per_cookie
            user_concurrent = self.spin_image_concurrent.value()
            max_concurrent = min(user_concurrent, total_max_jobs)
            
            # ✅ Kiểm tra số threads đang chạy (chính xác)
            with self.active_image_tasks_lock:
                current_active = self.active_image_tasks
                
                # Retry sẽ thêm 1 thread → check nếu current_active + 1 > max_concurrent
                if current_active + 1 > max_concurrent:
                    # Đã đạt giới hạn → đưa vào queue
                    self.log(f"⏳ Đã đạt giới hạn concurrent ({current_active}/{max_concurrent}, retry sẽ thành {current_active + 1}) - Đưa retry vào queue")
                    
                    # Cập nhật prompt trong table
                    prompt_item = self.image_results_table.item(row, 0)
                    if prompt_item:
                        display_text = self._format_image_prompt_table_text(index, new_prompt)
                        prompt_item.setText(display_text)
                        prompt_item.setData(Qt.UserRole, new_prompt)
                    
                    # Cập nhật status thành "Chờ xử lý"
                    num_images = self.spin_num_images.value()
                    self.image_results_table.setItem(row, 1, QTableWidgetItem("Chờ xử lý"))
                    self.signals.update_image_status.emit(index, "Chờ xử lý")
                    # ✅ Đảm bảo update card trong main thread
                    QTimer.singleShot(0, lambda: self.add_image_to_grid(index, new_prompt, "Chờ xử lý", "", 0, num_images))
                    
                    # Đưa vào retry queue
                    with self.image_retry_lock:
                        self.image_retry_queue.append({
                            'index': index,
                            'prompt': new_prompt,
                            'row': row,
                            'output_dir': output_dir,
                            'available_cookies': available_cookies
                        })
                        queue_size = len(self.image_retry_queue)
                    
                    self.log(f"📋 Đã thêm vào retry queue (vị trí #{queue_size}): Prompt #{index}")
                    # ✅ Không hiển thị popup - chỉ log (tránh phải nhấn OK nhiều lần)
                    return
            
            # ✅ Còn slot trống → chạy ngay
            # Cập nhật prompt trong table với prompt mới
            prompt_item = self.image_results_table.item(row, 0)
            if prompt_item:
                # Cập nhật prompt display (truncated)
                prompt_display = new_prompt[:50] + "..." if len(new_prompt) > 50 else new_prompt
                prompt_item.setText(prompt_display)
                # Lưu full prompt vào UserRole
                prompt_item.setData(Qt.UserRole, new_prompt)
            
            # Cập nhật status thành "Đang tạo"
            num_images = self.spin_num_images.value()
            self.image_results_table.setItem(row, 1, QTableWidgetItem("Đang tạo"))
            self.signals.update_image_status.emit(index, "Đang tạo")
            # ✅ Đảm bảo update card trong main thread
            QTimer.singleShot(0, lambda: self.add_image_to_grid(index, new_prompt, "Đang tạo", "", 0, num_images))
            
            # Xóa file path cũ (để tạo lại)
            self.image_results_table.setItem(row, 2, QTableWidgetItem(""))
            
            # Tăng số tasks đang chạy
            with self.active_image_tasks_lock:
                self.active_image_tasks += 1
            
            # Get settings - retry chỉ 1 prompt
            concurrent = 1
            actual_concurrent = 1
            
            # Start retry worker với prompt mới và index cũ
            self.log(f"🔄 Retry prompt #{index} với prompt mới: {new_prompt[:50]}... (Active: {self.active_image_tasks}/{max_concurrent})")
            # ✅ Không hiển thị popup - chỉ log (tránh phải nhấn OK nhiều lần)
            
            threading.Thread(
                target=self.run_image_generation_worker_v2_with_decrement,
                args=([new_prompt], Path(output_dir), actual_concurrent, available_cookies, index),
                daemon=True
            ).start()
            
        except Exception as e:
            self.log(f"❌ Error executing retry with new prompt: {e}")
            import traceback
            self.log(f"🔍 Traceback: {traceback.format_exc()}")
            QMessageBox.critical(self, "Lỗi", f"Lỗi khi chạy lại: {e}")
    
    def run_image_generation_worker_v2_with_decrement(self, prompts, output_dir, concurrent, available_cookies, start_index=1):
        """Wrapper cho run_image_generation_worker_v2 - Tự động giảm active_image_tasks và process queue khi xong"""
        try:
            # Chạy worker
            self.run_image_generation_worker_v2(prompts, output_dir, concurrent, available_cookies, start_index)
        finally:
            # Giảm số tasks đang chạy
            with self.active_image_tasks_lock:
                if self.active_image_tasks > 0:
                    self.active_image_tasks -= 1
                self.log(f"📊 Active tasks: {self.active_image_tasks}")
            
            # ✅ Tự động process retry queue nếu có slot trống
            self.process_image_retry_queue()
    
    def process_image_retry_queue(self):
        """Tự động xử lý retry queue khi có slot trống"""
        try:
            # Tính toán giới hạn concurrent
            available_cookies = []
            if self.cookies_list:
                available_cookies = self.cookies_list
            elif self.cookie_value:
                available_cookies = [self.cookie_value]
            
            if not available_cookies:
                return
            
            num_cookies = len(available_cookies)
            max_jobs_per_cookie = 3  # 1 cookie = 3 jobs max cho image
            total_max_jobs = num_cookies * max_jobs_per_cookie
            user_concurrent = self.spin_image_concurrent.value()
            max_concurrent = min(user_concurrent, total_max_jobs)
            
            # Kiểm tra queue và slot trống
            with self.image_retry_lock:
                if not self.image_retry_queue:
                    return  # Không có gì trong queue
                
                with self.active_image_tasks_lock:
                    current_active = self.active_image_tasks
                    available_slots = max_concurrent - current_active
                    
                    if available_slots <= 0:
                        return  # Không có slot trống
                    
                    # Lấy tasks từ queue (tối đa số slot trống)
                    tasks_to_process = []
                    for _ in range(min(available_slots, len(self.image_retry_queue))):
                        if self.image_retry_queue:
                            task = self.image_retry_queue.pop(0)
                            tasks_to_process.append(task)
            
            # ✅ Get delay setting từ người dùng
            delay_seconds = self.spin_image_delay.value()
            if delay_seconds <= 0:
                delay_seconds = 1  # Mặc định 1s
            
            # Xử lý từng task với delay
            import time
            for idx, task in enumerate(tasks_to_process, 1):
                index = task['index']
                prompt = task['prompt']
                row = task['row']
                output_dir = task['output_dir']
                task_cookies = task['available_cookies']
                
                # ✅ Delay giữa các retry requests (trừ request đầu tiên)
                if idx > 1:
                    time.sleep(delay_seconds)
                
                # ✅ Tăng số threads đang chạy (mỗi retry = 1 thread) với double check
                with self.active_image_tasks_lock:
                    # Double check trước khi tăng (tránh race condition)
                    if self.active_image_tasks + 1 > max_concurrent:
                        # Đã đạt giới hạn → đưa lại vào queue
                        with self.image_retry_lock:
                            self.image_retry_queue.insert(0, task)  # Đưa lại vào đầu queue
                        self.log(f"⚠️ Slot đã bị chiếm, đưa lại vào queue: Prompt #{index}")
                        continue
                    
                    self.active_image_tasks += 1
                    current_after = self.active_image_tasks
                
                # Cập nhật status thành "Đang tạo"
                num_images = self.spin_num_images.value()
                self.image_results_table.setItem(row, 1, QTableWidgetItem("Đang tạo"))
                self.signals.update_image_status.emit(index, "Đang tạo")
                # ✅ Đảm bảo update card trong main thread
                QTimer.singleShot(0, lambda: self.add_image_to_grid(index, prompt, "Đang tạo", "", 0, num_images))
                
                # Start worker
                self.log(f"🔄 Processing queued retry: Prompt #{index} (Active threads: {current_after}/{max_concurrent})")
                threading.Thread(
                    target=self.run_image_generation_worker_v2_with_decrement,
                    args=([prompt], Path(output_dir), 1, task_cookies, index),
                    daemon=True
                ).start()
                
        except Exception as e:
            self.log(f"❌ Lỗi process retry queue: {e}")
            import traceback
            self.log(f"🔍 Traceback: {traceback.format_exc()}")
    
    def extract_image_url(self, result):
        """Extract image URL from API result - SIMPLE và SAFE"""
        try:
            if not isinstance(result, dict):
                return None
            
            # Quick check - chỉ dùng _extract_file_urls từ gui_app
            # Đã được test kỹ và safe
            urls = _extract_file_urls(result)
            
            if urls:
                # Filter for image URLs
                for url in urls:
                    if not isinstance(url, str):
                        continue
                    lower_url = url.lower()
                    # Ưu tiên URLs có image extension
                    if any(ext in lower_url for ext in ['.jpg', '.jpeg', '.png', '.webp', '.gif', '.bmp']):
                        return url
                
                # Không có image extension, return first valid http URL
                for url in urls:
                    if isinstance(url, str) and url.startswith("http"):
                        return url
            
            return None
            
        except Exception as e:
            self.log(f"❌ Lỗi extract URL: {e}")
            return None
    
    def extract_base64_image(self, obj):
        """Extract base64 image data - COPY Y CHANG từ gui_app.py"""
        try:
            import base64
        except Exception:
            return (None, "jpg")

        likely_keys = {
            "rawImageBytes", "imageBase64", "imageBytes", "jpegBytes", "pngBytes",
            "encodedImage", "bytes", "data", "content"
        }

        def try_decode(s):
            if not isinstance(s, str) or len(s) < 200:
                return None
            if s.startswith("data:image") and ";base64," in s:
                s = s.split(",", 1)[1]
            try:
                return base64.b64decode(s, validate=False)
            except Exception:
                return None

        def guess_ext(data):
            try:
                if len(data) >= 12:
                    if data[:2] == b"\xFF\xD8":
                        return "jpg"
                    if data[:8] == b"\x89PNG\r\n\x1a\n":
                        return "png"
                    if data[:4] == b"RIFF" and data[8:12] == b"WEBP":
                        return "webp"
                return "jpg"
            except Exception:
                return "jpg"

        try:
            if isinstance(obj, dict):
                # Priority pass for known keys
                for k, v in obj.items():
                    if isinstance(v, str) and k in likely_keys:
                        data = try_decode(v)
                        if data and len(data) > 1000:
                            ext = guess_ext(data)
                            self.log(f"✅ Found base64 in key '{k}': {len(data)} bytes, ext: {ext}")
                            return (data, ext)
        except Exception:
            pass

        # Recursive search
        try:
            if isinstance(obj, dict):
                for v in obj.values():
                    b, ext = self.extract_base64_image(v)
                    if b is not None:
                        return (b, ext)
            elif isinstance(obj, (list, tuple)):
                for item in obj:
                    b, ext = self.extract_base64_image(item)
                    if b is not None:
                        return (b, ext)
        except Exception:
            pass
        return (None, "jpg")
    
    def download_image_sync(self, url, filename):
        """Download image synchronously - SAFE với timeout"""
        try:
            headers = {
                "user-agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) Chrome/120.0.0.0"
            }
            
            # Timeout 30s (đủ cho ảnh, không quá lâu)
            with requests.get(url, headers=headers, stream=True, timeout=30) as r:
                r.raise_for_status()
                
                # Limit download size (max 10MB cho ảnh)
                max_size = 10 * 1024 * 1024
                downloaded = 0
                
                with open(filename, 'wb') as f:
                    for chunk in r.iter_content(chunk_size=8192):
                        if self.stop_event.is_set():
                            return False
                        if chunk:
                            f.write(chunk)
                            downloaded += len(chunk)
                            
                            # Check size limit
                            if downloaded > max_size:
                                self.log(f"⚠️ File quá lớn (>{max_size/1024/1024}MB), dừng download")
                                return False
            
            # Verify file exists và có kích thước hợp lý
            if filename.exists():
                size = filename.stat().st_size
                if size > 0 and size < max_size:
                    return True
            
            return False
            
        except requests.exceptions.Timeout:
            self.log(f"⏰ Download timeout (30s)")
            return False
        except Exception as e:
            self.log(f"❌ Lỗi download: {e}")
            return False
    
    def on_image_table_double_click(self, index):
        """Handle double-click on image table - open first image"""
        try:
            row = index.row()
            if row < 0:
                return
            
            # Get image paths from column 2
            path_item = self.image_results_table.item(row, 2)
            if not path_item:
                return
            
            path_text = path_item.text()
            if not path_text:
                return
            
            # Get first image path
            paths = [p.strip() for p in path_text.split(";") if p.strip()]
            if paths and Path(paths[0]).exists():
                self.open_image_file(paths[0])
        
        except Exception as e:
            self.log(f"❌ Lỗi double-click: {e}")
    
    def show_image_context_menu(self, position):
        """Show context menu for image table"""
        try:
            from PySide6.QtWidgets import QMenu
            from PySide6.QtGui import QAction
            
            # Get selected row
            row = self.image_results_table.currentRow()
            if row < 0:
                return
            
            # Get image paths
            path_item = self.image_results_table.item(row, 2)
            if not path_item:
                return
            
            path_text = path_item.text()
            if not path_text:
                return
            
            paths = [p.strip() for p in path_text.split(";") if p.strip()]
            if not paths:
                return
            
            # Create menu
            menu = QMenu(self)
            menu.setStyleSheet("""
                QMenu {
                    background-color: white;
                    border: 1px solid #BDBDBD;
                    border-radius: 4px;
                    padding: 4px;
                }
                QMenu::item {
                    background-color: transparent;
                    color: #333333;
                    padding: 6px 20px;
                    margin: 2px 4px;
                    border-radius: 3px;
                }
                QMenu::item:selected {
                    background-color: #E3F2FD;
                    color: #1976D2;
                }
            """)
            
            # Add actions
            if len(paths) == 1:
                # Single image
                action_open = QAction("📁 Mở ảnh", self)
                action_open.triggered.connect(lambda: self.open_image_file(paths[0]))
                menu.addAction(action_open)
            else:
                # Multiple images - create submenu
                for i, path in enumerate(paths, 1):
                    action_open = QAction(f"📁 Mở ảnh {i}", self)
                    action_open.triggered.connect(lambda checked, p=path: self.open_image_file(p))
                    menu.addAction(action_open)
            
            menu.addSeparator()
            
            # Open folder
            action_folder = QAction("📂 Mở thư mục", self)
            action_folder.triggered.connect(lambda: self.open_image_folder(paths[0]))
            menu.addAction(action_folder)
            
            # Copy path
            action_copy = QAction("📋 Sao chép đường dẫn", self)
            action_copy.triggered.connect(lambda: self.copy_to_clipboard(paths[0]))
            menu.addAction(action_copy)
            
            # Show menu
            menu.exec(self.image_results_table.mapToGlobal(position))
            
        except Exception as e:
            self.log(f"❌ Lỗi context menu: {e}")
    
    def open_image_file(self, image_path):
        """Open image with default application"""
        try:
            if not Path(image_path).exists():
                self.log(f"❌ Ảnh không tồn tại: {image_path}")
                return
            
            import platform
            import subprocess
            
            system = platform.system()
            
            if system == "Windows":
                import os
                os.startfile(str(image_path))
            elif system == "Darwin":  # macOS
                subprocess.run(["open", str(image_path)])
            else:  # Linux
                subprocess.run(["xdg-open", str(image_path)])
            
            self.log(f"📁 Đang mở: {Path(image_path).name}")
            
        except Exception as e:
            self.log(f"❌ Lỗi mở ảnh: {e}")
    
    def open_image_folder(self, image_path):
        """Open folder containing image"""
        try:
            folder = str(Path(image_path).parent)
            
            if not Path(folder).exists():
                self.log(f"❌ Thư mục không tồn tại: {folder}")
                return
            
            import platform
            import subprocess
            
            system = platform.system()
            
            if system == "Windows":
                import os
                os.startfile(folder)
            elif system == "Darwin":  # macOS
                subprocess.run(["open", folder])
            else:  # Linux
                subprocess.run(["xdg-open", folder])
            
            self.log(f"📂 Đang mở thư mục: {folder}")
            
        except Exception as e:
            self.log(f"❌ Lỗi mở thư mục: {e}")
    
    def copy_to_clipboard(self, text):
        """Copy text to clipboard"""
        try:
            from PySide6.QtGui import QClipboard
            clipboard = QApplication.clipboard()
            clipboard.setText(text)
            self.log(f"📋 Đã copy: {text}")
        except Exception as e:
            self.log(f"❌ Lỗi copy: {e}")
    
    # ===== EXTEND VIDEO HANDLERS =====
    
    def browse_extend_txt_file(self):
        """Browse file TXT cho extend video"""
        file_path, _ = QFileDialog.getOpenFileName(
            self, "Chọn file TXT", "", "Text Files (*.txt);;All Files (*)"
        )
        if file_path:
            # Khi chọn single TXT → clear folder và bật gom nhóm
            if hasattr(self, 'txt_extend_txt_folder'):
                self.txt_extend_txt_folder.clear()
            if hasattr(self, 'combo_extend_group_size'):
                self.combo_extend_group_size.setEnabled(True)
            self.txt_extend_txt_file.setText(file_path)
            self.log(f"📄 File TXT: {file_path}")
            
            # Preview số dòng và tính số projects
            try:
                from extend_videos import parse_text_file
                segments = parse_text_file(file_path)
                group_size = int(self.combo_extend_group_size.currentText())
                num_projects = (len(segments) + group_size - 1) // group_size
                
                info = f"📝 {len(segments)} đoạn → {num_projects} project(s) (mỗi project {group_size} đoạn)"
                if hasattr(self, 'lbl_extend_info'):
                    self.lbl_extend_info.setText(info)
                    self.log(info)
                
                # Clear prompts table và hiển thị hướng dẫn
                self.prompts_table.setRowCount(0)
                self.log("💡 Nhấn 'Bắt đầu Extend' để tạo projects, sau đó click project để xem prompts")
                
                # ✅ ENABLE nút Extend khi có file mới VÀ RESET STYLE
                self.btn_extend_start.setEnabled(True)
                self.btn_extend_start.setStyleSheet("")  # Clear any custom style (restore default)
                
            except Exception as e:
                self.log(f"❌ Lỗi parse file: {e}")
    
    def load_extend_prompts_to_table(self, segments):
        """Load extend segments vào prompts table (preview all)"""
        try:
            # Clear prompts table
            self.prompts_table.setRowCount(0)
            
            # Add each segment as a row
            for i, segment in enumerate(segments, 1):
                row = self.prompts_table.rowCount()
                self.prompts_table.insertRow(row)
                
                # Checkbox
                chk = QCheckBox()
                chk_widget = QWidget()
                chk_layout = QHBoxLayout(chk_widget)
                chk_layout.addWidget(chk)
                chk_layout.setAlignment(Qt.AlignCenter)
                chk_layout.setContentsMargins(0, 0, 0, 0)
                self.prompts_table.setCellWidget(row, 0, chk_widget)
                
                # Prompt - hiển thị ~50 ký tự đầu
                segment_text = segment.text if hasattr(segment, 'text') else str(segment)
                max_display_length = 100  # TĂNG TỪ 50 → 100 KÝ TỰ
                if len(segment_text) > max_display_length:
                    display_text = f'{i}: {segment_text[:max_display_length]}...'
                else:
                    display_text = f'{i}: {segment_text}'
                
                prompt_item = self._create_prompt_table_item(display_text, segment_text, segment_index)
                self.prompts_table.setItem(row, 1, prompt_item)
                
                # Tiến độ (progress bar) - Create với màu gray (pending)
                progress_bar = QProgressBar()
                progress_bar.setRange(0, 100)
                progress_bar.setValue(0)
                progress_bar.setTextVisible(True)
                progress_bar.setFormat("%p%")
                progress_bar.setFixedHeight(20)
                progress_bar.setStyleSheet("""
                    QProgressBar {
                        border: 1px solid #BDBDBD;
                        border-radius: 3px;
                        text-align: center;
                        background-color: #F5F5F5;
                        font-weight: bold;
                        font-size: 10px;
                    }
                    QProgressBar::chunk {
                        background-color: #9E9E9E;
                        border-radius: 2px;
                    }
                """)
                self.prompts_table.setCellWidget(row, 2, progress_bar)
                
                # ✅ Trạng thái text (column 3) - "Done" (xanh lá) hoặc "Error" (đỏ)
                status_item = QTableWidgetItem("Đang xử lý...")
                status_item.setTextAlignment(Qt.AlignCenter)
                status_item.setForeground(QColor("#666666"))  # Xám
                self.prompts_table.setItem(row, 3, status_item)
                
                # Review button
                btn_review = QPushButton("Xem")
                btn_review.setMaximumSize(70, 24)
                btn_review.setObjectName("reviewLink")
                btn_review.setFlat(True)
                btn_review.clicked.connect(lambda checked, idx=i: self.log(f"Review segment {idx}"))
                self.prompts_table.setCellWidget(row, 4, btn_review)
            
            self.log(f"📋 Đã hiển thị {len(segments)} segments trong bảng")
            
        except Exception as e:
            self.log(f"❌ Lỗi load extend prompts: {e}")
    
    def on_extend_project_clicked(self, item):
        """Handle click trên extend project table - hiển thị prompts của project được chọn"""
        try:
            if not item:
                return
            
            row = item.row()
            if row < 0 or row >= self.extend_projects_table.rowCount():
                return
            
            # Get project name từ column 0
            project_item = self.extend_projects_table.item(row, 0)
            if not project_item:
                return
            
            project_name = project_item.text()
            
            # Get project từ extend_projects_data
            if not hasattr(self, 'extend_projects_data') or project_name not in self.extend_projects_data:
                self.log(f"⚠️ Không tìm thấy project: {project_name}")
                return
            
            project = self.extend_projects_data[project_name]
            
            # Load chỉ prompts của project này vào prompts table
            self.load_extend_project_prompts_to_table(project)
            
            self.log(f"📋 Hiển thị {len(project.segments)} segments của project: {project_name}")
            
        except Exception as e:
            self.log(f"❌ Lỗi click project: {e}")
    
    def load_extend_project_prompts_to_table(self, project):
        """Load prompts của 1 project cụ thể vào prompts table"""
        try:
            # Clear prompts table
            self.prompts_table.setRowCount(0)
            
            # Add each segment của project này
            for segment in project.segments:
                row = self.prompts_table.rowCount()
                self.prompts_table.insertRow(row)
                
                # Checkbox
                chk = QCheckBox()
                chk_widget = QWidget()
                chk_layout = QHBoxLayout(chk_widget)
                chk_layout.addWidget(chk)
                chk_layout.setAlignment(Qt.AlignCenter)
                chk_layout.setContentsMargins(0, 0, 0, 0)
                self.prompts_table.setCellWidget(row, 0, chk_widget)
                
                # Prompt - hiển thị segment index và text
                segment_text = segment.text if hasattr(segment, 'text') else str(segment)
                segment_index = segment.global_index if hasattr(segment, 'global_index') else segment.index if hasattr(segment, 'index') else row + 1
                
                max_display_length = 100  # TĂNG TỪ 50 → 100 KÝ TỰ
                if len(segment_text) > max_display_length:
                    display_text = f'{segment_index}: {segment_text[:max_display_length]}...'
                else:
                    display_text = f'{segment_index}: {segment_text}'
                
                # ✅ Sửa: dùng segment_text và segment_index thay vì prompt_text và prompt_idx
                prompt_item = self._create_prompt_table_item(display_text, segment_text, segment_index)
                self.prompts_table.setItem(row, 1, prompt_item)
                
                # Tiến độ (progress bar) dựa trên segment status
                initial_progress = 0
                if hasattr(segment, 'status'):
                    if segment.status == "completed":
                        initial_progress = 100
                    elif segment.status == "processing":
                        initial_progress = 50
                    elif segment.status == "error":
                        initial_progress = 0
                
                # Create progress bar và set màu đúng NGAY
                progress_bar = QProgressBar()
                progress_bar.setRange(0, 100)
                progress_bar.setValue(initial_progress)
                progress_bar.setTextVisible(True)
                progress_bar.setFormat("%p%")
                progress_bar.setFixedHeight(20)
                
                # Set màu dựa trên progress - GIỐNG text to video
                if initial_progress == 0:
                    chunk_color = "#9E9E9E"  # Gray
                elif initial_progress < 30:
                    chunk_color = "#FF9800"  # Orange
                elif initial_progress < 70:
                    chunk_color = "#2196F3"  # Blue
                elif initial_progress < 100:
                    chunk_color = "#1976D2"  # Dark Blue
                else:
                    chunk_color = "#4CAF50"  # Green
                
                progress_bar.setStyleSheet(f"""
                    QProgressBar {{
                        border: 1px solid #BDBDBD;
                        border-radius: 3px;
                        text-align: center;
                        background-color: #F5F5F5;
                        font-weight: bold;
                        font-size: 10px;
                    }}
                    QProgressBar::chunk {{
                        background-color: {chunk_color};
                        border-radius: 2px;
                    }}
                """)
                
                self.prompts_table.setCellWidget(row, 2, progress_bar)
                
                # ✅ Trạng thái text (column 3) - "Done" (xanh lá) hoặc "Error" (đỏ)
                status_item = QTableWidgetItem()
                status_item.setTextAlignment(Qt.AlignCenter)
                
                if hasattr(segment, 'status'):
                    if segment.status == "completed":
                        status_item.setText("Done")
                        status_item.setForeground(QColor("#4CAF50"))  # Xanh lá
                        status_item.setData(Qt.ForegroundRole, QColor("#4CAF50"))
                    elif segment.status == "error":
                        status_item.setText("Error")
                        status_item.setForeground(QColor("#F44336"))  # Đỏ
                        status_item.setData(Qt.ForegroundRole, QColor("#F44336"))
                    else:
                        status_item.setText("Đang xử lý...")
                        status_item.setForeground(QColor("#666666"))  # Xám
                        status_item.setData(Qt.ForegroundRole, QColor("#666666"))
                else:
                    status_item.setText("Đang xử lý...")
                    status_item.setForeground(QColor("#666666"))  # Xám
                    status_item.setData(Qt.ForegroundRole, QColor("#666666"))
                
                self.prompts_table.setItem(row, 3, status_item)
                
                # Review button
                btn_review = QPushButton("Xem")
                btn_review.setMaximumSize(70, 24)
                btn_review.setObjectName("reviewLink")
                btn_review.setFlat(True)
                btn_review.clicked.connect(lambda checked, seg=segment: self.show_extend_segment_review(seg))
                self.prompts_table.setCellWidget(row, 4, btn_review)
            
        except Exception as e:
            self.log(f"❌ Lỗi load project prompts: {e}")
    
    def show_extend_segment_review(self, segment):
        """Mở folder output chứa video đã concat của project"""
        try:
            # ✅ Lấy output folder từ input
            output_dir_str = self.txt_extend_output.text().strip() if hasattr(self, 'txt_extend_output') else ""
            if not output_dir_str:
                output_dir_str = str(Path.home() / "Downloads" / "Extended_Videos")
            
            output_dir = Path(output_dir_str)
            
            # ✅ Tìm project đang được chọn trong prompts table
            current_selection = self.extend_projects_table.currentRow()
            if current_selection >= 0:
                project_item = self.extend_projects_table.item(current_selection, 0)
                if project_item:
                    project_name = project_item.text()
                    
                    # ✅ Kiểm tra nếu project đã có concat_url (file đã concat)
                    if hasattr(self, 'extend_projects_data') and project_name in self.extend_projects_data:
                        project = self.extend_projects_data[project_name]
                        if hasattr(project, 'concat_url') and project.concat_url:
                            concat_path = Path(project.concat_url)
                            if concat_path.exists():
                                # Mở folder và chọn file
                                import subprocess
                                if concat_path.is_file():
                                    subprocess.Popen(f'explorer /select,"{concat_path}"')
                                    self.log(f"📁 Đã mở folder và chọn file: {concat_path.name}")
                                else:
                                    subprocess.Popen(f'explorer "{concat_path}"')
                                    self.log(f"📁 Đã mở folder: {concat_path}")
                                return
            
            # ✅ Fallback: Mở output folder
            if output_dir.exists():
                import subprocess
                subprocess.Popen(f'explorer "{output_dir}"')
                self.log(f"📁 Đã mở folder output: {output_dir}")
            else:
                QMessageBox.information(self, "Thông báo", f"Thư mục output chưa tồn tại:\n{output_dir}")
                
        except Exception as e:
            self.log(f"❌ Lỗi mở folder: {e}")
            QMessageBox.warning(self, "Lỗi", f"Không thể mở folder: {e}")
    
    def browse_extend_output(self):
        """Browse output folder cho extend video"""
        folder = QFileDialog.getExistingDirectory(self, "Chọn thư mục xuất")
        if folder:
            self.txt_extend_output.setText(folder)
            self.log(f"📁 Thư mục xuất: {folder}")
    
    def on_extend_start(self):
        """Start extend video processing"""
        try:
            # Xác định chế độ: Single TXT hoặc Folder TXT
            txt_file = self.txt_extend_txt_file.text().strip()
            folder_mode = False
            folder_path = ""
            if hasattr(self, 'txt_extend_txt_folder'):
                folder_path = self.txt_extend_txt_folder.text().strip()
                folder_mode = bool(folder_path)
            if not folder_mode:
                # Validate single TXT
                if not txt_file or not Path(txt_file).exists():
                    QMessageBox.warning(self, "Cảnh báo", "Vui lòng chọn file TXT hợp lệ!")
                    return
            
            if not self.cookie_value:
                if self.is_ultra_user:
                    # Ultra user - thử load từ server
                    if self.load_cookies_from_server():
                        self.log("✅ Auto-loaded cookies from server for Extend Video")
                    else:
                        QMessageBox.warning(self, "Cảnh báo Ultra", "Không tìm thấy cookies trên server!\nVui lòng liên hệ admin.")
                        return
                else:
                    QMessageBox.warning(self, "Cảnh báo", "Vui lòng nhập Cookie ở tab Video!")
                    return
            
            # Get group size
            try:
                group_size = int(self.combo_extend_group_size.currentText())
            except:
                group_size = 5
            
            # SHOW extend projects table
            self.extend_projects_table.setVisible(True)
            self.extend_control_frame.setVisible(True)
            
            # Disable controls
            self.btn_extend_start.setEnabled(False)
            self.btn_extend_stop.setEnabled(True)
            self.lbl_extend_status.setText("Đang xử lý...")
            self.lbl_extend_status.setStyleSheet("color: orange; font-weight: bold;")
            
            # Clear project table
            self.extend_projects_table.setRowCount(0)
            
            self.log(f"📊 Extend Projects Table visible: {self.extend_projects_table.isVisible()}")
            
            # Parse và preview projects TRƯỚC
            try:
                from extend_videos import parse_text_file, create_projects_from_segments, ExtendProject, ExtendSegment
                projects = []
                if folder_mode:
                    # Folder mode: mỗi file = 1 project (đã validate ≤ 100 dòng cho Ultra/Enterprise, ≤ 5 cho các gói khác ở bước load)
                    if not hasattr(self, 'extend_projects') or not self.extend_projects:
                        QMessageBox.critical(self, "Lỗi", "Thư mục không có project hợp lệ!")
                        self.finalize_extend()
                        return
                    self.log(f"📦 Folder mode: {len(self.extend_projects)} project(s)")
                    import uuid
                    for idx, entry in enumerate(self.extend_projects, start=1):
                        segs = []
                        for j, text in enumerate(entry.get('segments', []), start=1):
                            segs.append(ExtendSegment(index=j, global_index=j, text=text))
                        proj = ExtendProject(
                            project_id=str(uuid.uuid4()),
                            project_name=entry.get('name') or f"Project_{idx}",
                            segments=segs
                        )
                        # ✅ Lưu txt_file_path vào project để dùng khi process
                        proj.txt_file_path = entry.get('path', '')
                        projects.append(proj)
                else:
                    segments = parse_text_file(txt_file)
                    if not segments:
                        QMessageBox.critical(self, "Lỗi", "File txt rỗng!")
                        self.finalize_extend()
                        return
                    self.log(f"📄 Đọc được {len(segments)} đoạn")
                    projects = create_projects_from_segments(segments, group_size)
                    self.log(f"📦 Tạo {len(projects)} project(s)")
                
                # Sắp xếp natural theo tên project để bảng hiển thị đúng thứ tự
                try:
                    projects.sort(key=lambda proj: _alphanum_key(proj.project_name))
                except Exception:
                    pass
                
                # ADD PROJECTS VÀO TABLE NGAY (trong main thread)
                self.extend_projects_data = {}
                self.extend_project_row_map = {}
                
                for i, proj in enumerate(projects):
                    # Đảm bảo tất cả segments có status ban đầu là "pending"
                    for seg in proj.segments:
                        if not hasattr(seg, 'status') or seg.status is None:
                            seg.status = "pending"
                    
                    # Store data
                    self.extend_projects_data[proj.project_name] = proj
                    self.extend_project_row_map[proj.project_name] = i
                    
                    # Add row
                    row = self.extend_projects_table.rowCount()
                    self.extend_projects_table.insertRow(row)
                    self.extend_projects_table.setItem(row, 0, QTableWidgetItem(proj.project_name))
                    self.extend_projects_table.setItem(row, 1, QTableWidgetItem(f"{len(proj.segments)} đoạn"))
                    self.extend_projects_table.setItem(row, 2, QTableWidgetItem("⏳ Đang chờ..."))
                    
                    # THÊM TIẾN ĐỘ TEXT (column 3) - hiển thị "0/17"
                    progress_label = QLabel(f"0/{len(proj.segments)}")
                    progress_label.setAlignment(Qt.AlignCenter)
                    progress_label.setStyleSheet("font-weight: bold; color: #666666;")
                    self.extend_projects_table.setCellWidget(row, 3, progress_label)
                    
                    # ✅ BUTTON "Tiếp tục" (column 4) - thay thế "Tạo lại"
                    btn_continue = QPushButton("▶️ Tiếp tục")
                    btn_continue.setMaximumSize(100, 26)
                    btn_continue.setObjectName("retryBtn")
                    btn_continue.setEnabled(False)  # Disable ban đầu, enable khi có lỗi
                    btn_continue.clicked.connect(lambda checked, pname=proj.project_name: self.continue_extend_project(pname))
                    self.extend_projects_table.setCellWidget(row, 4, btn_continue)
                    
                    print(f"🔧 DEBUG: Created project {proj.project_name} with {len(proj.segments)} segments, all set to 'pending' status")
                    
                    # Initialize progress to 0% với màu gray
                    self.update_extend_project_progress(proj.project_name, 0)
                
                self.log(f"✅ Đã thêm {len(projects)} projects vào table")
                
                # Clear prompts table
                self.prompts_table.setRowCount(0)
                self.log("💡 Click vào project trong bảng để xem prompts của project đó")
            except Exception as e:
                self.log(f"❌ Lỗi parse/create projects: {e}")
                self.finalize_extend()
                return
            
            # Initialize stop event
            if not hasattr(self, 'extend_stop_event'):
                self.extend_stop_event = threading.Event()
            self.extend_stop_event.clear()
            
            # Start processing in background
            threading.Thread(
                target=self.extend_worker,
                args=(txt_file if not folder_mode else (folder_path or ""), group_size),
                daemon=True
            ).start()
            
        except Exception as e:
            self.log(f"❌ Lỗi bắt đầu extend: {e}")
            self.finalize_extend()
    
    def on_extend_stop(self):
        """Stop extend processing"""
        try:
            if hasattr(self, 'extend_stop_event'):
                self.extend_stop_event.set()
            self.lbl_extend_status.setText("Đang dừng...")
            self.lbl_extend_status.setStyleSheet("color: red; font-weight: bold;")
            self.log("🛑 Đang dừng extend...")
        except Exception:
            pass
    
    def extend_worker(self, txt_file, group_size):
        """Worker thread for extend video processing"""
        try:
            from extend_videos import ExtendVideoProcessor
            
            self.log(f"\n{'='*70}")
            self.log(f"🎬 BẮT ĐẦU XỬ LÝ EXTEND")
            self.log(f"{'='*70}")
            
            # Get projects từ extend_projects_data (đã được tạo trong on_extend_start)
            projects = list(self.extend_projects_data.values())
            
            if not projects:
                self.log("❌ Không có projects để xử lý")
                return
            
            self.log(f"📊 Xử lý {len(projects)} project(s)")
            
            # ✅ ĐA COOKIE: 1 cookie = 1 project (không cache giữa cookie)
            num_cookies_total = len(self.cookies_list) if self.cookies_list else 0
            active_cookies = []
            dead_cookies = []
            if num_cookies_total == 0:
                QMessageBox.warning(self, "Cảnh báo", "Chưa có cookie để chạy Extend Video!")
                self.finalize_extend()
                return
            # Kiểm tra cookie sống bằng fetch token
            for idx in range(num_cookies_total):
                client = self.build_client(idx)
                if client and client.fetch_access_token():
                    active_cookies.append(idx)
                else:
                    dead_cookies.append(idx)
            if dead_cookies:
                self.log(f"⚠️ Cookie die: {', '.join(str(i+1) for i in dead_cookies)}")
            if not active_cookies:
                QMessageBox.warning(self, "Cảnh báo", "Tất cả cookie đã die. Vui lòng kiểm tra lại trong Cài đặt Cookie.")
                # TODO: mở dialog cài đặt cookie nếu cần
                self.finalize_extend()
                return
            
            import queue
            cookie_queue = queue.Queue()
            for idx in active_cookies:
                cookie_queue.put(idx)
            
            max_workers = min(len(active_cookies), len(projects))
            self.log(f"🔑 Dùng {len(active_cookies)}/{num_cookies_total} cookie sống → workers: {max_workers}")
            
            aspect_map = {
                "16:9": "VIDEO_ASPECT_RATIO_LANDSCAPE",
                "9:16": "VIDEO_ASPECT_RATIO_PORTRAIT"
            }
            aspect = "16:9"  # Default - lấy từ model text
            aspect_value = aspect_map.get(aspect, "VIDEO_ASPECT_RATIO_LANDSCAPE")
            
            # ✅ Tạo project queue để xử lý tuần tự
            project_queue = queue.Queue()
            for project in projects:
                project_queue.put(project)
            
            # Process projects in parallel
            with ThreadPoolExecutor(max_workers=max_workers) as executor:
                future_to_project = {}
                pending_projects = len(projects)
                completed_count = 0
                
                # ✅ Submit projects ban đầu (số lượng = số cookie)
                initial_submits = min(max_workers, pending_projects)
                for _ in range(initial_submits):
                    if self.extend_stop_event.is_set() or project_queue.empty():
                        break
                    
                    try:
                        cookie_index = cookie_queue.get(timeout=5)
                    except Exception:
                        self.log("⚠️ Không lấy được cookie rảnh, dừng submit.")
                        break
                    
                    try:
                        project = project_queue.get_nowait()
                        pending_projects -= 1
                    except Exception:
                        break
                    
                    project_client = self.build_client(cookie_index)
                    if not project_client or not project_client.fetch_access_token():
                        self.log(f"⚠️ Cookie #{cookie_index+1} lỗi, bỏ qua project {project.project_name}")
                        # Trả lại project vào queue
                        project_queue.put(project)
                        pending_projects += 1
                        # Trả lại cookie nếu còn sống
                        if self._is_cookie_active(cookie_index):
                            cookie_queue.put(cookie_index)
                        continue
                    
                    self.log(f"🔑 {project.project_name}: Dùng cookie #{cookie_index+1}/{len(active_cookies)} (hàng đợi rảnh)")
                    
                    with self.extend_retry_lock:
                        self.extend_processing_projects.add(project.project_name)
                    
                    # ✅ Tạo renew cookie callback cho cookie này
                    cookie_str = self.cookies_list[cookie_index] if cookie_index < len(self.cookies_list) else ""
                    renew_cookie_callback = create_renew_cookie_callback(cookie_str) if cookie_str else None
                    
                    processor = ExtendVideoProcessor(
                        project_client, 
                        log_callback=self.log, 
                        aspect_ratio=aspect_value, 
                        stop_event=self.extend_stop_event,
                        cookie_index=cookie_index,
                        renew_cookie_callback=renew_cookie_callback
                    )
                    
                    self.log(f"📤 Submit {project.project_name} vào executor (cookie #{cookie_index+1})")
                    future = executor.submit(
                        self.process_extend_project,
                        processor,
                        project,
                        txt_file
                    )
                    future_to_project[future] = (project, cookie_index)
                    self.log(f"✅ {project.project_name} đã được submit (total futures: {len(future_to_project)}, pending: {pending_projects})")
                
                # ✅ Xử lý kết quả và tiếp tục submit project tiếp theo
                while completed_count < len(projects) and (future_to_project or not project_queue.empty()):
                    if self.extend_stop_event.is_set():
                        break
                    
                    if self.pause_event.is_set():
                        self.log(f"⏸️ PAUSED - Bỏ qua project đang dở và chờ tiếp tục...")
                        while self.pause_event.is_set():
                            if self.extend_stop_event.is_set():
                                break
                            import time
                            time.sleep(0.5)
                        if self.extend_stop_event.is_set():
                            break
                        self.log(f"▶️ RESUMED - Bỏ qua project đang dở, tiếp tục project tiếp theo...")
                    
                    # Đợi một future hoàn thành
                    if not future_to_project:
                        import time
                        time.sleep(0.1)
                        continue
                    
                    # Dùng as_completed với timeout để không block vô hạn
                    try:
                        from concurrent.futures import as_completed, TimeoutError as FuturesTimeoutError
                        for future in as_completed(future_to_project.keys(), timeout=1):
                            if self.extend_stop_event.is_set():
                                break
                            
                            project, cookie_index = future_to_project.pop(future, (None, None))
                            if project is None:
                                continue
                            
                            try:
                                success = future.result()
                                completed_count += 1
                                
                                with self.extend_retry_lock:
                                    self.extend_processing_projects.discard(project.project_name)
                                
                                if success:
                                    self.log(f"✅ {project.project_name} hoàn thành ({completed_count}/{len(projects)})")
                                else:
                                    self.log(f"❌ {project.project_name} thất bại ({completed_count}/{len(projects)})")
                                
                                # ✅ Trả cookie vào queue và submit project tiếp theo nếu còn
                                try:
                                    if self._is_cookie_active(cookie_index):
                                        cookie_queue.put(cookie_index)
                                        
                                        # ✅ Submit project tiếp theo nếu còn
                                        if not project_queue.empty() and not self.extend_stop_event.is_set():
                                            try:
                                                next_project = project_queue.get_nowait()
                                                pending_projects -= 1
                                                
                                                project_client = self.build_client(cookie_index)
                                                if project_client and project_client.fetch_access_token():
                                                    self.log(f"🔑 {next_project.project_name}: Dùng cookie #{cookie_index+1}/{len(active_cookies)} (tiếp tục)")
                                                    
                                                    with self.extend_retry_lock:
                                                        self.extend_processing_projects.add(next_project.project_name)
                                                    
                                                    # ✅ Tạo renew cookie callback cho cookie này
                                                    cookie_str = self.cookies_list[cookie_index] if cookie_index < len(self.cookies_list) else ""
                                                    renew_cookie_callback = create_renew_cookie_callback(cookie_str) if cookie_str else None
                                                    
                                                    processor = ExtendVideoProcessor(
                                                        project_client, 
                                                        log_callback=self.log, 
                                                        aspect_ratio=aspect_value, 
                                                        stop_event=self.extend_stop_event,
                                                        cookie_index=cookie_index,
                                                        renew_cookie_callback=renew_cookie_callback
                                                    )
                                                    
                                                    self.log(f"📤 Submit {next_project.project_name} vào executor (cookie #{cookie_index+1})")
                                                    next_future = executor.submit(
                                                        self.process_extend_project,
                                                        processor,
                                                        next_project,
                                                        txt_file
                                                    )
                                                    future_to_project[next_future] = (next_project, cookie_index)
                                                    self.log(f"✅ {next_project.project_name} đã được submit (total futures: {len(future_to_project)}, pending: {pending_projects})")
                                                else:
                                                    # Cookie lỗi, trả lại project vào queue
                                                    project_queue.put(next_project)
                                                    pending_projects += 1
                                                    self.log(f"⚠️ Cookie #{cookie_index+1} lỗi, trả lại project {next_project.project_name} vào queue")
                                            except Exception as e:
                                                self.log(f"⚠️ Lỗi submit project tiếp theo: {e}")
                                    else:
                                        self.log(f"⚠️ Cookie #{cookie_index+1} die, không đưa lại queue")
                                except Exception as e:
                                    self.log(f"⚠️ Lỗi trả cookie: {e}")
                                
                                QTimer.singleShot(100, self.check_and_process_extend_retry_queue)
                            except Exception as e:
                                self.log(f"❌ {project.project_name} lỗi: {e}")
                                with self.extend_retry_lock:
                                    self.extend_processing_projects.discard(project.project_name)
                                try:
                                    if self._is_cookie_active(cookie_index):
                                        cookie_queue.put(cookie_index)
                                        
                                        # ✅ Submit project tiếp theo nếu còn
                                        if not project_queue.empty() and not self.extend_stop_event.is_set():
                                            try:
                                                next_project = project_queue.get_nowait()
                                                pending_projects -= 1
                                                
                                                project_client = self.build_client(cookie_index)
                                                if project_client and project_client.fetch_access_token():
                                                    self.log(f"🔑 {next_project.project_name}: Dùng cookie #{cookie_index+1}/{len(active_cookies)} (tiếp tục)")
                                                    
                                                    with self.extend_retry_lock:
                                                        self.extend_processing_projects.add(next_project.project_name)
                                                    
                                                    # ✅ Tạo renew cookie callback cho cookie này
                                                    cookie_str = self.cookies_list[cookie_index] if cookie_index < len(self.cookies_list) else ""
                                                    renew_cookie_callback = create_renew_cookie_callback(cookie_str) if cookie_str else None
                                                    
                                                    processor = ExtendVideoProcessor(
                                                        project_client, 
                                                        log_callback=self.log, 
                                                        aspect_ratio=aspect_value, 
                                                        stop_event=self.extend_stop_event,
                                                        cookie_index=cookie_index,
                                                        renew_cookie_callback=renew_cookie_callback
                                                    )
                                                    
                                                    self.log(f"📤 Submit {next_project.project_name} vào executor (cookie #{cookie_index+1})")
                                                    next_future = executor.submit(
                                                        self.process_extend_project,
                                                        processor,
                                                        next_project,
                                                        txt_file
                                                    )
                                                    future_to_project[next_future] = (next_project, cookie_index)
                                                    self.log(f"✅ {next_project.project_name} đã được submit (total futures: {len(future_to_project)}, pending: {pending_projects})")
                                                else:
                                                    # Cookie lỗi, trả lại project vào queue
                                                    project_queue.put(next_project)
                                                    pending_projects += 1
                                            except Exception as e2:
                                                self.log(f"⚠️ Lỗi submit project tiếp theo: {e2}")
                                    else:
                                        self.log(f"⚠️ Cookie #{cookie_index+1} die, không đưa lại queue")
                                except Exception:
                                    pass
                                QTimer.singleShot(100, self.check_and_process_extend_retry_queue)
                    except FuturesTimeoutError:
                        # Timeout - không có future nào hoàn thành trong 1s, tiếp tục vòng lặp
                        import time
                        time.sleep(0.1)
                        continue
                    except Exception as e:
                        self.log(f"⚠️ Lỗi as_completed: {e}")
                        import time
                        time.sleep(0.1)
                        continue
            
            self.log(f"\n🎉 HOÀN TẤT EXTEND VIDEO!")
            QTimer.singleShot(0, lambda: self.lbl_extend_status.setText("Hoàn tất"))
            
            # Kiểm tra và xử lý retry queue sau khi tất cả projects hoàn thành
            QTimer.singleShot(200, self.check_and_process_extend_retry_queue)
            
        except Exception as e:
            self.log(f"❌ Lỗi extend worker: {e}")
            import traceback
            self.log(traceback.format_exc())
        finally:
            QTimer.singleShot(0, self.finalize_extend)
    
    def process_extend_project(self, processor, project, txt_file):
        """Process 1 extend project"""
        try:
            self.log(f"🚀 Bắt đầu xử lý project: {project.project_name}")
            # Status callback to update UI - DÙNG SIGNALS như text to video
            def status_callback(global_idx, status, message):
                try:
                    # Find segment and update status
                    for segment in project.segments:
                        if segment.global_index == global_idx:
                            if status == "processing":
                                segment.status = "processing"
                                # Update segment progress: 50%
                                self.update_extend_segment_progress(project.project_name, global_idx, 50)
                            elif status == "completed":
                                segment.status = "completed"
                                # Update segment progress: 100%
                                self.update_extend_segment_progress(project.project_name, global_idx, 100)
                            elif status == "error":
                                segment.status = "error"
                                segment.error_message = message
                                # Update segment progress: 0%
                                self.update_extend_segment_progress(project.project_name, global_idx, 0)
                            break
                    
                    # Calculate and update project progress
                    project_progress = self.calculate_project_progress(project)
                    self.update_extend_project_progress(project.project_name, project_progress)
                    
                except Exception as e:
                    print(f"❌ Error in status_callback: {e}")
            
            # Get output directory
            output_dir_str = self.txt_extend_output.text().strip()
            if not output_dir_str:
                output_dir_str = str(Path.home() / "Downloads" / "Extended_Videos")
            
            # ✅ Lấy txt_file từ project nếu có (folder mode), hoặc dùng txt_file được truyền vào
            txt_filename = getattr(project, 'txt_file_path', None) or txt_file
            
            # Process project
            self.log(f"🚀 Bắt đầu xử lý project: {project.project_name}")
            success = processor.process_project(
                project=project,
                output_dir=output_dir_str,
                txt_filename=txt_filename,
                status_callback=status_callback
            )
            
            if success:
                self.log(f"✅ Project {project.project_name} xử lý thành công!")
                
                # Download video if concat_url is available
                if project.concat_url:
                    if isinstance(project.concat_url, str) and not project.concat_url.startswith("http"):
                        # Local file (scene_builder đã được tạo)
                        local_path = Path(project.concat_url)
                        if local_path.exists():
                            self.log(f"✅ Video scene_builder đã được lưu: {local_path}")
                            
                            # ✅ Kiểm tra xem các file con đã được tải chưa
                            scenes_dir = local_path.parent / f"{project.project_name}_scenes"
                            expected_scenes = len(project.segments) if hasattr(project, 'segments') else 0
                            
                            if scenes_dir.exists():
                                scene_files = list(scenes_dir.glob("scene_*.mp4"))
                                if len(scene_files) >= expected_scenes:
                                    self.log(f"✅ Đã tải {len(scene_files)}/{expected_scenes} file con")
                                    project.status = "completed"
                                    # ✅ Chỉ set 100% khi cả scene_builder và các file con đã tải xong
                                    self.update_extend_project_progress(project.project_name, 100)
                                else:
                                    self.log(f"⏳ Đang tải file con: {len(scene_files)}/{expected_scenes}")
                                    # Set progress < 100% nếu chưa tải đủ file con
                                    progress = int((len(scene_files) / max(expected_scenes, 1)) * 90)  # 90% max cho scene_builder + scenes
                                    self.update_extend_project_progress(project.project_name, progress)
                            else:
                                # Chưa có thư mục scenes, có thể đang tải
                                self.log(f"⏳ Đang chờ tải file con...")
                                self.update_extend_project_progress(project.project_name, 90)  # 90% khi có scene_builder
                    else:
                        # URL - need download
                        output_dir = Path(output_dir_str)
                        output_dir.mkdir(parents=True, exist_ok=True)
                        filename = output_dir / f"{project.project_name}_extended.mp4"
                        
                        if self.download_video_simple(project.concat_url, filename):
                            self.log(f"✅ Đã lưu video: {filename.name}")
                            
                            # ✅ Kiểm tra xem các file con đã được tải chưa
                            scenes_dir = output_dir / f"{project.project_name}_scenes"
                            expected_scenes = len(project.segments) if hasattr(project, 'segments') else 0
                            
                            if scenes_dir.exists():
                                scene_files = list(scenes_dir.glob("scene_*.mp4"))
                                if len(scene_files) >= expected_scenes:
                                    self.log(f"✅ Đã tải {len(scene_files)}/{expected_scenes} file con")
                                    project.status = "completed"
                                    # ✅ Chỉ set 100% khi cả scene_builder và các file con đã tải xong
                                    self.update_extend_project_progress(project.project_name, 100)
                                else:
                                    self.log(f"⏳ Đang tải file con: {len(scene_files)}/{expected_scenes}")
                                    progress = int((len(scene_files) / max(expected_scenes, 1)) * 90)
                                    self.update_extend_project_progress(project.project_name, progress)
                            else:
                                self.log(f"⏳ Đang chờ tải file con...")
                                self.update_extend_project_progress(project.project_name, 90)
            else:
                self.log(f"❌ Project {project.project_name} thất bại")
                # Set progress to 0% on failure
                self.update_extend_project_progress(project.project_name, 0)
            
            return success
            
        except Exception as e:
            self.log(f"❌ Lỗi process extend project: {e}")
            import traceback
            self.log(traceback.format_exc())
            return False
    
    def update_extend_project_progress(self, project_name, progress_percent):
        """Update project progress - emit signal (thread-safe)"""
        try:
            self.signals.update_extend_project.emit(project_name, progress_percent)
        except Exception as e:
            print(f"❌ Error emitting extend project progress: {e}")
    
    @Slot(str, int)
    def update_extend_project_progress_slot(self, project_name, progress_percent):
        """SLOT: Update extend project progress - chạy trong main thread"""
        try:
            
            row = self.extend_project_row_map.get(project_name)
            if row is None:
                print(f"⚠️ Row not found for project: {project_name}")
                return
            
            if row >= self.extend_projects_table.rowCount():
                print(f"⚠️ Row {row} out of range")
                return
            
            # Update progress label (column 3) - hiển thị "5/17"
            progress_widget = self.extend_projects_table.cellWidget(row, 3)
            
            # ✅ Tính toán số segments đã chạy và tổng số segments
            if not hasattr(self, 'extend_projects_data') or project_name not in self.extend_projects_data:
                return
                
            project = self.extend_projects_data[project_name]
            total_segments = len(project.segments)
            completed_segments = sum(1 for seg in project.segments if hasattr(seg, 'status') and seg.status == "completed")
            error_segments = sum(1 for seg in project.segments if hasattr(seg, 'status') and seg.status == "error")
            processing_segments = sum(1 for seg in project.segments if hasattr(seg, 'status') and seg.status == "processing")
            
            # ✅ Số segments đã chạy = completed + error (cả 2 đều đã chạy, chỉ khác kết quả)
            completed_count = completed_segments + error_segments
            
            if isinstance(progress_widget, QLabel):
                # ✅ Update text với format "đã chạy/tổng" (ví dụ: "5/17")
                progress_text = f"{completed_count}/{total_segments}"
                progress_widget.setText(progress_text)
                
                # Update color based on status
                if progress_percent == 100:
                    color = "#4CAF50"  # Green
                elif error_segments > 0:
                    color = "#F44336"  # Red
                elif processing_segments > 0:
                    color = "#2196F3"  # Blue
                else:
                    color = "#666666"  # Gray
                
                progress_widget.setStyleSheet(f"font-weight: bold; color: {color};")
                print(f"✅ Extend project progress updated: {project_name} → {progress_text}")
            else:
                print(f"⚠️ Progress widget not found for row {row}, type: {type(progress_widget)}")
            
            if progress_percent == 100:
                status_text = "✅ HOÀN THÀNH"
            elif error_segments > 0:
                status_text = f"⚠️ {error_segments} lỗi ({completed_segments}/{total_segments} OK)"
            elif processing_segments > 0:
                status_text = f"🔄 Đang xử lý ({completed_segments}/{total_segments})"
            else:
                status_text = f"⏳ Đang chờ ({completed_segments}/{total_segments})"
            
            self.extend_projects_table.setItem(row, 2, QTableWidgetItem(status_text))
            
            # ✅ Enable button "Tiếp tục" CHỈ khi có lỗi (không enable khi hoàn thành 100%)
            continue_btn = self.extend_projects_table.cellWidget(row, 4)
            if continue_btn and isinstance(continue_btn, QPushButton):
                # Enable CHỈ khi có lỗi (để tiếp tục từ vị trí lỗi)
                if error_segments > 0:
                    continue_btn.setEnabled(True)
                else:
                    continue_btn.setEnabled(False)
                
        except Exception as e:
            print(f"❌ Lỗi update extend project progress slot: {e}")
    
    def update_extend_segment_progress(self, project_name, segment_idx, progress_percent):
        """Update segment progress - emit signal (thread-safe)"""
        try:
            self.signals.update_extend_segment.emit(project_name, segment_idx, progress_percent)
        except Exception as e:
            print(f"❌ Error emitting extend segment progress: {e}")
    
    @Slot(str, int, int)
    def update_extend_segment_progress_slot(self, project_name, segment_idx, progress_percent):
        """SLOT: Update extend segment progress trong prompts table - chạy trong main thread"""
        try:
            
            # Check if project đang được select
            current_selection = self.extend_projects_table.currentRow()
            if current_selection < 0:
                return
                
            # Get selected project name
            project_item = self.extend_projects_table.item(current_selection, 0)
            if not project_item:
                return
                
            selected_project_name = project_item.text()
            
            # Chỉ update nếu project đang được hiển thị
            if project_name != selected_project_name:
                return
            
            # Find segment row trong prompts table
            for row in range(self.prompts_table.rowCount()):
                prompt_item = self.prompts_table.item(row, 1)
                if not prompt_item:
                    continue
                
                # Extract segment index từ display text (format: "index: text...")
                prompt_text = prompt_item.text()
                if ': ' in prompt_text:
                    try:
                        idx_str = prompt_text.split(': ')[0]
                        idx = int(idx_str)
                        
                        if idx == segment_idx:
                            
                            # Update progress bar - GIỐNG HỆT text to video
                            progress_bar = self.prompts_table.cellWidget(row, 2)
                            if isinstance(progress_bar, QProgressBar):
                                # Update value
                                progress_bar.setValue(progress_percent)
                                
                                # Update color - GIỐNG HỆT text to video
                                if progress_percent == 0:
                                    chunk_color = "#9E9E9E"  # Gray
                                elif progress_percent < 30:
                                    chunk_color = "#FF9800"  # Orange
                                elif progress_percent < 70:
                                    chunk_color = "#2196F3"  # Blue
                                elif progress_percent < 100:
                                    chunk_color = "#1976D2"  # Dark Blue
                                else:
                                    chunk_color = "#4CAF50"  # Green
                                
                                progress_bar.setStyleSheet(f"""
                                    QProgressBar {{
                                        border: 1px solid #BDBDBD;
                                        border-radius: 3px;
                                        text-align: center;
                                        background-color: #F5F5F5;
                                        font-weight: bold;
                                        font-size: 10px;
                                    }}
                                    QProgressBar::chunk {{
                                        background-color: {chunk_color};
                                        border-radius: 2px;
                                    }}
                                """)
                                
                                print(f"✅ Segment {segment_idx} progress updated to {progress_percent}%")
                            
                            # ✅ Cập nhật cột trạng thái (column 3) - "Done" (xanh lá) hoặc "Error" (đỏ)
                            status_item = self.prompts_table.item(row, 3)
                            if not status_item:
                                status_item = QTableWidgetItem()
                                status_item.setTextAlignment(Qt.AlignCenter)
                                self.prompts_table.setItem(row, 3, status_item)
                            
                            if progress_percent >= 100:
                                status_item.setText("Done")
                                status_item.setForeground(QColor("#4CAF50"))  # Xanh lá
                                status_item.setData(Qt.ForegroundRole, QColor("#4CAF50"))
                            elif progress_percent == 0:
                                # ✅ Kiểm tra nếu segment có status = "error"
                                if hasattr(self, 'extend_projects_data') and project_name in self.extend_projects_data:
                                    project = self.extend_projects_data[project_name]
                                    for seg in project.segments:
                                        if seg.global_index == segment_idx and hasattr(seg, 'status') and seg.status == "error":
                                            status_item.setText("Error")
                                            status_item.setForeground(QColor("#F44336"))  # Đỏ
                                            status_item.setData(Qt.ForegroundRole, QColor("#F44336"))
                                            break
                                    else:
                                        # Nếu không tìm thấy segment error, vẫn hiển thị "Đang xử lý..."
                                        status_item.setText("Đang xử lý...")
                                        status_item.setForeground(QColor("#666666"))  # Xám
                                        status_item.setData(Qt.ForegroundRole, QColor("#666666"))
                                else:
                                    status_item.setText("Error")
                                    status_item.setForeground(QColor("#F44336"))  # Đỏ
                                    status_item.setData(Qt.ForegroundRole, QColor("#F44336"))
                            else:
                                status_item.setText("Đang xử lý...")
                                status_item.setForeground(QColor("#666666"))  # Xám
                                status_item.setData(Qt.ForegroundRole, QColor("#666666"))
                            
                            break
                    except (ValueError, IndexError):
                        continue
            
        except Exception as e:
            print(f"❌ Error updating segment progress slot: {e}")
    
    def calculate_project_progress(self, project):
        """Tính progress của project từ segments - GIỐNG LOGIC text to video"""
        try:
            total_segments = len(project.segments)
            if total_segments == 0:
                return 0
            
            total_progress_points = 0
            for seg in project.segments:
                if hasattr(seg, 'status'):
                    if seg.status == "completed":
                        total_progress_points += 100  # 100% cho completed
                    elif seg.status == "processing":
                        total_progress_points += 50   # 50% cho processing
                    elif seg.status == "error":
                        total_progress_points += 0    # 0% cho error
                    else:  # pending
                        total_progress_points += 0    # 0% cho pending
                else:
                    total_progress_points += 0
            
            progress_pct = int(total_progress_points / total_segments)
            
            
            return progress_pct
            
        except Exception as e:
            print(f"❌ Error calculating project progress: {e}")
            return 0
    
    def download_video_simple(self, url, filename):
        """Simple video download"""
        try:
            headers = {
                "user-agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) Chrome/120.0.0.0"
            }
            
            self.log(f"📥 Downloading: {url}")
            
            with requests.get(url, headers=headers, stream=True, timeout=120) as r:
                r.raise_for_status()
                
                with open(filename, 'wb') as f:
                    for chunk in r.iter_content(chunk_size=8192):
                        if self.extend_stop_event.is_set():
                            return False
                        if chunk:
                            f.write(chunk)
            
            if filename.exists() and filename.stat().st_size > 0:
                size_mb = filename.stat().st_size / 1024 / 1024
                self.log(f"✅ Downloaded: {filename.name} ({size_mb:.1f}MB)")
                return True
            
            return False
            
        except Exception as e:
            self.log(f"❌ Download error: {e}")
            return False
    
    
    def finalize_extend(self):
        """Finalize extend processing"""
        try:
            self.btn_extend_start.setEnabled(True)
            self.btn_extend_stop.setEnabled(False)
            if self.lbl_extend_status.text() != "Hoàn tất":
                self.lbl_extend_status.setText("Sẵn sàng")
                self.lbl_extend_status.setStyleSheet("color: green; font-weight: bold;")
        except Exception:
            pass
    
    def continue_extend_project(self, project_name):
        """Tiếp tục extend project từ vị trí lỗi - tìm segment lỗi đầu tiên và cho phép chỉnh sửa"""
        try:
            self.log(f"▶️ Tiếp tục project: {project_name}")
            
            # Check if project exists
            if not hasattr(self, 'extend_projects_data') or project_name not in self.extend_projects_data:
                QMessageBox.warning(self, "Lỗi", f"Không tìm thấy project: {project_name}")
                return
            
            project = self.extend_projects_data[project_name]
            
            # ✅ Tìm segment lỗi đầu tiên
            error_segment_index = None
            for seg in project.segments:
                if hasattr(seg, 'status') and seg.status == "error":
                    error_segment_index = seg.index
                    self.log(f"🔍 Tìm thấy segment lỗi: {error_segment_index} - {seg.text[:50]}...")
                    break
            
            if error_segment_index is None:
                QMessageBox.information(self, "Thông báo", "Không tìm thấy segment lỗi trong project này.")
                return
            
            # ✅ Hiển thị prompts table với segment lỗi được highlight
            self.load_extend_project_prompts_to_table(project)
            
            # ✅ Tìm và highlight row chứa segment lỗi trong prompts table
            for row in range(self.prompts_table.rowCount()):
                prompt_item = self.prompts_table.item(row, 1)
                if prompt_item:
                    prompt_text = prompt_item.text()
                    if ':' in prompt_text:
                        try:
                            idx_str = prompt_text.split(':')[0].strip()
                            idx = int(idx_str)
                            if idx == error_segment_index:
                                # Highlight row lỗi
                                self.prompts_table.selectRow(row)
                                self.prompts_table.scrollToItem(prompt_item)
                                self.log(f"📍 Đã highlight segment lỗi ở row {row}")
                                break
                        except (ValueError, IndexError):
                            continue
            
            # ✅ Mở dialog chỉnh sửa prompt (tự động focus vào segment lỗi)
            dialog = ExtendProjectEditDialog(project, self, highlight_index=error_segment_index)
            if dialog.exec() == QDialog.Accepted:
                # User đã chỉnh sửa và lưu
                self.log(f"✅ Đã chỉnh sửa prompts cho {project_name}")
                
                # ✅ Xác định segment cần chạy lại (segment lỗi đầu tiên)
                resume_index = error_segment_index
                project.resume_from_index = resume_index
                
                # Reset trạng thái từ segment cần chạy lại
                for seg in project.segments:
                    if seg.index >= resume_index:
                        seg.status = "pending"
                        seg.error_message = ""
                        seg.media_id = None
                        seg.video_url = None
                
                # Reset progress to 0
                self.update_extend_project_progress(project_name, 0)
                
                # Get txt_file from input
                txt_file = self.txt_extend_txt_file.text().strip()
                if not txt_file or not Path(txt_file).exists():
                    # ✅ Thử lấy từ folder mode - tìm file txt có tên giống project name
                    if hasattr(self, 'txt_extend_txt_folder') and self.txt_extend_txt_folder.text().strip():
                        folder_path = Path(self.txt_extend_txt_folder.text().strip())
                        if folder_path.exists() and folder_path.is_dir():
                            # Tìm file txt có tên giống project name
                            txt_file_path = folder_path / f"{project_name}.txt"
                            if txt_file_path.exists():
                                txt_file = str(txt_file_path)
                            else:
                                # Fallback: tìm file txt đầu tiên trong folder
                                txt_files = list(folder_path.glob("*.txt"))
                                if txt_files:
                                    txt_file = str(txt_files[0])
                                else:
                                    QMessageBox.warning(self, "Lỗi", f"Không tìm thấy file TXT cho project: {project_name}")
                                    return
                        else:
                            QMessageBox.warning(self, "Lỗi", "Thư mục TXT không hợp lệ!")
                            return
                    else:
                        QMessageBox.warning(self, "Lỗi", "File TXT không hợp lệ!")
                        return
                
                # Disable button
                row = self.extend_project_row_map.get(project_name)
                if row is not None:
                    continue_btn = self.extend_projects_table.cellWidget(row, 4)
                    if continue_btn:
                        continue_btn.setEnabled(False)
                    
                    # Update status
                    self.extend_projects_table.setItem(row, 2, QTableWidgetItem("⏳ Chờ trong hàng đợi..."))
                
                # Đưa vào retry queue
                with self.extend_retry_lock:
                    retry_item = {
                        'project_name': project_name,
                        'project': project,
                        'txt_file': txt_file
                    }
                    self.extend_retry_queue.append(retry_item)
                    queue_size = len(self.extend_retry_queue)
                
                self.log(f"📋 Đã thêm {project_name} vào retry queue (vị trí #{queue_size}) - Resume từ segment {resume_index}")
                
                # Kiểm tra và xử lý queue nếu không có project nào đang chạy
                self.check_and_process_extend_retry_queue()
            else:
                self.log(f"ℹ️ Hủy chỉnh sửa {project_name}")
            
        except Exception as e:
            self.log(f"❌ Lỗi continue project: {e}")
            QMessageBox.critical(self, "Lỗi", f"Không thể tiếp tục: {e}")
    
    def retry_extend_project(self, project_name):
        """Retry (tạo lại) 1 extend project - mở dialog chỉnh sửa prompt (giữ lại để tương thích)"""
        # Gọi continue_extend_project thay vì retry
        self.continue_extend_project(project_name)
    
    def check_and_process_extend_retry_queue(self):
        """✅ Kiểm tra và xử lý retry queue - chạy ngay khi có slot trống"""
        try:
            with self.extend_retry_lock:
                if not self.extend_retry_queue:
                    return  # Không có gì trong queue
                
                # ✅ Tính số slot còn trống
                num_cookies = len(self.cookies_list) if self.cookies_list else 1
                projects_per_cookie = 1  # 1 cookie chạy 1 project (không cache giữa cookie)
                max_concurrent_projects = num_cookies * projects_per_cookie
                
                current_running = len(self.extend_processing_projects)
                available_slots = max_concurrent_projects - current_running
                
                # ✅ Chạy ngay khi có slot trống
                while available_slots > 0 and self.extend_retry_queue:
                    retry_item = self.extend_retry_queue.pop(0)
                    project_name = retry_item['project_name']
                    project = retry_item['project']
                    txt_file = retry_item['txt_file']
                    
                    # Thêm vào set đang chạy
                    self.extend_processing_projects.add(project_name)
                    current_running += 1
                    available_slots -= 1
                    
                    # Update status
                    row = self.extend_project_row_map.get(project_name)
                    if row is not None:
                        self.extend_projects_table.setItem(row, 2, QTableWidgetItem("🔄 Đang xử lý..."))
                    
                    self.log(f"🚀 Bắt đầu retry {project_name} từ queue (slot {current_running}/{max_concurrent_projects})")
                    
                    # Start retry in background thread
                    threading.Thread(
                        target=self.retry_extend_worker,
                        args=(project, txt_file, project_name),
                        daemon=True
                    ).start()
                
                # Log nếu còn projects trong queue nhưng không có slot
                if self.extend_retry_queue and available_slots == 0:
                    queue_size = len(self.extend_retry_queue)
                    self.log(f"⏳ Retry queue có {queue_size} project(s) đang chờ (đã đầy {current_running}/{max_concurrent_projects} slots)")
        except Exception as e:
            self.log(f"❌ Lỗi check retry queue: {e}")
    
    def retry_extend_worker(self, project, txt_file, project_name):
        """Worker thread for retry extend project"""
        try:
            from extend_videos import ExtendVideoProcessor
            
            self.log(f"🚀 Bắt đầu retry project: {project.project_name}")
            
            # ✅ ĐA COOKIE: Chọn cookie theo round-robin
            num_cookies = len(self.cookies_list) if self.cookies_list else 1
            cookie_index = (hash(project_name) % num_cookies)  # Deterministic cookie selection
            
            # Build client với cookie này
            client = self.build_client(cookie_index)
            if not client or not client.fetch_access_token():
                self.log(f"⚠️ Cookie #{cookie_index+1} lỗi, thử cookie khác...")
                # Fallback: thử cookie 0
                client = self.build_client(0)
            if not client or not client.fetch_access_token():
                self.log("❌ Không thể tạo client hoặc lấy token")
                QTimer.singleShot(0, lambda: self.lbl_extend_status.setText("Lỗi"))
                # Remove from processing set
                with self.extend_retry_lock:
                    self.extend_processing_projects.discard(project_name)
                # Process next in queue
                QTimer.singleShot(100, self.check_and_process_extend_retry_queue)
                return
            
            self.log(f"🔑 Retry {project.project_name}: Dùng cookie #{cookie_index+1}/{num_cookies}")
            
            # Get aspect ratio from combo
            aspect_map = {
                "16:9": "VIDEO_ASPECT_RATIO_LANDSCAPE",
                "9:16": "VIDEO_ASPECT_RATIO_PORTRAIT"
            }
            aspect = "16:9"  # Default - lấy từ model text
            aspect_value = aspect_map.get(aspect, "VIDEO_ASPECT_RATIO_LANDSCAPE")
            
            # Create processor with aspect ratio
            processor = ExtendVideoProcessor(client, log_callback=self.log, aspect_ratio=aspect_value, stop_event=self.extend_stop_event)
            
            # Process project (reuse existing logic)
            success = self.process_extend_project(processor, project, txt_file)
            
            # Remove from processing set
            with self.extend_retry_lock:
                self.extend_processing_projects.discard(project_name)
            
            if success:
                self.log(f"✅ Retry thành công: {project.project_name}")
                QTimer.singleShot(0, lambda: self.lbl_extend_status.setText("Hoàn tất"))
            else:
                self.log(f"❌ Retry thất bại: {project.project_name}")
                QTimer.singleShot(0, lambda: self.lbl_extend_status.setText("Lỗi"))
            
            # Process next in queue
            QTimer.singleShot(100, self.check_and_process_extend_retry_queue)
                
        except Exception as e:
            self.log(f"❌ Lỗi retry worker: {e}")
            import traceback
            self.log(traceback.format_exc())
            QTimer.singleShot(0, lambda: self.lbl_extend_status.setText("Lỗi"))
            
            # Remove from processing set
            with self.extend_retry_lock:
                self.extend_processing_projects.discard(project_name)
            
            # Process next in queue
            QTimer.singleShot(100, self.check_and_process_extend_retry_queue)
    
