    def _download_worker(self):
        """Download worker - tải video về (NỘI BỘ - KHÔNG BỊ DỪNG BỞI USER ACTIONS)"""
        while True:
            # CHỈ sleep khi stop_event được set (khi user ấn Stop Processing)
            if self.stop_event.is_set():
                time.sleep(0.2)
                continue
            
            try:
                task = self.download_queue.get(timeout=0.2)
            except queue.Empty:
                continue
            
            try:
                # ✅ Retry download tối đa 3 lần trước khi đánh Fail
                max_attempts = 3
                success = False
                
                for attempt in range(1, max_attempts + 1):
                    try:
                        self.log(f"📥 Đang tải ({attempt}/{max_attempts}): {task.target_path.name}")
                        
                        # Ensure directory exists
                        task.target_path.parent.mkdir(parents=True, exist_ok=True)
                        
                        # Download via requests
                        headers = {
                            "user-agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) Chrome/120.0.0.0"
                        }
                        
                        with requests.get(task.url, headers=headers, stream=True, timeout=120) as r:
                            r.raise_for_status()
                            
                            # Get file size if available
                            total_size = int(r.headers.get('content-length', 0))
                            downloaded = 0
                            
                            with open(task.target_path, 'wb') as f:
                                for chunk in r.iter_content(chunk_size=8192):
                                    # ❌ KHÔNG check stop_event trong loop để tránh corrupt file
                                    if chunk:
                                        f.write(chunk)
                                        downloaded += len(chunk)
                                        
                                        # Log progress mỗi ~5MB (giảm spam log)
                                        if total_size > 0 and downloaded % (5 * 1024 * 1024) < 8192:
                                            progress = (downloaded / total_size) * 100
                                            self.log(
                                                f"📊 {task.target_path.name}: "
                                                f"{progress:.1f}% ({downloaded//1024//1024}/{total_size//1024//1024}MB)"
                                            )
                        
                        # Kiểm tra file sau khi tải
                        if task.target_path.exists() and task.target_path.stat().st_size > 0:
                            size_mb = task.target_path.stat().st_size / 1024 / 1024
                            self.log(f"✅ Đã tải: {task.target_path.name} ({size_mb:.1f}MB)")
                            success = True
                            break
                        else:
                            self.log(f"⚠️ File không tồn tại hoặc rỗng sau download: {task.target_path.name}")
                    
                    except requests.exceptions.RequestException as e:
                        self.log(f"❌ Lỗi mạng khi tải {task.target_path.name} (lần {attempt}/{max_attempts}): {e}")
                    except Exception as e:
                        self.log(f"❌ Lỗi tải {task.target_path.name} (lần {attempt}/{max_attempts}): {e}")
                    
                    # Nếu chưa thành công và còn attempt → đợi ngắn rồi thử lại
                    if not success and attempt < max_attempts:
                        time.sleep(2)
                
                # Sau khi retry đủ 3 lần mà vẫn fail → đánh Fail cho task liên quan
                if not success:
                    self.log(f"🛑 Tải thất bại sau {max_attempts} lần: {task.target_path.name}")
                    
                    # Xóa file rác (nếu có)
                    try:
                        if task.target_path.exists():
                            task.target_path.unlink()
                    except Exception:
                        pass
                    
                    # Thử parse task_index từ tên file: {index:03d}_xxxx.mp4
                    try:
                        stem = task.target_path.stem
                        idx_str = stem.split('_', 1)[0]
                        if idx_str.isdigit():
                            task_index = int(idx_str)
                            # Cập nhật UI: đánh Fail và progress = 0
                            try:
                                self.signals.update_status.emit(task_index, "Fail (Download lỗi)")
                                self.signals.update_progress.emit(task_index, 0)
                            except Exception:
                                # Nếu signal lỗi thì bỏ qua, tránh crash worker
                                pass
                    except Exception:
                        # Không parse được index → chỉ log, không update UI
                        pass
            
            finally:
                # Đảm bảo task_done được gọi
                try:
                    self.download_queue.task_done()
                except Exception:
                    pass
    
    # ===== INTEGRATE TO VIDEO METHODS =====
    
    def process_single_start_end_task(self, client, task, model, num_videos, aspect, output_folder, total_tasks, wave_position=1, retry_count=0):
        """Process 1 Start+End task (parallel) - VỚI RETRY VÀ COOKIE ERROR HANDLING"""
        try:
            # ✅ Check pause_event ngay đầu hàm - dừng ngay lập tức
            if self.pause_event.is_set():
                self.log(f"⏸️ PAUSED - Dừng task ngay lập tức")
                return False
            
            idx = task.task_index
            max_retries = 6
            
            # Initialize failed cookies set nếu chưa có
            if not hasattr(task, "_failed_cookies"):
                task._failed_cookies = set()
            
            # Smart delay + Multi-cookie với retry logic
            num_cookies = len(self.cookies_list) if self.cookies_list else 1
            cookie_index = None
            
            if num_cookies > 1:
                # Round-robin qua các cookie đang hoạt động
                self._init_cookie_status()
                
                # Nếu đang retry, bỏ qua cookie đã lỗi
                failed_cookies = getattr(task, "_failed_cookies", set())
                preferred_cookie = getattr(task, "_forced_cookie_index", None)
                candidate_order = []
                if preferred_cookie is not None:
                    candidate_order.append(preferred_cookie)
                for shift in range(num_cookies):
                    candidate = ((idx - 1) + shift) % num_cookies
                    if candidate not in candidate_order:
                        candidate_order.append(candidate)
                    
                for cookie_index in candidate_order:
                    # Skip cookie không active hoặc đã lỗi
                    if not self._is_cookie_active(cookie_index) or cookie_index in failed_cookies:
                        continue
                    
                    self.log(f"🔑 Start+End: Cookie #{cookie_index + 1}/{num_cookies}")
                    task_client = self.build_client(cookie_index)
                    
                    if task_client and task_client.fetch_access_token():
                        client = task_client
                        try:
                            setattr(task, "_cookie_index", cookie_index)
                            # Đăng ký task đang dùng cookie này
                            self._register_task_cookie(idx, cookie_index)
                        except Exception:
                            pass
                        break
                    else:
                        error_msg = "Fetch token thất bại"
                        self.log(f"⚠️ Cookie #{cookie_index + 1} lỗi: {error_msg}")
                        self._deactivate_cookie(cookie_index, error_msg)
                        failed_cookies.add(cookie_index)
                else:
                    # Không còn cookie nào active
                    self.log(f"🛑 Không còn cookie hoạt động cho task {idx}")
                    self._unregister_task_cookie(idx)
                    self.signals.update_status.emit(idx, "Không có cookie")
                    self.update_task_progress(idx, 0)
                    return False
            else:
                # Single cookie - vẫn đăng ký
                cookie_index = 0
                try:
                    setattr(task, "_cookie_index", cookie_index)
                    self._register_task_cookie(idx, cookie_index)
                except Exception:
                    pass
            
            self.log(f"\n{'='*50}")
            self.log(f"🎬 Task {idx}/{total_tasks}: {Path(task.image_path).name} → {Path(task.end_image_path).name}")
            
            self.signals.update_status.emit(idx, "Đang xử lý")
            self.update_task_progress(idx, 5)
            
            result = self._execute_start_end_video(client, task, model, num_videos, aspect, output_folder)
            
            if result:
                # ✅ Task thành công - hủy đăng ký
                self._unregister_task_cookie(idx)
                self.signals.update_status.emit(idx, "Done")
                self.update_task_progress(idx, 100)
            else:
                # ✅ Kiểm tra cookie error và retry
                error_detail = ""
                try:
                    error_detail = getattr(client, "last_error_detail", "") or ""
                    if not error_detail:
                        error_detail = getattr(client, "last_error", "") or ""
                except Exception:
                    pass
                
                # Check nếu là cookie error
                is_cookie_error = False
                if cookie_index is not None and error_detail:
                    is_cookie_error = self._check_cookie_error(error_detail, cookie_index)
                    if is_cookie_error:
                        self._deactivate_cookie(cookie_index, f"Lỗi Start+End: {error_detail[:120]}")
                        self._unregister_task_cookie(idx)
                        
                        # Thêm cookie vào failed list
                        task._failed_cookies.add(cookie_index)
                        
                        # Retry với cookie khác nếu còn retry và còn cookie
                        if retry_count < max_retries and num_cookies > 1:
                            self.log(f"🔄 Retry task {idx} với cookie khác (lần {retry_count + 1}/{max_retries})")
                            self.signals.update_status.emit(idx, f"Retry {retry_count + 1}")
                            
                            return self.process_single_start_end_task(
                                client, task, model, num_videos, aspect, output_folder, 
                                total_tasks, wave_position, retry_count + 1
                            )
                        else:
                            self.signals.update_status.emit(idx, "Fail (Cookie lỗi)")
                            self.update_task_progress(idx, 0)
                            return False
                
                # Không phải cookie error hoặc không còn retry
                self._unregister_task_cookie(idx)
                self.signals.update_status.emit(idx, "Fail")
                self.update_task_progress(idx, 0)
            
            self.signals.update_batch.emit(idx, total_tasks)
            
            return result
            
        except Exception as e:
            self.log(f"❌ Lỗi Start+End task {idx}: {e}")
            self._unregister_task_cookie(idx)
            self.signals.update_status.emit(idx, "Fail")
            self.update_task_progress(idx, 0)
            return False
    
