    def _concat_videos_expand_reference(self, client, media_generation_ids, task_idx):
        """Gọi concat API để nối các video lại với nhau
        
        Args:
            client: LabsFlowClient instance
            media_generation_ids: List[str] - Danh sách mediaGenerationId cần nối
            task_idx: int - Task index để log
            
        Returns:
            dict: Concat result hoặc None nếu lỗi
        """
        try:
            if not media_generation_ids or len(media_generation_ids) == 0:
                self.log(f"❌ Không có mediaGenerationId để concat")
                return None
            
            if len(media_generation_ids) < 2:
                self.log(f"⚠️ Cần ít nhất 2 video để concat, hiện có {len(media_generation_ids)}")
                return None
            
            self.log(f"🔗 Concat {len(media_generation_ids)} video(s)")
            
            # Đợi videos sẵn sàng
            import time
            self.log("⏳ Đợi videos sẵn sàng trước khi ghép (10s)...")
            time.sleep(10)
            
            # Build input videos
            input_videos = []
            for i, media_id in enumerate(media_generation_ids):
                input_videos.append({
                    "mediaGenerationId": media_id,
                    "lengthNanos": 8000,  # 8 seconds
                    "startTimeOffset": "0.000000000s" if i == 0 else "1.000000000s",
                    "endTimeOffset": "8.000000000s"
                })
            
            payload = {
                "json": {
                    "requestInput": {
                        "inputVideos": input_videos
                    }
                }
            }
            
            # Call concat API
            url = "https://labs.google/fx/api/trpc/videoFx.runConcatenateVideos"
            
            headers = {
                "accept": "*/*",
                "content-type": "application/json",
                "user-agent": "Mozilla/5.0",
                "origin": "https://labs.google",
                "referer": "https://labs.google/fx/tools/flow",
            }
            
            # Parse cookie
            cookie_index = getattr(self, "_cookie_index", None)
            cookies = None
            if self.cookies_list:
                cookies = self.cookies_list[0] if len(self.cookies_list) > 0 else None
            elif self.cookie_value:
                cookies = self.cookie_value
            
            if cookies:
                parsed_cookies = _parse_cookie_string(cookies)
                if parsed_cookies:
                    cookie_header_str = '; '.join([f"{k}={v}" for k, v in parsed_cookies.items()])
                    headers["cookie"] = cookie_header_str
            
            max_retries = 6
            resp = None
            for retry in range(max_retries):
                try:
                    import requests
                    resp = requests.post(url, headers=headers, json=payload, timeout=90)
                    
                    if resp.status_code == 200:
                        break
                    elif resp.status_code == 500 and retry < max_retries - 1:
                        wait_time = min(30, (retry + 1) * 10)
                        self.log(f"⚠️ Server error 500, đợi {wait_time}s trước khi thử lại...")
                        time.sleep(wait_time)
                        if retry >= 2:
                            client.fetch_access_token()
                    else:
                        error_text = resp.text[:500] if hasattr(resp, 'text') else ""
                        self.log(f"❌ Concat failed: {error_text}")
                        break
                except Exception as e:
                    self.log(f"❌ Lỗi khi gọi concat API: {e}")
                    if retry < max_retries - 1:
                        wait_time = (retry + 1) * 5
                        time.sleep(wait_time)
                    else:
                        return None
            
            if not resp or resp.status_code != 200:
                if resp:
                    self.log(f"❌ Concat failed: {resp.text[:200] if hasattr(resp, 'text') else ''}")
                else:
                    self.log(f"❌ Concat failed: No response received")
                return None
            
            result = resp.json()
            
            # Extract operation name
            operation_name = None
            if isinstance(result, dict):
                try:
                    json_data = result.get("result", {}).get("data", {}).get("json", {})
                    if json_data:
                        op_result = json_data.get("result", {})
                        op_container = op_result.get("operation", {})
                        inner_op = op_container.get("operation", {})
                        operation_name = inner_op.get("name")
                    
                    if not operation_name:
                        op = result.get("result", {}).get("data", {}).get("operation", {})
                        if isinstance(op, dict):
                            inner_op = op.get("operation", {})
                            operation_name = inner_op.get("name") or op.get("name")
                    
                    if not operation_name and "operation" in str(result):
                        import re
                        match = re.search(r'"name":\s*"([^"]+)"', str(result))
                        if match:
                            operation_name = match.group(1)
                except Exception as e:
                    self.log(f"❌ Error parsing operation name: {e}")
            
            if not operation_name:
                self.log(f"❌ Không tìm thấy operation name trong response")
                return None
            
            self.log(f"✅ Concat operation started: {operation_name[:50]}...")
            
            # Poll concat status
            self.log("⏳ Đang chờ concat hoàn thành...")
            concat_result = self._poll_concat_status_expand_reference(client, operation_name)
            
            return concat_result
            
        except Exception as e:
            self.log(f"❌ Lỗi concat videos: {e}")
            import traceback
            self.log(traceback.format_exc())
            return None
    
    def _concat_large_expand_reference_project(self, client, media_generation_ids, output_folder):
        """Concat project lớn (> 5 videos): chia thành batch 5, mỗi batch dùng API concat Google, sau đó dùng FFmpeg nối lại
        
        Args:
            client: LabsFlowClient instance
            media_generation_ids: List[str] - Danh sách mediaGenerationId cần nối
            output_folder: str - Thư mục output
            
        Returns:
            dict: Concat result với URLs hoặc None nếu thất bại
        """
        try:
            BATCH_SIZE = 5  # Chia thành batch 5 videos/project (mặc định)
            self.log(f"📦 Chia {len(media_generation_ids)} videos thành batch {BATCH_SIZE}...\n")
            
            base_output_folder = Path(output_folder).resolve()
            base_output_folder.mkdir(parents=True, exist_ok=True)
            
            # Tạo thư mục temp cho các video đã concat
            temp_dir = base_output_folder / "temp_concat_expand_ref"
            temp_dir.mkdir(parents=True, exist_ok=True)
            
            # Chia thành các batch và concat từng batch
            concat_video_paths = []
            num_batches = (len(media_generation_ids) + BATCH_SIZE - 1) // BATCH_SIZE
            
            for batch_idx in range(num_batches):
                start_idx = batch_idx * BATCH_SIZE
                end_idx = min(start_idx + BATCH_SIZE, len(media_generation_ids))
                batch_media_ids = media_generation_ids[start_idx:end_idx]
                
                self.log(f"📦 Batch {batch_idx + 1}/{num_batches}: Concat {len(batch_media_ids)} videos (từ {start_idx + 1} đến {end_idx})...\n")
                
                # Concat batch này bằng Google API
                batch_concat_result = self._concat_videos_expand_reference(client, batch_media_ids, batch_idx)
                
                if not batch_concat_result:
                    self.log(f"❌ Batch {batch_idx + 1} concat thất bại\n")
                    return None
                
                # Extract URL từ concat result
                batch_concat_urls = self._extract_file_urls_from_concat(batch_concat_result)
                
                if not batch_concat_urls:
                    self.log(f"❌ Batch {batch_idx + 1} không có URL để download\n")
                    return None
                
                # Download video đã concat (lấy URL đầu tiên)
                batch_output = temp_dir / f"batch_{batch_idx + 1:03d}.mp4"
                batch_url = batch_concat_urls[0]
                
                import shutil
                if batch_url.startswith("file://"):
                    # Local file
                    try:
                        file_path = batch_url.replace("file://", "").replace("\\", "/")
                        if file_path.startswith("/") and ":" in file_path:
                            file_path = file_path[1:]
                        source_path = Path(file_path)
                        if source_path.exists():
                            shutil.copy2(source_path, batch_output)
                            concat_video_paths.append(batch_output)
                            self.log(f"✅ Batch {batch_idx + 1} đã concat và copy: {batch_output}\n")
                        else:
                            self.log(f"❌ File không tồn tại: {source_path}\n")
                            return None
                    except Exception as e:
                        self.log(f"❌ Lỗi copy batch {batch_idx + 1}: {e}\n")
                        return None
                else:
                    # HTTP/HTTPS URL - download
                    from complete_flow import download_video
                    if download_video(batch_url, batch_output, self.log):
                        concat_video_paths.append(batch_output)
                        self.log(f"✅ Batch {batch_idx + 1} đã concat và download: {batch_output}\n")
                    else:
                        self.log(f"❌ Không thể download batch {batch_idx + 1}\n")
                        return None
            
            # ✅ Nối các video đã concat lại bằng FFmpeg với dissolve transition
            if len(concat_video_paths) > 1:
                self.log(f"\n🔗 Nối {len(concat_video_paths)} video đã concat bằng FFmpeg với dissolve transition...\n")
                
                final_output_path = base_output_folder / "expand_reference_concat_final.mp4"
                
                # Import hàm merge từ extend_videos
                from extend_videos import merge_videos_with_ffmpeg_dissolve
                
                if merge_videos_with_ffmpeg_dissolve(concat_video_paths, final_output_path, 
                                                     duration=3.0, offset=3.0, log_callback=self.log):
                    self.log(f"✅ Đã nối tất cả video bằng FFmpeg: {final_output_path}\n")
                    
                    # Cleanup temp files
                    try:
                        for path in concat_video_paths:
                            if path.exists():
                                path.unlink()
                        temp_dir.rmdir()
                    except Exception as e:
                        self.log(f"  ⚠️ Cleanup warning: {e}\n")
                    
                    # Return result với file path
                    return {"type": "url", "data": f"file://{final_output_path}"}
                else:
                    self.log(f"❌ FFmpeg merge thất bại\n")
                    return None
            elif len(concat_video_paths) == 1:
                # Chỉ có 1 batch (≤ 5 videos), không cần merge thêm
                final_output_path = base_output_folder / "expand_reference_concat_final.mp4"
                
                # Move file từ temp sang final
                try:
                    concat_video_paths[0].rename(final_output_path)
                    self.log(f"✅ Đã lưu video: {final_output_path}\n")
                    
                    # Cleanup
                    try:
                        temp_dir.rmdir()
                    except Exception:
                        pass
                    
                    return {"type": "url", "data": f"file://{final_output_path}"}
                except Exception as e:
                    self.log(f"❌ Lỗi move file: {e}\n")
                    return None
            else:
                self.log(f"❌ Không có video nào để merge\n")
                return None
                
        except Exception as e:
            self.log(f"❌ Lỗi _concat_large_expand_reference_project: {e}\n")
            import traceback
            self.log(f"🔍 Traceback: {traceback.format_exc()}\n")
            return None
    
    def _poll_concat_status_expand_reference(self, client, operation_name, max_wait=600):
        """Poll concat status cho Expand + Reference"""
        try:
            import time
            
            url = "https://aisandbox-pa.googleapis.com/v1:runVideoFxCheckConcatenationStatus"
            payload = {
                "operation": {
                    "operation": {
                        "name": operation_name
                    }
                }
            }
            
            deadline = time.time() + max_wait
            poll_interval = 5
            
            while time.time() < deadline and not self.stop_event.is_set():
                resp = client.session.post(
                    url,
                    headers=client._aisandbox_headers(),
                    json=payload,
                    timeout=30
                )
                
                if resp.status_code == 200:
                    result = resp.json()
                    
                    # Check for encodedVideo
                    encoded_video = result.get("encodedVideo", "")
                    if encoded_video:
                        self.log(f"✅ Concat hoàn thành với encodedVideo ({len(encoded_video)} chars)")
                        return {"type": "encoded", "data": encoded_video}
                    
                    # Check for outputUri
                    video_urls = _extract_file_urls(result)
                    output_uri = video_urls[0] if video_urls else ""
                    if output_uri:
                        self.log(f"✅ Concat hoàn thành với outputUri")
                        return {"type": "url", "data": output_uri}
                    
                    # Check status
                    status = str(result.get("status", "")).upper()
                    if "FAILED" in status or "ERROR" in status:
                        self.log(f"❌ Concat FAILED: {status}")
                        return None
                    elif "COMPLETE" in status or "SUCCESS" in status:
                        video_urls = _extract_file_urls(result)
                        if video_urls:
                            return {"type": "url", "data": video_urls[0]}
                        self.log(f"⚠️ Concat completed but no URL found")
                        return None
                
                time.sleep(poll_interval)
            
            if time.time() >= deadline:
                self.log(f"⏰ Timeout polling concat status")
                return None
            
            return None
            
        except Exception as e:
            self.log(f"❌ Lỗi poll concat status: {e}")
            return None
    
    def _extract_file_urls_from_concat(self, concat_result):
        """Extract file URLs từ concat result
        
        Args:
            concat_result: dict - Kết quả từ concat API
            
        Returns:
            List[str]: Danh sách URLs hoặc empty list
        """
        try:
            urls = []
            
            if isinstance(concat_result, dict):
                result_type = concat_result.get("type")
                
                if result_type == "encoded":
                    # Encoded video - cần decode base64
                    encoded_data = concat_result.get("data")
                    if encoded_data:
                        # Decode và lưu tạm, sau đó trả về path
                        import base64
                        import tempfile
                        video_bytes = base64.b64decode(encoded_data)
                        temp_file = tempfile.NamedTemporaryFile(delete=False, suffix='.mp4')
                        temp_file.write(video_bytes)
                        temp_file.close()
                        urls.append(f"file://{temp_file.name}")
                
                elif result_type == "url":
                    # Direct URL
                    video_url = concat_result.get("data")
                    if video_url:
                        urls.append(video_url)
                
                # Fallback: thử extract từ result trực tiếp
                if not urls:
                    urls = _extract_file_urls(concat_result)
            
            return urls
            
        except Exception as e:
            self.log(f"❌ Lỗi extract URLs từ concat: {e}")
            return []


