    def on_edit_add_videos(self):
        """Add videos to edit list"""
        files, _ = QFileDialog.getOpenFileNames(
            self, "Chọn video", "", "Video (*.mp4 *.mov *.mkv *.avi *.webm);;All (*.*)"
        )
        if files:
            paths = [Path(f) for f in files]
            paths = natural_sort_paths(paths)
            self.edit_video_paths.extend(paths)
            self.refresh_edit_video_list()
            self.log(f"📹 Đã thêm {len(files)} video")
    
    def on_edit_add_folder(self):
        """Add all videos from folder"""
        folder = QFileDialog.getExistingDirectory(self, "Chọn thư mục chứa video")
        if folder:
            try:
                video_files = []
                for ext in ("*.mp4", "*.mov", "*.mkv", "*.avi", "*.webm"):
                    video_files.extend(Path(folder).glob(ext))
                video_files = natural_sort_paths(list(video_files))
                self.edit_video_paths.extend(video_files)
                self.refresh_edit_video_list()
                self.log(f"📁 Đã thêm {len(video_files)} video từ thư mục")
            except Exception as e:
                self.edit_log(f"❌ Lỗi: {e}")
    
    def on_edit_select_all(self):
        """Select all videos"""
        self.lst_edit_videos.selectAll()
        self.edit_log(f"✅ Đã chọn tất cả {self.lst_edit_videos.rowCount()} video")
    
    def on_edit_deselect_all(self):
        """Deselect all videos"""
        self.lst_edit_videos.clearSelection()
        self.edit_log("Đã bỏ chọn")
    
    def on_edit_remove_selected(self):
        """Remove selected videos"""
        selected = self.lst_edit_videos.selectedItems()
        if not selected:
            self.edit_log("⚠️ Không có video nào được chọn")
            return
        
        # Get row indices (unique)
        rows = list(set([item.row() for item in selected]))
        rows.sort(reverse=True)
        
        # Remove from list and table
        for row in rows:
            if 0 <= row < len(self.edit_video_paths):
                del self.edit_video_paths[row]
        
        self.refresh_edit_video_list()
        self.edit_log(f"🗑️ Đã xóa {len(rows)} video")
    
    def on_edit_move_selected(self, delta):
        """Move selected video up/down"""
        selected = self.lst_edit_videos.selectedItems()
        if not selected:
            return
        
        row = selected[0].row()
        new_row = max(0, min(len(self.edit_video_paths) - 1, row + delta))
        
        if new_row != row:
            self.edit_video_paths[row], self.edit_video_paths[new_row] = \
                self.edit_video_paths[new_row], self.edit_video_paths[row]
            self.refresh_edit_video_list()
            self.lst_edit_videos.selectRow(new_row)
    
    def on_edit_random_order(self):
        """Randomize video order"""
        if not self.edit_video_paths:
            self.edit_log("⚠️ Không có video nào")
            return
        
        import random
        random.shuffle(self.edit_video_paths)
        self.refresh_edit_video_list()
        self.edit_log(f"🎲 Đã xáo trộn {len(self.edit_video_paths)} video")
    
    def refresh_edit_video_list(self):
        """Refresh video list table"""
        try:
            self.lst_edit_videos.setRowCount(0)
            for i, path in enumerate(self.edit_video_paths):
                self.lst_edit_videos.insertRow(i)
                self.lst_edit_videos.setItem(i, 0, QTableWidgetItem(str(path)))
        except Exception as e:
            self.edit_log(f"❌ Lỗi refresh: {e}")
    
