    def on_edit_run(self):
        """Run edit/merge"""
        if self.edit_processing:
            return
        
        if not self.edit_video_paths:
            QMessageBox.warning(self, "Cảnh báo", "Chưa có video nào")
            return
        
        out = self.txt_edit_output.text().strip()
        if not out:
            QMessageBox.warning(self, "Cảnh báo", "Chưa chọn file xuất")
            return
        
        # Get audio mode
        if self.rb_audio_mix.isChecked():
            mode = "mix"
        elif self.rb_audio_keep.isChecked():
            mode = "keep"
        elif self.rb_audio_bgm.isChecked():
            mode = "bgm"
        else:
            mode = "mute"
        
        bgm = self.txt_bgm_path.text().strip()
        
        self.btn_edit_run.setEnabled(False)
        self.btn_edit_cancel.setEnabled(True)
        self.edit_processing = True
        
        threading.Thread(
            target=self.edit_worker,
            args=(out, mode, bgm),
            daemon=True
        ).start()
    
    def on_edit_cancel(self):
        """Cancel edit"""
        self.edit_processing = False
        self.edit_log("🛑 Đã hủy")
    
    def edit_log(self, msg):
        """Log to edit text area"""
        try:
            self.txt_edit_log.append(msg)
            scrollbar = self.txt_edit_log.verticalScrollBar()
            scrollbar.setValue(scrollbar.maximum())
        except Exception:
            pass
    
    def probe_duration_seconds(self, media_path):
        """Probe media duration using ffprobe"""
        try:
            ffprobe = self.find_tool("ffprobe")
            if not ffprobe:
                return None
            
            import subprocess
            creationflags = subprocess.CREATE_NO_WINDOW if sys.platform == 'win32' else 0
            proc = subprocess.run([
                ffprobe,
                "-v", "error",
                "-show_entries", "format=duration",
                "-of", "default=noprint_wrappers=1:nokey=1",
                media_path
            ], stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=10,
            creationflags=creationflags)
            
            if proc.returncode == 0 and proc.stdout:
                return float(proc.stdout.strip())
        except Exception:
            pass
        return None
    
    def find_tool(self, name):
        """Find ffmpeg/ffprobe tool"""
        # Search local folder first
        candidates = [
            str(Path.cwd() / f"{name}.exe"),
            name,
        ]
        for c in candidates:
            try:
                import subprocess
                creationflags = subprocess.CREATE_NO_WINDOW if sys.platform == 'win32' else 0
                proc = subprocess.run([c, "-version"], stdout=subprocess.PIPE, 
                                    stderr=subprocess.STDOUT, timeout=3,
                                    creationflags=creationflags)
                if proc.returncode == 0 or proc.stdout:
                    return c
            except Exception:
                continue
        return None
    
    def edit_worker(self, out_path, mode, bgm_path):
        """Worker thread for edit/merge"""
        ffmpeg = self.find_tool("ffmpeg")
        if not ffmpeg:
            QTimer.singleShot(0, lambda: QMessageBox.critical(
                self, "Lỗi", "Không tìm thấy ffmpeg. Vui lòng đặt ffmpeg.exe cùng folder app."
            ))
            self.finalize_edit()
            return
        
        try:
            import tempfile
            import subprocess
            
            # Create concat list
            tmpdir = Path(tempfile.mkdtemp(prefix="edit_concat_"))
            concat_txt = tmpdir / "concat.txt"
            
            # Handle repeat logic
            target_seconds = None
            use_repeat = self.chk_repeat_enable.isChecked()
            
            if use_repeat:
                # Get target duration
                if bgm_path:
                    d = self.probe_duration_seconds(bgm_path)
                    if d and d > 0:
                        target_seconds = d
                
                if target_seconds is None:
                    try:
                        target_seconds = float(self.txt_repeat_seconds.text().strip())
                    except:
                        target_seconds = None
                
                if not target_seconds or target_seconds <= 0:
                    self.edit_log("⚠️ Thời lượng không hợp lệ. Bỏ qua lặp")
                    use_repeat = False
            
            if use_repeat and target_seconds:
                self.edit_log(f"🔄 Lặp video đến ~{int(target_seconds)}s...")
                # Build repeated sequence
                inputs = list(self.edit_video_paths)
                durations = []
                for p in inputs:
                    d = self.probe_duration_seconds(str(p)) or 0.0
                    durations.append(max(0.0, d))
                
                seq = []
                total = 0.0
                i = 0
                if sum(durations) > 0:
                    while total < target_seconds and self.edit_processing:
                        p = inputs[i % len(inputs)]
                        seq.append(p)
                        total += durations[i % len(inputs)]
                        i += 1
                else:
                    seq = inputs.copy()
                
                self.edit_log(f"📊 Sau lặp: ~{total:.1f}s, {len(seq)} đoạn")
                
                with open(concat_txt, "w", encoding="utf-8") as f:
                    for p in seq:
                        escaped = str(p).replace('\\', '/').replace("'", "'\\''")
                        f.write(f"file '{escaped}'\n")
            else:
                with open(concat_txt, "w", encoding="utf-8") as f:
                    for p in self.edit_video_paths:
                        escaped = str(p).replace('\\', '/').replace("'", "'\\''")
                        f.write(f"file '{escaped}'\n")
            
            # Concat videos
            concat_out = tmpdir / "concat.mp4"
            
            if use_repeat and mode in ("bgm", "mute"):
                cmd_concat = [
                    ffmpeg, "-y", "-f", "concat", "-safe", "0",
                    "-i", str(concat_txt), "-c:v", "copy", "-an", str(concat_out)
                ]
            else:
                cmd_concat = [
                    ffmpeg, "-y", "-f", "concat", "-safe", "0",
                    "-i", str(concat_txt), "-c:v", "copy", "-c:a", "copy", str(concat_out)
                ]
            
            self.edit_log("🔄 Đang ghép video...")
            creationflags = subprocess.CREATE_NO_WINDOW if sys.platform == 'win32' else 0
            if self.chk_ffmpeg_console.isChecked():
                creationflags = 0
            
            proc = subprocess.Popen(cmd_concat, creationflags=creationflags)
            while True:
                if proc.poll() is not None:
                    break
                if not self.edit_processing:
                    proc.terminate()
                    self.finalize_edit(cancelled=True)
                    return
                import time
                time.sleep(0.2)
            
            if proc.returncode != 0:
                QTimer.singleShot(0, lambda: QMessageBox.critical(
                    self, "Lỗi", "Ghép video thất bại"
                ))
                self.finalize_edit()
                return
            
            # Process audio
            final_src = concat_out
            
            if mode == "mute":
                cmd = [ffmpeg, "-y", "-i", str(final_src), "-an", "-c:v", "copy", out_path]
            elif mode == "bgm":
                if bgm_path:
                    cmd = [ffmpeg, "-y", "-i", str(final_src), "-i", bgm_path,
                          "-map", "0:v:0", "-map", "1:a:0"]
                    if use_repeat and target_seconds:
                        cmd += ["-t", str(target_seconds)]
                    else:
                        cmd += ["-shortest"]
                    cmd += ["-c:v", "copy", "-c:a", "copy", out_path]
                else:
                    cmd = [ffmpeg, "-y", "-i", str(final_src), "-an", "-c:v", "copy", out_path]
            elif mode == "mix":
                if bgm_path:
                    vol_f = 1.0
                    try:
                        vol_f = float(self.txt_bgm_volume.text().strip())
                    except:
                        vol_f = 1.0
                    
                    filter_complex = f"[1:a]volume={vol_f}[bg];[0:a][bg]amix=inputs=2:duration=shortest:dropout_transition=0[aout]"
                    cmd = [
                        ffmpeg, "-y", "-i", str(final_src), "-i", bgm_path,
                        "-filter_complex", filter_complex,
                        "-map", "0:v:0", "-map", "[aout]",
                        "-c:v", "copy", "-c:a", "aac", "-b:a", "192k"
                    ]
                    if use_repeat and target_seconds:
                        cmd += ["-t", str(target_seconds)]
                    else:
                        cmd += ["-shortest"]
                    cmd += [out_path]
                else:
                    cmd = [ffmpeg, "-y", "-i", str(final_src), "-c:v", "copy", "-c:a", "copy", out_path]
            else:  # keep
                cmd = [ffmpeg, "-y", "-i", str(final_src), "-c:v", "copy", "-c:a", "copy", out_path]
            
            self.edit_log("🎵 Đang xử lý audio...")
            proc2 = subprocess.Popen(cmd, creationflags=creationflags)
            while True:
                if proc2.poll() is not None:
                    break
                if not self.edit_processing:
                    proc2.terminate()
                    self.finalize_edit(cancelled=True)
                    return
                import time
                time.sleep(0.2)
            
            if proc2.returncode != 0:
                QTimer.singleShot(0, lambda: QMessageBox.critical(
                    self, "Lỗi", "Xử lý audio thất bại"
                ))
                self.finalize_edit()
                return
            
            QTimer.singleShot(0, lambda: QMessageBox.information(
                self, "Thành công", f"Đã xuất: {out_path}"
            ))
            
            # Open file
            try:
                import os
                os.startfile(out_path)
            except:
                pass
            
            self.finalize_edit()
            
        except Exception as e:
            self.edit_log(f"❌ Lỗi: {e}")
            self.finalize_edit()
    
    def finalize_edit(self, cancelled=False):
        """Finalize edit processing"""
        self.edit_processing = False
        try:
            self.btn_edit_run.setEnabled(True)
            self.btn_edit_cancel.setEnabled(False)
            if cancelled:
                self.edit_log("Đã hủy")
            else:
                self.edit_log("Hoàn tất")
        except:
            pass
    
    # ===== SYNC TAB HANDLERS =====
    
    def on_sync_script_changed_debounced(self):
        """Debounced script change - auto calculate seconds - FIXED TIMER LEAK"""
        try:
            # ✅ INIT TIMER ONLY ONCE (prevent memory leak và conflicts)
            if not hasattr(self, '_sync_script_timer'):
                self._sync_script_timer = QTimer()
                self._sync_script_timer.setSingleShot(True)
                self._sync_script_timer.timeout.connect(self.on_sync_script_changed)
            
            # Cancel current timer if running
            if self._sync_script_timer.isActive():
                self._sync_script_timer.stop()
            
            # Restart timer
            self._sync_script_timer.start(500)  # 500ms delay
            
        except Exception as e:
            # Log errors để debug
            if hasattr(self, 'log'):
                self.log(f"❌ Error in sync script debounce: {e}")
            else:
                print(f"❌ Timer error: {e}")
    
    def on_sync_script_changed(self):
        """Handle script change - auto calculate seconds - PREVENT INFINITE LOOP"""
        try:
            # ✅ PREVENT INFINITE LOOP với flag
            if getattr(self, '_sync_updating', False):
                return  # Skip nếu đang update để tránh circular calls
            
            self._sync_updating = True
            
            script = self.txt_sync_script.toPlainText().strip()
            lines = [line.strip() for line in script.split('\n') if line.strip()]
            
            if lines:
                # Auto calculate: số dòng × 8 giây
                suggested_seconds = len(lines) * 8
                suggested_seconds = min(480, suggested_seconds)
                
                # ✅ DISCONNECT signal temporarily để tránh loop
                self.spin_sync_total_secs.blockSignals(True)
                self.spin_sync_total_secs.setValue(suggested_seconds)
                self.spin_sync_total_secs.blockSignals(False)
                
                # Manual trigger update (không qua signal)
                self.on_sync_total_secs_changed()
                
                self.sync_log(f"📝 Tự động tính: {len(lines)} dòng × 8s = {suggested_seconds}s")
        except Exception as e:
            # Silent error handling
            pass
        finally:
            self._sync_updating = False
    
    def on_sync_total_secs_changed(self):
        """Handle total seconds change - update calculations - CRASH-PROOF"""
        try:
            # ✅ DEBUG LOG
            self.sync_log("🔄 Đang cập nhật số video và phân cảnh...\n")
            # ✅ PREVENT CIRCULAR UPDATES
            if getattr(self, '_sync_updating', False):
                return
            
            # ✅ COMPREHENSIVE WIDGET EXISTENCE CHECK
            required_widgets = [
                'txt_sync_script', 'spin_sync_total_secs', 
                'lbl_sync_num_videos', 'lbl_sync_num_stages'
            ]
            
            for widget_name in required_widgets:
                widget = getattr(self, widget_name, None)
                if widget is None:
                    return  # Skip nếu bất kỳ widget nào missing
            
            # ✅ SAFE WIDGET ACCESS với individual try-catch
            try:
                script = self.txt_sync_script.toPlainText().strip()
            except Exception:
                return
                
            try:
                total_secs = self.spin_sync_total_secs.value()
            except Exception:
                total_secs = 40  # default
            
            # ✅ ĐẾM TỪ PROMPTS JSON FILES thay vì script lines
            num_videos = 0
            num_scenes = 0
            
            try:
                # ✅ TÌM THÊM TRONG NHIỀU LOCATIONS KHÁC NHAU
                outdir_text = ""
                if hasattr(self, 'txt_sync_outdir') and self.txt_sync_outdir:
                    outdir_text = self.txt_sync_outdir.text().strip()
                
                if outdir_text:
                    output_dir = Path(outdir_text)
                    
                    # Try multiple locations
                    possible_paths = [
                        output_dir / "json_prompt_outputs" / "video_json",
                        output_dir / "video_json",
                        Path.cwd() / "json_prompt_outputs" / "video_json",
                    ]
                    
                    json_files = []
                    for video_json_dir in possible_paths:
                        if video_json_dir.exists():
                            json_files = sorted([f for f in video_json_dir.glob("line_*.json")])
                            if json_files:
                                self.sync_log(f"📁 Tìm thấy {len(json_files)} JSON prompts tại: {video_json_dir}\n")
                                break
                    
                    if json_files:
                        num_videos = len(json_files)
                        num_scenes = num_videos  # Mỗi video = 1 scene
                    else:
                        # Fallback: đếm từ script lines nếu chưa có prompts
                        lines = [line.strip() for line in script.split('\n') if line.strip()]
                        num_scenes = len(lines)
                        num_videos = num_scenes if num_scenes > 0 else 0
                        self.sync_log(f"⚠️ Không tìm thấy JSON prompts, đếm từ script: {num_videos} dòng\n")
                else:
                    # Fallback: đếm từ script lines nếu chưa chọn output dir
                    lines = [line.strip() for line in script.split('\n') if line.strip()]
                    num_scenes = len(lines)
                    num_videos = num_scenes if num_scenes > 0 else 0
                    self.sync_log(f"⚠️ Chưa chọn output dir, đếm từ script: {num_videos} dòng\n")
            except Exception as e:
                # Fallback: đếm từ script lines nếu có lỗi
                self.sync_log(f"⚠️ Lỗi đếm JSON files: {e}\n")
                try:
                    lines = [line.strip() for line in script.split('\n') if line.strip()]
                    num_scenes = len(lines)
                    num_videos = num_scenes if num_scenes > 0 else 0
                except:
                    num_videos = 0
                    num_scenes = 0
            
            # ✅ SAFE LABEL UPDATES
            try:
                self.lbl_sync_num_videos.setText(str(num_videos))
                self.sync_log(f"✅ Đã cập nhật số video: {num_videos}\n")
            except Exception as e:
                self.sync_log(f"⚠️ Lỗi update num_videos: {e}\n")
                pass
                
            try:
                self.lbl_sync_num_stages.setText(str(num_scenes))
                self.sync_log(f"✅ Đã cập nhật số phân cảnh: {num_scenes}\n")
            except Exception as e:
                self.sync_log(f"⚠️ Lỗi update num_stages: {e}\n")
                pass
            
        except Exception as e:
            # ✅ SILENT ERROR HANDLING để tránh cascade crashes
            pass
    
