    def on_sync_export_json(self):
        """Export scene JSON"""
        try:
            script = self.txt_sync_script.toPlainText().strip()
            if not script:
                QMessageBox.warning(self, "Cảnh báo", "Vui lòng nhập kịch bản trước!")
                return
            
            style = self.combo_sync_style.currentText()
            total_secs = self.spin_sync_total_secs.value()
            output_dir = Path(self.txt_sync_outdir.text().strip())
            
            self.sync_log(f"📤 Bắt đầu xuất Scene JSON...")
            self.sync_log(f"📋 Style: {style}")
            self.sync_log(f"📋 Tổng thời gian: {total_secs}s")
            
            # Parse script
            lines = [line.strip() for line in script.split('\n') if line.strip()]
            self.sync_log(f"📋 Số cảnh: {len(lines)}")
            
            # Build scenes data
            scenes = []
            secs_per_scene = total_secs / len(lines) if lines else 8.0
            
            for i, line in enumerate(lines):
                scene = {
                    "scene_id": i + 1,
                    "text": line,
                    "style": style,
                    "duration": secs_per_scene,
                    "start_time": i * secs_per_scene,
                    "end_time": (i + 1) * secs_per_scene,
                    "image_prompt": f"{line} in {style} style",
                    "video_prompt": f"{line} in {style} style, cinematic, high quality"
                }
                scenes.append(scene)
            
            # Export file
            output_dir.mkdir(parents=True, exist_ok=True)
            import time
            output_file = output_dir / f"scenes_{time.strftime('%Y%m%d_%H%M%S')}.json"
            
            with open(output_file, 'w', encoding='utf-8') as f:
                json.dump({
                    "metadata": {
                        "created_at": time.strftime("%Y-%m-%d %H:%M:%S"),
                        "style": style,
                        "total_seconds": total_secs,
                        "num_scenes": len(scenes)
                    },
                    "scenes": scenes
                }, f, ensure_ascii=False, indent=2)
            
            self.sync_log(f"✅ Đã xuất: {output_file.name}")
            QMessageBox.information(self, "Thành công", f"Đã xuất: {output_file.name}")
            
        except Exception as e:
            self.sync_log(f"❌ Lỗi xuất JSON: {e}")
            QMessageBox.critical(self, "Lỗi", f"Lỗi xuất JSON: {e}")
    
