            from PySide6.QtWidgets import (QDialog, QVBoxLayout, QHBoxLayout, QLabel, QPushButton, 
                                          QTextEdit, QScrollArea, QWidget, QFileDialog, QMessageBox,
                                          QDialogButtonBox, QSplitter, QLineEdit)
            from PySide6.QtCore import Qt
