    def copy_all_failed_prompts(self, failed_tasks_data: Dict[str, List[Dict]], 
                                 prompt_editors: Dict[int, QTextEdit], prompts_table: QTableWidget):
        """✅ Copy toàn bộ prompts lỗi vào clipboard"""
        try:
            all_prompts = []
            
            # Thu thập tất cả prompts từ tất cả files
            for file_stem, failed_tasks in failed_tasks_data.items():
                for task in failed_tasks:
                    global_index = task['global_index']
                    
                    # Kiểm tra xem prompt có được sửa trong editor không
                    edited_prompt = None
                    for row in range(prompts_table.rowCount()):
                        file_line_item = prompts_table.item(row, 1)
                        if file_line_item and file_line_item.data(Qt.UserRole) == global_index:
                            editor = prompt_editors.get(row)
                            if editor:
                                edited_prompt = editor.toPlainText().strip()
                            break
                    
                    # Dùng prompt đã sửa nếu có, không thì dùng prompt gốc
                    prompt = edited_prompt if edited_prompt else task['prompt']
                    if prompt:
                        all_prompts.append(prompt)
            
            if not all_prompts:
                QMessageBox.warning(self, "Cảnh báo", "Không có prompt nào để copy!")
                return
            
            # Copy vào clipboard
            clipboard = QApplication.clipboard()
            clipboard.setText('\n'.join(all_prompts))
            
            self.log(f"✅ Đã copy {len(all_prompts)} prompts lỗi vào clipboard")
            QMessageBox.information(
                self,
                "Thành công",
                f"✅ Đã copy {len(all_prompts)} prompts lỗi vào clipboard!"
            )
            
        except Exception as e:
            self.log(f"❌ Lỗi copy failed prompts: {e}")
            import traceback
            self.log(traceback.format_exc())
            QMessageBox.critical(self, "Lỗi", f"Không thể copy prompts:\n{e}")
    
    def export_failed_prompts_to_txt(self, failed_tasks_data: Dict[str, List[Dict]], 
                                      prompt_editors: Dict[int, QTextEdit], prompts_table: QTableWidget):
        """✅ Xuất tất cả prompts lỗi ra file TXT"""
        try:
            # Chọn file để lưu
            file_path, _ = QFileDialog.getSaveFileName(
                self,
                "Xuất Prompts Lỗi ra File TXT",
                "",
                "Text Files (*.txt);;All Files (*)"
            )
            
            if not file_path:
                return
            
            # Đảm bảo có extension .txt
            if not file_path.lower().endswith('.txt'):
                file_path += '.txt'
            
            # Thu thập prompts theo file (giữ nguyên cấu trúc file)
            output_lines = []
            
            for file_stem in sorted(failed_tasks_data.keys()):
                failed_tasks = failed_tasks_data[file_stem]
                
                # Thêm header cho file
                output_lines.append(f"# File: {file_stem}.txt ({len(failed_tasks)} prompts lỗi)")
                output_lines.append("")
                
                for task in failed_tasks:
                    global_index = task['global_index']
                    
                    # Kiểm tra xem prompt có được sửa trong editor không
                    edited_prompt = None
                    for row in range(prompts_table.rowCount()):
                        file_line_item = prompts_table.item(row, 1)
                        if file_line_item and file_line_item.data(Qt.UserRole) == global_index:
                            editor = prompt_editors.get(row)
                            if editor:
                                edited_prompt = editor.toPlainText().strip()
                            break
                    
                    # Dùng prompt đã sửa nếu có, không thì dùng prompt gốc
                    prompt = edited_prompt if edited_prompt else task['prompt']
                    if prompt:
                        output_lines.append(prompt)
                
                # Thêm dòng trống giữa các file
                output_lines.append("")
                output_lines.append("")
            
            # Ghi file
            with open(file_path, 'w', encoding='utf-8') as f:
                f.write('\n'.join(output_lines))
            
            total_prompts = sum(len(tasks) for tasks in failed_tasks_data.values())
            self.log(f"✅ Đã xuất {total_prompts} prompts lỗi từ {len(failed_tasks_data)} file(s) ra: {file_path}")
            QMessageBox.information(
                self,
                "Thành công",
                f"✅ Đã xuất {total_prompts} prompts lỗi từ {len(failed_tasks_data)} file(s) ra:\n{file_path}"
            )
            
        except Exception as e:
            self.log(f"❌ Lỗi export failed prompts: {e}")
            import traceback
            self.log(traceback.format_exc())
            QMessageBox.critical(self, "Lỗi", f"Không thể xuất prompts:\n{e}")
    
    def import_txt_to_failed_prompts(self, failed_tasks_data: Dict[str, List[Dict]], 
                                      prompt_editors: Dict[int, QTextEdit], prompts_table: QTableWidget):
        """✅ Import file TXT và fill vào các ô prompt lỗi
        
        Logic:
        - Đếm số dòng lỗi đang hiển thị trong prompts_table
        - Chỉ lấy số dòng đầu tiên từ file TXT bằng số dòng lỗi
        - Fill vào các editor theo thứ tự từ trên xuống
        """
        try:
            # Chọn file TXT để import
            file_path, _ = QFileDialog.getOpenFileName(
                self,
                "Import File TXT để Sửa Prompts Lỗi",
                "",
                "Text Files (*.txt);;All Files (*)"
            )
            
            if not file_path or not Path(file_path).exists():
                return
            
            # Tìm file đang được chọn trong files_table (nếu có)
            current_file_stem = None
            parent_dialog = prompts_table.window()
            if isinstance(parent_dialog, QDialog):
                # Tìm TableWidget tên "files_table" trong dialog (cùng level)
                files_table = parent_dialog.findChild(QTableWidget)
                if files_table and files_table.selectedItems():
                    sel_item = files_table.selectedItems()[1] if len(files_table.selectedItems()) > 1 else files_table.selectedItems()[0]
                    current_file_stem = sel_item.data(Qt.UserRole)
            # Fallback: lấy từ dòng đầu tiên nếu chưa chọn
            if not current_file_stem and files_table and files_table.rowCount() > 0:
                current_file_stem = files_table.item(0, 1).data(Qt.UserRole)
            
            # Đếm số dòng lỗi đang hiển thị trong prompts_table
            num_error_rows = prompts_table.rowCount()
            if num_error_rows == 0:
                QMessageBox.warning(self, "Cảnh báo", "Không có prompt lỗi nào đang hiển thị!\nVui lòng chọn file để xem prompts lỗi trước.")
                return
            
            # Đọc file TXT
            with open(file_path, 'r', encoding='utf-8') as f:
                all_lines = [line.strip() for line in f if line.strip()]
            
            if not all_lines:
                QMessageBox.warning(self, "Cảnh báo", "File TXT rỗng hoặc không có dòng nào hợp lệ!")
                return
            
            # ✅ Validate: Chỉ lấy số dòng đầu tiên bằng số dòng lỗi
            if len(all_lines) < num_error_rows:
                QMessageBox.warning(
                    self, 
                    "Cảnh báo", 
                    f"File TXT chỉ có {len(all_lines)} dòng, nhưng có {num_error_rows} dòng lỗi cần sửa!\n\n"
                    f"Chỉ sẽ fill {len(all_lines)} dòng đầu tiên."
                )
                lines_to_fill = all_lines
            else:
                lines_to_fill = all_lines[:num_error_rows]
                if len(all_lines) > num_error_rows:
                    QMessageBox.information(
                        self,
                        "Thông báo",
                        f"File TXT có {len(all_lines)} dòng, nhưng chỉ có {num_error_rows} dòng lỗi.\n\n"
                        f"Chỉ lấy {num_error_rows} dòng đầu tiên để fill."
                    )
            
            # Fill vào các editor theo thứ tự từ trên xuống
            filled_count = 0
            for row_idx in range(min(len(lines_to_fill), num_error_rows)):
                editor = prompt_editors.get(row_idx)
                if editor:
                    editor.setPlainText(lines_to_fill[row_idx])
                    filled_count += 1
                    # Cập nhật vào failed_tasks_data để không mất khi đổi file
                    if current_file_stem and current_file_stem in failed_tasks_data:
                        file_tasks = failed_tasks_data[current_file_stem]
                        if row_idx < len(file_tasks):
                            file_tasks[row_idx]['prompt'] = lines_to_fill[row_idx]
            
            self.log(f"✅ Đã import {filled_count}/{num_error_rows} prompts từ file: {Path(file_path).name}")
            QMessageBox.information(
                self,
                "Thành công",
                f"✅ Đã import {filled_count} prompts từ file:\n{Path(file_path).name}\n\n"
                f"Đã fill vào {filled_count}/{num_error_rows} ô prompt lỗi."
            )
            
        except Exception as e:
            self.log(f"❌ Lỗi import TXT: {e}")
            import traceback
            self.log(traceback.format_exc())
            QMessageBox.critical(self, "Lỗi", f"Không thể import file TXT:\n{e}")
    
    def save_and_merge_failed_prompts(self, dialog, failed_tasks_data: Dict[str, List[Dict]], 
                                       prompt_editors: Dict[int, QTextEdit], prompts_table: QTableWidget):
        """✅ Lưu prompts đã sửa và merge vào bảng chính, clear các dòng đã hoàn thành"""
        try:
            # Trước tiên, lưu các edit đang hiển thị (nếu có) vào failed_tasks_data
            try:
                parent_dialog = prompts_table.window()
                # Tìm files_table để xác định file đang xem
                files_table = parent_dialog.findChild(QTableWidget)
                if files_table and files_table.selectedItems():
                    sel_item = files_table.selectedItems()[1] if len(files_table.selectedItems()) > 1 else files_table.selectedItems()[0]
                    current_file_stem = sel_item.data(Qt.UserRole)
                else:
                    current_file_stem = None
                # Lưu các editor hiện tại vào failed_tasks_data
                for row in range(prompts_table.rowCount()):
                    file_line_item = prompts_table.item(row, 1)
                    if not file_line_item:
                        continue
                    global_idx = file_line_item.data(Qt.UserRole)
                    editor = prompt_editors.get(row)
                    if editor:
                        new_prompt = editor.toPlainText().strip()
                        if new_prompt:
                            # Tìm task tương ứng để cập nhật
                            if current_file_stem and current_file_stem in failed_tasks_data:
                                for task in failed_tasks_data[current_file_stem]:
                                    if task['global_index'] == global_idx:
                                        task['prompt'] = new_prompt
                                        break
                            else:
                                # Tìm trên toàn bộ data
                                for tasks in failed_tasks_data.values():
                                    for task in tasks:
                                        if task['global_index'] == global_idx:
                                            task['prompt'] = new_prompt
                                            break
            except Exception:
                pass

            # Collect updated prompts TỪ failed_tasks_data (đã bao gồm các edit cache)
            updated_prompts = {}  # {global_index: new_prompt}
            for tasks in failed_tasks_data.values():
                for task in tasks:
                    if task.get('prompt'):
                        updated_prompts[task['global_index']] = task['prompt']
            
            dialog.accept()
            
            self.log(f"💾 Đang merge {len(updated_prompts)} prompts đã sửa vào bảng chính...")
            
            # ✅ 1. Update all_prompts_data với prompts đã sửa
            for global_idx, new_prompt in updated_prompts.items():
                if 1 <= global_idx <= len(self.all_prompts_data):
                    old_prompt = self.all_prompts_data[global_idx - 1]
                    self.all_prompts_data[global_idx - 1] = new_prompt
                    self.log(f"  ✅ Updated prompt #{global_idx}: {old_prompt[:50]}... → {new_prompt[:50]}...")
            
            # ✅ 2. Update current_tasks nếu có
            if hasattr(self, 'current_tasks') and self.current_tasks:
                for global_idx, new_prompt in updated_prompts.items():
                    if 1 <= global_idx <= len(self.current_tasks):
                        task = self.current_tasks[global_idx - 1]
                        task.prompt_text = new_prompt
                        self.log(f"  ✅ Updated task #{global_idx} prompt")
            
            # ✅ 3. Clear các dòng đã hoàn thành (progress = 100) khỏi all_prompts_data
            # Nhưng giữ lại các dòng lỗi/chưa hoàn thành
            completed_indices = set()
            
            for row in range(self.prompts_table.rowCount()):
                prompt_item = self.prompts_table.item(row, 1)
                if not prompt_item:
                    continue
                
                global_idx = prompt_item.data(Qt.UserRole)
                if global_idx is None:
                    continue
                
                progress_bar = self.prompts_table.cellWidget(row, 2)
                if isinstance(progress_bar, QProgressBar):
                    if progress_bar.value() == 100:
                        # Check status text để đảm bảo thực sự hoàn thành
                        status_text = progress_bar.text() if hasattr(progress_bar, 'text') else ""
                        if "Done" in status_text or "Hoàn thành" in status_text or "✅" in status_text:
                            completed_indices.add(global_idx)

            # ✅ Bổ sung: lấy completed từ global_task_progress (phòng khi table chưa refresh)
            if hasattr(self, 'global_task_progress'):
                for g_idx, prog in list(self.global_task_progress.items()):
                    try:
                        if prog >= 100:
                            completed_indices.add(g_idx)
                    except Exception:
                        continue
            
            # ✅ 4. Tạo all_prompts_data mới chỉ chứa prompts chưa hoàn thành
            new_all_prompts_data = []
            new_mapping_global_to_new = {}  # {old_global_idx: new_global_idx}
            new_global_idx = 1
            
            for old_global_idx in range(1, len(self.all_prompts_data) + 1):
                if old_global_idx not in completed_indices:
                    new_all_prompts_data.append(self.all_prompts_data[old_global_idx - 1])
                    new_mapping_global_to_new[old_global_idx] = new_global_idx
                    new_global_idx += 1
            
            # ✅ 5. Update mappings
            new_file_mapping = {}
            new_local_mapping = {}
            
            for old_global_idx, new_global_idx in new_mapping_global_to_new.items():
                if old_global_idx in self.video_prompt_file_mapping:
                    new_file_mapping[new_global_idx] = self.video_prompt_file_mapping[old_global_idx]
                if old_global_idx in self.video_prompt_local_mapping:
                    new_local_mapping[new_global_idx] = self.video_prompt_local_mapping[old_global_idx]
            
            self.video_prompt_file_mapping = new_file_mapping
            self.video_prompt_local_mapping = new_local_mapping
            
            # ✅ 6. Update all_prompts_data
            self.all_prompts_data = new_all_prompts_data
            
            # ✅ 7. LOGIC ĐƠN GIẢN: Rebuild current_tasks chỉ với prompts đã sửa và chưa hoàn thành
            # ✅ Chỉ giữ lại các tasks có global_index trong new_mapping_global_to_new (tức là chưa hoàn thành)
            new_current_tasks = []
            failed_indices = set(updated_prompts.keys())  # Các prompts đã được sửa
            
            # ✅ Lấy tất cả global_index của prompts chưa hoàn thành từ prompts_table
            incomplete_indices = set()
            for row in range(self.prompts_table.rowCount()):
                prompt_item = self.prompts_table.item(row, 1)
                if prompt_item:
                    global_idx = prompt_item.data(Qt.UserRole)
                    if global_idx:
                        progress_bar = self.prompts_table.cellWidget(row, 2)
                        if isinstance(progress_bar, QProgressBar):
                            if progress_bar.value() < 100:  # Chưa hoàn thành
                                incomplete_indices.add(global_idx)
            
            # ✅ Kết hợp: prompts đã sửa + prompts chưa hoàn thành
            keep_indices = failed_indices | incomplete_indices
            
            # ✅ Rebuild current_tasks chỉ với các tasks này
            # ✅ QUAN TRỌNG: Tạo task MỚI từ new_all_prompts_data (đã được cập nhật) để đảm bảo prompt đúng
            # PromptTask đã được import ở đầu file, không cần import lại
            
            for old_global_idx, new_global_idx in sorted(new_mapping_global_to_new.items()):
                if old_global_idx in keep_indices:
                    # ✅ Lấy prompt từ new_all_prompts_data (đã được cập nhật ở bước 1 và 4)
                    if 1 <= new_global_idx <= len(new_all_prompts_data):
                        updated_prompt = new_all_prompts_data[new_global_idx - 1]
                        
                        # ✅ Tạo task MỚI với prompt đã được cập nhật
                        if 1 <= old_global_idx <= len(self.current_tasks):
                            old_task = self.current_tasks[old_global_idx - 1]
                            # Copy các attributes từ task cũ
                            new_task = PromptTask(
                                prompt_text=updated_prompt,  # ✅ Dùng prompt đã được cập nhật
                                prompt_index=new_global_idx,
                                output_folder=getattr(old_task, 'output_folder', None)
                            )
                            # Copy các attributes khác nếu có
                            if hasattr(old_task, 'source_file'):
                                new_task.source_file = old_task.source_file
                            if hasattr(old_task, 'local_index'):
                                new_task.local_index = old_task.local_index
                            if hasattr(old_task, 'image_path'):
                                new_task.image_path = old_task.image_path
                            if hasattr(old_task, 'end_image_path'):
                                new_task.end_image_path = old_task.end_image_path
                            
                            new_current_tasks.append(new_task)
                            self.log(f"  ✅ Rebuild task #{new_global_idx} (old #{old_global_idx}): prompt = {updated_prompt[:50]}...")
                        else:
                            # Fallback: tạo task mới chỉ với prompt
                            new_task = PromptTask(
                                prompt_text=updated_prompt,
                                prompt_index=new_global_idx,
                                output_folder=None
                            )
                            new_current_tasks.append(new_task)
                            self.log(f"  ✅ Rebuild task #{new_global_idx} (old #{old_global_idx}): tạo mới với prompt = {updated_prompt[:50]}...")
                    else:
                        # Fallback: dùng updated_prompts nếu có
                        if old_global_idx in updated_prompts:
                            if 1 <= old_global_idx <= len(self.current_tasks):
                                old_task = self.current_tasks[old_global_idx - 1]
                                new_task = PromptTask(
                                    prompt_text=updated_prompts[old_global_idx],
                                    prompt_index=new_global_idx,
                                    output_folder=getattr(old_task, 'output_folder', None)
                                )
                                # Copy các attributes khác
                                if hasattr(old_task, 'source_file'):
                                    new_task.source_file = old_task.source_file
                                if hasattr(old_task, 'local_index'):
                                    new_task.local_index = old_task.local_index
                                new_current_tasks.append(new_task)
                                self.log(f"  ✅ Rebuild task #{new_global_idx} (old #{old_global_idx}): dùng updated_prompts")
            
            self.current_tasks = new_current_tasks
            self.log(f"✅ Rebuilt current_tasks: {len(new_current_tasks)} tasks (đã sửa: {len(failed_indices)}, chưa hoàn thành: {len(incomplete_indices)})")
            
            # ✅ 7b. Update task_retry_metadata với mapping mới
            if hasattr(self, 'task_retry_metadata'):
                new_task_retry_metadata = {}
                for old_global_idx, new_global_idx in new_mapping_global_to_new.items():
                    if old_global_idx in self.task_retry_metadata:
                        new_task_retry_metadata[new_global_idx] = self.task_retry_metadata[old_global_idx]
                self.task_retry_metadata = new_task_retry_metadata
            
            # ✅ 7c. Update i2v_task_mapping, start_end_task_mapping, expand_reference_task_mapping với mapping mới
            # Để giữ nguyên mediaID và cookie_index đã cache
            if hasattr(self, 'i2v_task_mapping'):
                new_i2v_mapping = {}
                for old_global_idx, new_global_idx in new_mapping_global_to_new.items():
                    if old_global_idx in self.i2v_task_mapping:
                        new_i2v_mapping[new_global_idx] = self.i2v_task_mapping[old_global_idx]
                self.i2v_task_mapping = new_i2v_mapping
                self.log(f"💾 Đã update i2v_task_mapping: {len(new_i2v_mapping)} tasks (giữ nguyên mediaID và cookie_index)")
            
            if hasattr(self, 'start_end_task_mapping'):
                new_start_end_mapping = {}
                for old_global_idx, new_global_idx in new_mapping_global_to_new.items():
                    if old_global_idx in self.start_end_task_mapping:
                        new_start_end_mapping[new_global_idx] = self.start_end_task_mapping[old_global_idx]
                self.start_end_task_mapping = new_start_end_mapping
                self.log(f"💾 Đã update start_end_task_mapping: {len(new_start_end_mapping)} tasks (giữ nguyên mediaIDs và cookie_index)")
            
            if hasattr(self, 'expand_reference_task_mapping'):
                new_expand_ref_mapping = {}
                for old_global_idx, new_global_idx in new_mapping_global_to_new.items():
                    if old_global_idx in self.expand_reference_task_mapping:
                        new_expand_ref_mapping[new_global_idx] = self.expand_reference_task_mapping[old_global_idx]
                self.expand_reference_task_mapping = new_expand_ref_mapping
                self.log(f"💾 Đã update expand_reference_task_mapping: {len(new_expand_ref_mapping)} tasks (giữ nguyên cookie_index)")
            
            # ✅ 8. Clear progress cho các dòng đã xóa
            for old_global_idx in completed_indices:
                if old_global_idx in self.global_task_progress:
                    del self.global_task_progress[old_global_idx]
            
            # ✅ 9. Rebuild progress mapping
            new_progress = {}
            for old_global_idx, new_global_idx in new_mapping_global_to_new.items():
                if old_global_idx in self.global_task_progress:
                    new_progress[new_global_idx] = self.global_task_progress[old_global_idx]
            self.global_task_progress = new_progress
            
            # ✅ 10. Refresh prompts table
            self.current_prompts_page = 1
            self.refresh_prompts_table_page()
            
            # ✅ 11. Update batch table status (nếu có)
            if hasattr(self, 'batch_table') and hasattr(self, 'video_batch_file_status'):
                try:
                    for row in range(self.batch_table.rowCount()):
                        file_item = self.batch_table.item(row, 1)
                        if file_item:
                            file_name = file_item.text()
                            file_stem = Path(file_name).stem
                            
                            # Đếm số prompts chưa hoàn thành của file này
                            incomplete_count = 0
                            for new_global_idx in self.video_prompt_file_mapping:
                                if self.video_prompt_file_mapping[new_global_idx] == file_stem:
                                    incomplete_count += 1
                            
                            # Update status
                            if file_stem in self.video_batch_file_status:
                                total = self.video_batch_file_status[file_stem]['total']
                                completed = total - incomplete_count
                                status_item = self.batch_table.item(row, 2)
                                if status_item:
                                    status_item.setText(f"{completed}/{total}")
                except Exception as e:
                    self.log(f"⚠️ Lỗi update batch table status: {e}")
            
            self.log(f"✅ Đã merge {len(updated_prompts)} prompts và clear {len(completed_indices)} dòng đã hoàn thành")
            self.log(f"📊 Bảng chính còn lại {len(self.all_prompts_data)} prompts chưa hoàn thành")
            
            QMessageBox.information(
                self,
                "Thành công",
                f"✅ Đã lưu {len(updated_prompts)} prompts đã sửa\n"
                f"🗑️ Đã xóa {len(completed_indices)} dòng đã hoàn thành\n"
                f"📊 Còn lại {len(self.all_prompts_data)} prompts chưa hoàn thành\n\n"
                f"Bạn có thể ấn 'Bắt đầu' để chạy lại."
            )
            
        except Exception as e:
            self.log(f"❌ Lỗi save and merge failed prompts: {e}")
            import traceback
            self.log(traceback.format_exc())
            QMessageBox.critical(self, "Lỗi", f"Không thể lưu prompts:\n{e}")

    def show_fix_prompts_dialog(self, failed_tasks):
        """Hiện dialog để sửa prompts lỗi - MỖI PROMPT 1 Ô RIÊNG VỚI LABEL HIỂN THỊ FILE TXT"""
        try:
            dialog = QDialog(self)
            dialog.setWindowTitle(f"Sửa {len(failed_tasks)} Prompt Lỗi")
            dialog.setMinimumSize(1200, 800)
            
            layout = QVBoxLayout(dialog)
            layout.setSpacing(15)
            layout.setContentsMargins(20, 20, 20, 20)
            
            # Title
            title = QLabel(f"📝 Sửa {len(failed_tasks)} Prompt Lỗi")
            title.setStyleSheet("font-size: 18px; font-weight: bold; margin-bottom: 10px; color: #1976D2;")
            layout.addWidget(title)
            
            # Info
            info = QLabel("✏️ Mỗi prompt lỗi hiển thị trong 1 ô riêng. Label cho biết file txt gốc và số thứ tự dòng.\n⚠️ Lưu ý: Chỉ cập nhật prompts trong bộ nhớ và chạy lại các prompts đã sửa. File txt gốc KHÔNG bị thay đổi.")
            info.setStyleSheet("color: #666666; margin-bottom: 15px; font-size: 13px;")
            info.setWordWrap(True)
            layout.addWidget(info)
            
            # Scroll area
            from PySide6.QtWidgets import QScrollArea
            scroll_widget = QWidget()
            scroll_layout = QVBoxLayout(scroll_widget)
            scroll_layout.setSpacing(12)
            
            # Store prompt editors - mỗi prompt 1 editor riêng
            prompt_editors = []  # List of dicts: [{'task': task_dict, 'editor': QLineEdit, 'file_label': QLabel}, ...]
            
            for task in failed_tasks:
                # Tạo container cho mỗi prompt
                prompt_container = QFrame()
                prompt_container.setFrameShape(QFrame.Box)
                prompt_container.setStyleSheet("""
                    QFrame {
                        border: 2px solid #e0e0e0;
                        border-radius: 8px;
                        background-color: #fafafa;
                        padding: 10px;
                    }
                """)
                prompt_layout = QVBoxLayout(prompt_container)
                prompt_layout.setSpacing(8)
                
                # ✅ Label hiển thị file txt gốc và số thứ tự dòng
                # Lấy từ nhiều nguồn để đảm bảo có thông tin
                source_file = task.get('source_file')
                local_index = task.get('local_index')
                task_index = task.get('index')
                
                # ✅ Debug log
                self.log(f"🔍 Dialog task {task_index}: source_file={source_file}, local_index={local_index}")
                
                # ✅ Nếu không có trong task dict, thử lấy từ task object trong current_tasks
                if (not source_file or not local_index) and task_index:
                    # Kiểm tra current_tasks
                    if hasattr(self, 'current_tasks') and self.current_tasks:
                        if task_index > 0 and task_index <= len(self.current_tasks):
                            task_obj = self.current_tasks[task_index - 1]
                            if not source_file and hasattr(task_obj, 'source_file') and task_obj.source_file:
                                source_file = task_obj.source_file
                                self.log(f"  ✅ Lấy source_file từ task object: {source_file}")
                            if not local_index and hasattr(task_obj, 'local_index') and task_obj.local_index is not None:
                                local_index = task_obj.local_index
                                self.log(f"  ✅ Lấy local_index từ task object: {local_index}")
                        else:
                            self.log(f"  ⚠️ task_index {task_index} ngoài phạm vi current_tasks (len={len(self.current_tasks)})")
                    else:
                        self.log(f"  ⚠️ current_tasks rỗng hoặc không tồn tại")
                
                # ✅ Nếu vẫn không có, thử lấy từ mapping
                if not source_file and task_index:
                    if hasattr(self, 'video_prompt_file_mapping') and self.video_prompt_file_mapping:
                        source_file = self.video_prompt_file_mapping.get(task_index, None)
                        if source_file:
                            self.log(f"  ✅ Lấy source_file từ mapping: {source_file}")
                        else:
                            self.log(f"  ⚠️ Không tìm thấy source_file trong mapping cho task_index {task_index}")
                            self.log(f"  📋 Mapping keys: {list(self.video_prompt_file_mapping.keys())[:10]}...")
                    else:
                        self.log(f"  ⚠️ video_prompt_file_mapping không tồn tại hoặc rỗng")
                
                if not local_index and task_index:
                    if hasattr(self, 'video_prompt_local_mapping') and self.video_prompt_local_mapping:
                        local_index = self.video_prompt_local_mapping.get(task_index, None)
                        if local_index:
                            self.log(f"  ✅ Lấy local_index từ mapping: {local_index}")
                        else:
                            self.log(f"  ⚠️ Không tìm thấy local_index trong mapping cho task_index {task_index}")
                            self.log(f"  📋 Mapping keys: {list(self.video_prompt_local_mapping.keys())[:10]}...")
                    else:
                        self.log(f"  ⚠️ video_prompt_local_mapping không tồn tại hoặc rỗng")
                
                # ✅ Fallback: hiển thị "Unknown" và "?" nếu vẫn không có
                source_file = source_file or 'Unknown'
                local_index = local_index if local_index is not None else '?'
                
                self.log(f"  📄 Kết quả: File={source_file}, Dòng={local_index}")
                
                # ✅ Format file name (thêm .txt nếu chưa có)
                if source_file != 'Unknown':
                    file_display = source_file if source_file.endswith('.txt') else f"{source_file}.txt"
                else:
                    file_display = 'Unknown.txt'
                
                file_label = QLabel(f"📄 File: {file_display} | Dòng: {local_index}")
                file_label.setStyleSheet("""
                    QLabel {
                        font-weight: bold;
                        font-size: 13px;
                        color: #1976D2;
                        padding: 5px;
                        background-color: #e3f2fd;
                        border-radius: 4px;
                    }
                """)
                prompt_layout.addWidget(file_label)
                
                # Text editor cho prompt (QLineEdit hoặc QTextEdit tùy độ dài)
                prompt_text = task.get('prompt', '')
                
                # Dùng QTextEdit để có thể chỉnh sửa prompt dài
                editor = QTextEdit()
                editor.setPlainText(prompt_text)
                editor.setMaximumHeight(100)
                editor.setStyleSheet("""
                    QTextEdit {
                        border: 1px solid #ccc;
                        border-radius: 4px;
                        padding: 8px;
                        font-size: 13px;
                        background-color: white;
                    }
                    QTextEdit:focus {
                        border: 2px solid #1976D2;
                    }
                """)
                prompt_layout.addWidget(editor)
                
                # Lưu thông tin
                prompt_editors.append({
                    'task': task,
                    'editor': editor,
                    'file_label': file_label
                })
                
                scroll_layout.addWidget(prompt_container)
            
            # Add to scroll area
            scroll_area = QScrollArea()
            scroll_area.setWidget(scroll_widget)
            scroll_area.setWidgetResizable(True)
            scroll_area.setStyleSheet("""
                QScrollArea {
                    border: 1px solid #ddd;
                    border-radius: 4px;
                    background-color: white;
                }
            """)
            layout.addWidget(scroll_area)
            
            # Buttons
            btn_layout = QHBoxLayout()
            btn_layout.addStretch()
            
            btn_save = QPushButton("💾 Lưu & Chạy Lại")
            btn_save.setObjectName("startButton")
            btn_save.setStyleSheet("""
                QPushButton {
                    padding: 12px 24px;
                    font-size: 14px;
                    font-weight: bold;
                    min-width: 200px;
                }
            """)
            # ✅ Fix closure bug: dùng default argument để capture đúng giá trị
            btn_save.clicked.connect(
                lambda checked=False, d=dialog, pe=prompt_editors: 
                self.save_and_retry_failed_grouped(d, pe)
            )
            btn_layout.addWidget(btn_save)
            
            btn_cancel = QPushButton("❌ Hủy")
            btn_cancel.setStyleSheet("""
                QPushButton {
                    padding: 12px 24px;
                    font-size: 14px;
                    min-width: 100px;
                }
            """)
            btn_cancel.clicked.connect(dialog.reject)
            btn_layout.addWidget(btn_cancel)
            
            layout.addLayout(btn_layout)
            
            dialog.exec()
            
        except Exception as e:
            self.log(f"❌ Lỗi show dialog: {e}")
            import traceback
            self.log(traceback.format_exc())
    
    def show_retry_cookie_dialog(self) -> bool:
        """Hiển thị dialog cookie trước khi retry - trả về True nếu user đã nhập cookie"""
        try:
            cookie_dialog = QDialog(self)
            cookie_dialog.setWindowTitle("🔑 Cài Đặt Cookie - Retry")
            cookie_dialog.setMinimumSize(700, 500)
            
            layout = QVBoxLayout(cookie_dialog)
            layout.setSpacing(15)
            layout.setContentsMargins(20, 20, 20, 20)
            
            # Title
            title = QLabel("🔑 Nhập Cookie Mới Trước Khi Retry")
            title.setStyleSheet("font-size: 18px; font-weight: bold; color: #1976D2; margin-bottom: 10px;")
            layout.addWidget(title)
            
            # Info
            info = QLabel("Vui lòng dán cookie mới vào ô bên dưới trước khi chạy lại các prompts đã sửa.")
            info.setWordWrap(True)
            info.setStyleSheet("color: #666666; font-size: 13px; margin-bottom: 10px;")
            layout.addWidget(info)
            
            # Cookie input
            cookie_label = QLabel("Cookie:")
            cookie_label.setStyleSheet("font-weight: 600; font-size: 13px;")
            layout.addWidget(cookie_label)
            
            cookie_edit = QTextEdit()
            cookie_edit.setPlaceholderText("Dán cookie vào đây...")
            cookie_edit.setMinimumHeight(200)
            cookie_edit.setStyleSheet("""
                QTextEdit {
                    border: 2px solid #1976D2;
                    border-radius: 6px;
                    padding: 10px;
                    font-size: 12px;
                    font-family: 'Courier New', monospace;
                }
                QTextEdit:focus {
                    border: 2px solid #0d47a1;
                }
            """)
            # ❗️Không pre-fill cookie cũ nữa — luôn để trống để user nhập cookie HOÀN TOÀN MỚI
            layout.addWidget(cookie_edit)
            
            # Buttons
            btn_layout = QHBoxLayout()
            btn_layout.addStretch()
            
            btn_ok = QPushButton("✅ Lưu & Tiếp Tục")
            btn_ok.setStyleSheet("""
                QPushButton {
                    padding: 12px 24px;
                    font-size: 14px;
                    font-weight: bold;
                    background-color: #1976D2;
                    color: white;
                    border-radius: 6px;
                    min-width: 150px;
                }
                QPushButton:hover {
                    background-color: #1565C0;
                }
            """)
            
            btn_cancel = QPushButton("❌ Hủy")
            btn_cancel.setStyleSheet("""
                QPushButton {
                    padding: 12px 24px;
                    font-size: 14px;
                    border-radius: 6px;
                    min-width: 100px;
                }
            """)
            
            cookie_saved = False
            
            def on_ok_clicked():
                nonlocal cookie_saved
                cookie_text = cookie_edit.toPlainText().strip()
                
                # ✅ BẮT BUỘC phải nhập cookie mới khi retry
                if not cookie_text:
                    QMessageBox.warning(cookie_dialog, "Cảnh báo", "Vui lòng nhập cookie MỚI trước khi tiếp tục!")
                    return
                
                try:
                    # Parse cookie string giống như trong show_cookie_dialog
                    from complete_flow import _parse_cookie_string
                    
                    # ✅ Parse cookies (mỗi cookie cách nhau bởi blank line - giống show_cookie_dialog)
                    # Nếu không có blank line, thử tách theo pattern khác hoặc coi như 1 cookie duy nhất
                    if "\n\n" in cookie_text:
                        # Tách theo blank line (2 newlines)
                        parsed_cookies = [c.strip() for c in cookie_text.split("\n\n") if c.strip()]
                    elif cookie_text.count("\n") >= 10:
                        # Nếu có nhiều dòng nhưng không có blank line, có thể là nhiều cookie được nối lại
                        # Thử tách theo pattern: tìm các dòng bắt đầu bằng "domain" hoặc "name"
                        lines = cookie_text.split("\n")
                        parsed_cookies = []
                        current_cookie = []
                        for line in lines:
                            line = line.strip()
                            if not line:
                                continue
                            # Nếu dòng bắt đầu bằng "domain" hoặc "name", có thể là cookie mới
                            if line.startswith("domain") or line.startswith("name"):
                                if current_cookie:
                                    parsed_cookies.append("\n".join(current_cookie))
                                current_cookie = [line]
                            else:
                                current_cookie.append(line)
                        if current_cookie:
                            parsed_cookies.append("\n".join(current_cookie))
                        # Nếu không parse được, coi như 1 cookie
                        if not parsed_cookies:
                            parsed_cookies = [cookie_text.strip()] if cookie_text.strip() else []
                    else:
                        # Nếu chỉ có 1 cookie (không có blank line), dùng toàn bộ text
                        parsed_cookies = [cookie_text.strip()] if cookie_text.strip() else []
                    
                    # Validate từng cookie
                    valid_cookies = []
                    for cookie_str in parsed_cookies:
                        # Parse cookie string để validate
                        cookies_dict = _parse_cookie_string(cookie_str)
                        if cookies_dict:
                            valid_cookies.append(cookie_str)  # Lưu cookie string gốc
                            self.log(f"✅ Cookie hợp lệ: {cookie_str[:50]}...")
                        else:
                            # Nếu parse fail, cảnh báo nhưng vẫn cho phép lưu (có thể cookie format đặc biệt)
                            self.log(f"⚠️ Cookie có thể không hợp lệ (vẫn lưu): {cookie_str[:50]}...")
                            valid_cookies.append(cookie_str)
                    
                    if not valid_cookies:
                        QMessageBox.warning(cookie_dialog, "Cảnh báo", "Không có cookie hợp lệ nào được tìm thấy!")
                        return
                    
                    parsed_cookies = valid_cookies
                    
                    # Lưu cookies sau khi validate
                    self.cookies_list = parsed_cookies
                    
                    # Apply plan cookie limit nếu có
                    if hasattr(self, '_apply_plan_cookie_limit'):
                        self._apply_plan_cookie_limit()
                    
                    # Set cookie_value cho backward compatibility
                    self.cookie_value = self.cookies_list[0] if self.cookies_list else ""
                    
                    # Clear cookie status cache để force re-validate
                    if hasattr(self, '_cookie_status_cache'):
                        self._cookie_status_cache.clear()
                    if hasattr(self, '_init_cookie_status'):
                        self._init_cookie_status()
                    
                    # Cập nhật Flow concurrent range
                    if hasattr(self, 'update_flow_concurrent_range'):
                        self.update_flow_concurrent_range()
                    
                    # Auto-adjust max concurrent jobs
                    if hasattr(self, 'update_max_concurrent_from_cookies'):
                        self.update_max_concurrent_from_cookies()
                    if hasattr(self, 'update_max_image_concurrent_from_cookies'):
                        self.update_max_image_concurrent_from_cookies()
                    
                    num_cookies = len(self.cookies_list)
                    self.log(f"✅ Đã cập nhật {num_cookies} cookie(s) từ dialog retry")
                    
                    # Test cookie đầu tiên để đảm bảo hợp lệ
                    if num_cookies > 0:
                        test_client = self.build_client(0)
                        if test_client:
                            self.log(f"✅ Cookie đầu tiên đã được validate thành công")
                        else:
                            self.log(f"⚠️ Cookie đầu tiên có thể không hợp lệ, nhưng vẫn tiếp tục retry")
                    
                    cookie_saved = True
                    cookie_dialog.accept()
                    
                except Exception as e:
                    self.log(f"❌ Lỗi khi parse cookie trong dialog retry: {e}")
                    import traceback
                    self.log(traceback.format_exc())
                    QMessageBox.critical(cookie_dialog, "Lỗi", f"Không thể parse cookie:\n{e}")
                    return
            
            btn_ok.clicked.connect(on_ok_clicked)
            btn_cancel.clicked.connect(cookie_dialog.reject)
            
            btn_layout.addWidget(btn_ok)
            btn_layout.addWidget(btn_cancel)
            layout.addLayout(btn_layout)
            
            # Show dialog
            result = cookie_dialog.exec()
            return cookie_saved and result == QDialog.Accepted
            
        except Exception as e:
            self.log(f"❌ Lỗi show_retry_cookie_dialog: {e}")
            import traceback
            self.log(traceback.format_exc())
            return False
    
    def save_and_retry_failed_grouped(self, dialog, prompt_editors):
        """Cập nhật prompts đã sửa trong current_tasks và CHỈ RETRY các prompts đã sửa (KHÔNG sửa file txt)"""
        try:
            updated_tasks = []  # Danh sách các task đã được cập nhật để retry
            
            # Cập nhật prompts trong current_tasks
            for editor_info in prompt_editors:
                task_dict = editor_info['task']
                editor = editor_info['editor']
                new_prompt = editor.toPlainText().strip()
                
                if not new_prompt:
                    continue
                
                task_index = task_dict.get('index', None)
                if not task_index or task_index < 1 or task_index > len(self.current_tasks):
                    self.log(f"⚠️ Bỏ qua prompt: task_index {task_index} không hợp lệ")
                    continue
                
                # Cập nhật prompt trong current_tasks
                task = self.current_tasks[task_index - 1]
                old_prompt = task.prompt_text
                task.prompt_text = new_prompt
                self._update_task_metadata_cache([task])
                
                self.log(f"✅ Cập nhật prompt #{task_index}: {old_prompt[:50]}... → {new_prompt[:50]}...")
                
                # Cập nhật trong table - tìm row chính xác theo task_index
                target_row = None
                for row in range(self.prompts_table.rowCount()):
                    prompt_item = self.prompts_table.item(row, 1)
                    if prompt_item:
                        prompt_text = prompt_item.text()
                        # Tìm theo format "index: prompt" hoặc chỉ "prompt"
                        if ':' in prompt_text:
                            try:
                                item_index = int(prompt_text.split(':')[0].strip())
                                if item_index == task_index:
                                    target_row = row
                                    break
                            except:
                                pass
                        else:
                            # Nếu không có prefix, dùng row + 1 làm index
                            if row + 1 == task_index:
                                target_row = row
                                break
                
                # Fallback: dùng row từ task_dict nếu không tìm thấy
                if target_row is None:
                    target_row = task_dict.get('row', task_index - 1)
                
                if target_row is not None and target_row < self.prompts_table.rowCount():
                    max_display_length = 100
                    if len(new_prompt) > max_display_length:
                        display_text = f'{task_index}: {new_prompt[:max_display_length]}...'
                    else:
                        display_text = f'{task_index}: {new_prompt}'
                    
                    # Tạo item mới với đầy đủ data
                    new_item = QTableWidgetItem(display_text)
                    new_item.setData(Qt.UserRole, task_index)  # Store global index
                    new_item.setData(Qt.UserRole + 1, new_prompt)  # Store full text
                    self.prompts_table.setItem(target_row, 1, new_item)
                    self.log(f"✅ Đã cập nhật table row {target_row} cho task #{task_index}")
                
                updated_tasks.append(task_index)
            
            # ✅ Nếu không có prompt nào được sửa, retry tất cả failed tasks với prompts gốc
            if not updated_tasks:
                # Lấy tất cả task indices từ prompt_editors để retry với prompts gốc
                for editor_info in prompt_editors:
                    task_dict = editor_info.get('task', {})
                    task_index = task_dict.get('index', None)
                    if task_index and task_index > 0 and task_index <= len(self.current_tasks):
                        updated_tasks.append(task_index)
                
                if not updated_tasks:
                    QMessageBox.warning(self, "Cảnh báo", "Không có prompts hợp lệ để retry!")
                    return
                
                self.log(f"ℹ️ Không có prompt nào được sửa, sẽ retry {len(updated_tasks)} prompts với prompts gốc...")
            else:
                self.log(f"✅ Đã cập nhật {len(updated_tasks)} prompts trong current_tasks")
            
            dialog.accept()
            
            # ✅ Hiển thị dialog cookie chính (giống nút cài đặt cookie) trước khi retry
            self.show_cookie_dialog()
            
            # ✅ Kiểm tra cookies sau khi đóng dialog
            if not (self.cookie_value or self.cookies_list):
                self.log("⚠️ Người dùng không nhập cookie, dừng retry")
                QMessageBox.warning(self, "Cảnh báo", "Vui lòng nhập cookie trước khi retry!")
                return
            
            # ✅ RETRY các prompts (đã sửa hoặc prompts gốc nếu không sửa)
            self.log(f"🔄 Bắt đầu retry {len(updated_tasks)} prompts...")
            
            # Get settings
            model_text = self.combo_model.currentText()
            # Xác định portrait/landscape từ model text thay vì aspect combo
            is_portrait = "9:16" in model_text
            # Map display text to actual model key - Veo 3.1 Full Models
            model_map = {
                # Landscape
                "Fast": "veo_3_1_t2v_fast_ultra",   # 10 credits
                "Quality": "veo_3_1_t2v",           # 100 credits
                "Low Fast": "veo_3_1_t2v_fast_ultra_relaxed",  # 0 credits
                # Portrait
                "Fast (9:16)": "veo_3_1_t2v_fast_portrait_ultra",   # 10 credits
                "Quality (9:16)": "veo_3_1_t2v_portrait",           # 100 credits
                "Low Fast (9:16)": "veo_3_1_t2v_fast_portrait_ultra_relaxed",  # 0 credits
                # Legacy names (backward compatibility)
                "Veo 3.1 Ultra": "veo_3_1_t2v_fast_ultra",
                "Veo 3.1 Ultra Portrait": "veo_3_1_t2v_fast_portrait_ultra",
                "Veo 3.1 Standard": "veo_3_1_t2v",
                "Veo 3.1 Standard Portrait": "veo_3_1_t2v_portrait",
                "Veo 2.1 Fast": "veo_2_1_fast_d_15_t2v",
                "Veo 3.1 Relaxed": "veo_3_1_t2v_fast_ultra_relaxed",
                "Veo 3.1 Relaxed Portrait": "veo_3_1_t2v_fast_portrait_ultra_relaxed",
            }
            # ⚠️ Default luôn là bản 10 credits
            model = model_map.get(model_text, "veo_3_1_t2v_fast_ultra")
            # Aspect được xác định từ model text - không cần override
            num_videos = self.spin_num_videos.value()
            aspect = "16:9" if "16:9" in model_text else "9:16"
            current_mode = getattr(self, "current_video_mode", "")
            
            # ✅ Override model cho Integrate to Video và Expand + Reference mode
            if current_mode == "Integrate to Video" or current_mode == "Expand + Reference":
                # ✅ Update to Veo 3.1 Reference Images models based on aspect ratio
                if aspect == "9:16":
                    model = "veo_3_1_r2v_fast_portrait_ultra"
                else:  # 16:9 landscape
                    model = "veo_3_1_r2v_fast_landscape_ultra"
            elif model == "veo_3_1_t2v_fast_ultra_relaxed":
                if current_mode == "Image to Video":
                    model = "veo_3_1_i2v_s_fast_portrait_ultra_relaxed"
                elif aspect == "9:16":
                    model = "veo_3_1_t2v_fast_portrait_ultra_relaxed"
            output_folder = self.output_folder.text().strip()
            
            # Tạo list tasks để retry (chỉ các tasks đã sửa)
            retry_tasks = []
            for task_index in updated_tasks:
                if task_index > 0 and task_index <= len(self.current_tasks):
                    task = self.current_tasks[task_index - 1]
                    
                    # ✅ XỬ LÝ IMAGE TO VIDEO: Tạo ImageTask từ mapping
                    if self.current_video_mode == "Image to Video":
                        if task_index in self.i2v_task_mapping:
                            mapping = self.i2v_task_mapping[task_index]
                            image_path = mapping.get("image_path")
                            
                            if image_path and Path(image_path).exists():
                                # Cập nhật prompt trong mapping
                                mapping["prompt"] = task.prompt_text
                                
                                # Tạo ImageTask từ mapping
                                retry_task = ImageTask(
                                    image_path=image_path,
                                    prompt_text=task.prompt_text,
                                    task_index=task_index
                                )
                                
                                output_folder_value = mapping.get("output_folder")
                                self.log(f"🔄 Retry Image to Video task #{task_index}: image={Path(image_path).name}, output_folder={output_folder_value}")
                                retry_tasks.append(retry_task)
                            else:
                                self.log(f"⚠️ Image path không tồn tại cho task {task_index}: {image_path}")
                        else:
                            self.log(f"⚠️ Không tìm thấy mapping cho Image to Video task {task_index}")
                    else:
                        # ✅ TEXT TO VIDEO: Tạo PromptTask
                        # ✅ Đảm bảo lấy đúng output_folder, source_file và local_index
                        # Ưu tiên: task -> cache -> mapping
                        output_folder_value = getattr(task, 'output_folder', None)
                        source_file_value = getattr(task, 'source_file', None)
                        local_index_value = getattr(task, 'local_index', None)
                        
                        # ✅ Nếu không có trong task, thử lấy từ cache
                        if not output_folder_value or not source_file_value or not local_index_value:
                            if hasattr(self, 'task_retry_metadata') and task_index in self.task_retry_metadata:
                                cache = self.task_retry_metadata[task_index]
                                if not output_folder_value:
                                    output_folder_value = cache.get('output_folder')
                                if not source_file_value:
                                    source_file_value = cache.get('source_file')
                                if not local_index_value:
                                    local_index_value = cache.get('local_index')
                        
                        # ✅ Nếu vẫn không có, thử lấy từ mapping
                        if not source_file_value and hasattr(self, 'video_prompt_file_mapping'):
                            source_file_value = self.video_prompt_file_mapping.get(task_index, None)
                        
                        if not local_index_value and hasattr(self, 'video_prompt_local_mapping'):
                            local_index_value = self.video_prompt_local_mapping.get(task_index, None)
                        
                        # ✅ Nếu vẫn không có output_folder, dùng source_file làm output_folder
                        if not output_folder_value and source_file_value:
                            output_folder_value = source_file_value
                        
                        # ✅ BUG FIX: Cập nhật lại metadata vào task gốc để lần retry sau vẫn có
                        if output_folder_value:
                            task.output_folder = output_folder_value
                        if source_file_value:
                            task.source_file = source_file_value
                        if local_index_value:
                            task.local_index = local_index_value
                        
                        # ✅ Cập nhật cache để preserve cho lần retry sau
                        if hasattr(self, 'task_retry_metadata'):
                            if task_index not in self.task_retry_metadata:
                                self.task_retry_metadata[task_index] = {}
                            self.task_retry_metadata[task_index].update({
                                'output_folder': output_folder_value,
                                'source_file': source_file_value,
                                'local_index': local_index_value,
                                'prompt_text': task.prompt_text,
                                'integrate_images': getattr(task, 'integrate_images', None),
                                'is_expand_reference': getattr(task, 'is_expand_reference', False),
                                'is_custom_integrate': getattr(task, 'is_custom_integrate', False)
                            })
                        
                        # Tạo task mới với prompt đã sửa
                        # ✅ Xử lý cả ImageTask và PromptTask (ImageTask có task_index, PromptTask có prompt_index)
                        task_idx = getattr(task, 'task_index', None) or getattr(task, 'prompt_index', None)
                        if task_idx is None:
                            self.log(f"❌ Task không có task_index hoặc prompt_index: {type(task)}")
                            continue
                        
                        retry_task = PromptTask(
                            prompt_text=task.prompt_text,
                            prompt_index=task_idx,
                            output_folder=output_folder_value
                        )
                        retry_task.source_file = source_file_value
                        retry_task.local_index = local_index_value
                        
                        # ✅ Lấy integrate_images từ task gốc hoặc từ cache
                        integrate_images = getattr(task, 'integrate_images', None)
                        
                        # ✅ FIX BUG: Nếu task gốc không có integrate_images, thử lấy từ cache
                        if not integrate_images and hasattr(self, 'task_retry_metadata') and task_index in self.task_retry_metadata:
                            integrate_images = self.task_retry_metadata[task_index].get('integrate_images')
                            if integrate_images:
                                self.log(f"♻️ Lấy integrate_images từ cache cho task #{task_index}")
                        
                        # ✅ FIX BUG: Nếu vẫn không có, thử lấy từ expand_reference_task_mapping
                        if not integrate_images and hasattr(self, 'expand_reference_task_mapping') and task_index in self.expand_reference_task_mapping:
                            integrate_images = self.expand_reference_task_mapping[task_index].get('integrate_images')
                            if integrate_images:
                                self.log(f"♻️ Lấy integrate_images từ expand_reference_task_mapping cho task #{task_index}")
                        
                        if integrate_images:
                            retry_task.integrate_images = list(integrate_images)
                            self.log(f"📋 Task #{task_index} có {len(retry_task.integrate_images)} integrate_images")
                        
                        if hasattr(task, 'is_custom_integrate'):
                            retry_task.is_custom_integrate = getattr(task, 'is_custom_integrate', False)
                        
                        # ✅ FIX BUG: Copy is_expand_reference để đảm bảo mode đúng
                        if hasattr(task, 'is_expand_reference'):
                            retry_task.is_expand_reference = getattr(task, 'is_expand_reference', False)
                        elif current_mode == "Expand + Reference":
                            retry_task.is_expand_reference = True
                        
                        self.log(f"🔄 Retry task #{task_index}: output_folder={output_folder_value}, source_file={source_file_value}, local_index={local_index_value}, integrate_images={len(integrate_images) if integrate_images else 0}")
                        retry_tasks.append(retry_task)
                    
                    # Reset status và progress trong table
                    self.update_task_status(task_index, "Chờ xử lý")
                    self.update_task_progress(task_index, 0)
            
            if retry_tasks:
                # ✅ Kiểm tra cookie đang chạy trước khi retry (với lock để tránh race condition)
                num_cookies = len(self.cookies_list) if self.cookies_list else 1
                self._init_cookie_status()
                
                import threading
                if not hasattr(self, '_cookie_task_mapping_lock'):
                    self._cookie_task_mapping_lock = threading.Lock()
                
                # Kiểm tra từng task xem cookie của nó có đang chạy không
                # ✅ CHỈ CHECK TASK THỰC SỰ ĐANG CHẠY (status != "Done" và status != "Error")
                blocked_tasks = []
                with self._cookie_task_mapping_lock:
                    for retry_task in retry_tasks:
                        # ✅ BUG FIX: ImageTask có task_index, PromptTask có prompt_index
                        task_index = getattr(retry_task, 'task_index', None) or getattr(retry_task, 'prompt_index', None)
                        if task_index is None:
                            self.log(f"⚠️ Retry task không có task_index hoặc prompt_index: {type(retry_task)}, bỏ qua")
                            continue
                        if num_cookies > 1:
                            selected_cookie = (task_index - 1) % num_cookies
                        else:
                            selected_cookie = 0
                        
                        if hasattr(self, 'cookie_task_mapping') and selected_cookie in self.cookie_task_mapping:
                            running_tasks = self.cookie_task_mapping[selected_cookie].copy()  # Copy để tránh modification during iteration
                            if running_tasks:
                                # ✅ Loại bỏ task đã Done hoặc Error (không còn chạy)
                                actually_running = set()
                                for running_task_idx in running_tasks:
                                    # Kiểm tra status của task này
                                    running_status = None
                                    # Tìm row trong table để lấy status
                                    for row in range(self.prompts_table.rowCount()):
                                        prompt_item = self.prompts_table.item(row, 1)
                                        if prompt_item:
                                            stored_index = prompt_item.data(Qt.UserRole)
                                            if stored_index == running_task_idx:
                                                status_item = self.prompts_table.item(row, 3)
                                                if status_item:
                                                    running_status = status_item.text()
                                                break
                                    
                                    # Chỉ coi là đang chạy nếu status không phải "Done" hoặc "Error"
                                    if running_status not in ["Done", "Error"]:
                                        actually_running.add(running_task_idx)
                                
                                # Loại bỏ task hiện tại nếu có (vì có thể đang retry chính task đó)
                                actually_running.discard(task_index)
                                if actually_running:
                                    blocked_tasks.append((task_index, selected_cookie, sorted(list(actually_running))))
                
                if blocked_tasks:
                    blocked_info = "\n".join([
                        f"  - Task #{task_idx}: Cookie #{cookie_idx + 1} đang chạy task(s) {running}"
                        for task_idx, cookie_idx, running in blocked_tasks
                    ])
                    self.log(f"⚠️ Không thể retry {len(blocked_tasks)} task(s) vì cookie đang bận:\n{blocked_info}")
                    QMessageBox.warning(
                        self,
                        "⚠️ Cookie đang bận",
                        f"Không thể retry {len(blocked_tasks)} task(s) vì cookie đang chạy task khác:\n\n{blocked_info}\n\n"
                        f"Vui lòng đợi task(s) đang chạy hoàn thành trước khi retry."
                    )
                    # Chỉ retry các task không bị block
                    retry_tasks = [t for t in retry_tasks if t.prompt_index not in [bt[0] for bt in blocked_tasks]]
            
            if retry_tasks:
                # ✅ Gọi run_processing_worker trong thread riêng để retry các tasks đã sửa
                threading.Thread(
                    target=self.run_processing_worker,
                    args=(retry_tasks, model, num_videos, aspect, output_folder),
                    daemon=True
                ).start()
                
                self.log(f"✅ Đã thêm {len(retry_tasks)} tasks đã sửa vào queue retry")
            else:
                self.log(f"⚠️ Không có task nào có thể retry (tất cả đều bị block)")
            
            # Notify user
            QMessageBox.information(
                self,
                "Cập nhật và Retry",
                f"✅ Đã cập nhật {len(updated_tasks)} prompts\n\n"
                f"🔄 Đang chạy lại {len(updated_tasks)} prompts đã sửa...\n\n"
                f"Chỉ các prompts đã sửa được chạy lại, các prompts khác không bị ảnh hưởng."
            )
            
        except Exception as e:
            self.log(f"❌ Lỗi save and retry: {e}")
            import traceback
            self.log(traceback.format_exc())
            QMessageBox.critical(self, "Lỗi", f"Không thể cập nhật và retry:\n{e}")
    
    def save_and_retry_failed(self, dialog, prompt_editors):
        """Lưu prompts đã sửa và retry - OLD VERSION (không dùng nữa)"""
        try:
            # Update prompts trong current_tasks
            for editor_info in prompt_editors:
                index = editor_info['index']
                new_prompt = editor_info['editor'].toPlainText().strip()
                
                if index <= len(self.current_tasks):
                    task = self.current_tasks[index - 1]
                    task.prompt_text = new_prompt
                    
                    # Update table
                    row = editor_info['row']
                    max_display_length = 100  # TĂNG TỪ 50 → 100 KÝ TỰ
                    if len(new_prompt) > max_display_length:
                        display_text = f'{index}: {new_prompt[:max_display_length]}...'
                    else:
                        display_text = f'{index}: {new_prompt}'
                    prompt_item = self._create_prompt_table_item(display_text, new_prompt, index)
                    self.prompts_table.setItem(row, 1, prompt_item)
            
            dialog.accept()
            
            # Retry all failed tasks
            self.log(f"🔄 Bắt đầu retry {len(prompt_editors)} prompts đã sửa...")
            
            for editor_info in prompt_editors:
                task_index = editor_info['index']
                self.retry_single_task(task_index)
                
        except Exception as e:
            self.log(f"❌ Lỗi save and retry: {e}")
    
