def main():
    # ✅ SINGLE INSTANCE CHECK - Chặn mở app 2 lần
    # Cross-platform: sử dụng msvcrt trên Windows, fcntl trên Unix/macOS
    import tempfile
    
    LOCK_FILE = os.path.join(tempfile.gettempdir(), "GoogleLabsFlowQt6_SingleInstance.lock")
    lock_file = None
    lock_acquired = False
    
    # Kiểm tra hệ điều hành
    is_windows = sys.platform == 'win32'
    
    try:
        # Mở file lock
        lock_file = open(LOCK_FILE, 'w')
        
        # Thử khóa file - nếu không được nghĩa là app đang chạy
        try:
            if is_windows:
                # Windows: sử dụng msvcrt
                import msvcrt
                msvcrt.locking(lock_file.fileno(), msvcrt.LK_NBLCK, 1)
            else:
                # Unix/macOS: sử dụng fcntl
                import fcntl
                fcntl.flock(lock_file.fileno(), fcntl.LOCK_EX | fcntl.LOCK_NB)
            
            # Ghi PID vào file để debug
            lock_file.write(str(os.getpid()))
            lock_file.flush()
            lock_acquired = True  # ✅ Lock thành công
        except (IOError, OSError):
            # File đã bị khóa bởi instance khác
            if lock_file:
                lock_file.close()
                lock_file = None
            # App đã đang chạy - hiển thị thông báo và thoát
            # Cần tạo QApplication trước để hiển thị QMessageBox
            temp_app = QApplication(sys.argv)
            msg = QMessageBox()
            msg.setIcon(QMessageBox.Warning)
            msg.setWindowTitle("⚠️ Ứng dụng đã đang chạy")
            msg.setText("Google Labs Flow đã được mở.\n\nVui lòng sử dụng cửa sổ đang có sẵn.")
            msg.setInformativeText("Không thể mở 2 instance cùng lúc.")
            msg.exec()
            return 1
    
        # ✅ Đảm bảo lock được giải phóng khi app đóng (chỉ khi lock thành công)
        if lock_acquired:
            def release_lock():
                nonlocal lock_file
                if lock_file:
                    try:
                        if is_windows:
                            import msvcrt
                            msvcrt.locking(lock_file.fileno(), msvcrt.LK_UNLCK, 1)
                        else:
                            import fcntl
                            fcntl.flock(lock_file.fileno(), fcntl.LOCK_UN)
                        lock_file.close()
                    except:
                        pass
                    # Xóa file lock nếu có thể
                    try:
                        os.remove(LOCK_FILE)
                    except:
                        pass
            atexit.register(release_lock)
        
    except Exception as e:
        # Nếu có lỗi khi tạo lock, vẫn cho phép app chạy (fallback)
        print(f"Warning: Could not create lock file: {e}")
        if lock_file:
            try:
                lock_file.close()
            except:
                pass
    
    app = QApplication(sys.argv)
    
    # ==================== GLOBAL NO SCROLL EVENT FILTER ====================
    # Vô hiệu hóa wheel scroll trên tất cả ComboBox, SpinBox, DoubleSpinBox
    class NoScrollEventFilter(QObject):
        """Event filter để disable wheel scroll trên ComboBox và SpinBox"""
        def eventFilter(self, obj, event):
            if event.type() == QEvent.Wheel:
                # Check nếu widget là ComboBox hoặc SpinBox
                if isinstance(obj, (QComboBox, QSpinBox, QDoubleSpinBox)):
                    # Ignore wheel event - scroll sẽ được truyền lên parent (scroll area)
                    event.ignore()
                    return True  # Event đã được xử lý
            return False  # Không xử lý, cho phép tiếp tục
    
    no_scroll_filter = NoScrollEventFilter(app)
    app.installEventFilter(no_scroll_filter)
    # ==================== END GLOBAL NO SCROLL EVENT FILTER ====================
    
    # Modern Fusion style
    app.setStyle('Fusion')
    
    # Color palette
    palette = QPalette()
    palette.setColor(QPalette.Window, QColor(250, 250, 250))
    palette.setColor(QPalette.WindowText, QColor(33, 33, 33))
    palette.setColor(QPalette.Base, QColor(255, 255, 255))
    palette.setColor(QPalette.AlternateBase, QColor(245, 245, 245))
    palette.setColor(QPalette.Text, QColor(33, 33, 33))
    palette.setColor(QPalette.Button, QColor(240, 240, 240))
    palette.setColor(QPalette.ButtonText, QColor(33, 33, 33))
    palette.setColor(QPalette.Highlight, QColor(33, 150, 243))
    palette.setColor(QPalette.HighlightedText, QColor(255, 255, 255))
    app.setPalette(palette)

    # --- Auto reCAPTCHA token: Selenium Driver (mặc định) hoặc Extension ---
    # Mặc định dùng Selenium Driver (Trình duyệt) - không cần extension
    # Để dùng Extension: set RECAPTCHA_MODE="extension"
    os.environ.setdefault("AUTO_RECAPTCHA", "1")
    os.environ.setdefault("RECAPTCHA_MODE", "selenium")  # ✅ Mặc định: Selenium Driver
    os.environ.setdefault("CAPTCHA_BRIDGE_URL", "http://localhost:3000")
    
    # ✅ Chỉ start bridge server nếu dùng Extension mode
    recaptcha_mode = os.environ.get("RECAPTCHA_MODE", "selenium").lower()
    if recaptcha_mode in ("extension", "bridge", "ext"):
        ensure_captcha_bridge_server(os.environ["CAPTCHA_BRIDGE_URL"], auto_start=True)
        print("✓ reCAPTCHA mode: Extension (Bridge Server)")
    else:
        print("✓ reCAPTCHA mode: Selenium Driver (Trình duyệt) - Mặc định")
    
    # ✅ CHECK EXISTING SESSION TRƯỚC (nếu user đã login)
    # Điều này quan trọng để check subscription validity của session cũ
    try:
        session_valid, session_data = check_iting_session()
        if session_valid:
            print("✅ Existing session found, checking subscription...")
            
            # Kiểm tra subscription từ session data
            subscription = session_data.get("subscription", {})
            days_remaining = subscription.get("days_remaining")
            end_date = subscription.get("end_date")
            
            # ✅ Xử lý subscription vĩnh viễn (end_date = null)
            is_lifetime = (not end_date or end_date == "null" or str(end_date).lower() == "none")
            
            # Chỉ coi là hết hạn nếu:
            # 1. Không phải subscription vĩnh viễn VÀ
            # 2. days_remaining có giá trị VÀ <= 0
            if not is_lifetime and days_remaining is not None and days_remaining <= 0:
                # Subscription trong session đã hết hạn
                print("🚨 Existing session has expired subscription - forcing re-login")
                
                # Clear session và bắt buộc login lại
                try:
                    api = ItingAPI()
                    api.clear_auth_token(clear_all=True)
                except:
                    pass
                
                # Show message và force login
                msg = QMessageBox()
                msg.setIcon(QMessageBox.Critical)
                msg.setWindowTitle("🚨 Gói Dịch Vụ Hết Hạn")
                msg.setText("Gói dịch vụ của bạn đã hết hạn.\n\nVui lòng đăng nhập lại để kiểm tra trạng thái gói.")
                msg.exec()
                
                # Continue to login form
            else:
                # Session và subscription hợp lệ - skip login form
                print(f"✅ Valid session found with {days_remaining} days remaining")
                
                login_data = {
                    "success": True,
                    "username": session_data.get("username", "Unknown"),
                    "data": session_data,
                    "remember": False,  # Không cần remember vì đã có session
                    "saved_username": "",
                    "saved_password": ""
                }
                
                # Skip login form
                print("⏩ Skipping login form - using existing session")
            
        else:
            # Không có session hợp lệ - hiển thị login form
            print("⚠️ No valid session found - showing login form")
            login_data = None
    
    except Exception as session_check_error:
        print(f"⚠️ Session check error: {session_check_error}")
        login_data = None
    
    # ✅ HIỂN THỊ LOGIN NẾU CHƯA CÓ SESSION HỢP LỆ
    if not login_data:
        login_data = show_standalone_login()
    if not login_data:
        return 0  # User cancelled login
    
    # ✅ TẠO MAIN WINDOW SAU KHI LOGIN THÀNH CÔNG
    window = GoogleLabsFlowQt6()
    
    # Set saved credentials
    window.saved_username = login_data.get("saved_username", "")
    window.saved_password = login_data.get("saved_password", "")
    window.remember_login = login_data.get("remember", False)
    
    # ✅ Lưu activation_key nếu là key login
    if login_data.get("is_key_login"):
        window.activation_key = login_data.get("activation_key", "")
        window.is_key_login = True
    
    # Update account info (bao gồm user_id để start subscription monitoring)
    window.update_account_info(login_data["username"], login_data["data"])
    
    # ✅ Force show and activate window on macOS
    window.show()
    window.raise_()
    window.activateWindow()
    
    # ✅ Additional macOS-specific activation
    try:
        # Force app to front on macOS
        app.setActiveWindow(window)
    except:
        pass
    
    print("✅ Main window shown and activated")
    
    return app.exec()


if __name__ == "__main__":
    sys.exit(main())